_APP_DEFAULT_PLAYER_PROP_BOOKMAKERS = ("fanduel", "draftkings", "betmgm", "bet365")


def _canonical_bookmaker_key(book: Any) -> str:
    try:
        if callable(_normalize_bookmaker_key):
            bk = str(_normalize_bookmaker_key(book) or "").strip().lower()
            if bk:
                return bk
    except Exception:
        pass
    try:
        raw = str(book or "").strip().lower()
    except Exception:
        return ""
    if not raw:
        return ""
    compact = raw.replace(" ", "").replace("-", "").replace("_", "")
    aliases = {
        "fd": "fanduel",
        "fanduel": "fanduel",
        "dk": "draftkings",
        "draftkings": "draftkings",
        "mgm": "betmgm",
        "betmgm": "betmgm",
        "bet365": "bet365",
        "bet365us": "bet365",
    }
    return aliases.get(compact, raw)


def _player_prop_bookmakers_tuple(raw: str | None = None, *, env_name: str = "PLAYER_PROP_BOOKMAKERS") -> tuple[str, ...]:
    try:
        s = raw if raw is not None else os.environ.get(env_name)
        if callable(_resolve_player_prop_bookmakers):
            vals = tuple(str(x).strip().lower() for x in _resolve_player_prop_bookmakers(s) if str(x).strip())
            if vals:
                return vals
            if str(s or "").strip().lower() in {"all", "none", "off", "0", "false", "no"}:
                return tuple()
    except Exception:
        pass
    s = str(raw if raw is not None else os.environ.get(env_name, "")).strip()
    if not s:
        return _APP_DEFAULT_PLAYER_PROP_BOOKMAKERS
    if s.lower() in {"all", "none", "off", "0", "false", "no"}:
        return tuple()
    out: list[str] = []
    seen: set[str] = set()
    for part in s.split(","):
        bk = _canonical_bookmaker_key(part)
        if not bk or bk in seen:
            continue
        seen.add(bk)
        out.append(bk)
    return tuple(out)


def _player_prop_bookmakers_set(raw: str | None = None, *, env_name: str = "PLAYER_PROP_BOOKMAKERS") -> set[str]:
    return set(_player_prop_bookmakers_tuple(raw, env_name=env_name))


def _player_prop_bookmakers_csv(raw: str | None = None, *, env_name: str = "PLAYER_PROP_BOOKMAKERS") -> str | None:
    vals = _player_prop_bookmakers_tuple(raw, env_name=env_name)
    return ",".join(vals) if vals else None


def _live_oddsapi_period_totals_for_game(date_str: str, home_tri: str, away_tri: str) -> dict[str, Any]:
        """Best-effort OddsAPI lines for a matchup (fast path).

        Returns:
            {
                source,
                event_id,
                swapped,
                period_totals: {h1, q1..q4},
                game_lines: {total, home_spread, away_spread, home_ml, away_ml},
                market_keys: {...}
            }
        """
        api_key = (os.environ.get("ODDS_API_KEY") or os.environ.get("THE_ODDS_API_KEY") or "").strip()
        if not api_key:
            return {}

        h = str(home_tri or "").upper().strip()
        a = str(away_tri or "").upper().strip()
        if not h or not a:
            return {}

        cache_key = f"{date_str}:{h}:{a}"
        now = time.time()
        ent = _live_oddsapi_period_cache.get(cache_key)
        if ent and (now - ent[0] < 20):
            return ent[1]

        # Fast direct HTTP calls with short timeouts (avoid blocking UI/pollers).
        base = "https://api.the-odds-api.com"
        sport = "basketball_nba"
        headers = {"Accept": "application/json", "User-Agent": "nba-betting/1.0"}
        timeout_s = 3

        # 1) List events and match by team tricodes.
        # Important: OddsAPI can return multiple events for the same teams over a season.
        # Choose the best match closest to now to avoid pulling a future/past instance.
        event_id = None
        swapped = False
        try:
            r = requests.get(f"{base}/v4/sports/{sport}/events", params={"apiKey": api_key}, headers=headers, timeout=timeout_s)
            evs = r.json() if r.ok else []
            events = evs if isinstance(evs, list) else []
        except Exception:
            events = []

        def _parse_commence_time_utc_naive(x: Any) -> datetime | None:
            try:
                s = str(x or "").strip()
                if not s:
                    return None
                # OddsAPI commonly returns ISO strings like '2026-02-21T03:10:00Z'
                dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
                if dt.tzinfo is not None:
                    dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
                return dt
            except Exception:
                return None

        best: tuple[float, Any, bool] | None = None  # (abs_seconds_from_now, event_id, swapped)
        now_utc = datetime.utcnow()
        for ev in events:
            try:
                if not isinstance(ev, dict):
                    continue
                eh = _get_tricode(str(ev.get("home_team") or ""))
                ea = _get_tricode(str(ev.get("away_team") or ""))
                if not ((eh == h and ea == a) or (eh == a and ea == h)):
                    continue

                dt = _parse_commence_time_utc_naive(ev.get("commence_time"))
                if dt is None:
                    # Still allow selection, but strongly de-prioritize unknown timestamps.
                    abs_s = 1e18
                else:
                    abs_s = float(abs((dt - now_utc).total_seconds()))

                sw = bool(eh == a and ea == h)
                if best is None or abs_s < best[0]:
                    best = (abs_s, ev.get("id"), sw)
            except Exception:
                continue

        if best is not None:
            event_id = best[1]
            swapped = best[2]

        if not event_id:
            out = {}
            _live_oddsapi_period_cache[cache_key] = (now, out)
            return out

        # 2) Discover market keys.
        keys: set[str] = set()
        try:
            r = requests.get(
                f"{base}/v4/sports/{sport}/events/{event_id}/markets",
                params={"apiKey": api_key, "regions": "us"},
                headers=headers,
                timeout=timeout_s,
            )
            jd = r.json() if r.ok else None
            if isinstance(jd, dict):
                # OddsAPI v4 shape: {id, ... , bookmakers:[{markets:[{key,...},...]}, ...]}
                bks = jd.get("bookmakers") or []
                if isinstance(bks, list):
                    for bk in bks:
                        if not isinstance(bk, dict):
                            continue
                        markets = bk.get("markets") or []
                        if not isinstance(markets, list):
                            continue
                        for m in markets:
                            if isinstance(m, dict) and m.get("key"):
                                keys.add(str(m.get("key")))
            elif isinstance(jd, list):
                # Some variants may return a flat list of market metadata
                for m in jd:
                    if isinstance(m, dict) and m.get("key"):
                        keys.add(str(m.get("key")))
        except Exception:
            keys = set()

        # Candidate keys (OddsAPI period keys commonly use suffixes like _q1 and _h1)
        want: dict[str, list[str]] = {
            "game_total": ["totals"],
            "game_spreads": ["spreads"],
            "game_h2h": ["h2h"],
            "h1": ["totals_h1", "totals_1h", "totals_1st_half", "totals_first_half"],
            "q1": ["totals_q1", "totals_1q", "totals_1st_quarter", "totals_first_quarter"],
            "q2": ["totals_q2", "totals_2q", "totals_2nd_quarter", "totals_second_quarter"],
            "q3": ["totals_q3", "totals_3q", "totals_3rd_quarter", "totals_third_quarter"],
            "q4": ["totals_q4", "totals_4q", "totals_4th_quarter", "totals_fourth_quarter"],
        }

        picked: dict[str, str] = {}
        for label, cands in want.items():
            for k in cands:
                if k in keys:
                    picked[label] = k
                    break

        req_markets = sorted(set(picked.values()))
        if not req_markets:
            out = {
                "source": "oddsapi_fast",
                "event_id": str(event_id),
                "swapped": bool(swapped),
                "period_totals": {},
                "game_lines": {},
                "market_keys": {},
            }
            _live_oddsapi_period_cache[cache_key] = (now, out)
            return out

        # 3) Fetch odds for the picked markets and extract the points.
        period_totals: dict[str, float] = {}
        game_lines: dict[str, float] = {}
        try:
            r = requests.get(
                f"{base}/v4/sports/{sport}/events/{event_id}/odds",
                params={
                    "apiKey": api_key,
                    "regions": "us",
                    "markets": ",".join(req_markets),
                    "oddsFormat": "american",
                },
                headers=headers,
                timeout=timeout_s,
            )
            obj = r.json() if r.ok else None
        except Exception:
            obj = None

        mk_to_label = {mkey: label for label, mkey in picked.items()}
        # Aggregate across bookmakers to avoid arbitrary "first book wins" volatility.
        period_pts: dict[str, list[float]] = {k: [] for k in ["h1", "q1", "q2", "q3", "q4"]}
        game_total_pts: list[float] = []
        home_spreads: list[float] = []
        away_spreads: list[float] = []
        home_mls: list[float] = []
        away_mls: list[float] = []

        if isinstance(obj, dict):
            bks = obj.get("bookmakers") or []
            if isinstance(bks, list):
                for bk in bks:
                    if not isinstance(bk, dict):
                        continue
                    markets = bk.get("markets") or []
                    if not isinstance(markets, list):
                        continue
                    for m in markets:
                        if not isinstance(m, dict):
                            continue
                        mkey = str(m.get("key") or "")
                        label = mk_to_label.get(mkey)
                        if not label:
                            continue
                        outs = m.get("outcomes") or []
                        if not isinstance(outs, list):
                            continue

                        if label in {"h1", "q1", "q2", "q3", "q4"}:
                            for oc in outs:
                                if not isinstance(oc, dict):
                                    continue
                                pt = oc.get("point")
                                try:
                                    v = float(pt)
                                    if np.isfinite(v):
                                        period_pts[label].append(float(v))
                                except Exception:
                                    continue

                        # Full-game markets
                        if label == "game_total":
                            for oc in outs:
                                if not isinstance(oc, dict):
                                    continue
                                pt = oc.get("point")
                                try:
                                    v = float(pt)
                                    if np.isfinite(v):
                                        game_total_pts.append(float(v))
                                except Exception:
                                    continue

                        if label == "game_spreads":
                            for oc in outs:
                                if not isinstance(oc, dict):
                                    continue
                                nm = str(oc.get("name") or "")
                                tri = _get_tricode(nm)
                                pt = oc.get("point")
                                try:
                                    v = float(pt)
                                    if not np.isfinite(v):
                                        continue
                                except Exception:
                                    continue
                                if tri == h:
                                    home_spreads.append(float(v))
                                if tri == a:
                                    away_spreads.append(float(v))

                        if label == "game_h2h":
                            for oc in outs:
                                if not isinstance(oc, dict):
                                    continue
                                nm = str(oc.get("name") or "")
                                tri = _get_tricode(nm)
                                pr = oc.get("price")
                                try:
                                    v = float(pr)
                                    if not np.isfinite(v):
                                        continue
                                except Exception:
                                    continue
                                if tri == h:
                                    home_mls.append(float(v))
                                if tri == a:
                                    away_mls.append(float(v))

        # Reduce aggregated values to a single best-effort line.
        try:
            for label, pts in period_pts.items():
                if pts:
                    period_totals[label] = float(np.median(np.asarray(pts, dtype=float)))
        except Exception:
            pass
        try:
            if game_total_pts:
                game_lines["total"] = float(np.median(np.asarray(game_total_pts, dtype=float)))
        except Exception:
            pass
        try:
            if home_spreads:
                game_lines["home_spread"] = float(np.median(np.asarray(home_spreads, dtype=float)))
            if away_spreads:
                game_lines["away_spread"] = float(np.median(np.asarray(away_spreads, dtype=float)))
        except Exception:
            pass
        try:
            if home_mls:
                game_lines["home_ml"] = float(np.median(np.asarray(home_mls, dtype=float)))
            if away_mls:
                game_lines["away_ml"] = float(np.median(np.asarray(away_mls, dtype=float)))
        except Exception:
            pass

        out = {
            "source": "oddsapi_fast",
            "event_id": str(event_id),
            "swapped": bool(swapped),
            "period_totals": period_totals,
            "game_lines": game_lines,
            "market_keys": picked,
        }
        _live_oddsapi_period_cache[cache_key] = (now, out)
        return out


def _live_oddsapi_player_props_for_game(date_str: str, home_tri: str, away_tri: str) -> dict[str, Any]:
    """Best-effort OddsAPI live player prop lines for a matchup.

    Notes:
      - Uses short HTTP timeouts to avoid blocking UI polling.
      - Aggregates lines as the median across returned bookmakers.
      - Returns only a small subset of markets used by the live player lens.

    Returns:
      {
        source,
        event_id,
        swapped,
        markets_requested: [...],
        lines: { "<NAME_KEY>|<stat>": float, ... },
                prices: { "<NAME_KEY>|<stat>": {"over": float|None, "under": float|None}, ... },
        generated_at,
      }
    """
    api_key = (os.environ.get("ODDS_API_KEY") or os.environ.get("THE_ODDS_API_KEY") or "").strip()
    if not api_key:
        return {}

    # Allow a quick kill-switch if quota/cost becomes an issue.
    if str(os.environ.get("LIVE_PLAYER_PROPS_ODDSAPI", "1")).strip().lower() in {"0", "false", "no"}:
        return {}

    h = str(home_tri or "").upper().strip()
    a = str(away_tri or "").upper().strip()
    if not h or not a:
        return {}

    allowed_books = _player_prop_bookmakers_set(os.environ.get("LIVE_PLAYER_PROP_BOOKMAKERS"), env_name="PLAYER_PROP_BOOKMAKERS")
    bookmakers_csv = _player_prop_bookmakers_csv(os.environ.get("LIVE_PLAYER_PROP_BOOKMAKERS"), env_name="PLAYER_PROP_BOOKMAKERS")

    def _env_int(name: str, default: int, lo: int, hi: int) -> int:
        try:
            raw = str(os.environ.get(name, str(default))).strip()
            v = int(float(raw))
            return int(max(lo, min(hi, v)))
        except Exception:
            return int(max(lo, min(hi, int(default))))

    # Cache separately from endpoint TTL to keep quota under control.
    # Important: this function does multiple OddsAPI requests (events + markets + odds).
    # We keep event discovery + market discovery on longer TTLs, and only refresh odds
    # more frequently.
    odds_cache_ttl = _env_int("LIVE_PLAYER_PROPS_ODDS_TTL_SEC", 20, 5, 300)
    event_cache_ttl = _env_int("LIVE_PLAYER_PROPS_EVENT_TTL_SEC", 6 * 60 * 60, 300, 48 * 60 * 60)
    markets_cache_ttl = _env_int("LIVE_PLAYER_PROPS_MARKETS_TTL_SEC", 30 * 60, 60, 6 * 60 * 60)

    # Regions: allow expanding beyond "us" if a deployment/book mix requires it.
    # Example: set LIVE_PLAYER_PROPS_REGIONS="us,us2".
    regions = str(os.environ.get("LIVE_PLAYER_PROPS_REGIONS", "us") or "us").strip() or "us"
    books_sig = bookmakers_csv or "all"
    matchup_key = f"{date_str}:{h}:{a}:{regions}:{books_sig}"
    now = time.time()

    ent = _live_oddsapi_player_props_cache.get(matchup_key)
    if ent and (now - ent[0] < float(odds_cache_ttl)):
        return ent[1]

    base = "https://api.the-odds-api.com"
    sport = "basketball_nba"
    headers = {"Accept": "application/json", "User-Agent": "nba-betting/1.0"}
    timeout_s = 3

    def _parse_iso_utc_naive(x: Any) -> datetime | None:
        try:
            s = str(x or "").strip()
            if not s:
                return None
            dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
            if dt.tzinfo is not None:
                dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
            return dt
        except Exception:
            return None

    def _dt_to_z(dt: datetime) -> str:
        try:
            return dt.replace(tzinfo=timezone.utc).isoformat(timespec="seconds").replace("+00:00", "Z")
        except Exception:
            return dt.isoformat(timespec="seconds") + "Z"

    want_all_markets = str(os.environ.get("LIVE_PLAYER_PROPS_ALL_MARKETS", "1")).strip().lower() in {"1", "true", "yes"}
    try:
        markets_batch = int(float(str(os.environ.get("LIVE_PLAYER_PROPS_MARKETS_BATCH", "20")).strip()))
        markets_batch = int(max(1, min(100, markets_batch)))
    except Exception:
        markets_batch = 20

    # Map lens stats -> OddsAPI market keys.
    # Note: some feeds expose player props primarily under *_alternate keys.
    stat_to_markets: dict[str, list[str]] = {
        "pts": ["player_points", "player_points_alternate"],
        "reb": ["player_rebounds", "player_rebounds_alternate"],
        "ast": ["player_assists", "player_assists_alternate"],
        "threes": ["player_threes"],
        "pra": ["player_points_rebounds_assists", "player_points_rebounds_assists_alternate"],
        "stl": ["player_steals"],
        "blk": ["player_blocks"],
        "tov": ["player_turnovers"],
    }
    market_to_stat: dict[str, str] = {}
    for st, mks in stat_to_markets.items():
        for mk in (mks or []):
            mk0 = str(mk or "").strip()
            if mk0:
                market_to_stat[mk0] = st
    primary_market_by_stat: dict[str, str] = {
        st: str(mks[0]).strip()
        for st, mks in stat_to_markets.items()
        if isinstance(mks, list) and mks and str(mks[0]).strip()
    }
    desired_markets = sorted(set(market_to_stat.keys()))

    # 1) List events and match by team tricodes; select closest commence_time to now.
    # Cache this step aggressively; event ids should be stable for the day.
    event_id = None
    swapped = False

    ev_matchup_key = matchup_key
    ev_ent = _live_oddsapi_player_props_event_cache.get(ev_matchup_key)
    if ev_ent and (now - ev_ent[0] < float(event_cache_ttl)):
        try:
            obj0 = ev_ent[1]
            if isinstance(obj0, dict):
                eid0 = str(obj0.get("event_id") or "").strip()
                if eid0:
                    event_id = eid0
                    swapped = bool(obj0.get("swapped"))
        except Exception:
            event_id = None
            swapped = False

    if not event_id:
        try:
            r = requests.get(
                f"{base}/v4/sports/{sport}/events",
                params={"apiKey": api_key},
                headers=headers,
                timeout=timeout_s,
            )
            evs = r.json() if r.ok else []
            events = evs if isinstance(evs, list) else []
        except Exception:
            events = []

    def _parse_commence_time_utc_naive(x: Any) -> datetime | None:
        try:
            s = str(x or "").strip()
            if not s:
                return None
            dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
            if dt.tzinfo is not None:
                dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
            return dt
        except Exception:
            return None

    if not event_id:
        best: tuple[float, Any, bool] | None = None
        now_utc = datetime.utcnow()
        for ev in events:
            try:
                if not isinstance(ev, dict):
                    continue
                eh = _get_tricode(str(ev.get("home_team") or ""))
                ea = _get_tricode(str(ev.get("away_team") or ""))
                if not ((eh == h and ea == a) or (eh == a and ea == h)):
                    continue
                dt = _parse_commence_time_utc_naive(ev.get("commence_time"))
                abs_s = 1e18 if dt is None else float(abs((dt - now_utc).total_seconds()))
                sw = bool(eh == a and ea == h)
                if best is None or abs_s < best[0]:
                    best = (abs_s, ev.get("id"), sw)
            except Exception:
                continue

        if best is not None:
            event_id = best[1]
            swapped = best[2]

        try:
            eid_s = str(event_id or "").strip()
            if eid_s:
                _live_oddsapi_player_props_event_cache[ev_matchup_key] = (now, {"event_id": eid_s, "swapped": bool(swapped)})
        except Exception:
            pass

    if not event_id:
        out = {}
        _live_oddsapi_player_props_cache[matchup_key] = (now, out)
        return out

    # 2) Discover market keys (some books/plans won't expose player markets).
    mk_cache_key = (
        f"{str(event_id)}:ALL:{regions}:{books_sig}"
        if want_all_markets
        else (f"{str(event_id)}:{','.join(desired_markets)}:{regions}:{books_sig}")
    )
    req_markets: list[str] = []
    mk_ent = _live_oddsapi_player_props_markets_cache.get(mk_cache_key)
    if mk_ent and (now - mk_ent[0] < float(markets_cache_ttl)):
        try:
            req_markets = [str(x) for x in (mk_ent[1] or []) if str(x).strip()]
        except Exception:
            req_markets = []

    if not req_markets:
        keys: set[str] = set()
        try:
            params = {"apiKey": api_key, "regions": regions}
            if bookmakers_csv:
                params["bookmakers"] = bookmakers_csv
            r = requests.get(
                f"{base}/v4/sports/{sport}/events/{event_id}/markets",
                params=params,
                headers=headers,
                timeout=timeout_s,
            )
            jd = r.json() if r.ok else None
            if isinstance(jd, dict):
                bks = jd.get("bookmakers") or []
                if isinstance(bks, list):
                    for bk in bks:
                        if not isinstance(bk, dict):
                            continue
                        markets = bk.get("markets") or []
                        if not isinstance(markets, list):
                            continue
                        for m in markets:
                            if isinstance(m, dict) and m.get("key"):
                                keys.add(str(m.get("key")))
            elif isinstance(jd, list):
                for m in jd:
                    if isinstance(m, dict) and m.get("key"):
                        keys.add(str(m.get("key")))
        except Exception:
            keys = set()

        if want_all_markets and keys:
            # "All" player props markets visible for the event.
            req_markets = sorted({k for k in keys if str(k).startswith("player_")})
        else:
            req_markets = [m for m in desired_markets if m in keys] if keys else desired_markets
        try:
            _live_oddsapi_player_props_markets_cache[mk_cache_key] = (now, list(req_markets))
        except Exception:
            pass
    if not req_markets:
        out = {
            "source": "oddsapi_fast",
            "event_id": str(event_id),
            "swapped": bool(swapped),
            "markets_requested": [],
            "lines": {},
            "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        }
        _live_oddsapi_player_props_cache[matchup_key] = (now, out)
        return out

    # 3) Fetch odds for those markets and aggregate player lines.
    def _chunks(xs: list[str], n: int) -> list[list[str]]:
        outc: list[list[str]] = []
        if n <= 0:
            return [list(xs)]
        cur: list[str] = []
        for x in xs:
            cur.append(x)
            if len(cur) >= n:
                outc.append(cur)
                cur = []
        if cur:
            outc.append(cur)
        return outc

    # Collect points + prices across books; reduce with median.
    # Core (lens) keys: (name_key, stat_key)
    pts_by_key_primary: dict[tuple[str, str], list[float]] = {}
    books_by_key_primary: dict[tuple[str, str], set[str]] = {}
    prices_by_key_primary: dict[tuple[str, str, str], list[float]] = {}
    last_update_by_key_primary: dict[tuple[str, str], list[datetime]] = {}
    pts_by_key_alt: dict[tuple[str, str], list[float]] = {}
    books_by_key_alt: dict[tuple[str, str], set[str]] = {}
    prices_by_key_alt: dict[tuple[str, str, str], list[float]] = {}
    last_update_by_key_alt: dict[tuple[str, str], list[datetime]] = {}

    # Short-key fallback (LAST+FIRST_INITIAL) for OddsAPI abbreviated names.
    # Only emitted when the short key maps to exactly one full name_key for the event.
    short_pts_by_key_primary: dict[tuple[str, str], list[float]] = {}
    short_books_by_key_primary: dict[tuple[str, str], set[str]] = {}
    short_prices_by_key_primary: dict[tuple[str, str, str], list[float]] = {}
    short_last_update_by_key_primary: dict[tuple[str, str], list[datetime]] = {}
    short_pts_by_key_alt: dict[tuple[str, str], list[float]] = {}
    short_books_by_key_alt: dict[tuple[str, str], set[str]] = {}
    short_prices_by_key_alt: dict[tuple[str, str, str], list[float]] = {}
    short_last_update_by_key_alt: dict[tuple[str, str], list[datetime]] = {}
    short_owners_by_key: dict[tuple[str, str], set[str]] = {}

    # All-markets keys: (name_key, market_key)
    pts_by_mk: dict[tuple[str, str], list[float]] = {}
    books_by_mk: dict[tuple[str, str], set[str]] = {}
    prices_by_mk: dict[tuple[str, str, str], list[float]] = {}
    last_update_by_mk: dict[tuple[str, str], list[datetime]] = {}

    def _stat_bucket_maps(stat: str, market_key: str) -> tuple[
        dict[tuple[str, str], list[float]],
        dict[tuple[str, str], set[str]],
        dict[tuple[str, str, str], list[float]],
        dict[tuple[str, str], list[datetime]],
        dict[tuple[str, str], list[float]],
        dict[tuple[str, str], set[str]],
        dict[tuple[str, str, str], list[float]],
        dict[tuple[str, str], list[datetime]],
    ]:
        if primary_market_by_stat.get(stat) == market_key:
            return (
                pts_by_key_primary,
                books_by_key_primary,
                prices_by_key_primary,
                last_update_by_key_primary,
                short_pts_by_key_primary,
                short_books_by_key_primary,
                short_prices_by_key_primary,
                short_last_update_by_key_primary,
            )
        return (
            pts_by_key_alt,
            books_by_key_alt,
            prices_by_key_alt,
            last_update_by_key_alt,
            short_pts_by_key_alt,
            short_books_by_key_alt,
            short_prices_by_key_alt,
            short_last_update_by_key_alt,
        )

    def _merged_keys(*maps: dict[Any, Any]) -> set[Any]:
        out_keys: set[Any] = set()
        for mp in maps:
            out_keys.update(mp.keys())
        return out_keys

    for batch in _chunks(list(req_markets), int(markets_batch)):
        if not batch:
            continue
        try:
            params = {
                "apiKey": api_key,
                "regions": regions,
                "markets": ",".join(batch),
                "oddsFormat": "american",
            }
            if bookmakers_csv:
                params["bookmakers"] = bookmakers_csv
            r = requests.get(
                f"{base}/v4/sports/{sport}/events/{event_id}/odds",
                params=params,
                headers=headers,
                timeout=timeout_s,
            )
            obj = r.json() if r.ok else None
        except Exception:
            obj = None

        if not isinstance(obj, dict):
            continue

        bks = obj.get("bookmakers") or []
        if not isinstance(bks, list):
            continue

        for bk in bks:
            if not isinstance(bk, dict):
                continue
            bk_key = _canonical_bookmaker_key(bk.get("key") or bk.get("title"))
            if allowed_books and (not bk_key or bk_key not in allowed_books):
                continue
            bk_lu = _parse_iso_utc_naive(bk.get("last_update"))
            markets = bk.get("markets") or []
            if not isinstance(markets, list):
                continue
            for m in markets:
                if not isinstance(m, dict):
                    continue
                mkey = str(m.get("key") or "").strip()
                if not mkey:
                    continue

                stat = market_to_stat.get(mkey)
                m_lu = _parse_iso_utc_naive(m.get("last_update"))
                lu = m_lu if m_lu is not None else bk_lu
                outs = m.get("outcomes") or []
                if not isinstance(outs, list):
                    continue
                for oc in outs:
                    if not isinstance(oc, dict):
                        continue
                    player_name = oc.get("description") or oc.get("participant")
                    if not player_name:
                        continue
                    nk = _norm_player_name(str(player_name))
                    if not nk:
                        continue
                    sk = None
                    try:
                        sk0 = _short_player_key(nk)
                        sk = str(sk0 or "").strip().upper() or None
                    except Exception:
                        sk = None

                    # Outcome side: typically "Over" / "Under".
                    side_raw = str(oc.get("name") or oc.get("side") or "").strip().upper()
                    side = None
                    if side_raw in {"OVER", "O"}:
                        side = "OVER"
                    elif side_raw in {"UNDER", "U"}:
                        side = "UNDER"

                    pt = oc.get("point")
                    try:
                        v = float(pt)
                        if not np.isfinite(v):
                            continue
                    except Exception:
                        continue

                    pts_by_mk.setdefault((nk, mkey), []).append(float(v))
                    if bk_key:
                        books_by_mk.setdefault((nk, mkey), set()).add(bk_key)
                    if lu is not None:
                        last_update_by_mk.setdefault((nk, mkey), []).append(lu)

                    if stat:
                        (
                            pts_by_key_target,
                            books_by_key_target,
                            prices_by_key_target,
                            last_update_by_key_target,
                            short_pts_by_key_target,
                            short_books_by_key_target,
                            short_prices_by_key_target,
                            short_last_update_by_key_target,
                        ) = _stat_bucket_maps(stat, mkey)
                        pts_by_key_target.setdefault((nk, stat), []).append(float(v))
                        if bk_key:
                            books_by_key_target.setdefault((nk, stat), set()).add(bk_key)
                        if lu is not None:
                            last_update_by_key_target.setdefault((nk, stat), []).append(lu)

                        # Short-key aggregation for abbreviated player names.
                        if sk is not None:
                            short_owners_by_key.setdefault((sk, stat), set()).add(nk)
                            short_pts_by_key_target.setdefault((sk, stat), []).append(float(v))
                            if bk_key:
                                short_books_by_key_target.setdefault((sk, stat), set()).add(bk_key)
                            if lu is not None:
                                short_last_update_by_key_target.setdefault((sk, stat), []).append(lu)

                    # Capture price when available.
                    if side is not None:
                        pr = oc.get("price")
                        try:
                            pv = float(pr)
                            if np.isfinite(pv) and abs(pv) <= 20000:
                                prices_by_mk.setdefault((nk, mkey, side), []).append(float(pv))
                                if stat:
                                    prices_by_key_target.setdefault((nk, stat, side), []).append(float(pv))
                                    if sk is not None:
                                        short_prices_by_key_target.setdefault((sk, stat, side), []).append(float(pv))
                        except Exception:
                            pass

    lines: dict[str, float] = {}
    try:
        for (nk, stat) in _merged_keys(pts_by_key_primary, pts_by_key_alt):
            pts = pts_by_key_primary.get((nk, stat)) or pts_by_key_alt.get((nk, stat)) or []
            if not pts:
                continue
            lines[f"{nk}|{stat}"] = float(np.median(np.asarray(pts, dtype=float)))
    except Exception:
        lines = {}

    # Line dispersion / distinct-book count by key (helps downstream bettability and diagnostics).
    points_span_by_key: dict[str, float] = {}
    points_n_by_key: dict[str, int] = {}
    try:
        for (nk, stat) in _merged_keys(pts_by_key_primary, pts_by_key_alt):
            pts = pts_by_key_primary.get((nk, stat)) or pts_by_key_alt.get((nk, stat)) or []
            if not pts:
                continue
            k = f"{nk}|{stat}"
            books = books_by_key_primary.get((nk, stat)) or books_by_key_alt.get((nk, stat)) or set()
            book_count = len({x for x in books if x})
            points_n_by_key[k] = int(book_count if book_count > 0 else len(pts))
            uniq = sorted({round(float(x), 2) for x in pts if x is not None and np.isfinite(float(x))})
            if len(uniq) >= 2:
                points_span_by_key[k] = float(max(uniq) - min(uniq))
            else:
                points_span_by_key[k] = 0.0
    except Exception:
        points_span_by_key = {}
        points_n_by_key = {}

    prices: dict[str, dict[str, float]] = {}
    try:
        for (nk, stat, side) in _merged_keys(prices_by_key_primary, prices_by_key_alt):
            prs = prices_by_key_primary.get((nk, stat, side)) or prices_by_key_alt.get((nk, stat, side)) or []
            if not prs:
                continue
            med = float(np.median(np.asarray(prs, dtype=float)))
            k = f"{nk}|{stat}"
            rec = prices.setdefault(k, {})
            if side == "OVER":
                rec["over"] = med
            elif side == "UNDER":
                rec["under"] = med
    except Exception:
        prices = {}

    # Reduce short-key maps (only when unambiguous).
    short_lines: dict[str, float] = {}
    short_points_span_by_key: dict[str, float] = {}
    short_points_n_by_key: dict[str, int] = {}
    short_prices: dict[str, dict[str, float]] = {}
    short_last_update_by_key_out: dict[str, str] = {}
    try:
        # lines + dispersion
        for (sk, stat) in _merged_keys(short_pts_by_key_primary, short_pts_by_key_alt):
            pts = short_pts_by_key_primary.get((sk, stat)) or short_pts_by_key_alt.get((sk, stat)) or []
            owners = short_owners_by_key.get((sk, stat)) or set()
            if len(owners) != 1:
                continue
            if not pts:
                continue
            k = f"{sk}|{stat}"
            short_lines[k] = float(np.median(np.asarray(pts, dtype=float)))
            books = short_books_by_key_primary.get((sk, stat)) or short_books_by_key_alt.get((sk, stat)) or set()
            book_count = len({x for x in books if x})
            short_points_n_by_key[k] = int(book_count if book_count > 0 else len(pts))
            uniq = sorted({round(float(x), 2) for x in pts if x is not None and np.isfinite(float(x))})
            short_points_span_by_key[k] = float(max(uniq) - min(uniq)) if len(uniq) >= 2 else 0.0

        # prices
        for (sk, stat, side) in _merged_keys(short_prices_by_key_primary, short_prices_by_key_alt):
            prs = short_prices_by_key_primary.get((sk, stat, side)) or short_prices_by_key_alt.get((sk, stat, side)) or []
            owners = short_owners_by_key.get((sk, stat)) or set()
            if len(owners) != 1:
                continue
            if not prs:
                continue
            med = float(np.median(np.asarray(prs, dtype=float)))
            k = f"{sk}|{stat}"
            rec = short_prices.setdefault(k, {})
            if side == "OVER":
                rec["over"] = med
            elif side == "UNDER":
                rec["under"] = med

        # last_update
        for (sk, stat) in _merged_keys(short_last_update_by_key_primary, short_last_update_by_key_alt):
            dts = short_last_update_by_key_primary.get((sk, stat)) or short_last_update_by_key_alt.get((sk, stat)) or []
            owners = short_owners_by_key.get((sk, stat)) or set()
            if len(owners) != 1:
                continue
            if not dts:
                continue
            dt_max = max(dts)
            short_last_update_by_key_out[f"{sk}|{stat}"] = _dt_to_z(dt_max)
    except Exception:
        short_lines = {}
        short_points_span_by_key = {}
        short_points_n_by_key = {}
        short_prices = {}
        short_last_update_by_key_out = {}

    out = {
        "source": "oddsapi_fast",
        "event_id": str(event_id),
        "swapped": bool(swapped),
        "markets_requested": req_markets,
        "lines": lines,
        "prices": prices,
        "short_lines": short_lines,
        "short_prices": short_prices,
        "points_span_by_key": points_span_by_key,
        "points_n_by_key": points_n_by_key,
        "short_points_span_by_key": short_points_span_by_key,
        "short_points_n_by_key": short_points_n_by_key,
        "all_lines": {},
        "all_prices": {},
        "all_points_span_by_key": {},
        "all_points_n_by_key": {},
        "last_update_max": None,
        "last_update_by_key": {},
        "short_last_update_by_key": short_last_update_by_key_out,
        "all_last_update_by_key": {},
        "generated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
    }

    # All-markets reductions.
    try:
        all_lines: dict[str, float] = {}
        for (nk, mkey), pts in pts_by_mk.items():
            if not pts:
                continue
            all_lines[f"{nk}|{mkey}"] = float(np.median(np.asarray(pts, dtype=float)))
        out["all_lines"] = all_lines
    except Exception:
        out["all_lines"] = {}

    try:
        all_prices: dict[str, dict[str, float]] = {}
        for (nk, mkey, side), prs in prices_by_mk.items():
            if not prs:
                continue
            med = float(np.median(np.asarray(prs, dtype=float)))
            k = f"{nk}|{mkey}"
            rec = all_prices.setdefault(k, {})
            if side == "OVER":
                rec["over"] = med
            elif side == "UNDER":
                rec["under"] = med
        out["all_prices"] = all_prices
    except Exception:
        out["all_prices"] = {}

    try:
        span_map: dict[str, float] = {}
        n_map: dict[str, int] = {}
        for (nk, mkey), pts in pts_by_mk.items():
            if not pts:
                continue
            k = f"{nk}|{mkey}"
            book_count = len({x for x in (books_by_mk.get((nk, mkey)) or set()) if x})
            n_map[k] = int(book_count if book_count > 0 else len(pts))
            uniq = sorted({round(float(x), 2) for x in pts if x is not None and np.isfinite(float(x))})
            span_map[k] = float(max(uniq) - min(uniq)) if len(uniq) >= 2 else 0.0
        out["all_points_span_by_key"] = span_map
        out["all_points_n_by_key"] = n_map
    except Exception:
        out["all_points_span_by_key"] = {}
        out["all_points_n_by_key"] = {}

    # Reduce last_update timestamps (max = freshest).
    try:
        dt_all: list[datetime] = []
        lu_map: dict[str, str] = {}
        for (nk, stat) in _merged_keys(last_update_by_key_primary, last_update_by_key_alt):
            dts = last_update_by_key_primary.get((nk, stat)) or last_update_by_key_alt.get((nk, stat)) or []
            if not dts:
                continue
            dt_max = max(dts)
            dt_all.append(dt_max)
            lu_map[f"{nk}|{stat}"] = _dt_to_z(dt_max)
        out["last_update_by_key"] = lu_map
        if dt_all:
            out["last_update_max"] = _dt_to_z(max(dt_all))
    except Exception:
        pass

    # Reduce last_update timestamps for all markets.
    try:
        lu_all: dict[str, str] = {}
        for (nk, mkey), dts in last_update_by_mk.items():
            if not dts:
                continue
            dt_max = max(dts)
            lu_all[f"{nk}|{mkey}"] = _dt_to_z(dt_max)
        out["all_last_update_by_key"] = lu_all
    except Exception:
        out["all_last_update_by_key"] = {}

    _live_oddsapi_player_props_cache[matchup_key] = (now, out)
    return out


def _live_append_snapshot(kind: str, date_str: str, record: dict[str, Any]) -> None:
    """Append a Live Lens snapshot record to JSONL (best-effort).

    Controlled by env var LIVE_LENS_SNAPSHOTS in {"1","true","yes"}.
    Writes under <live_lens_artifacts_dir>/live_snapshots/<kind>_<date>.jsonl
    """
    try:
        enabled = str(os.environ.get("LIVE_LENS_SNAPSHOTS", "0")).strip().lower() in {"1", "true", "yes"}
        if not enabled:
            return
        ds = str(date_str or "").strip() or _default_us_slate_date_str()
        kk = str(kind or "").strip() or "snapshot"
        root = _live_lens_artifacts_dir() / "live_snapshots"
        root.mkdir(parents=True, exist_ok=True)
        path = root / f"{kk}_{ds}.jsonl"
        rec = _to_jsonable(record)
        with path.open("a", encoding="utf-8") as f:
            f.write(json.dumps(rec, ensure_ascii=False) + "\n")
    except Exception:
        return



def _safe_int(x: Any) -> int | None:
    try:
        if x is None:
            return None
        if isinstance(x, (int, np.integer)):
            return int(x)
        v = float(x)
        return int(v) if np.isfinite(v) else None
    except Exception:
        return None


def _live_parse_clock_to_sec_left(clock: Any) -> Optional[int]:
    """Parse NBA clock to seconds left in period.

    Supports:
      - 'PT11M45.00S'
      - '11:45'
      - numeric seconds
    """
    try:
        if clock is None:
            return None
        if isinstance(clock, (int, float, np.integer, np.floating)):
            try:
                v = float(clock)
                if not np.isfinite(v):
                    return None
                return int(v)
            except Exception:
                return None
        s = str(clock).strip()
        if not s:
            return None
        # ISO8601-ish: PT11M45.00S
        m = re.match(r"^PT(?:(\d+)M)?(?:(\d+)(?:\.\d+)?)S$", s)
        if m:
            mm = int(m.group(1) or 0)
            ss = int(m.group(2) or 0)
            return mm * 60 + ss
        # Classic mm:ss
        if ":" in s:
            parts = s.split(":")
            if len(parts) == 2:
                mm = int(parts[0])
                ss = int(parts[1])
                return mm * 60 + ss
        return None
    except Exception:
        return None


def _live_round_to_step(v: Optional[float], step: int, *, lo: int, hi: int) -> Optional[int]:
    try:
        if v is None:
            return None
        x = float(v)
        if not np.isfinite(x):
            return None
        # Round *down* to a valid select option (3-minute ladder)
        r = int(np.floor(x / step) * step)
        return int(max(lo, min(hi, r)))
    except Exception:
        return None


def _live_load_smart_sim_by_game_id(date_str: str, game_id: str) -> dict[str, Any] | None:
    """Load the processed SmartSim JSON for a given date+game_id.

    Uses a small TTL cache to avoid disk churn during 60s polling.
    """
    try:
        if not date_str or not game_id:
            return None
        gid_norm = _live_norm_game_id(game_id)
        if not gid_norm:
            return None

        key = f"{date_str}:{gid_norm}"
        now = time.time()
        ent = _live_sim_cache.get(key)
        if ent and (now - ent[0] < 60):
            return ent[1]

        for fp in _load_smart_sim_files_for_date(date_str):
            try:
                raw = fp.read_text(encoding="utf-8")
                obj = json.loads(raw)
                if not isinstance(obj, dict):
                    continue
                # SmartSim JSONs may store 8-digit ids (e.g., 22500814) while live
                # endpoints/frontends may use 10-digit normalized ids (e.g., 0022500814).
                # Compare canonicalized forms so the lookup works either way.
                gid_raw = obj.get("game_id")
                if gid_raw is None:
                    gid_raw = obj.get("nba_game_id")
                gid = _live_norm_game_id(gid_raw) if gid_raw is not None else ""
                if gid and gid == gid_norm:
                    _live_sim_cache[key] = (now, obj)
                    return obj
            except Exception:
                continue
        _live_sim_cache[key] = (now, {})
        return None
    except Exception:
        return None


def _live_interp_cum_p50(intervals: dict[str, Any] | None, *, elapsed_min: float, total_minutes: int) -> float | None:
    """Interpolate cumulative total p50 at arbitrary elapsed minute using 3-min SmartSim ladder."""
    try:
        if not intervals or not isinstance(intervals, dict):
            return None
        segs = intervals.get("segments")
        if not isinstance(segs, list) or not segs:
            return None
        t = float(elapsed_min)
        if not np.isfinite(t):
            return None
        t = max(0.0, min(float(total_minutes), t))
        if t <= 0:
            return 0.0

        step = 3.0
        prev_end = math.floor(t / step) * step
        next_end = min(float(total_minutes), math.ceil(t / step) * step)

        def _cum_at_end(end_min: float) -> float | None:
            if end_min <= 0:
                return 0.0
            seg_end_count = int(math.floor(end_min / step))
            idx = seg_end_count - 1
            if idx < 0:
                return 0.0
            idx = int(max(0, min(len(segs) - 1, idx)))
            s = segs[idx] if isinstance(segs[idx], dict) else {}
            cq = s.get("cum_q") if isinstance(s, dict) else None
            v = (cq or {}).get("p50") if isinstance(cq, dict) else None
            try:
                fv = float(v)
                return float(fv) if np.isfinite(fv) else None
            except Exception:
                return None

        a = _cum_at_end(prev_end)
        b = _cum_at_end(next_end)
        if a is None or b is None:
            return None
        denom = (next_end - prev_end)
        if denom <= 0:
            return float(a)
        frac = (t - prev_end) / denom
        return float(a + frac * (b - a))
    except Exception:
        return None


def _live_cum_p50_series_by_min(intervals: dict[str, Any] | None, *, total_minutes: int) -> list[float | None]:
    """Return list length total_minutes+1 of interpolated cum p50 at each elapsed minute 0..total_minutes."""
    out: list[float | None] = []
    for m in range(0, int(total_minutes) + 1):
        out.append(_live_interp_cum_p50(intervals, elapsed_min=float(m), total_minutes=int(total_minutes)))
    return out


def _live_fetch_cdn_scoreboard(date_str: str) -> dict[str, Any]:
    """Fetch NBA CDN scoreboard for a date and return JSON dict."""
    try:
        # Cache for 10 seconds
        now = time.time()
        ent = _live_cdn_scoreboard_cache.get(date_str)
        if ent and (now - ent[0] < 10):
            return ent[1]

        try:
            target = datetime.strptime(date_str, "%Y-%m-%d").date()
        except Exception:
            return {}
        today = datetime.now().date()

        headers = {
            "Accept": "application/json, text/plain, */*",
            "Accept-Language": "en-US,en;q=0.9",
            "Cache-Control": "no-cache",
            "Pragma": "no-cache",
            "Referer": "https://www.nba.com/",
            "User-Agent": (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/125.0.0.0 Safari/537.36"
            ),
        }
        if target == today:
            u = "https://cdn.nba.com/static/json/liveData/scoreboard/todaysScoreboard_00.json"
        else:
            ymd = target.strftime("%Y%m%d")
            u = f"https://cdn.nba.com/static/json/liveData/scoreboard/scoreboard_{ymd}.json"
        # Some environments inject broken proxy settings via env vars.
        # Use a session that ignores env (trust_env=False) for reliability.
        try:
            sess = requests.Session()
            sess.trust_env = False
            r = sess.get(u, headers=headers, timeout=15)
        except Exception:
            r = requests.get(u, headers=headers, timeout=15)
        if not r.ok:
            payload = {}
        else:
            payload = r.json() or {}
        _live_cdn_scoreboard_cache[date_str] = (now, payload)
        return payload
    except Exception:
        return {}


def _live_norm_game_id(game_id: str) -> str:
    """Normalize a game_id to the canonical format used by the frontend.

    - If numeric-ish, return 10-digit zero-padded string.
    - Otherwise, return stripped original.
    """
    try:
        s = str(game_id or "").strip()
        if not s:
            return ""
        digits = "".join(ch for ch in s if ch.isdigit())
        if digits:
            return digits.zfill(10) if len(digits) < 10 else digits
        return s
    except Exception:
        return str(game_id or "").strip()


def _live_fetch_espn_scoreboard(date_str: str) -> dict[str, Any]:
    """Fetch ESPN public scoreboard JSON for the date with a short TTL cache."""
    try:
        now = time.time()
        ent = _live_espn_scoreboard_cache.get(date_str)
        if ent and (now - ent[0] < 20):
            return ent[1]
        jd = _fetch_espn_scoreboard(date_str) or {}
        payload = jd if isinstance(jd, dict) else {}
        _live_espn_scoreboard_cache[date_str] = (now, payload)
        return payload
    except Exception:
        return {}


def _live_fetch_espn_summary(event_id: str) -> dict[str, Any]:
    """Fetch ESPN game summary JSON (includes play-by-play) with a short TTL cache."""
    try:
        eid = str(event_id or "").strip()
        if not eid:
            return {}
        now = time.time()
        ent = _live_espn_summary_cache.get(eid)
        if ent and (now - ent[0] < 15):
            return ent[1]
        url = f"https://site.web.api.espn.com/apis/site/v2/sports/basketball/nba/summary?event={eid}"
        try:
            headers = {
                "Accept": "application/json, text/plain, */*",
                "Accept-Language": "en-US,en;q=0.9",
                "Cache-Control": "no-cache",
                "Pragma": "no-cache",
                "User-Agent": (
                    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                    "AppleWebKit/537.36 (KHTML, like Gecko) "
                    "Chrome/125.0.0.0 Safari/537.36"
                ),
                "Referer": "https://www.espn.com/",
            }
            # Ignore proxy env vars for stability.
            try:
                sess = requests.Session()
                sess.trust_env = False
                r = sess.get(url, headers=headers, timeout=10)
            except Exception:
                r = requests.get(url, headers=headers, timeout=10)
            if not r.ok:
                _live_espn_summary_cache[eid] = (now, {})
                return {}
            jd = r.json() or {}
            payload = jd if isinstance(jd, dict) else {}
            _live_espn_summary_cache[eid] = (now, payload)
            return payload
        except Exception:
            _live_espn_summary_cache[eid] = (now, {})
            return {}
    except Exception:
        return {}


def _live_espn_actions_from_summary(summary: dict[str, Any]) -> list[dict[str, Any]]:
    """Translate ESPN summary plays into the Live Lens action schema.

    The downstream PBP parsers expect NBA-CDN-like fields:
      teamTricode, actionType, shotResult, isFieldGoal, shotValue, period, clock, scoreHome, scoreAway
    """
    try:
        if not isinstance(summary, dict):
            return []

        # Map ESPN team id -> tricode
        team_id_to_tri: dict[str, str] = {}
        try:
            hdr = summary.get("header") if isinstance(summary.get("header"), dict) else {}
            comps = hdr.get("competitions") if isinstance(hdr, dict) else None
            if isinstance(comps, list) and comps:
                comp0 = comps[0] if isinstance(comps[0], dict) else {}
                competitors = comp0.get("competitors") if isinstance(comp0, dict) else None
                if isinstance(competitors, list):
                    for c in competitors:
                        if not isinstance(c, dict):
                            continue
                        tm = c.get("team") if isinstance(c.get("team"), dict) else {}
                        tid = str(tm.get("id") or "").strip()
                        ab = _espn_to_tri(str(tm.get("abbreviation") or "").strip())
                        if tid and ab:
                            team_id_to_tri[tid] = ab
        except Exception:
            team_id_to_tri = {}

        plays = summary.get("plays")
        if not isinstance(plays, list) or not plays:
            return []

        out: list[dict[str, Any]] = []
        for p in plays:
            try:
                if not isinstance(p, dict):
                    continue
                per = None
                try:
                    per = int(((p.get("period") or {}) if isinstance(p.get("period"), dict) else {}).get("number"))
                except Exception:
                    per = None

                clk = None
                try:
                    clk = (((p.get("clock") or {}) if isinstance(p.get("clock"), dict) else {}).get("displayValue"))
                except Exception:
                    clk = None

                sh = _safe_int(p.get("homeScore"))
                sa = _safe_int(p.get("awayScore"))

                team_id = None
                try:
                    team_id = str(((p.get("team") or {}) if isinstance(p.get("team"), dict) else {}).get("id") or "").strip()
                except Exception:
                    team_id = None
                tri = team_id_to_tri.get(team_id or "", "unknown")

                shooting = bool(p.get("shootingPlay"))
                pts_att = _safe_int(p.get("pointsAttempted"))
                score_val = _safe_int(p.get("scoreValue"))
                text = str(p.get("text") or "").strip()
                text_l = text.lower()

                # Derive a minimal shot taxonomy compatible with existing attempt stats.
                action_type = str(((p.get("type") or {}) if isinstance(p.get("type"), dict) else {}).get("text") or "").strip()
                if shooting and pts_att == 1 and ("free throw" in text_l or "free throw" in action_type.lower()):
                    action_type = "Free Throw"

                is_fg = bool(shooting and (pts_att in (2, 3)))
                shot_val = int(pts_att) if (is_fg and pts_att in (2, 3)) else 0
                shot_res = ""
                if shooting:
                    if score_val is not None and score_val > 0:
                        shot_res = "Made"
                    elif "miss" in text_l:
                        shot_res = "Missed"
                    elif "make" in text_l:
                        shot_res = "Made"

                out.append(
                    {
                        "teamTricode": tri,
                        "actionType": action_type,
                        "shotResult": shot_res,
                        "isFieldGoal": 1 if is_fg else 0,
                        "shotValue": shot_val,
                        "period": per,
                        "clock": clk,
                        "scoreHome": sh,
                        "scoreAway": sa,
                        "description": text,
                    }
                )
            except Exception:
                continue

        return out
    except Exception:
        return []


def _live_extract_player_boxscore_from_espn_summary(summary: dict[str, Any]) -> list[dict[str, Any]]:
    """Extract per-player boxscore totals from an ESPN /summary payload.

        Returns a flat list of dicts with keys:
            team_tri, player_id, player, mp, pts, reb, ast, stl, blk, tov, threes_made,
            pf (personal fouls, best-effort), starter (best-effort)

    This is best-effort and tolerant to ESPN schema changes.
    """

    def _to_num(x: Any) -> float | None:
        try:
            if x is None:
                return None
            s = str(x).strip()
            if not s or s.lower() in {"nan", "none", "null", "dnp", "--"}:
                return None
            return float(s)
        except Exception:
            return None

    def _to_int(x: Any) -> int | None:
        try:
            v = _to_num(x)
            if v is None:
                return None
            return int(round(v))
        except Exception:
            return None

    def _parse_made_attempts(x: Any) -> int | None:
        try:
            s = str(x or "").strip()
            if not s:
                return None
            if "-" in s:
                a = s.split("-", 1)[0].strip()
                return int(float(a))
            return int(float(s))
        except Exception:
            return None

    def _parse_minutes(x: Any) -> float | None:
        try:
            s = str(x or "").strip()
            if not s:
                return None
            if s.lower() in {"dnp", "--"}:
                return 0.0
            if ":" in s:
                mm, ss = s.split(":", 1)
                m = float(mm)
                sec = float(ss)
                return m + (sec / 60.0)
            return float(s)
        except Exception:
            return None

    out: list[dict[str, Any]] = []
    try:
        if not isinstance(summary, dict):
            return []
        box = summary.get("boxscore") if isinstance(summary.get("boxscore"), dict) else {}
        teams = box.get("players") if isinstance(box, dict) else None
        if not isinstance(teams, list) or not teams:
            return []

        for tb in teams:
            if not isinstance(tb, dict):
                continue
            team = tb.get("team") if isinstance(tb.get("team"), dict) else {}
            team_tri = _espn_to_tri(str(team.get("abbreviation") or team.get("shortDisplayName") or "").strip())
            if not team_tri:
                team_tri = str(team.get("abbreviation") or "").strip().upper() or None

            stats_groups = tb.get("statistics")
            if not isinstance(stats_groups, list):
                continue

            for sg in stats_groups:
                if not isinstance(sg, dict):
                    continue
                labels = sg.get("labels")
                if not isinstance(labels, list) or not labels:
                    labels = sg.get("keys") if isinstance(sg.get("keys"), list) else []
                labels_l = [str(x or "").strip().lower() for x in (labels or [])]
                athletes = sg.get("athletes")
                if not isinstance(athletes, list) or not athletes:
                    continue

                for a in athletes:
                    if not isinstance(a, dict):
                        continue
                    starter = None
                    try:
                        starter = bool(a.get("starter")) if ("starter" in a) else None
                    except Exception:
                        starter = None
                    ath = a.get("athlete") if isinstance(a.get("athlete"), dict) else {}
                    player_id = str(ath.get("id") or "").strip() or None
                    player = str(ath.get("displayName") or ath.get("shortName") or a.get("name") or "").strip()
                    if not player:
                        continue

                    vals = a.get("stats") if isinstance(a.get("stats"), list) else []
                    m: dict[str, Any] = {}
                    for i, lab in enumerate(labels_l):
                        try:
                            if i < len(vals) and lab:
                                m[lab] = vals[i]
                        except Exception:
                            continue

                    mp = _parse_minutes(m.get("min") or m.get("minutes") or m.get("mp") or m.get("time"))
                    if mp is None:
                        mp = 0.0

                    pts = _to_int(m.get("pts") or m.get("points"))
                    reb = _to_int(m.get("reb") or m.get("rebs") or m.get("totreb"))
                    ast = _to_int(m.get("ast") or m.get("assists"))
                    stl = _to_int(m.get("stl") or m.get("steals"))
                    blk = _to_int(m.get("blk") or m.get("blocks"))
                    tov = _to_int(m.get("to") or m.get("tov") or m.get("turnovers"))

                    pf = _to_int(m.get("pf") or m.get("fouls") or m.get("pfouls") or m.get("personal fouls"))
                    if pf is None:
                        try:
                            for k, v in m.items():
                                kk = str(k or "").lower().strip()
                                if kk in {"pf", "fouls", "personal fouls"} or ("foul" in kk and len(kk) <= 20):
                                    pf = _to_int(v)
                                    if pf is not None:
                                        break
                        except Exception:
                            pf = None

                    threes = _parse_made_attempts(m.get("3pt") or m.get("3pm") or m.get("3p"))
                    if threes is None:
                        try:
                            for k, v in m.items():
                                kk = str(k or "").lower()
                                if "3" in kk and "pt" in kk:
                                    threes = _parse_made_attempts(v)
                                    if threes is not None:
                                        break
                        except Exception:
                            threes = None

                    nonzero = any((x or 0) > 0 for x in [pts or 0, reb or 0, ast or 0, stl or 0, blk or 0, tov or 0, threes or 0])
                    if mp <= 0.0 and not nonzero:
                        continue

                    out.append(
                        {
                            "team_tri": str(team_tri).upper().strip() if team_tri else None,
                            "player_id": player_id,
                            "player": player,
                            "mp": float(mp),
                            "pts": pts,
                            "reb": reb,
                            "ast": ast,
                            "stl": stl,
                            "blk": blk,
                            "tov": tov,
                            "threes_made": threes,
                            "pf": pf,
                            "starter": starter,
                        }
                    )

        return out
    except Exception:
        return []


def _live_extract_espn_games(jd: dict[str, Any]) -> list[dict[str, Any]]:
    """Extract live-ish game objects from ESPN scoreboard.

    Output records match the shape used by /api/live/scoreboard as closely as possible.
    Note: ESPN event ids do not match NBA game ids.
    """
    out: list[dict[str, Any]] = []
    try:
        evs = jd.get("events") if isinstance(jd, dict) else None
        if not isinstance(evs, list):
            return []
        for e in evs:
            try:
                comps = e.get("competitions") if isinstance(e, dict) else None
                if not isinstance(comps, list) or not comps:
                    continue
                c = comps[0] if isinstance(comps[0], dict) else {}
                status = c.get("status") if isinstance(c, dict) else {}
                st_type = (status.get("type") if isinstance(status, dict) else {}) or {}
                completed = bool(st_type.get("completed"))
                state = str(st_type.get("state") or "").strip().lower()  # pre|in|post
                short = str(st_type.get("shortDetail") or st_type.get("detail") or "").strip()
                if not short:
                    short = "Final" if completed else "Scheduled"

                period = None
                clock = None
                try:
                    period = int(status.get("period")) if isinstance(status, dict) and status.get("period") is not None else None
                except Exception:
                    period = None
                try:
                    clock = status.get("displayClock") if isinstance(status, dict) else None
                except Exception:
                    clock = None

                teams = c.get("competitors") if isinstance(c, dict) else None
                if not isinstance(teams, list) or len(teams) < 2:
                    continue
                home = next((t for t in teams if str((t or {}).get("homeAway")) == "home"), None)
                away = next((t for t in teams if str((t or {}).get("homeAway")) == "away"), None)
                if not isinstance(home, dict) or not isinstance(away, dict):
                    continue
                home_tri = _espn_to_tri((((home.get("team") or {}) if isinstance(home.get("team"), dict) else {}).get("abbreviation")))
                away_tri = _espn_to_tri((((away.get("team") or {}) if isinstance(away.get("team"), dict) else {}).get("abbreviation")))
                if not home_tri or not away_tri:
                    continue

                def _score(x: dict[str, Any]) -> int | None:
                    try:
                        s = x.get("score")
                        if s is None or str(s).strip() == "":
                            return None
                        return int(float(s))
                    except Exception:
                        return None

                home_pts = _score(home)
                away_pts = _score(away)
                in_progress = bool(state == "in")
                final = bool(completed or state == "post")
                status_id = 2 if in_progress else (3 if final else 1)
                periods: list[dict[str, Any]] = []
                try:
                    home_ls = home.get("linescores") if isinstance(home, dict) else None
                    away_ls = away.get("linescores") if isinstance(away, dict) else None
                    if isinstance(home_ls, list) or isinstance(away_ls, list):
                        n_periods = max(
                            len(home_ls) if isinstance(home_ls, list) else 0,
                            len(away_ls) if isinstance(away_ls, list) else 0,
                        )
                        for i in range(n_periods):
                            try:
                                hv = None
                                av = None
                                if isinstance(home_ls, list) and i < len(home_ls):
                                    hv = home_ls[i].get("value")
                                if isinstance(away_ls, list) and i < len(away_ls):
                                    av = away_ls[i].get("value")
                                periods.append(
                                    {
                                        "period": int(i + 1),
                                        "home": int(float(hv)) if hv is not None and str(hv).strip() != "" else None,
                                        "away": int(float(av)) if av is not None and str(av).strip() != "" else None,
                                    }
                                )
                            except Exception:
                                continue
                except Exception:
                    periods = []

                out.append(
                    {
                        "game_id": str(e.get("id") or "").strip() or None,  # ESPN event id
                        "home": str(home_tri).upper(),
                        "away": str(away_tri).upper(),
                        "home_pts": home_pts,
                        "away_pts": away_pts,
                        "status_id": status_id,
                        "status": short,
                        "period": period,
                        "clock": clock,
                        "in_progress": in_progress,
                        "final": final,
                        "periods": periods,
                    }
                )
            except Exception:
                continue
        return out
    except Exception:
        return []


def _live_sim_matchups_for_date(date_str: str) -> list[dict[str, Any]]:
    """Return SmartSim games for a date as minimal matchup records."""
    out: list[dict[str, Any]] = []
    for fp in _load_smart_sim_files_for_date(date_str):
        try:
            obj = json.loads(fp.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(obj, dict):
            continue
        home = str(obj.get("home") or "").strip().upper()
        away = str(obj.get("away") or "").strip().upper()
        if not home or not away:
            continue
        # Prefer the numeric NBA game id used by SmartSim (/api/cards uses this).
        # Fall back to a stable matchup id when missing.
        gid_raw = obj.get("game_id")
        if gid_raw is None:
            gid_raw = obj.get("nba_game_id")
        gid_norm = _live_norm_game_id(gid_raw) if gid_raw is not None else ""
        out.append({"game_id": gid_norm or f"{away}@{home}", "home": home, "away": away})
    return out


def _live_build_scoreboard_games(date_str: str) -> tuple[str, list[dict[str, Any]]]:
    """Build the live scoreboard game list.

    Prefers ESPN for status/clock, but keeps NBA game_id stable by matching ESPN
    events to SmartSim games via (home,away).

    Falls back to NBA CDN when SmartSim games are unavailable or ESPN fails.
    """
    try:
        sim_games = _live_sim_matchups_for_date(date_str)
        jd = _live_fetch_espn_scoreboard(date_str)
        espn_games = _live_extract_espn_games(jd) if jd else []

        def _matchup_id(home_tri: Any, away_tri: Any) -> str:
            h = str(home_tri or "").strip().upper()
            a = str(away_tri or "").strip().upper()
            return f"{a}@{h}" if h and a else ""

        if sim_games and espn_games:
            espn_by_pair: dict[tuple[str, str], dict[str, Any]] = {}
            for eg in espn_games:
                try:
                    k = (str(eg.get("home") or "").upper(), str(eg.get("away") or "").upper())
                    if k[0] and k[1]:
                        espn_by_pair[k] = eg
                except Exception:
                    continue

            merged: list[dict[str, Any]] = []
            for sg in sim_games:
                home = str(sg.get("home") or "").upper()
                away = str(sg.get("away") or "").upper()
                sg_gid = str(sg.get("game_id") or "").strip()
                gid = _live_norm_game_id(sg_gid) if sg_gid else ""
                gid = gid or _matchup_id(home, away)
                eg = espn_by_pair.get((home, away))
                if eg:
                    merged.append(
                        {
                            "game_id": gid,
                            "home": home,
                            "away": away,
                            "home_pts": eg.get("home_pts"),
                            "away_pts": eg.get("away_pts"),
                            "status_id": eg.get("status_id"),
                            "status": eg.get("status"),
                            "period": eg.get("period"),
                            "clock": eg.get("clock"),
                            "in_progress": bool(eg.get("in_progress")),
                            "final": bool(eg.get("final")),
                            "periods": eg.get("periods") if isinstance(eg.get("periods"), list) else [],
                            "espn_event_id": eg.get("game_id"),
                            "match": "teams",
                        }
                    )
                else:
                    merged.append(
                        {
                            "game_id": gid,
                            "home": home,
                            "away": away,
                            "home_pts": None,
                            "away_pts": None,
                            "status_id": 1,
                            "status": "Scheduled",
                            "period": None,
                            "clock": None,
                            "in_progress": False,
                            "final": False,
                            "periods": [],
                            "espn_event_id": None,
                            "match": None,
                        }
                    )
            return "espn", merged

        # If SmartSim isn't available (common on Render / fresh deploy), still provide
        # a usable scoreboard from ESPN. NBA CDN's dated scoreboard URLs are no longer
        # reliably accessible (often 403), so ESPN is the safest fallback.
        if (not sim_games) and espn_games:
            out: list[dict[str, Any]] = []
            for eg in espn_games:
                try:
                    eid = str(eg.get("game_id") or "").strip()
                    gid = _matchup_id(eg.get("home"), eg.get("away"))
                    rec = dict(eg)
                    rec["game_id"] = gid
                    rec["espn_event_id"] = eid
                    rec["match"] = None
                    out.append(rec)
                except Exception:
                    continue
            return "espn", out

        # If we have sim games but ESPN failed/empty, still return sim list.
        if sim_games and not espn_games:
            merged = []
            for sg in sim_games:
                sg_gid = str(sg.get("game_id") or "").strip()
                gid = _live_norm_game_id(sg_gid) if sg_gid else ""
                merged.append(
                    {
                        "game_id": gid or _matchup_id(sg.get("home"), sg.get("away")) or sg_gid,
                        "home": sg.get("home"),
                        "away": sg.get("away"),
                        "home_pts": None,
                        "away_pts": None,
                        "status_id": 1,
                        "status": "Scheduled",
                        "period": None,
                        "clock": None,
                        "in_progress": False,
                        "final": False,
                        "periods": [],
                        "espn_event_id": None,
                        "match": None,
                    }
                )
            return "sim_only", merged

        # Fallback to NBA CDN scoreboard (best-effort; dated CDN URLs often 403)
        sb = _live_fetch_cdn_scoreboard(date_str)
        games = _live_extract_scoreboard_games(sb)
        # Prefer matchup ids for frontend joins; retain NBA numeric id separately when present.
        for g in games:
            try:
                nba_gid = str(g.get("game_id") or "").strip()
                h = str(g.get("home") or "").strip().upper()
                a = str(g.get("away") or "").strip().upper()
                g["nba_game_id"] = _live_norm_game_id(nba_gid) if nba_gid else None
                g["game_id"] = _matchup_id(h, a) or nba_gid
                g.setdefault("espn_event_id", None)
            except Exception:
                continue
        return "nba_cdn", games
    except Exception:
        sb = _live_fetch_cdn_scoreboard(date_str)
        games = _live_extract_scoreboard_games(sb)
        return "nba_cdn", games


def _live_extract_scoreboard_games(sb_json: dict[str, Any]) -> list[dict[str, Any]]:
    try:
        games = (sb_json.get("scoreboard") or {}).get("games") or []
        out: list[dict[str, Any]] = []
        for g in games:
            try:
                gid = str(g.get("gameId") or "").strip() or None
                home = (g.get("homeTeam") or {})
                away = (g.get("awayTeam") or {})
                home_tri = str(home.get("teamTricode") or "").upper().strip() or None
                away_tri = str(away.get("teamTricode") or "").upper().strip() or None
                home_pts = _safe_int(home.get("score"))
                away_pts = _safe_int(away.get("score"))
                st_id = _safe_int(g.get("gameStatus"))
                st_text = g.get("gameStatusText")
                period = _safe_int((g.get("period") or {}).get("current"))
                clock = (g.get("gameClock") or (g.get("clock") or None))
                in_progress = bool(st_id == 2)
                final = bool(st_id == 3)
                out.append(
                    {
                        "game_id": gid,
                        "home": home_tri,
                        "away": away_tri,
                        "home_pts": home_pts,
                        "away_pts": away_pts,
                        "status_id": st_id,
                        "status": st_text,
                        "period": period,
                        "clock": clock,
                        "in_progress": in_progress,
                        "final": final,
                    }
                )
            except Exception:
                continue
        return out
    except Exception:
        return []


def _live_fetch_pbp_actions(game_id: str) -> list[dict[str, Any]]:
    try:
        # Cache CDN PBP fetches (these are the slowest piece of live_player_lens).
        # Keep TTL separate from endpoint TTL so frequent UI polling doesn't hammer the CDN.
        try:
            ttl = int(float(str(os.environ.get("LIVE_PBP_TTL_SEC", "10")).strip()))
        except Exception:
            ttl = 10
        ttl = int(max(1, min(120, ttl)))

        headers = {
            "Accept": "application/json, text/plain, */*",
            "Accept-Language": "en-US,en;q=0.9",
            "Cache-Control": "no-cache",
            "Pragma": "no-cache",
            "Referer": "https://www.nba.com/",
            "User-Agent": (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/125.0.0.0 Safari/537.36"
            ),
        }
        gid = str(game_id).strip()
        if not gid:
            return []

        now = time.time()
        ent = _live_pbp_actions_cache.get(gid)
        if ent and (now - float(ent[0]) < float(ttl)):
            return ent[1]

        u = f"https://cdn.nba.com/static/json/liveData/playbyplay/playbyplay_00_{gid}.json"
        r = requests.get(u, headers=headers, timeout=15)
        if not r.ok:
            u2 = f"https://nba-prod-us-east-1-mediaops-stats.s3.amazonaws.com/NBA/liveData/playbyplay/playbyplay_00_{gid}.json"
            r = requests.get(u2, headers=headers, timeout=15)
        if not r.ok:
            return []
        j = r.json() or {}
        actions = ((j.get("game") or {}).get("actions") or [])
        try:
            if isinstance(actions, list):
                _live_pbp_actions_cache[gid] = (now, actions)
        except Exception:
            pass
        return actions if isinstance(actions, list) else []
    except Exception:
        return []


def _live_load_lens_override() -> dict[str, Any] | None:
    """Best-effort cached read of live_lens_tuning_override.json.

    This file can be read on every poll via /api/live_player_lens; cache it by
    mtime (plus a short TTL) to avoid repeated disk I/O.
    """
    global _live_lens_override_cache
    try:
        p = _live_lens_artifacts_dir() / "live_lens_tuning_override.json"
    except Exception:
        return None

    if not p.exists():
        return None

    try:
        ttl = int(float(str(os.environ.get("LIVE_LENS_OVERRIDE_TTL_SEC", "5")).strip()))
    except Exception:
        ttl = 5
    ttl = int(max(1, min(60, ttl)))

    now = time.time()
    try:
        mtime = float(p.stat().st_mtime)
    except Exception:
        mtime = 0.0

    try:
        loaded_at, last_mtime, cached = _live_lens_override_cache
        if cached is not None and (now - float(loaded_at) < float(ttl)) and float(last_mtime) == float(mtime):
            return cached
    except Exception:
        pass

    try:
        obj = json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        obj = None

    if not isinstance(obj, dict):
        obj = None

    try:
        _live_lens_override_cache = (now, mtime, obj)
    except Exception:
        pass
    return obj


def _live_roster_pid_by_team_nk() -> dict[tuple[str, str], int]:
    """Cached mapping (TEAM_TRI, name_key) -> player_id."""
    global _roster_pid_by_team_nk_cache
    try:
        roster = _ensure_rosters_loaded()
    except Exception:
        roster = None

    if not isinstance(roster, pd.DataFrame) or roster.empty:
        return {}

    try:
        n = int(len(roster.index))
    except Exception:
        n = -1

    try:
        if _roster_pid_by_team_nk_cache is not None and int(_roster_pid_by_team_nk_cache[0]) == int(n):
            return _roster_pid_by_team_nk_cache[1]
    except Exception:
        pass

    out: dict[tuple[str, str], int] = {}
    try:
        # itertuples is much faster than iterrows for tight loops.
        for rr in roster.itertuples(index=False):
            try:
                # Access via getattr to tolerate missing columns.
                tri0 = str(getattr(rr, "TEAM_ABBREVIATION", "") or "").strip().upper()
                nm0 = str(getattr(rr, "PLAYER", "") or "").strip()
                pid0 = _safe_int(getattr(rr, "PLAYER_ID", None))
                if not tri0 or not nm0 or pid0 is None:
                    continue
                nk0 = _norm_player_name(nm0)
                if not nk0:
                    continue
                out[(tri0, nk0)] = int(pid0)
            except Exception:
                continue
    except Exception:
        out = {}

    try:
        _roster_pid_by_team_nk_cache = (n, out)
    except Exception:
        pass
    return out


def _live_pbp_attempt_stats(actions: list[dict[str, Any]]) -> dict[str, Any]:
    """Compute FT/2P/3P attempt stats from CDN play-by-play actions."""
    def _init():
        return {"ft_att": 0, "ft_made": 0, "fg2_att": 0, "fg2_made": 0, "fg3_att": 0, "fg3_made": 0}

    def _finalize(d: dict[str, Any]) -> dict[str, Any]:
        try:
            ft_att = int(d.get("ft_att") or 0)
            ft_made = int(d.get("ft_made") or 0)
            fg2_att = int(d.get("fg2_att") or 0)
            fg2_made = int(d.get("fg2_made") or 0)
            fg3_att = int(d.get("fg3_att") or 0)
            fg3_made = int(d.get("fg3_made") or 0)

            d["ft_miss"] = max(0, ft_att - ft_made)
            d["fg2_miss"] = max(0, fg2_att - fg2_made)
            d["fg3_miss"] = max(0, fg3_att - fg3_made)
            d["fga"] = fg2_att + fg3_att
            d["fgm"] = fg2_made + fg3_made
            d["fg_miss"] = max(0, d["fga"] - d["fgm"])
            pts = ft_made + 2 * fg2_made + 3 * fg3_made
            d["pts_from_shots"] = pts

            def _pct(made: int, att: int) -> float | None:
                try:
                    if att <= 0:
                        return None
                    return float(made) / float(att)
                except Exception:
                    return None

            d["ft_pct"] = _pct(ft_made, ft_att)
            d["fg2_pct"] = _pct(fg2_made, fg2_att)
            d["fg3_pct"] = _pct(fg3_made, fg3_att)
            d["fg_pct"] = _pct(d["fgm"], d["fga"])
            try:
                d["efg_pct"] = (float(d["fgm"]) + 0.5 * float(fg3_made)) / float(d["fga"]) if d["fga"] > 0 else None
            except Exception:
                d["efg_pct"] = None
            try:
                denom = 2.0 * (float(d["fga"]) + 0.44 * float(ft_att))
                d["ts_pct"] = float(pts) / denom if denom > 0 else None
            except Exception:
                d["ts_pct"] = None
        except Exception:
            return d
        return d

    out: dict[str, Any] = {"home": _init(), "away": _init(), "unknown": _init(), "total": _init()}
    for a in actions or []:
        try:
            tri = str(a.get("teamTricode") or "").upper().strip() or "unknown"
            if tri not in out:
                out[tri] = _init()

            a_type = str(a.get("actionType") or "").lower()
            shot_res = str(a.get("shotResult") or "").lower()
            is_made = (shot_res == "made")

            if "free throw" in a_type:
                out[tri]["ft_att"] += 1
                out["total"]["ft_att"] += 1
                if is_made:
                    out[tri]["ft_made"] += 1
                    out["total"]["ft_made"] += 1
                continue

            is_fg = a.get("isFieldGoal")
            try:
                is_fg = bool(int(is_fg))
            except Exception:
                is_fg = bool(is_fg)
            if not is_fg:
                continue

            try:
                shot_val = int(a.get("shotValue") or 0)
            except Exception:
                shot_val = 0
            if shot_val == 3:
                out[tri]["fg3_att"] += 1
                out["total"]["fg3_att"] += 1
                if is_made:
                    out[tri]["fg3_made"] += 1
                    out["total"]["fg3_made"] += 1
            else:
                # Treat anything else as 2PT attempt
                out[tri]["fg2_att"] += 1
                out["total"]["fg2_att"] += 1
                if is_made:
                    out[tri]["fg2_made"] += 1
                    out["total"]["fg2_made"] += 1
        except Exception:
            continue

    # Derived fields (misses, shooting %s)
    try:
        for k in list(out.keys()):
            if isinstance(out.get(k), dict):
                out[k] = _finalize(out[k])
    except Exception:
        pass
    return out


def _live_pbp_attempt_stats_periods(actions: list[dict[str, Any]]) -> dict[str, Any]:
        """Compute FT/2P/3P attempts by regulation segments.

        Returns:
            {
                "q1": {...}, "q2": {...}, "q3": {...}, "q4": {...},
                "h1": {...}, "h2": {...},
                "game": {...}
            }
        """
        try:
                out: dict[str, Any] = {}
                acts = actions or []
                for q in (1, 2, 3, 4):
                        out[f"q{q}"] = _live_pbp_attempt_stats([a for a in acts if _safe_int(a.get("period")) == q])
                out["h1"] = _live_pbp_attempt_stats([a for a in acts if _safe_int(a.get("period")) in (1, 2)])
                out["h2"] = _live_pbp_attempt_stats([a for a in acts if _safe_int(a.get("period")) in (3, 4)])
                out["game"] = _live_pbp_attempt_stats(acts)
                return out
        except Exception:
                return {}


def _live_pbp_possession_stats(actions: list[dict[str, Any]], pbp_attempts: dict[str, Any] | None = None) -> dict[str, Any]:
    """Estimate possessions from PBP.

    Uses a standard approximation:
      poss ≈ FGA + TOV + 0.44*FTA - OREB

    Notes:
      - Requires turnovers + offensive rebounds, inferred from actionType/description.
      - Returns per-team buckets like pbp_attempts (home/away/unknown/total + any tricodes seen).
    """

    def _init():
        return {"tov": 0, "oreb": 0, "dreb": 0, "poss_est": None}

    out: dict[str, Any] = {"home": _init(), "away": _init(), "unknown": _init(), "total": _init()}
    if pbp_attempts is None:
        pbp_attempts = _live_pbp_attempt_stats(actions) if actions else {}

    for a in actions or []:
        try:
            tri = str(a.get("teamTricode") or "").upper().strip() or "unknown"
            if tri not in out:
                out[tri] = _init()

            a_type = str(a.get("actionType") or "").lower()
            desc = str(a.get("description") or a.get("actionDescription") or "").lower()

            if "turnover" in a_type:
                out[tri]["tov"] += 1
                out["total"]["tov"] += 1

            if "rebound" in a_type:
                # Best-effort OR/DR split (works well for CDN; ESPN uses description text)
                if "offensive" in desc:
                    out[tri]["oreb"] += 1
                    out["total"]["oreb"] += 1
                elif "defensive" in desc:
                    out[tri]["dreb"] += 1
                    out["total"]["dreb"] += 1
        except Exception:
            continue

    # Compute possession estimate from attempts + tov/oreb
    try:
        for k, v in list(out.items()):
            if not isinstance(v, dict):
                continue
            att = pbp_attempts.get(k) if isinstance(pbp_attempts, dict) else None
            if not isinstance(att, dict):
                # If attempts are keyed by tricode only (not home/away), still try.
                att = pbp_attempts.get(k) if isinstance(pbp_attempts, dict) else None
            fga = 0
            fta = 0
            if isinstance(att, dict):
                fga = int((att.get("fg2_att") or 0) + (att.get("fg3_att") or 0))
                fta = int(att.get("ft_att") or 0)
            tov = int(v.get("tov") or 0)
            oreb = int(v.get("oreb") or 0)
            v["poss_est"] = float(fga) + float(tov) + 0.44 * float(fta) - float(oreb)
    except Exception:
        pass

    return out


def _live_pbp_possession_stats_periods(actions: list[dict[str, Any]]) -> dict[str, Any]:
        """Compute possession estimates by regulation segments.

        Returns:
            {
                "q1": {...}, "q2": {...}, "q3": {...}, "q4": {...},
                "h1": {...}, "h2": {...},
                "game": {...}
            }
        """
        try:
                out: dict[str, Any] = {}
                acts = actions or []
                for q in (1, 2, 3, 4):
                        sub = [a for a in acts if _safe_int(a.get("period")) == q]
                        att = _live_pbp_attempt_stats(sub) if sub else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                        out[f"q{q}"] = _live_pbp_possession_stats(sub, att) if sub else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                sub_h1 = [a for a in acts if _safe_int(a.get("period")) in (1, 2)]
                att_h1 = _live_pbp_attempt_stats(sub_h1) if sub_h1 else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                out["h1"] = _live_pbp_possession_stats(sub_h1, att_h1) if sub_h1 else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                sub_h2 = [a for a in acts if _safe_int(a.get("period")) in (3, 4)]
                att_h2 = _live_pbp_attempt_stats(sub_h2) if sub_h2 else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                out["h2"] = _live_pbp_possession_stats(sub_h2, att_h2) if sub_h2 else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                att_g = _live_pbp_attempt_stats(acts) if acts else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                out["game"] = _live_pbp_possession_stats(acts, att_g) if acts else {"home": {}, "away": {}, "unknown": {}, "total": {}}
                return out
        except Exception:
                return {}


def _live_pbp_score_by_minute(actions: list[dict[str, Any]]) -> dict[str, Any]:
    """Build regulation score series by elapsed minute from CDN actions.

    Returns:
      {
        "game": {"home": [..49..], "away": [..49..], "total": [..49..]},
        "half": {"home": [..25..], "away": [..25..], "total": [..25..]}
      }
    Values are carried forward (last known) once a first score is observed.
    """
    def _empty_game():
        return {"home": [None] * 49, "away": [None] * 49, "total": [None] * 49}

    def _empty_half():
        return {"home": [None] * 25, "away": [None] * 25, "total": [None] * 25}

    out = {"game": _empty_game(), "half": _empty_half()}
    if not actions:
        return out

    # First pass: map elapsed minute -> (home, away)
    game_map: dict[int, tuple[int, int]] = {}
    half_map: dict[int, tuple[int, int]] = {}

    for a in actions:
        try:
            per = _safe_int(a.get("period"))
            if per is None:
                continue
            if per <= 0:
                continue
            # Only regulation for per-minute lens series
            if per > 4:
                continue

            sec_left = _live_parse_clock_to_sec_left(a.get("clock") or a.get("timeRemaining"))
            if sec_left is None:
                continue
            sec_left = int(max(0, min(12 * 60, sec_left)))
            elapsed_sec = (per - 1) * (12 * 60) + ((12 * 60) - sec_left)
            m = int(max(0, min(48, math.floor(elapsed_sec / 60.0))))

            # Scores are usually present on action rows
            sh = a.get("scoreHome")
            sa = a.get("scoreAway")
            if sh is None or sa is None:
                continue
            h = _safe_int(sh)
            aw = _safe_int(sa)
            if h is None or aw is None:
                continue

            game_map[m] = (h, aw)

            if per <= 2:
                half_elapsed_sec = (per - 1) * (12 * 60) + ((12 * 60) - sec_left)
                mh = int(max(0, min(24, math.floor(half_elapsed_sec / 60.0))))
                half_map[mh] = (h, aw)
        except Exception:
            continue

    # Carry-forward fill
    last_h = None
    last_a = None
    for m in range(0, 49):
        if m in game_map:
            last_h, last_a = game_map[m]
        if last_h is not None and last_a is not None:
            out["game"]["home"][m] = last_h
            out["game"]["away"][m] = last_a
            out["game"]["total"][m] = int(last_h + last_a)

    last_h = None
    last_a = None
    for m in range(0, 25):
        if m in half_map:
            last_h, last_a = half_map[m]
        if last_h is not None and last_a is not None:
            out["half"]["home"][m] = last_h
            out["half"]["away"][m] = last_a
            out["half"]["total"][m] = int(last_h + last_a)

    return out


def _live_pbp_quarter_totals(actions: list[dict[str, Any]]) -> dict[str, Any]:
    """Compute per-quarter total points from CDN PBP actions (regulation only).

    Returns:
      {
        "q_totals": {"q1": int|None, "q2": int|None, "q3": int|None, "q4": int|None},
        "current": {"period": int|None, "q_total": int|None}
      }
    """
    out: dict[str, Any] = {
        "q_totals": {"q1": None, "q2": None, "q3": None, "q4": None},
        "current": {"period": None, "q_total": None},
    }
    if not actions:
        return out

    # Track best-known end-of-quarter scores
    best_elapsed_in_period: dict[int, int] = {}
    score_end: dict[int, tuple[int, int]] = {}

    # Track latest observed score (for current quarter running total)
    latest_global_elapsed = -1
    latest_score: tuple[int, int] | None = None
    latest_period: int | None = None

    for a in actions:
        try:
            per = _safe_int(a.get("period"))
            if per is None or per <= 0 or per > 4:
                continue

            sec_left = _live_parse_clock_to_sec_left(a.get("clock") or a.get("timeRemaining"))
            if sec_left is None:
                continue
            sec_left = int(max(0, min(12 * 60, sec_left)))
            elapsed_in_period = int((12 * 60) - sec_left)
            global_elapsed = int((per - 1) * (12 * 60) + elapsed_in_period)

            sh = _safe_int(a.get("scoreHome"))
            sa = _safe_int(a.get("scoreAway"))
            if sh is None or sa is None:
                continue

            if global_elapsed >= latest_global_elapsed:
                latest_global_elapsed = global_elapsed
                latest_score = (int(sh), int(sa))
                latest_period = int(per)

            prev_best = best_elapsed_in_period.get(per)
            if prev_best is None or elapsed_in_period >= prev_best:
                best_elapsed_in_period[per] = elapsed_in_period
                score_end[per] = (int(sh), int(sa))
        except Exception:
            continue

    end_total: dict[int, int] = {}
    for q, sc in score_end.items():
        try:
            end_total[int(q)] = int(sc[0] + sc[1])
        except Exception:
            continue

    prev_end = 0
    for q in (1, 2, 3, 4):
        if q in end_total:
            qt = int(end_total[q] - prev_end)
            out["q_totals"][f"q{q}"] = qt
            prev_end = end_total[q]

    if latest_period is not None and latest_score is not None and 1 <= int(latest_period) <= 4:
        try:
            cur_tot = int(latest_score[0] + latest_score[1])
            prev_end_tot = int(end_total.get(int(latest_period) - 1, 0))
            out["current"] = {"period": int(latest_period), "q_total": int(cur_tot - prev_end_tot)}
        except Exception:
            pass

    return out


def _live_pbp_recent_window_stats(actions: list[dict[str, Any]], window_sec: int = 180) -> dict[str, Any]:
    """Compute recent-window PBP stats from CDN/ESPN-style actions.

    Returns a compact dict suitable for polling payloads.
    Regulation only (period 1..4). If the game is in OT, this returns best-effort
    using the latest regulation timestamp.
    """
    try:
        w = int(max(10, min(600, int(window_sec or 180))))
    except Exception:
        w = 180

    def _elapsed_reg_sec(a: dict[str, Any]) -> int | None:
        try:
            per = _safe_int(a.get("period"))
            if per is None or per < 1 or per > 4:
                return None
            sec_left = _live_parse_clock_to_sec_left(a.get("clock") or a.get("timeRemaining"))
            if sec_left is None:
                return None
            sec_left = int(max(0, min(12 * 60, sec_left)))
            elapsed = int((per - 1) * (12 * 60) + ((12 * 60) - sec_left))
            return int(max(0, min(48 * 60, elapsed)))
        except Exception:
            return None

    acts = actions or []
    if not acts:
        return {"window_sec": w, "points_total": None, "attempts": None, "possessions": None}

    # Determine the most recent regulation timestamp we can observe.
    latest = None
    for a in acts:
        e = _elapsed_reg_sec(a) if isinstance(a, dict) else None
        if e is None:
            continue
        if latest is None or int(e) > int(latest):
            latest = int(e)
    if latest is None:
        return {"window_sec": w, "points_total": None, "attempts": None, "possessions": None}

    cutoff = int(max(0, int(latest) - int(w)))
    sub: list[dict[str, Any]] = []
    for a in acts:
        if not isinstance(a, dict):
            continue
        e = _elapsed_reg_sec(a)
        if e is None:
            continue
        if int(e) < cutoff:
            continue
        if int(e) > int(latest):
            continue
        sub.append(a)

    if not sub:
        return {"window_sec": w, "points_total": None, "attempts": None, "possessions": None}

    # Points delta in window (best-effort) from score fields.
    scored: list[tuple[int, int]] = []
    for a in sub:
        try:
            e = _elapsed_reg_sec(a)
            if e is None:
                continue
            sh = _safe_int(a.get("scoreHome"))
            sa = _safe_int(a.get("scoreAway"))
            if sh is None or sa is None:
                continue
            scored.append((int(e), int(sh) + int(sa)))
        except Exception:
            continue
    points_total = None
    if scored:
        scored.sort(key=lambda x: x[0])
        try:
            points_total = int(scored[-1][1] - scored[0][1])
        except Exception:
            points_total = None

    attempts = _live_pbp_attempt_stats(sub) if sub else {"home": {}, "away": {}, "unknown": {}, "total": {}}
    possessions = _live_pbp_possession_stats(sub, attempts) if sub else {"home": {}, "away": {}, "unknown": {}, "total": {}}

    return {
        "window_sec": int(w),
        "latest_elapsed_reg_sec": int(latest),
        "cutoff_elapsed_reg_sec": int(cutoff),
        "points_total": points_total,
        "attempts": attempts,
        "possessions": possessions,
    }


def _live_pbp_recent_player_usage(actions: list[dict[str, Any]], window_sec: int = 180) -> dict[str, Any]:
    """Compute recent-window + game-to-date player usage proxies from CDN actions.

    Output:
      {
        window_sec, latest_elapsed_reg_sec, cutoff_elapsed_reg_sec,
        recent: {NAME_KEY: {team_tri, fga, fg3a, fta, pts_from_shots, usg_proxy}},
        game:   {NAME_KEY: {team_tri, fga, fg3a, fta, pts_from_shots, usg_proxy}},
      }

    Notes:
    - NAME_KEY uses `_norm_player_name()` to match against props artifacts.
    - usg_proxy is a simple boxscore-like usage proxy: fga + 0.44*fta.
    - Regulation only; OT actions are ignored.
    """
    try:
        w = int(max(10, min(600, int(window_sec or 180))))
    except Exception:
        w = 180

    def _elapsed_reg_sec(a: dict[str, Any]) -> int | None:
        try:
            per = _safe_int(a.get("period"))
            if per is None or per < 1 or per > 4:
                return None
            sec_left = _live_parse_clock_to_sec_left(a.get("clock") or a.get("timeRemaining"))
            if sec_left is None:
                return None
            sec_left = int(max(0, min(12 * 60, sec_left)))
            elapsed = int((per - 1) * (12 * 60) + ((12 * 60) - sec_left))
            return int(max(0, min(48 * 60, elapsed)))
        except Exception:
            return None

    def _init(team_tri: str | None) -> dict[str, Any]:
        return {
            "team_tri": team_tri,
            "fga": 0,
            "fg3a": 0,
            "fg2a": 0,
            "fgm": 0,
            "fg3m": 0,
            "fg2m": 0,
            "fta": 0,
            "ftm": 0,
            "pts_from_shots": 0,
            "usg_proxy": 0.0,
        }

    def _touch(d: dict[str, Any], tri: str | None) -> dict[str, Any]:
        if d is None:
            d = {}
        if d.get("team_tri") is None and tri:
            d["team_tri"] = tri
        return d

    acts = actions or []
    if not acts:
        return {"window_sec": w, "latest_elapsed_reg_sec": None, "cutoff_elapsed_reg_sec": None, "recent": {}, "game": {}}

    latest = None
    for a in acts:
        e = _elapsed_reg_sec(a) if isinstance(a, dict) else None
        if e is None:
            continue
        if latest is None or int(e) > int(latest):
            latest = int(e)
    if latest is None:
        return {"window_sec": w, "latest_elapsed_reg_sec": None, "cutoff_elapsed_reg_sec": None, "recent": {}, "game": {}}

    cutoff = int(max(0, int(latest) - int(w)))

    recent: dict[str, dict[str, Any]] = {}
    game: dict[str, dict[str, Any]] = {}

    for a in acts:
        if not isinstance(a, dict):
            continue
        e = _elapsed_reg_sec(a)
        if e is None:
            continue
        # Track game-to-date for regulation only.
        tri = str(a.get("teamTricode") or "").upper().strip() or None
        pname = str(a.get("playerName") or a.get("playerNameI") or "").strip()
        if not pname:
            continue
        nk = _norm_player_name(pname)
        if not nk:
            continue

        a_type = str(a.get("actionType") or "").lower()
        shot_res = str(a.get("shotResult") or "").lower()
        is_made = (shot_res == "made")

        is_fg = a.get("isFieldGoal")
        try:
            is_fg = bool(int(is_fg))
        except Exception:
            is_fg = bool(is_fg)

        def _apply(dest: dict[str, dict[str, Any]]):
            d0 = dest.get(nk)
            if not isinstance(d0, dict):
                d0 = _init(tri)
            d0 = _touch(d0, tri)

            # Field goal attempts
            if is_fg:
                d0["fga"] = int(d0.get("fga") or 0) + 1
                try:
                    shot_val = int(a.get("shotValue") or 0)
                except Exception:
                    shot_val = 0
                if shot_val == 3:
                    d0["fg3a"] = int(d0.get("fg3a") or 0) + 1
                    if is_made:
                        d0["fg3m"] = int(d0.get("fg3m") or 0) + 1
                else:
                    d0["fg2a"] = int(d0.get("fg2a") or 0) + 1
                    if is_made:
                        d0["fg2m"] = int(d0.get("fg2m") or 0) + 1
                if is_made:
                    d0["fgm"] = int(d0.get("fgm") or 0) + 1
                if is_made:
                    d0["pts_from_shots"] = int(d0.get("pts_from_shots") or 0) + int(max(0, shot_val))

            # Free throw attempts
            if "free throw" in a_type:
                d0["fta"] = int(d0.get("fta") or 0) + 1
                if is_made:
                    d0["ftm"] = int(d0.get("ftm") or 0) + 1
                    d0["pts_from_shots"] = int(d0.get("pts_from_shots") or 0) + 1

            try:
                fga = int(d0.get("fga") or 0)
                fta = int(d0.get("fta") or 0)
                d0["usg_proxy"] = float(fga) + 0.44 * float(fta)
            except Exception:
                pass

            dest[nk] = d0

        # Always apply to game-to-date
        _apply(game)
        # Apply to recent window if within cutoff
        if int(e) >= cutoff and int(e) <= int(latest):
            _apply(recent)

    return {
        "window_sec": int(w),
        "latest_elapsed_reg_sec": int(latest),
        "cutoff_elapsed_reg_sec": int(cutoff),
        "recent": recent,
        "game": game,
    }


def _live_pbp_rotation_state(actions: list[dict[str, Any]], starters_by_team: dict[str, set[str]] | None = None) -> dict[str, Any]:
    """Derive a lightweight on/off + stint/rest summary from NBA-CDN play-by-play.

    This is best-effort and regulation-only.

    Output:
      {
        latest_elapsed_reg_sec,
        players: {
          NAME_KEY: {
            team_tri, on_court,
            cur_on_sec, cur_off_sec,
            last_enter_sec, last_exit_sec,
            avg_stint_sec, avg_rest_sec,
            stints_n, rests_n,
          }
        }
      }
    """

    def _elapsed_reg_sec(a: dict[str, Any]) -> int | None:
        try:
            per = _safe_int(a.get("period"))
            if per is None or per < 1 or per > 4:
                return None
            sec_left = _live_parse_clock_to_sec_left(a.get("clock") or a.get("timeRemaining"))
            if sec_left is None:
                return None
            sec_left = int(max(0, min(12 * 60, sec_left)))
            elapsed = int((per - 1) * (12 * 60) + ((12 * 60) - sec_left))
            return int(max(0, min(48 * 60, elapsed)))
        except Exception:
            return None

    def _mean(xs: list[int]) -> float | None:
        try:
            if not xs:
                return None
            return float(sum(xs)) / float(len(xs))
        except Exception:
            return None

    def _parse_sub(desc: str) -> tuple[str | None, str | None]:
        try:
            s = str(desc or "").strip()
            if not s:
                return None, None
            # Typical: "SUB: Kleber FOR Powell"
            if ":" in s:
                # keep RHS of first colon
                s = s.split(":", 1)[1].strip()
            u = s.upper()
            j = u.find(" FOR ")
            if j < 0:
                return None, None
            incoming = s[:j].strip()
            outgoing = s[j + 5 :].strip()
            incoming = incoming.replace("  ", " ").strip()
            outgoing = outgoing.replace("  ", " ").strip()
            return (incoming or None), (outgoing or None)
        except Exception:
            return None, None

    acts = [a for a in (actions or []) if isinstance(a, dict)]
    if not acts:
        return {"latest_elapsed_reg_sec": None, "players": {}}

    latest = None
    for a in acts:
        e = _elapsed_reg_sec(a)
        if e is None:
            continue
        if latest is None or int(e) > int(latest):
            latest = int(e)
    if latest is None:
        return {"latest_elapsed_reg_sec": None, "players": {}}

    def _sort_key(a: dict[str, Any]) -> tuple[int, int]:
        e = _elapsed_reg_sec(a)
        try:
            an = int(a.get("actionNumber") or a.get("actionId") or 0)
        except Exception:
            an = 0
        return (int(e) if e is not None else 10**9, int(an))

    acts_sorted = sorted(acts, key=_sort_key)

    starters_by_team = starters_by_team or {}
    on_court_by_team: dict[str, set[str]] = {str(k).upper().strip(): set(v or set()) for k, v in starters_by_team.items() if str(k).strip()}

    last_enter: dict[tuple[str, str], int] = {}
    last_exit: dict[tuple[str, str], int] = {}
    stints: dict[tuple[str, str], list[int]] = {}
    rests: dict[tuple[str, str], list[int]] = {}

    # Seed starter enter-times at t=0 (when known).
    for tri, starters in on_court_by_team.items():
        for nk in starters:
            if nk:
                last_enter[(tri, nk)] = 0

    for a in acts_sorted:
        try:
            e = _elapsed_reg_sec(a)
            if e is None:
                continue

            a_type = str(a.get("actionType") or "").strip().lower()
            if "sub" not in a_type:
                continue
            tri = str(a.get("teamTricode") or "").upper().strip() or "unknown"
            desc = str(a.get("description") or "").strip()
            incoming, outgoing = _parse_sub(desc)

            # Outgoing defaults to action playerName (often the player subbed out)
            if not outgoing:
                outgoing = str(a.get("playerName") or a.get("playerNameI") or "").strip() or None

            nk_out = _norm_player_name(outgoing) if outgoing else ""
            nk_in = _norm_player_name(incoming) if incoming else ""

            oc = on_court_by_team.setdefault(tri, set())

            # Mark outgoing off-court
            if nk_out:
                if nk_out in oc:
                    enter_t = last_enter.get((tri, nk_out))
                    if enter_t is not None and int(e) >= int(enter_t):
                        dur = int(e) - int(enter_t)
                        if dur > 0:
                            stints.setdefault((tri, nk_out), []).append(dur)
                oc.discard(nk_out)
                last_exit[(tri, nk_out)] = int(e)

            # Mark incoming on-court
            if nk_in:
                if nk_in not in oc:
                    exit_t = last_exit.get((tri, nk_in))
                    if exit_t is not None and int(e) >= int(exit_t):
                        dur = int(e) - int(exit_t)
                        if dur > 0:
                            rests.setdefault((tri, nk_in), []).append(dur)
                    oc.add(nk_in)
                    last_enter[(tri, nk_in)] = int(e)
        except Exception:
            continue

    players_out: dict[str, dict[str, Any]] = {}
    # Collect all seen players (from stints/rests + on-court + last-enter/exit)
    all_keys: set[tuple[str, str]] = set()
    all_keys |= set(stints.keys())
    all_keys |= set(rests.keys())
    all_keys |= set(last_enter.keys())
    all_keys |= set(last_exit.keys())
    for tri, oc in on_court_by_team.items():
        for nk in oc:
            if nk:
                all_keys.add((tri, nk))

    for tri, nk in sorted(all_keys):
        try:
            if not nk:
                continue
            oc = on_court_by_team.get(tri, set())
            on_now = bool(nk in oc)
            le = last_enter.get((tri, nk))
            lx = last_exit.get((tri, nk))
            cur_on = None
            cur_off = None
            if on_now and le is not None:
                cur_on = int(max(0, int(latest) - int(le)))
            if (not on_now) and lx is not None:
                cur_off = int(max(0, int(latest) - int(lx)))

            s = stints.get((tri, nk), [])
            r = rests.get((tri, nk), [])
            avg_s = _mean(s)
            avg_r = _mean(r)

            players_out[nk] = {
                "team_tri": tri,
                "on_court": on_now,
                "cur_on_sec": cur_on,
                "cur_off_sec": cur_off,
                "last_enter_sec": int(le) if le is not None else None,
                "last_exit_sec": int(lx) if lx is not None else None,
                "avg_stint_sec": float(avg_s) if avg_s is not None else None,
                "avg_rest_sec": float(avg_r) if avg_r is not None else None,
                "stints_n": int(len(s)),
                "rests_n": int(len(r)),
            }
        except Exception:
            continue

    return {"latest_elapsed_reg_sec": int(latest), "players": players_out}


def _live_bovada_lines_for_date(date_str: str) -> list[dict[str, Any]]:
    """Return Bovada current full-game lines normalized to dicts."""
    try:
        if _fetch_bovada_odds_current is None:
            return []
        now = time.time()
        ent = _live_bovada_lines_cache.get(date_str)
        if ent and (now - ent[0] < 60):
            return ent[1]
        df = _fetch_bovada_odds_current(str(date_str), verbose=False)
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            _live_bovada_lines_cache[date_str] = (now, [])
            return []
        keep = []
        # Common columns from odds_bovada.py
        cols = set(df.columns)
        for _, r in df.iterrows():
            try:
                home = str(r.get("home") or r.get("home_team") or "").strip().upper()
                away = str(r.get("away") or r.get("away_team") or "").strip().upper()
                if not home or not away:
                    continue
                keep.append(
                    {
                        "home": home,
                        "away": away,
                        "home_spread": _safe_float(r.get("home_spread")),
                        "away_spread": _safe_float(r.get("away_spread")),
                        "home_spread_price": _safe_float(r.get("home_spread_price")),
                        "away_spread_price": _safe_float(r.get("away_spread_price")),
                        "total": _safe_float(r.get("total")),
                        "total_over_price": _safe_float(r.get("total_over_price")),
                        "total_under_price": _safe_float(r.get("total_under_price")),
                        "home_ml": _safe_float(r.get("home_ml")),
                        "away_ml": _safe_float(r.get("away_ml")),
                    }
                )
            except Exception:
                continue
        _live_bovada_lines_cache[date_str] = (now, keep)
        return keep
    except Exception:
        return []


def _live_match_lines(lines: list[dict[str, Any]], home_tri: str, away_tri: str) -> dict[str, Any]:
    try:
        h = str(home_tri or "").upper().strip()
        a = str(away_tri or "").upper().strip()
        if not h or not a:
            return {}
        for row in lines or []:
            try:
                if str(row.get("home") or "").upper() == h and str(row.get("away") or "").upper() == a:
                    return row
                # Some feeds may swap
                if str(row.get("home") or "").upper() == a and str(row.get("away") or "").upper() == h:
                    # swap spreads so 'home_spread' always refers to this game's home
                    return {
                        "home": h,
                        "away": a,
                        "home_spread": row.get("away_spread"),
                        "away_spread": row.get("home_spread"),
                        "home_spread_price": row.get("away_spread_price"),
                        "away_spread_price": row.get("home_spread_price"),
                        "total": row.get("total"),
                        "total_over_price": row.get("total_over_price"),
                        "total_under_price": row.get("total_under_price"),
                        "home_ml": row.get("away_ml"),
                        "away_ml": row.get("home_ml"),
                    }
            except Exception:
                continue
        return {}
    except Exception:
        return {}

# Serve the static frontend under /web, and serve the cards at '/'
app = Flask(__name__, static_folder=str(WEB_DIR), static_url_path="/web")

# ---- Minimal UI mode (lock down routes) ----
# The project accumulated many experimental UI pages and admin/cron endpoints.
# Default to a strict allowlist so the deployed app only exposes the 4 required pages
# plus the APIs those pages need.
_MINIMAL_UI = str(os.environ.get("NBA_APP_MINIMAL_UI", "1") or "1").strip().lower() in {"1", "true", "yes"}

@app.before_request
def _enforce_minimal_ui_allowlist():
    if not _MINIMAL_UI:
        return None
    try:
        p = str(request.path or "/")

        # Cron endpoints are token-gated; allow them even in minimal UI mode.
        if p.startswith("/api/cron/"):
            return None

        # Exact pages
        allowed_exact = {
            "/",
            "/recommendations",
            "/reconciliation",
            "/features",
            "/accuracy-market",
            "/live-lens-accuracy",
            "/live-game-lens-accuracy",
            "/live-player-props-lens-accuracy",
            "/health",
            "/favicon.ico",
        }
        if p in allowed_exact:
            return None

        # Static frontend assets (tight allowlist)
        if p.startswith("/web/"):
            allowed_web_exact = {
                "/web/styles.css",
                "/web/cards.js",
                "/web/app.js",
            }
            allowed_web_prefixes = (
                "/web/assets/",
            )
            if p in allowed_web_exact or any(p.startswith(pref) for pref in allowed_web_prefixes):
                return None

            return jsonify({"error": "not found"}), 404

        # APIs required by the 4 pages
        allowed_api = {
            "/api/status/props-refresh",
            "/api/cards",
            "/api/predictions",
            "/api/schedule",
            "/api/scoreboard",
            "/api/line-score",
            "/api/evaluate/games",
            "/api/evaluate/props",
            # Accuracy (frontend analytics)
            "/api/accuracy-market",
            "/api/accuracy_market",
            "/api/props",
            "/api/version",
            "/api/features",
            "/api/props/recommendations",
            "/api/props-recommendations",
            "/api/props/movement-callouts",
            "/api/props/pregame-movement",
            "/api/list/processed",
            "/api/processed/recon_games",
            "/api/processed/recon_quarters",
            "/api/processed/recon_players",
            # Live Lens (polling + logging)
            "/api/live/scoreboard",
            "/api/live/game",
            "/api/live/log",
            # NCAAB-parity Live Lens endpoints
            "/api/live_state",
            "/api/live_pbp_stats",
            "/api/live_lines",
            "/api/live_lens_tuning",
            "/api/live_lens_signal",
            "/api/live_lens_projection",
            "/api/live_lens_accuracy",
            "/api/live_lens_side_accuracy",
            "/api/live_lens_analytics",
            "/api/live_game_lens_analytics",
            "/api/live_player_props_lens_analytics",
            "/api/download_live_lens_signals",
            "/api/upload_live_lens_signals",
            "/api/download_live_lens_projections",
            "/api/upload_live_lens_projections",
            "/api/download_live_lens_tuning",
            "/api/upload_live_lens_tuning",
            "/api/live_player_boxscore",
            "/api/live_player_lens",
        }
        if p in allowed_api:
            return None

        # JSON sub-views share the /recommendations route
        if p.startswith("/recommendations"):
            return None

        return jsonify({"error": "not found"}), 404
    except Exception:
        return jsonify({"error": "not found"}), 404

# --- Lightweight name normalizers to align across odds/preds/injuries ---
def _norm_player_name(s: str) -> str:
    if s is None:
        return ""
    t = str(s)
    if "(" in t:
        t = t.split("(", 1)[0]
    # normalize punctuation/hyphens and quotes to align with edges matching
    t = t.replace("-", " ")
    t = t.replace(".", "").replace("'", "").replace(",", " ").strip()
    for suf in [" JR", " SR", " II", " III", " IV"]:
        if t.upper().endswith(suf):
            t = t[: -len(suf)]
    # Transliterates diacritics (e.g., Vučević -> Vucevic) instead of dropping letters.
    try:
        import unicodedata as _ud
        t = _ud.normalize("NFKD", t)
        t = t.encode("ascii", "ignore").decode("ascii")
    except Exception:
        pass
    return t.upper().strip()

def _short_player_key(s: str) -> str:
    s2 = _norm_player_name(s)
    parts = [p for p in s2.replace("-", " ").split() if p]
    if not parts:
        return s2
    last = parts[-1]
    first_initial = parts[0][0] if parts and parts[0] else ""
    return f"{last}{first_initial}"

def _injury_name_sets_for_date(date_str: str) -> tuple[set[str], set[str]]:
    """Return sets of name_key and short_key for players to exclude on a date.

    Sources (union):
      1) data/processed/injuries_excluded_<date>.csv if present
      2) any data/raw/injuries_overrides_*.csv with suffix date <= requested date
      3) data/raw/injuries.csv latest status per player (OUT/DOUBTFUL/SUSPENDED/INACTIVE/REST or season-long/indefinite)
    """
    name_keys: set[str] = set()
    short_keys: set[str] = set()
    try:
        cutoff = pd.to_datetime(date_str).date()
    except Exception:
        from datetime import date as _date
        cutoff = _date.today()

    EXCLUDE_STATUSES = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}

    # Build a best-effort roster team map for the date so we can ignore injury-feed rows
    # that have incorrect team assignments (common on trades / feed glitches).
    roster_name_to_tri: dict[str, str] = {}
    try:
        _, roster_name_to_tri = _build_roster_team_maps(str(date_str))
    except Exception:
        roster_name_to_tri = {}

    def _tri_from_team(x: Any) -> str:
        try:
            s = str(x or "").strip().upper()
        except Exception:
            return ""
        if not s:
            return ""
        if len(s) == 3 and s.isalpha():
            return s
        # Try local team normalizer if available
        try:
            t = _get_tricode(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        try:
            from nba_betting.teams import to_tricode as _to_tri  # type: ignore

            t = _to_tri(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        return s

    def _excluded_status(u: str) -> bool:
        try:
            u = str(u).upper().strip()
        except Exception:
            return False
        if not u:
            return False
        if u in EXCLUDE_STATUSES:
            return True
        if ("OUT" in u and ("SEASON" in u or "INDEFINITE" in u)) or ("SEASON-ENDING" in u):
            return True
        return False

    def _add_players_from_df(df: pd.DataFrame, player_col: str = "player") -> None:
        nonlocal name_keys, short_keys
        try:
            if not isinstance(df, pd.DataFrame) or df is None or df.empty:
                return
            col = player_col if player_col in df.columns else ("player" if "player" in df.columns else None)
            if not col:
                return
            team_col = None
            for tc in ("team_tri", "TEAM_TRI", "team", "TEAM", "TEAM_ABBREVIATION"):
                if tc in df.columns:
                    team_col = tc
                    break

            for _, r in df.iterrows():
                try:
                    nm = r.get(col)
                except Exception:
                    nm = None
                if nm is None:
                    continue
                try:
                    nm_s = str(nm).strip()
                except Exception:
                    continue
                if not nm_s:
                    continue

                nk = _norm_player_name(nm_s)
                if not nk:
                    continue

                # If injury feed has a team, require it match the player's roster team (when known).
                if team_col is not None:
                    try:
                        inj_tri = _tri_from_team(r.get(team_col))
                    except Exception:
                        inj_tri = ""
                    try:
                        rost_tri = roster_name_to_tri.get(nk) or ""
                    except Exception:
                        rost_tri = ""
                    if inj_tri and rost_tri and (inj_tri != rost_tri):
                        continue

                name_keys.add(nk)
                short_keys.add(_short_player_key(nm_s))
        except Exception:
            return

    # 1) Processed daily exclusions
    try:
        proc_path = DATA_PROCESSED_DIR / f"injuries_excluded_{date_str}.csv"
        if (not proc_path.exists()):
            try:
                _maybe_fetch_remote_processed(proc_path.name)
            except Exception:
                pass

        if proc_path.exists():
            df = pd.read_csv(proc_path)
            # NOTE: the diagnostics file is a per-run snapshot but can include injury rows whose
            # own timestamps are older than the slate date. Use a recency window to avoid stale
            # OUT labels persisting forever when the upstream feed isn't updated for RTP.
            if isinstance(df, pd.DataFrame) and not df.empty and ("date" in df.columns):
                try:
                    df["date"] = pd.to_datetime(df["date"], errors="coerce").dt.date
                    df = df[df["date"].notna() & (df["date"] <= cutoff)].copy()
                    recency_days = 30
                    fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                    status_norm = df.get("status", "").astype(str).str.upper().str.strip()
                    injury_norm = df.get("injury", "").astype(str).str.upper().str.strip() if ("injury" in df.columns) else ""
                    is_season = (
                        status_norm.astype(str).str.contains("SEASON", na=False)
                        | status_norm.astype(str).str.contains("INDEFINITE", na=False)
                        | status_norm.astype(str).str.contains("SEASON-ENDING", na=False)
                    )
                    if isinstance(injury_norm, pd.Series):
                        is_season = is_season | injury_norm.astype(str).str.contains("OUT FOR SEASON", na=False) | injury_norm.astype(str).str.contains("SEASON-ENDING", na=False) | injury_norm.astype(str).str.contains("INDEFINITE", na=False)
                    df = df[(df["date"] >= fresh_cutoff) | is_season].copy()
                except Exception:
                    pass
            if isinstance(df, pd.DataFrame) and not df.empty and ("status" in df.columns):
                try:
                    df = df[df["status"].map(_excluded_status)].copy()
                except Exception:
                    pass
            _add_players_from_df(df, player_col="player")
    except Exception:
        pass

    # 2) Overrides up to the cutoff date
    try:
        raw_dir = DATA_RAW_DIR
        for p in sorted(raw_dir.glob("injuries_overrides_*.csv")):
            try:
                dstr = p.stem.replace("injuries_overrides_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or dval.date() > cutoff:
                    continue
                df = pd.read_csv(p)
                # If status column exists, keep only excluded statuses
                if "status" in df.columns:
                    # Allow-list statuses can *remove* a player from the excluded set.
                    try:
                        allow_statuses = {"IN", "ACTIVE", "AVAILABLE"}
                        s_allow = df["status"].astype(str).str.upper().str.strip()
                        allow_df = df[s_allow.map(lambda u: u in allow_statuses)].copy()
                        if isinstance(allow_df, pd.DataFrame) and not allow_df.empty:
                            col = "player" if "player" in allow_df.columns else None
                            if col:
                                names = allow_df[col].dropna().astype(str)
                                if not names.empty:
                                    rm_nk = set(names.map(_norm_player_name).tolist())
                                    rm_sk = set(names.map(_short_player_key).tolist())
                                    name_keys.difference_update({k for k in rm_nk if k})
                                    short_keys.difference_update({k for k in rm_sk if k})
                    except Exception:
                        pass
                    try:
                        df = df[df["status"].map(_excluded_status)]
                    except Exception:
                        pass
                _add_players_from_df(df, player_col="player")
            except Exception:
                continue
    except Exception:
        pass

    # 3) Raw injuries.csv latest rows
    try:
        inj_path = DATA_RAW_DIR / "injuries.csv"
        if inj_path.exists():
            inj = pd.read_csv(inj_path)
            if isinstance(inj, pd.DataFrame) and not inj.empty and ("player" in inj.columns) and ("status" in inj.columns):
                if "date" in inj.columns:
                    inj["date"] = pd.to_datetime(inj["date"], errors="coerce").dt.date
                    inj = inj[inj["date"].notna()]
                    inj = inj[inj["date"] <= cutoff].copy()
                    # Avoid stale "OUT" labels persisting forever (common if the upstream feed
                    # isn't updated for return-to-play). Keep a short recency window, but still
                    # allow season-ending/indefinite outs.
                    try:
                        recency_days = 30
                        fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                        inj["status_norm"] = inj.get("status", "").astype(str).str.upper().str.strip()
                        is_season = inj["status_norm"].astype(str).str.contains("SEASON", na=False) | inj["status_norm"].astype(str).str.contains("INDEFINITE", na=False) | inj["status_norm"].astype(str).str.contains("SEASON-ENDING", na=False)
                        inj = inj[(inj["date"] >= fresh_cutoff) | is_season].copy()
                    except Exception:
                        pass
                # latest by player (+team if present)
                sort_cols = [c for c in ["date"] if c in inj.columns]
                if sort_cols:
                    inj = inj.sort_values(sort_cols)
                grp_cols = [c for c in ["player","team"] if c in inj.columns] or ["player"]
                latest = inj.groupby(grp_cols, as_index=False).tail(1).copy()
                latest.loc[:, "status_norm"] = latest["status"].astype(str).str.upper().str.strip()
                bad = latest[latest["status_norm"].map(_excluded_status)].copy()
                _add_players_from_df(bad, player_col="player")
    except Exception:
        pass

    # 4) Hard override: if a player actually logged minutes on this date,
    # they must not be excluded by stale injury rows.
    # This directly fixes cases where injuries.csv isn't updated for RTP.
    try:
        bs_path = DATA_PROCESSED_DIR / f"boxscores_{date_str}.csv"
        if bs_path.exists():
            bs = pd.read_csv(bs_path)
            if isinstance(bs, pd.DataFrame) and (not bs.empty):
                name_col = next(
                    (c for c in ["PLAYER_NAME", "player_name", "PLAYER", "player"] if c in bs.columns),
                    None,
                )
                min_col = next(
                    (c for c in ["MIN", "min", "MINUTES", "minutes"] if c in bs.columns),
                    None,
                )
                if name_col and min_col:
                    mins = bs[min_col].map(_parse_minutes_to_float)
                    played = bs.loc[pd.to_numeric(mins, errors="coerce").fillna(0.0) > 0.0, name_col].dropna().astype(str)
                    if not played.empty:
                        rm_nk = set(played.map(_norm_player_name).tolist())
                        rm_sk = set(played.map(_short_player_key).tolist())
                        name_keys.difference_update({k for k in rm_nk if k})
                        short_keys.difference_update({k for k in rm_sk if k})
    except Exception:
        pass

    # 5) Secondary override: if we have player props lines for the date,
    # treat those players as active for exclusion purposes.
    try:
        pp_path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
        if pp_path.exists():
            pp = pd.read_csv(pp_path)
            if isinstance(pp, pd.DataFrame) and (not pp.empty):
                name_col = next(
                    (c for c in ["player_name", "player"] if c in pp.columns),
                    None,
                )
                if name_col:
                    names = pp[name_col].dropna().astype(str)
                    if not names.empty:
                        rm_nk = set(names.map(_norm_player_name).tolist())
                        rm_sk = set(names.map(_short_player_key).tolist())
                        name_keys.difference_update({k for k in rm_nk if k})
                        short_keys.difference_update({k for k in rm_sk if k})
    except Exception:
        pass

    return name_keys, short_keys


def _injury_name_sets_for_teams(date_str: str, team_tris: set[str]) -> tuple[set[str], set[str]]:
    """Team-aware variant of _injury_name_sets_for_date.

    Only returns exclusions for the provided team tricodes (or rows with missing team).
    This prevents false exclusions when an upstream injury row has an incorrect team.
    """
    teams = {str(t or "").strip().upper() for t in (team_tris or set()) if str(t or "").strip()}
    if not teams:
        return _injury_name_sets_for_date(date_str)

    name_keys: set[str] = set()
    short_keys: set[str] = set()
    try:
        cutoff = pd.to_datetime(date_str).date()
    except Exception:
        cutoff = datetime.utcnow().date()

    EXCLUDE_STATUSES = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}

    def _excluded_status(u: str) -> bool:
        try:
            u = str(u).upper().strip()
        except Exception:
            return False
        if not u:
            return False
        if u in EXCLUDE_STATUSES:
            return True
        if ("OUT" in u and ("SEASON" in u or "INDEFINITE" in u)) or ("SEASON-ENDING" in u):
            return True
        return False

    def _tri_from_team(x: Any) -> str:
        try:
            s = str(x or "").strip().upper()
        except Exception:
            return ""
        if not s:
            return ""
        if len(s) == 3 and s.isalpha():
            return s
        try:
            t = _get_tricode(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        try:
            from nba_betting.teams import to_tricode as _to_tri  # type: ignore

            t = _to_tri(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        return s

    def _team_ok(row: pd.Series) -> bool:
        # If row has a team field, require it match one of the requested teams.
        # If missing/blank, accept (best-effort).
        try:
            for tc in ("team_tri", "TEAM_TRI", "team", "TEAM", "TEAM_ABBREVIATION"):
                if tc in row.index:
                    tri = _tri_from_team(row.get(tc))
                    return (not tri) or (tri in teams)
        except Exception:
            return True
        return True

    def _add_from_df(df: pd.DataFrame) -> None:
        nonlocal name_keys, short_keys
        if not isinstance(df, pd.DataFrame) or df.empty or ("player" not in df.columns):
            return
        for _, r in df.iterrows():
            try:
                if not _team_ok(r):
                    continue
                nm = str(r.get("player") or "").strip()
                if not nm:
                    continue
                nk = _norm_player_name(nm)
                if nk:
                    name_keys.add(nk)
                    short_keys.add(_short_player_key(nm))
            except Exception:
                continue

    # 1) Processed daily exclusions (team-aware)
    try:
        proc_path = DATA_PROCESSED_DIR / f"injuries_excluded_{date_str}.csv"
        if not proc_path.exists():
            try:
                _maybe_fetch_remote_processed(proc_path.name)
            except Exception:
                pass
        if proc_path.exists():
            df = pd.read_csv(proc_path)
            if isinstance(df, pd.DataFrame) and not df.empty:
                if "date" in df.columns:
                    try:
                        df["date"] = pd.to_datetime(df["date"], errors="coerce").dt.date
                        df = df[df["date"].notna() & (df["date"] <= cutoff)].copy()
                        recency_days = 30
                        fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                        status_norm = df.get("status", "").astype(str).str.upper().str.strip()
                        injury_norm = df.get("injury", "").astype(str).str.upper().str.strip() if ("injury" in df.columns) else ""
                        is_season = (
                            status_norm.astype(str).str.contains("SEASON", na=False)
                            | status_norm.astype(str).str.contains("INDEFINITE", na=False)
                            | status_norm.astype(str).str.contains("SEASON-ENDING", na=False)
                        )
                        if isinstance(injury_norm, pd.Series):
                            is_season = is_season | injury_norm.astype(str).str.contains("OUT FOR SEASON", na=False) | injury_norm.astype(str).str.contains("SEASON-ENDING", na=False) | injury_norm.astype(str).str.contains("INDEFINITE", na=False)
                        df = df[(df["date"] >= fresh_cutoff) | is_season].copy()
                    except Exception:
                        pass
                if "status" in df.columns:
                    try:
                        df = df[df["status"].map(_excluded_status)].copy()
                    except Exception:
                        pass
                _add_from_df(df)
    except Exception:
        pass

    # 2) Overrides up to cutoff (team-aware) with allowlist removals
    try:
        raw_dir = DATA_RAW_DIR
        for p in sorted(raw_dir.glob("injuries_overrides_*.csv")):
            try:
                dstr = p.stem.replace("injuries_overrides_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or dval.date() > cutoff:
                    continue
                df = pd.read_csv(p)
                if not isinstance(df, pd.DataFrame) or df.empty:
                    continue
                if "status" in df.columns:
                    try:
                        allow_statuses = {"IN", "ACTIVE", "AVAILABLE"}
                        s_allow = df["status"].astype(str).str.upper().str.strip()
                        allow_df = df[s_allow.map(lambda u: u in allow_statuses)].copy()
                        if isinstance(allow_df, pd.DataFrame) and (not allow_df.empty):
                            for _, r in allow_df.iterrows():
                                try:
                                    if not _team_ok(r):
                                        continue
                                    nm = str(r.get("player") or "").strip()
                                    if not nm:
                                        continue
                                    name_keys.discard(_norm_player_name(nm))
                                    short_keys.discard(_short_player_key(nm))
                                except Exception:
                                    continue
                    except Exception:
                        pass
                    try:
                        df = df[df["status"].map(_excluded_status)].copy()
                    except Exception:
                        pass
                _add_from_df(df)
            except Exception:
                continue
    except Exception:
        pass

    # 3) Raw injuries.csv latest rows (team-aware)
    try:
        inj_path = DATA_RAW_DIR / "injuries.csv"
        if inj_path.exists():
            inj = pd.read_csv(inj_path)
            if isinstance(inj, pd.DataFrame) and (not inj.empty) and ("player" in inj.columns) and ("status" in inj.columns):
                if "date" in inj.columns:
                    inj["date"] = pd.to_datetime(inj["date"], errors="coerce").dt.date
                    inj = inj[inj["date"].notna()]
                    inj = inj[inj["date"] <= cutoff].copy()
                    try:
                        recency_days = 30
                        fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                        inj["status_norm"] = inj.get("status", "").astype(str).str.upper().str.strip()
                        is_season = inj["status_norm"].astype(str).str.contains("SEASON", na=False) | inj["status_norm"].astype(str).str.contains("INDEFINITE", na=False) | inj["status_norm"].astype(str).str.contains("SEASON-ENDING", na=False)
                        inj = inj[(inj["date"] >= fresh_cutoff) | is_season].copy()
                    except Exception:
                        pass
                if "date" in inj.columns:
                    inj = inj.sort_values(["date"])
                grp_cols = [c for c in ["player", "team"] if c in inj.columns] or ["player"]
                latest = inj.groupby(grp_cols, as_index=False).tail(1).copy()
                latest.loc[:, "status_norm"] = latest["status"].astype(str).str.upper().str.strip()
                bad = latest[latest["status_norm"].map(_excluded_status)].copy()
                _add_from_df(bad)
    except Exception:
        pass

    # 4) Hard override: if a player actually logged minutes on this date,
    # they must not be excluded by stale injury rows.
    try:
        bs_path = DATA_PROCESSED_DIR / f"boxscores_{date_str}.csv"
        if bs_path.exists():
            bs = pd.read_csv(bs_path)
            if isinstance(bs, pd.DataFrame) and (not bs.empty):
                name_col = next(
                    (c for c in ["PLAYER_NAME", "player_name", "PLAYER", "player"] if c in bs.columns),
                    None,
                )
                min_col = next(
                    (c for c in ["MIN", "min", "MINUTES", "minutes"] if c in bs.columns),
                    None,
                )
                if name_col and min_col:
                    mins = bs[min_col].map(_parse_minutes_to_float)
                    played = bs.loc[pd.to_numeric(mins, errors="coerce").fillna(0.0) > 0.0, name_col].dropna().astype(str)
                    if not played.empty:
                        rm_nk = set(played.map(_norm_player_name).tolist())
                        rm_sk = set(played.map(_short_player_key).tolist())
                        name_keys.difference_update({k for k in rm_nk if k})
                        short_keys.difference_update({k for k in rm_sk if k})
    except Exception:
        pass

    # 5) Secondary override: if we have player props lines for the date,
    # treat those players as active for exclusion purposes.
    try:
        pp_path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
        if pp_path.exists():
            pp = pd.read_csv(pp_path)
            if isinstance(pp, pd.DataFrame) and (not pp.empty):
                name_col = next(
                    (c for c in ["player_name", "player"] if c in pp.columns),
                    None,
                )
                if name_col:
                    names = pp[name_col].dropna().astype(str)
                    if not names.empty:
                        rm_nk = set(names.map(_norm_player_name).tolist())
                        rm_sk = set(names.map(_short_player_key).tolist())
                        name_keys.difference_update({k for k in rm_nk if k})
                        short_keys.difference_update({k for k in rm_sk if k})
    except Exception:
        pass

    return name_keys, short_keys


def _load_injury_context_map(date_str: str) -> dict[tuple[str, str], dict[str, Any]]:
    """Return a map of (TEAM_TRI, NAME_KEY) -> injury context.

    Source: data/raw/injuries.csv

    Intended for display/context (e.g., cards UI), not for exclusion logic.
    """
    out: dict[tuple[str, str], dict[str, Any]] = {}

    # Prefer league_status for a per-date team assignment + broad injury status context.
    # This keeps "who" + status consistent even when raw injury feeds have stale team tags.
    try:
        ls_path = DATA_PROCESSED_DIR / f"league_status_{date_str}.csv"
        if ls_path.exists():
            ls = pd.read_csv(ls_path)
            if isinstance(ls, pd.DataFrame) and (not ls.empty):
                cols = {c.lower(): c for c in ls.columns}
                ncol = cols.get("player_name")
                tcol = cols.get("team")
                scol = cols.get("injury_status")
                pcol = cols.get("playing_today")
                if ncol and tcol:
                    use_cols = [tcol, ncol] + ([scol] if scol else []) + ([pcol] if pcol else [])
                    tmp = ls[use_cols].copy()
                    tmp[tcol] = tmp[tcol].astype(str).map(lambda x: (_get_tricode(x) or str(x).strip().upper()))
                    tmp[ncol] = tmp[ncol].astype(str)
                    if scol:
                        tmp[scol] = tmp[scol].astype(str)
                    for _, r in tmp.iterrows():
                        try:
                            tri = str(r.get(tcol) or "").strip().upper()
                            nm = str(r.get(ncol) or "").strip()
                            if not tri or not nm:
                                continue
                            nk = _norm_player_name(nm)
                            if not nk:
                                continue
                            st = str(r.get(scol) or "").strip().upper() if scol else ""
                            if st in {"NAN", "NONE", "NULL"}:
                                st = ""
                            out[(tri, nk)] = {
                                "player_name": nm,
                                "injury_status": st,
                                "playing_today": (r.get(pcol) if pcol else None),
                                "injury": None,
                                "injury_date": None,
                            }
                        except Exception:
                            continue
    except Exception:
        pass

    # Prefer the processed daily snapshot (committed to git for Render parity).
    # This avoids relying on raw injuries.csv being present in the deployed filesystem.
    snap_path = DATA_PROCESSED_DIR / f"injuries_counts_{date_str}.json"
    if snap_path.exists():
        try:
            obj = json.loads(snap_path.read_text(encoding="utf-8"))
        except Exception:
            obj = None
        players = (obj or {}).get("players") or []
        if isinstance(players, list) and players:
            EXCLUDE_STATUSES_SNAP = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}
            for r in players:
                if not isinstance(r, dict):
                    continue
                team_raw = str(r.get("team") or "").strip().upper()
                if not team_raw:
                    continue
                if len(team_raw) == 3 and team_raw.isalpha():
                    tri = team_raw
                else:
                    try:
                        tri = str(_get_tricode(team_raw) or team_raw).strip().upper()
                    except Exception:
                        tri = team_raw

                nm = str(r.get("player") or r.get("player_name") or "").strip()
                if not tri or not nm:
                    continue
                st = str(r.get("status") or "").strip().upper()
                if not st:
                    continue

                playing_today = False if st in EXCLUDE_STATUSES_SNAP else None
                nk = _norm_player_name(nm)
                key = (tri, nk)
                # IMPORTANT: league_status is the primary source. The snapshot should not
                # override an existing per-date context (it can be stale or derived from
                # an incomplete upstream feed).
                if key not in out:
                    out[key] = {
                        "player_name": nm,
                        "injury_status": ("OUT" if st == "OUT" else st),
                        "playing_today": playing_today,
                        "injury": None,
                        "injury_date": None,
                    }
                else:
                    prev = out.get(key) or {}
                    # Only fill missing fields; never clobber league_status context.
                    if prev.get("player_name") in {None, ""}:
                        prev["player_name"] = nm
                    # Don't worsen: if league_status implies the player is active,
                    # don't import an OUT-ish status from the snapshot.
                    prev_playing = prev.get("playing_today")
                    if (not prev.get("injury_status")) and st:
                        if not (prev_playing is True and st in EXCLUDE_STATUSES_SNAP):
                            prev["injury_status"] = ("OUT" if st == "OUT" else st)
                    if prev.get("playing_today") is None and playing_today is not None:
                        prev["playing_today"] = playing_today
                    out[key] = prev
        # Note: do not early-return; we may enrich injury description/date from raw injuries.csv
        # while keeping league_status/snapshot as the primary team+status context.

    inj_path = DATA_RAW_DIR / "injuries.csv"
    if not inj_path.exists():
        return out

    try:
        cutoff = pd.to_datetime(date_str).date()
    except Exception:
        cutoff = datetime.utcnow().date()

    # Roster map to guard against injury-feed team mismatches.
    roster_name_to_tri: dict[str, str] = {}
    try:
        _, roster_name_to_tri = _build_roster_team_maps(str(date_str))
    except Exception:
        roster_name_to_tri = {}

    EXCLUDE_STATUSES = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}

    def _tri_from_team(x: Any) -> str:
        try:
            s = str(x or "").strip().upper()
        except Exception:
            return ""
        if not s:
            return ""
        if len(s) == 3 and s.isalpha():
            return s
        try:
            t = _get_tricode(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        try:
            from nba_betting.teams import to_tricode as _to_tri  # type: ignore

            t = _to_tri(s)
            if isinstance(t, str) and t.strip():
                return t.strip().upper()
        except Exception:
            pass
        return s

    def _status_norm(x: Any) -> str:
        try:
            s = str(x).strip().upper()
        except Exception:
            return ""
        # Pandas sometimes parses NA-ish strings; normalize anyway.
        if not s or s in {"NAN", "NONE", "NULL"}:
            return ""
        return s

    try:
        inj = pd.read_csv(inj_path)
        if not isinstance(inj, pd.DataFrame) or inj.empty:
            return out
        if "player" not in inj.columns or "status" not in inj.columns:
            return out

        inj = inj.copy()
        if "date" in inj.columns:
            inj["date"] = pd.to_datetime(inj["date"], errors="coerce").dt.date
            inj = inj[inj["date"].notna()]
            inj = inj[inj["date"] <= cutoff].copy()
            # Keep recent statuses (avoid stale RTP issues), but allow season-ending/indefinite.
            try:
                recency_days = 30
                fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                s_norm = inj["status"].astype(str).str.upper().str.strip()
                is_season = (
                    s_norm.str.contains("SEASON", na=False)
                    | s_norm.str.contains("INDEFINITE", na=False)
                    | s_norm.str.contains("SEASON-ENDING", na=False)
                )
                inj = inj[(inj["date"] >= fresh_cutoff) | is_season].copy()
            except Exception:
                pass

        # Normalize team tri; require it when possible.
        if "team" in inj.columns:
            inj["team_tri"] = inj["team"].map(_tri_from_team)
        else:
            inj["team_tri"] = ""

        # latest row per player+team
        if "date" in inj.columns:
            inj = inj.sort_values(["date"]).copy()
        latest = inj.groupby(["player", "team_tri"], as_index=False).tail(1).copy()

        for _, r in latest.iterrows():
            try:
                player = str(r.get("player") or "").strip()
            except Exception:
                player = ""
            if not player:
                continue

            nk = _norm_player_name(player)
            if not nk:
                continue

            # Prefer roster team when known (injury feeds often have wrong teams).
            try:
                rost_tri = roster_name_to_tri.get(nk) or ""
            except Exception:
                rost_tri = ""
            row_tri = str(r.get("team_tri") or "").strip().upper()
            team_tri = (rost_tri or row_tri).strip().upper()
            if not team_tri:
                continue

            status = _status_norm(r.get("status"))
            injury_desc = None
            try:
                if "injury" in latest.columns:
                    injury_desc = r.get("injury")
            except Exception:
                injury_desc = None
            if isinstance(injury_desc, float) and np.isnan(injury_desc):
                injury_desc = None

            ctx: dict[str, Any] = {
                "player_name": player,
                "injury": injury_desc,
            }

            inj_date = None
            if "date" in latest.columns:
                inj_date = r.get("date")
                ctx["injury_date"] = inj_date

            # Raw injuries feeds can be stale / wrong-team; only treat excluded statuses as
            # actionable if very recent or clearly season-ending/indefinite.
            if status:
                is_season = ("SEASON" in status) or ("INDEFINITE" in status) or ("SEASON-ENDING" in status)
                is_excl = status in EXCLUDE_STATUSES
                days_old = None
                try:
                    if inj_date is not None:
                        days_old = int((cutoff - inj_date).days)
                except Exception:
                    days_old = None

                if not is_excl:
                    ctx["injury_status"] = status
                    ctx["playing_today"] = True
                else:
                    # Keep recent outs/doubtful, and keep season/indefinite regardless of age.
                    if is_season or (days_old is not None and days_old <= 3):
                        ctx["injury_status"] = status
                        ctx["playing_today"] = False

            key = (team_tri, nk)
            if key not in out:
                out[key] = ctx
            else:
                prev = out.get(key) or {}
                if prev.get("injury") is None and ctx.get("injury") is not None:
                    prev["injury"] = ctx.get("injury")
                if prev.get("injury_date") is None and ctx.get("injury_date") is not None:
                    prev["injury_date"] = ctx.get("injury_date")
                if (not prev.get("injury_status")) and ctx.get("injury_status"):
                    prev["injury_status"] = ctx.get("injury_status")
                if prev.get("playing_today") is None and ("playing_today" in ctx):
                    prev["playing_today"] = ctx.get("playing_today")
                out[key] = prev
    except Exception:
        return out

    # Defensive cleanup: if raw injuries.csv produced an excluded status with a stale date,
    # strip it so we don't badge players as OUT forever when the feed isn't updated.
    # (league_status / injuries_counts snapshots don't populate injury_date, so this
    # mostly targets raw-feed-derived rows.)
    try:
        EXCLUDE_STATUSES = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}
        for key, ctx in list(out.items()):
            try:
                if not isinstance(ctx, dict):
                    continue
                st = str(ctx.get("injury_status") or "").strip().upper()
                if st not in EXCLUDE_STATUSES:
                    continue
                inj_date = ctx.get("injury_date")
                if inj_date is None:
                    continue
                # Keep season-ending/indefinite, drop stale day-to-day outs.
                if ("SEASON" in st) or ("INDEFINITE" in st) or ("SEASON-ENDING" in st):
                    continue
                try:
                    days_old = int((cutoff - inj_date).days)
                except Exception:
                    continue
                if days_old > 3:
                    ctx.pop("injury_status", None)
                    ctx.pop("playing_today", None)
                    ctx.pop("injury", None)
                    ctx.pop("injury_date", None)
                    out[key] = ctx
            except Exception:
                continue
    except Exception:
        pass

    # Hard override: if a player is clearly active for this date (logged minutes)
    # or still has props lines, do not surface them as OUT due to stale injury rows.
    # This mirrors the exclusion-logic safeguards in _injury_name_sets_for_date.
    try:
        active_keys: set[str] = set()

        # 1) Strongest evidence: boxscore minutes > 0.
        try:
            bs_path = DATA_PROCESSED_DIR / f"boxscores_{date_str}.csv"
            if bs_path.exists():
                bs = pd.read_csv(bs_path)
                if isinstance(bs, pd.DataFrame) and (not bs.empty):
                    name_col = next(
                        (c for c in ["PLAYER_NAME", "player_name", "PLAYER", "player"] if c in bs.columns),
                        None,
                    )
                    min_col = next(
                        (c for c in ["MIN", "min", "MINUTES", "minutes"] if c in bs.columns),
                        None,
                    )
                    if name_col and min_col:
                        mins = bs[min_col].map(_parse_minutes_to_float)
                        played = bs.loc[pd.to_numeric(mins, errors="coerce").fillna(0.0) > 0.0, name_col].dropna().astype(str)
                        if not played.empty:
                            active_keys |= {k for k in played.map(_norm_player_name).tolist() if k}
        except Exception:
            pass

        # 2) Pregame evidence: props predictions implies a line exists (usually only for active players).
        try:
            pp_path = DATA_PROCESSED_DIR / f"props_predictions_{date_str}.csv"
            if pp_path.exists():
                pp = pd.read_csv(pp_path)
                if isinstance(pp, pd.DataFrame) and (not pp.empty):
                    name_col = next(
                        (c for c in ["player_name", "player", "PLAYER_NAME", "PLAYER"] if c in pp.columns),
                        None,
                    )
                    if name_col:
                        names = pp[name_col].dropna().astype(str)
                        if not names.empty:
                            active_keys |= {k for k in names.map(_norm_player_name).tolist() if k}
        except Exception:
            pass

        if active_keys:
            EXCLUDE_STATUSES = {"OUT", "DOUBTFUL", "SUSPENDED", "INACTIVE", "REST"}
            for key, ctx in list(out.items()):
                try:
                    if not isinstance(ctx, dict):
                        continue
                    nk = str(key[1] or "")
                    if not nk or nk not in active_keys:
                        continue

                    st = str(ctx.get("injury_status") or "").strip().upper()
                    if st in EXCLUDE_STATUSES or (ctx.get("playing_today") is False):
                        ctx["playing_today"] = True
                        # Clear stale OUT-ish tags so UI doesn't badge as OUT.
                        ctx.pop("injury_status", None)
                        ctx.pop("injury", None)
                        ctx.pop("injury_date", None)
                        out[key] = ctx
                except Exception:
                    continue
    except Exception:
        pass

    return out


def _injury_designations_for_matchup(
    date_str: str,
    home_tri: str,
    away_tri: str,
    home_roster: Optional[List[str]] = None,
    away_roster: Optional[List[str]] = None,
) -> Dict[str, List[Dict[str, Any]]]:
    """Return injury designation rows for the matchup, aligned to our exclusion logic.

    This is intentionally framed as *injury exclusions* (why players got removed from the connected
    sim roster) rather than a perfect injury report, because some upstream injury feeds can have
    incorrect team assignments.

    Output shape (stable for frontend):
      {"home": [{"player": "...", "status": "...", "source": "..."}, ...],
       "away": [...]}.

    Approach:
      1) Build excluded name/short-key sets via _injury_name_sets_for_date(date_str)
      2) Intersect with each team roster to decide which excluded players belong to this matchup
      3) For each excluded player, derive a display status from the latest available row across:
         - data/processed/injuries_excluded_<date>.csv (highest)
         - data/raw/injuries_overrides_*.csv (high)
         - data/raw/injuries.csv (fallback)
         Matching is by normalized player name (ignoring team fields).
    """
    try:
        cutoff = pd.to_datetime(date_str).date()
    except Exception:
        cutoff = datetime.utcnow().date()

    htri = str(home_tri or "").strip().upper()
    atri = str(away_tri or "").strip().upper()

    # Build roster-based team assignment + display names.
    def _roster_maps(roster: Optional[List[str]]) -> tuple[set[str], Dict[str, str]]:
        keys: set[str] = set()
        display: Dict[str, str] = {}
        for nm in (roster or []):
            try:
                s = str(nm).strip()
            except Exception:
                continue
            if not s:
                continue
            k = _norm_player_name(s)
            if not k:
                continue
            keys.add(k)
            # Keep the first seen display name (often best formatted).
            display.setdefault(k, s)
        return keys, display

    home_keys, home_display = _roster_maps(home_roster)
    away_keys, away_display = _roster_maps(away_roster)

    # Exclusion sets (actual logic used elsewhere). Use team-aware exclusions so
    # mis-tagged injury rows (wrong team) don't show up as exclusions.
    try:
        excluded_name_keys, excluded_short_keys = _injury_name_sets_for_teams(str(date_str), {htri, atri})
    except Exception:
        excluded_name_keys, excluded_short_keys = set(), set()

    def _is_excluded_player(nm: str) -> bool:
        try:
            return (_norm_player_name(nm) in excluded_name_keys) or (_short_player_key(nm) in excluded_short_keys)
        except Exception:
            return False

    # Dedup store: per side, keep best status per player.
    # Keyed by normalized name.
    store: Dict[str, Dict[str, Dict[str, Any]]] = {"home": {}, "away": {}}

    def _status_norm(s: Any) -> str:
        try:
            u = str(s or "").strip().upper()
            if u in {"NAN", "NONE", "NULL"}:
                return ""
            return u
        except Exception:
            return ""

    def _severity(status_u: str) -> int:
        u = _status_norm(status_u)
        if not u:
            return 0
        if "SEASON-ENDING" in u or ("OUT" in u and ("SEASON" in u or "INDEFINITE" in u)):
            return 6
        if u in {"OUT"}:
            return 5
        if u in {"SUSPENDED", "INACTIVE"}:
            return 4
        if u in {"DOUBTFUL"}:
            return 3
        if u in {"QUESTIONABLE", "REST"}:
            return 2
        if u in {"PROBABLE"}:
            return 1
        return 1

    def _add(player: Any, status: Any, side: str, source: str) -> None:
        try:
            p = str(player or "").strip()
        except Exception:
            return
        if not p:
            return
        k = _norm_player_name(p)
        if not k:
            return

        s = side
        if s not in ("home", "away"):
            return

        st = _status_norm(status)
        if not st:
            st = "OUT" if source in ("processed_excluded", "override") else ""

        disp = p
        if s == "home" and k in home_display:
            disp = home_display[k]
        elif s == "away" and k in away_display:
            disp = away_display[k]

        cur = store[s].get(k)
        cand = {"player": disp, "status": st, "source": source}
        if cur is None or _severity(st) > _severity(str(cur.get("status") or "")):
            store[s][k] = cand
    # Build a "latest status by player" map per source (ignoring team).
    status_by_player: Dict[str, Dict[str, str]] = {
        "processed_excluded": {},
        "override": {},
        "raw": {},
    }

    def _ingest_latest_status(df: pd.DataFrame, source_key: str, recency_days: int | None = None) -> None:
        try:
            if not isinstance(df, pd.DataFrame) or df.empty:
                return
            if "player" not in df.columns:
                return
            if "status" not in df.columns:
                return

            tmp = df.copy()
            if "date" in tmp.columns:
                tmp["date"] = pd.to_datetime(tmp["date"], errors="coerce").dt.date
                tmp = tmp[tmp["date"].notna()]
                tmp = tmp[tmp["date"] <= cutoff].copy()
                tmp = tmp.sort_values("date")
                if recency_days is not None:
                    try:
                        fresh_cutoff = (cutoff - timedelta(days=int(recency_days)))
                        tmp["_status_norm"] = tmp.get("status", "").astype(str).str.upper().str.strip()
                        season = tmp["_status_norm"].astype(str).str.contains("SEASON", na=False) | tmp["_status_norm"].astype(str).str.contains("INDEFINITE", na=False) | tmp["_status_norm"].astype(str).str.contains("SEASON-ENDING", na=False)
                        tmp = tmp[(tmp["date"] >= fresh_cutoff) | season].copy()
                    except Exception:
                        pass

            tmp["_nk"] = tmp["player"].astype(str).map(_norm_player_name)
            tmp["_st"] = tmp["status"].map(_status_norm)
            tmp = tmp[(tmp["_nk"].astype(str).str.len() > 0) & (tmp["_st"].astype(str).str.len() > 0)].copy()
            if tmp.empty:
                return

            latest = tmp.groupby("_nk", as_index=False).tail(1)
            m = status_by_player.get(source_key)
            if m is None:
                return
            for _, r in latest.iterrows():
                k = str(r.get("_nk") or "").strip().upper()
                st = str(r.get("_st") or "").strip().upper()
                if k and st:
                    m[k] = st
        except Exception:
            return

    # 1) processed_excluded (best when present)
    try:
        proc_path = DATA_PROCESSED_DIR / f"injuries_excluded_{date_str}.csv"
        if proc_path.exists():
            _ingest_latest_status(pd.read_csv(proc_path), "processed_excluded", recency_days=30)
    except Exception:
        pass

    # 2) overrides
    try:
        raw_dir = DATA_RAW_DIR
        odfs: list[pd.DataFrame] = []
        for p in sorted(raw_dir.glob("injuries_overrides_*.csv")):
            try:
                dstr = p.stem.replace("injuries_overrides_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or dval.date() > cutoff:
                    continue
                odfs.append(pd.read_csv(p))
            except Exception:
                continue
        if odfs:
            _ingest_latest_status(pd.concat(odfs, ignore_index=True), "override")
    except Exception:
        pass

    # 3) raw injuries.csv (fallback for designation only; team fields are ignored)
    try:
        inj_path = DATA_RAW_DIR / "injuries.csv"
        if inj_path.exists():
            _ingest_latest_status(pd.read_csv(inj_path), "raw")
    except Exception:
        pass

    def _best_status_for_key(nk: str) -> tuple[str, str]:
        for src in ("processed_excluded", "override", "raw"):
            st = status_by_player.get(src, {}).get(nk)
            if st:
                return st, src
        return "OUT", "derived"

    # Build per-side lists: roster players that are excluded by injury filter.
    for nk, disp in home_display.items():
        if _is_excluded_player(disp):
            st, src = _best_status_for_key(nk)
            _add(disp, st, side="home", source=src)
    for nk, disp in away_display.items():
        if _is_excluded_player(disp):
            st, src = _best_status_for_key(nk)
            _add(disp, st, side="away", source=src)

    def _finalize(side: str) -> List[Dict[str, Any]]:
        rows = list((store.get(side) or {}).values())
        rows.sort(key=lambda x: (-_severity(str(x.get("status") or "")), str(x.get("player") or "")))
        return rows

    return {"home": _finalize("home"), "away": _finalize("away")}

# --- Opponent allowances and team injury counts (for props explainability) ---
_OPP_ALLOWED_CACHE: dict[str, dict[str, dict[str, float]]] = {}
_OPP_ALLOWED_RANKS_CACHE: dict[str, dict[str, dict[str, int]]] = {}
_TEAM_INJURY_COUNTS_CACHE: dict[str, dict[str, int]] = {}
_TEAM_INJURY_IDENTITY_CACHE: dict[str, tuple[dict[str, list[str]], dict[str, float]]] = {}

# --- Team metadata (timezone offsets, altitude) ---
_TEAM_META_TZ: dict[str, float] = {}
_TEAM_META_ALT: dict[str, float] = {}
_TEAM_META_LAT: dict[str, float] = {}
_TEAM_META_LON: dict[str, float] = {}

def _load_team_metadata() -> None:
    try:
        if _TEAM_META_TZ and _TEAM_META_ALT:
            return
        p = DATA_RAW_DIR / "team_metadata.csv"
        if not p.exists():
            return
        import pandas as _pd
        df = _pd.read_csv(p)
        cols = {c.lower(): c for c in df.columns}
        c_tri = cols.get("tri") or cols.get("team") or cols.get("team_tricode")
        c_tz = cols.get("tz_offset") or cols.get("timezone_offset") or cols.get("tz")
        c_alt = cols.get("altitude_ft") or cols.get("altitude")
        c_lat = cols.get("lat") or cols.get("latitude")
        c_lon = cols.get("lon") or cols.get("lng") or cols.get("longitude")
        if not c_tri:
            return
        for _, r in df.iterrows():
            tri = str(r.get(c_tri) or '').strip().upper()
            if not tri:
                continue
            if c_tz and c_tz in df.columns:
                try:
                    _TEAM_META_TZ[tri] = float(r.get(c_tz))
                except Exception:
                    pass
            if c_alt and c_alt in df.columns:
                try:
                    _TEAM_META_ALT[tri] = float(r.get(c_alt))
                except Exception:
                    pass
            if c_lat and c_lat in df.columns:
                try:
                    _TEAM_META_LAT[tri] = float(r.get(c_lat))
                except Exception:
                    pass
            if c_lon and c_lon in df.columns:
                try:
                    _TEAM_META_LON[tri] = float(r.get(c_lon))
                except Exception:
                    pass
    except Exception:
        return

def _tz_offset_meta(tri: str) -> float:
    try:
        _load_team_metadata()
        t = str(tri or '').upper()
        if t in _TEAM_META_TZ:
            return float(_TEAM_META_TZ[t])
        # Fallback mapping if metadata absent
        m = {
            "ATL": -5, "BKN": -5, "BOS": -5, "CHA": -5, "CHI": -6, "CLE": -5,
            "DET": -5, "IND": -5, "MIA": -5, "MIL": -6, "NYK": -5, "ORL": -5,
            "PHI": -5, "TOR": -5, "WAS": -5,
            "DAL": -6, "HOU": -6, "MEM": -6, "MIN": -6, "NOP": -6, "OKC": -6, "SAS": -6,
            "DEN": -7, "UTA": -7, "PHX": -7,
            "GSW": -8, "LAC": -8, "LAL": -8, "SAC": -8, "POR": -8
        }
        return float(m.get(t, 0.0))
    except Exception:
        return 0.0

def _altitude_ft_meta(tri: str) -> float:
    try:
        _load_team_metadata()
        t = str(tri or '').upper()
        if t in _TEAM_META_ALT:
            return float(_TEAM_META_ALT[t])
        # Fallback approximate altitudes (only high altitude flagged)
        m = {"DEN": 5280.0, "UTA": 4226.0}
        return float(m.get(t, 0.0))
    except Exception:
        return 0.0

def _haversine_km(lat1: float, lon1: float, lat2: float, lon2: float) -> float:
    try:
        from math import radians, sin, cos, asin, sqrt
        R = 6371.0
        dlat = radians(lat2 - lat1)
        dlon = radians(lon2 - lon1)
        a = sin(dlat/2)**2 + cos(radians(lat1)) * cos(radians(lat2)) * sin(dlon/2)**2
        c = 2 * asin(sqrt(a))
        return float(R * c)
    except Exception:
        return 0.0

def _compute_team_allowed_stats(date_str: str, days_back: int = 21) -> tuple[dict[str, dict[str, float]], dict[str, dict[str, int]]]:
    """Compute per-team opponent allowances for key prop markets over a recent window.

    Returns two dicts keyed by team tricode:
      - averages: {team: {"pts": avg_pts_allowed, "reb": avg_reb_allowed, "ast": avg_ast_allowed, "threes": avg_3pm_allowed}}
      - ranks:    {team: {market: rank}} with 1=lowest allowed (stingy), 30=highest allowed (favorable)

    Reads data/processed/boxscores_YYYY-MM-DD.csv files for the last N days and aggregates per game.
    """
    try:
        if date_str in _OPP_ALLOWED_CACHE and date_str in _OPP_ALLOWED_RANKS_CACHE:
            return _OPP_ALLOWED_CACHE[date_str], _OPP_ALLOWED_RANKS_CACHE[date_str]
        base = DATA_PROCESSED_DIR
        if not base.exists():
            _OPP_ALLOWED_CACHE[date_str] = {}
            _OPP_ALLOWED_RANKS_CACHE[date_str] = {}
            return _OPP_ALLOWED_CACHE[date_str], _OPP_ALLOWED_RANKS_CACHE[date_str]
        cutoff = pd.to_datetime(date_str, errors="coerce")
        if pd.isna(cutoff):
            from datetime import date as _date
            cutoff = pd.Timestamp(_date.today())
        start = cutoff - pd.Timedelta(days=days_back)

        # Collect per-game team totals, then attribute opponent totals as "allowed" to the other team
        needed_cols = {
            "gameId": {"gameId", "GAME_ID", "game_id"},
            "team": {"teamTricode", "TEAM_ABBREVIATION", "team", "slugTeam"},
            "pts": {"points", "PTS"},
            "reb": {"reboundsTotal", "REB", "TREB"},
            "ast": {"assists", "AST"},
            "threes": {"threePointersMade", "FG3M"},
            "stl": {"steals", "STL"},
            "blk": {"blocks", "BLK"},
            "tov": {"turnovers", "TO", "TOV"},
        }
        per_game: dict[str, dict[str, dict[str, float]]] = {}

        for p in sorted(base.glob("boxscores_*.csv")):
            try:
                dstr = p.stem.replace("boxscores_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or not (start <= dval <= cutoff):
                    continue
                df = pd.read_csv(p)
                cols = {c.lower(): c for c in df.columns}
                def _col(keys: set[str]) -> str | None:
                    for k in keys:
                        if k.lower() in cols:
                            return cols[k.lower()]
                    return None
                gid = _col(needed_cols["gameId"])
                team = _col(needed_cols["team"])
                c_pts = _col(needed_cols["pts"])
                c_reb = _col(needed_cols["reb"])
                c_ast = _col(needed_cols["ast"])
                c_3 = _col(needed_cols["threes"])
                c_stl = _col(needed_cols["stl"])
                c_blk = _col(needed_cols["blk"])
                c_tov = _col(needed_cols["tov"])
                if not gid or not team:
                    continue
                use_cols = [x for x in [gid, team, c_pts, c_reb, c_ast, c_3, c_stl, c_blk, c_tov] if x]
                tmp = df[use_cols].copy()
                for c in [c_pts, c_reb, c_ast, c_3, c_stl, c_blk, c_tov]:
                    if c and c in tmp.columns:
                        tmp[c] = pd.to_numeric(tmp[c], errors="coerce")
                grp = tmp.groupby([gid, team], as_index=False).sum()
                for gk, sub in grp.groupby(gid):
                    rows = sub.to_dict(orient="records")
                    if len(rows) < 2:
                        continue
                    # Attribute opponent totals as allowed to the other team
                    for i in range(len(rows)):
                        a = rows[i]; b = rows[1 - i] if len(rows) == 2 else None
                        if not b:
                            continue
                        t = str(a.get(team) or "").strip().upper()
                        if not t:
                            continue
                        per_game.setdefault(t, {})[gk] = {
                            "pts": float(b.get(c_pts, 0.0) or 0.0) if c_pts else np.nan,
                            "reb": float(b.get(c_reb, 0.0) or 0.0) if c_reb else np.nan,
                            "ast": float(b.get(c_ast, 0.0) or 0.0) if c_ast else np.nan,
                            "threes": float(b.get(c_3, 0.0) or 0.0) if c_3 else np.nan,
                            "stl": float(b.get(c_stl, 0.0) or 0.0) if c_stl else np.nan,
                            "blk": float(b.get(c_blk, 0.0) or 0.0) if c_blk else np.nan,
                            "tov": float(b.get(c_tov, 0.0) or 0.0) if c_tov else np.nan,
                        }
            except Exception:
                continue

        averages: dict[str, dict[str, float]] = {}
        for team_key, game_map in per_game.items():
            if not game_map:
                continue
            vals = pd.DataFrame(list(game_map.values()))
            averages[team_key] = {
                "pts": float(vals["pts"].mean()) if "pts" in vals.columns else np.nan,
                "reb": float(vals["reb"].mean()) if "reb" in vals.columns else np.nan,
                "ast": float(vals["ast"].mean()) if "ast" in vals.columns else np.nan,
                "threes": float(vals["threes"].mean()) if "threes" in vals.columns else np.nan,
                "stl": float(vals["stl"].mean()) if "stl" in vals.columns else np.nan,
                "blk": float(vals["blk"].mean()) if "blk" in vals.columns else np.nan,
                "tov": float(vals["tov"].mean()) if "tov" in vals.columns else np.nan,
            }

        # Build ranks per market: higher allowed => higher rank (favorable for overs)
        ranks: dict[str, dict[str, int]] = {}
        for mk in ["pts","reb","ast","threes","stl","blk","tov"]:
            series = pd.Series({t: (averages.get(t, {}).get(mk, np.nan)) for t in averages.keys()})
            # Drop NaN and rank among available teams
            series = series.dropna()
            if series.empty:
                continue
            # Rank ascending => lowest allowed rank 1; we want highest allowed => rank max
            ord = series.rank(method="min", ascending=True)
            max_rank = int(ord.max()) if len(ord) > 0 else 0
            for t, r in ord.items():
                ranks.setdefault(t, {})[mk] = int(r)
            # Normalize ranks to 1..N where N=len(series)
            # (already in that form via rank(min))
        _OPP_ALLOWED_CACHE[date_str] = averages
        _OPP_ALLOWED_RANKS_CACHE[date_str] = ranks
        return averages, ranks
    except Exception:
        _OPP_ALLOWED_CACHE[date_str] = {}
        _OPP_ALLOWED_RANKS_CACHE[date_str] = {}
        return _OPP_ALLOWED_CACHE[date_str], _OPP_ALLOWED_RANKS_CACHE[date_str]

def _compute_team_offense_stats(date_str: str, days_back: int = 21) -> tuple[dict[str, float], dict[str, int]]:
    """Compute per-team recent offensive points averages and ranks over a window.

    Returns two dicts keyed by team tricode:
      - averages: {team: avg_points_scored}
      - ranks:    {team: rank} with 1=lowest offense, 30=highest offense

    Reads data/processed/boxscores_YYYY-MM-DD.csv files and aggregates per game.
    """
    try:
        base = DATA_PROCESSED_DIR
        if not base.exists():
            return {}, {}
        cutoff = pd.to_datetime(date_str, errors="coerce")
        if pd.isna(cutoff):
            from datetime import date as _date
            cutoff = pd.Timestamp(_date.today())
        start = cutoff - pd.Timedelta(days=days_back)

        needed_cols = {
            "gameId": {"gameId", "GAME_ID", "game_id"},
            "team": {"teamTricode", "TEAM_ABBREVIATION", "team", "slugTeam"},
            "pts": {"points", "PTS"},
        }
        per_team_points: dict[str, list[float]] = {}
        for p in sorted(base.glob("boxscores_*.csv")):
            try:
                dstr = p.stem.replace("boxscores_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or not (start <= dval <= cutoff):
                    continue
                df = pd.read_csv(p)
                cols = {c.lower(): c for c in df.columns}
                def _col(keys: set[str]) -> str | None:
                    for k in keys:
                        if k.lower() in cols:
                            return cols[k.lower()]
                    return None
                c_team = _col(needed_cols["team"])
                c_pts = _col(needed_cols["pts"])
                if not c_team or not c_pts:
                    continue
                tmp = df[[c_team, c_pts]].copy()
                tmp[c_pts] = pd.to_numeric(tmp[c_pts], errors="coerce")
                grp = tmp.groupby(c_team, as_index=False).sum()
                for _, r in grp.iterrows():
                    tri = str(r.get(c_team) or "").strip().upper()
                    if not tri:
                        continue
                    val = float(r.get(c_pts) or 0.0)
                    per_team_points.setdefault(tri, []).append(val)
            except Exception:
                continue
        averages: dict[str, float] = {}
        for t, pts in per_team_points.items():
            if pts:
                try:
                    averages[t] = float(np.mean([float(x) for x in pts if np.isfinite(float(x))]))
                except Exception:
                    continue
        # Build ranks: higher offense => higher rank
        ranks: dict[str, int] = {}
        if averages:
            series = pd.Series(averages)
            series = series.dropna()
            ord = series.rank(method="min", ascending=True)
            for t, r in ord.items():
                ranks[t] = int(r)
        return averages, ranks
    except Exception:
        return {}, {}


# --- Player minutes priors (for connected sim; avoids placeholder players) ---
_PLAYER_MIN_PRIORS_CACHE: dict[tuple[str, int], dict[tuple[str, str], float]] = {}

# --- Player stat priors from player_logs.csv (for connected sim; all counting stats) ---
_PLAYER_STAT_PRIORS_CACHE: dict[tuple[str, int], dict[tuple[str, str], dict[str, float]]] = {}


def _norm_player_name_for_keys(x: object) -> str:
    try:
        return _norm_player_name(str(x or ""))
    except Exception:
        return ""


def _parse_minutes_to_float(x: object) -> float:
    """Parse boxscore minutes like '32:48' into float minutes (32.8)."""
    try:
        s = str(x or "").strip()
        if not s:
            return 0.0
        if ":" in s:
            mm, ss = s.split(":", 1)
            m = pd.to_numeric(mm, errors="coerce")
            sec = pd.to_numeric(ss, errors="coerce")
            if pd.isna(m) or pd.isna(sec):
                return 0.0
            out = float(m) + float(sec) / 60.0
            return float(out) if np.isfinite(out) else 0.0
        v = pd.to_numeric(s, errors="coerce")
        if pd.isna(v):
            return 0.0
        v = float(v)
        return float(v) if np.isfinite(v) else 0.0
    except Exception:
        return 0.0


def _compute_player_minutes_priors(date_str: str, days_back: int = 21) -> dict[tuple[str, str], float]:
    """Average minutes played per (team_tricode, PLAYER_NAME) over recent boxscores.

    Reads data/processed/boxscores_YYYY-MM-DD.csv in a lookback window.
    Returns dict keyed by (TEAM_TRICODE, NORMALIZED_PLAYER_NAME).
    """
    try:
        key = (str(date_str or ""), int(days_back))
        if key in _PLAYER_MIN_PRIORS_CACHE:
            return _PLAYER_MIN_PRIORS_CACHE[key]

        base = DATA_PROCESSED_DIR
        if not base.exists():
            _PLAYER_MIN_PRIORS_CACHE[key] = {}
            return _PLAYER_MIN_PRIORS_CACHE[key]

        cutoff = pd.to_datetime(date_str, errors="coerce")
        if pd.isna(cutoff):
            from datetime import date as _date
            cutoff = pd.Timestamp(_date.today())
        start = cutoff - pd.Timedelta(days=int(days_back))

        # Column candidates in boxscore files
        team_keys = {"teamTricode", "TEAM_ABBREVIATION", "team", "slugTeam"}
        min_keys = {"minutes", "MIN"}
        name_keys = {"player_name", "PLAYER", "name", "fullName"}

        rows: list[tuple[str, str, float]] = []
        for p in sorted(base.glob("boxscores_*.csv")):
            try:
                dstr = p.stem.replace("boxscores_", "")
                dval = pd.to_datetime(dstr, errors="coerce")
                if pd.isna(dval) or not (start <= dval <= cutoff):
                    continue
                df = pd.read_csv(p)
                if df is None or df.empty:
                    continue
                cols = {c.lower(): c for c in df.columns}

                def _col(keys: set[str]) -> str | None:
                    for k in keys:
                        if k.lower() in cols:
                            return cols[k.lower()]
                    return None

                c_team = _col(team_keys)
                c_min = _col(min_keys)

                # Prefer a prebuilt name column if present; otherwise build from first/family.
                c_name = _col(name_keys)
                c_first = cols.get("firstname")
                c_last = cols.get("familyname")

                if not c_team or not c_min:
                    continue

                tmp = df[[c_team, c_min] + ([c_name] if c_name else []) + ([c_first] if c_first else []) + ([c_last] if c_last else [])].copy()
                tmp[c_team] = tmp[c_team].astype(str).str.strip().str.upper()

                if c_name and c_name in tmp.columns:
                    tmp["_player"] = tmp[c_name].astype(str)
                elif c_first and c_last and c_first in tmp.columns and c_last in tmp.columns:
                    tmp["_player"] = (tmp[c_first].astype(str).str.strip() + " " + tmp[c_last].astype(str).str.strip())
                else:
                    # last resort: try concatenating any two likely name columns
                    tmp["_player"] = ""

                tmp["_player"] = tmp["_player"].map(_norm_player_name_for_keys)
                tmp["_min_float"] = tmp[c_min].map(_parse_minutes_to_float)

                tmp = tmp[(tmp[c_team].astype(str).str.len() > 0) & (tmp["_player"].astype(str).str.len() > 0)]
                # Drop DNP/zeros; we want priors from actual floor time.
                tmp = tmp[tmp["_min_float"] > 0]
                if tmp.empty:
                    continue
                for _, r in tmp.iterrows():
                    rows.append((str(r[c_team]), str(r["_player"]), float(r["_min_float"])))
            except Exception:
                continue

        if not rows:
            _PLAYER_MIN_PRIORS_CACHE[key] = {}
            return _PLAYER_MIN_PRIORS_CACHE[key]

        dfm = pd.DataFrame(rows, columns=["team", "player", "min"])
        pri = dfm.groupby(["team", "player"], as_index=False)["min"].mean()
        out: dict[tuple[str, str], float] = {}
        for _, r in pri.iterrows():
            t = str(r.get("team") or "").strip().upper()
            n = str(r.get("player") or "").strip().upper()
            m = float(r.get("min") or 0.0)
            if t and n and np.isfinite(m) and m > 0:
                out[(t, n)] = float(m)

        _PLAYER_MIN_PRIORS_CACHE[key] = out
        return _PLAYER_MIN_PRIORS_CACHE[key]
    except Exception:
        return {}


def _compute_player_stat_priors(date_str: str, days_back: int = 21) -> dict[tuple[str, str], dict[str, float]]:
    """Return per-player priors for all major boxscore stats used by connected sim.

    Output mapping key: (TEAM_TRI, PLAYER_KEY) -> dict with fields like:
      min_mu, pts_pm, reb_pm, ast_pm, threes_pm, stl_pm, blk_pm, tov_pm
    """
    try:
        key = (str(date_str or ""), int(days_back))
        if key in _PLAYER_STAT_PRIORS_CACHE:
            return _PLAYER_STAT_PRIORS_CACHE[key]

        # Lazy import to keep app startup fast.
        from nba_betting.player_priors import PlayerPriorsConfig, compute_player_priors, write_player_priors_snapshot  # type: ignore

        pri = compute_player_priors(
            str(date_str),
            cfg=PlayerPriorsConfig(days_back=int(days_back), min_games=3, min_minutes_avg=4.0),
        )

        # Optional snapshot for debugging/inspection.
        try:
            flag = str(os.environ.get("WRITE_PLAYER_PRIORS_SNAPSHOT", "")).strip().lower()
            if flag in {"1", "true", "yes", "y"}:
                write_player_priors_snapshot(pri, str(date_str))
        except Exception:
            pass

        _PLAYER_STAT_PRIORS_CACHE[key] = pri.rates
        return _PLAYER_STAT_PRIORS_CACHE[key]
    except Exception:
        return {}

def _team_injury_counts(date_str: str) -> dict[str, int]:
    """Return count of excluded-status injuries per team for the date (latest per player).

    Uses data/raw/injuries.csv if present; filters to OUT/SUSPENDED/INACTIVE/REST and season-long/indefinite.
    Excludes DOUBTFUL by default. Maps counts to both full team names and tricodes, and filters to roster membership for date.
    """
    try:
        if date_str in _TEAM_INJURY_COUNTS_CACHE:
            return _TEAM_INJURY_COUNTS_CACHE[date_str]
        inj_path = DATA_RAW_DIR / "injuries.csv"
        out: dict[str, int] = {}
        if not inj_path.exists():
            _TEAM_INJURY_COUNTS_CACHE[date_str] = out
            return out
        inj = pd.read_csv(inj_path)
        if not isinstance(inj, pd.DataFrame) or inj.empty:
            _TEAM_INJURY_COUNTS_CACHE[date_str] = out
            return out
        if "date" in inj.columns:
            inj["date"] = pd.to_datetime(inj["date"], errors="coerce").dt.date
            inj = inj[inj["date"].notna()]
            cutoff = pd.to_datetime(date_str, errors="coerce")
            if pd.isna(cutoff):
                from datetime import date as _date
                cutoff = pd.Timestamp(_date.today())
            inj = inj[inj["date"] <= cutoff.date()].copy()
        sort_cols = [c for c in ["date"] if c in inj.columns]
        if sort_cols:
            inj = inj.sort_values(sort_cols)
        grp_cols = [c for c in ["player","team"] if c in inj.columns] or ["player"]
        latest = inj.groupby(grp_cols, as_index=False).tail(1).copy()
        latest.loc[:, "status_norm"] = latest["status"].astype(str).str.upper()
        # Exclude doubtful by default; count hard outs and season-ending/indefinite
        EXCLUDE_STATUSES = {"OUT","SUSPENDED","INACTIVE","REST"}
        def _excluded_status(u: str) -> bool:
            try:
                u = str(u).upper()
            except Exception:
                return False
            if u in EXCLUDE_STATUSES:
                return True
            if ("OUT" in u and ("SEASON" in u or "INDEFINITE" in u)) or ("SEASON-ENDING" in u):
                return True
            return False
        # Build roster-based filter and map to tricodes for reliable lookups
        roster = _roster_players_for_date(date_str)
        try:
            latest["_name_key"] = latest["player"].astype(str).map(_norm_player_name)
        except Exception:
            latest["_name_key"] = latest.get("player", "").astype(str)
        latest["team_tri"] = latest.get("team", "").astype(str).map(lambda t: (_get_tricode(t) or str(t).strip().upper()))
        filt = latest[latest["status_norm"].map(_excluded_status)].copy()
        if not filt.empty:
            # Keep only players present on that team's roster for the date
            try:
                mask = filt.apply(lambda r: r["_name_key"] in (roster.get(str(r["team_tri"]).upper(), set()) or set()), axis=1)
                filt = filt[mask].copy()
            except Exception:
                pass
            # Count by full team name and tricode
            for _, row in filt.iterrows():
                t_full = str(row.get("team") or "").strip().upper()
                t_tri = str(row.get("team_tri") or "").strip().upper()
                if t_full:
                    out[t_full] = int(out.get(t_full, 0) + 1)
                if t_tri:
                    out[t_tri] = int(out.get(t_tri, 0) + 1)
        # Fallback: if counts empty, derive from identity-aware names for the date
        if not out:
            try:
                names_map, _impact_map = _team_injury_identity(date_str)
                if isinstance(names_map, dict) and names_map:
                    for k, v in names_map.items():
                        try:
                            tk = str(k or "").strip().upper()
                            cnt = len([n for n in (v or []) if str(n).strip()])
                            if tk and cnt > 0:
                                out[tk] = int(cnt)
                        except Exception:
                            continue
            except Exception:
                pass
        _TEAM_INJURY_COUNTS_CACHE[date_str] = out
        return out
    except Exception:
        _TEAM_INJURY_COUNTS_CACHE[date_str] = {}
        return {}

def _team_injury_identity(date_str: str) -> tuple[dict[str, list[str]], dict[str, float]]:
    """Return per-team key outs (names) and impact score for the date.

    Prefers data/processed/injuries_counts_<date>.json from tools/snapshot_injuries.py.
    Fallbacks to empty maps if unavailable.
    """
    try:
        if date_str in _TEAM_INJURY_IDENTITY_CACHE:
            return _TEAM_INJURY_IDENTITY_CACHE[date_str]
        proc = DATA_PROCESSED_DIR
        fp = proc / f"injuries_counts_{date_str}.json"
        names_map: dict[str, list[str]] = {}
        impact_map: dict[str, float] = {}
        if fp.exists():
            try:
                with open(fp, "r", encoding="utf-8") as f:
                    obj = json.load(f)
                if isinstance(obj, dict):
                    km = obj.get("team_key_outs") or {}
                    im = obj.get("team_impact") or {}
                    # Normalize keys to upper
                    for k, v in (km.items() if isinstance(km, dict) else []):
                        rawk = str(k or "").strip()
                        tk = rawk.upper()
                        if not tk:
                            continue
                        try:
                            if isinstance(v, list):
                                vals = [str(x or "") for x in v][:3]
                                names_map[tk] = vals
                                # Also map tricode if resolvable
                                tri = _get_tricode(rawk)
                                triu = (tri.upper() if isinstance(tri, str) and tri else None)
                                if triu:
                                    names_map[triu] = vals
                        except Exception:
                            continue
                    for k, v in (im.items() if isinstance(im, dict) else []):
                        rawk = str(k or "").strip()
                        tk = rawk.upper()
                        if not tk:
                            continue
                        try:
                            valf = float(v)
                            impact_map[tk] = valf
                            tri = _get_tricode(rawk)
                            triu = (tri.upper() if isinstance(tri, str) and tri else None)
                            if triu:
                                impact_map[triu] = valf
                        except Exception:
                            continue
            except Exception:
                pass
        _TEAM_INJURY_IDENTITY_CACHE[date_str] = (names_map, impact_map)
        return names_map, impact_map
    except Exception:
        _TEAM_INJURY_IDENTITY_CACHE[date_str] = ({}, {})
        return {}, {}

def _roster_players_for_date(date_str: str) -> dict[str, set[str]]:
    """Return map of team tricode -> set of normalized player names for the date.

    Prefers data/processed/league_status_<date>.csv; falls back to overrides/team_roster_<date>.csv.
    """
    out: dict[str, set[str]] = {}
    try:
        proc = DATA_PROCESSED_DIR
        fp = proc / f"league_status_{date_str}.csv"
        if fp.exists():
            df = pd.read_csv(fp)
            cols = {c.upper(): c for c in df.columns}
            tcol = cols.get("TEAM_ABBREVIATION") or cols.get("TEAM")
            ncol = cols.get("PLAYER") or cols.get("PLAYER_NAME")
            if tcol and ncol:
                tmp = df[[tcol, ncol]].copy()
                tmp[tcol] = tmp[tcol].astype(str).str.strip().str.upper()
                tmp[ncol] = tmp[ncol].astype(str)
                tmp["_name_key"] = tmp[ncol].map(_norm_player_name)
                for tri, sg in tmp.groupby(tcol):
                    out[str(tri).strip().upper()] = set(sg["_name_key"].dropna().astype(str).tolist())
        else:
            # fallback to overrides
            ov = DATA_OVERRIDES_DIR / f"team_roster_{date_str}.csv"
            if ov.exists():
                df = pd.read_csv(ov)
                cols = {c.upper(): c for c in df.columns}
                tcol = cols.get("TEAM_ABBREVIATION") or cols.get("TEAM")
                ncol = cols.get("PLAYER")
                if tcol and ncol:
                    tmp = df[[tcol, ncol]].copy()
                    tmp[tcol] = tmp[tcol].astype(str).str.strip().str.upper()
                    tmp[ncol] = tmp[ncol].astype(str)
                    tmp["_name_key"] = tmp[ncol].map(_norm_player_name)
                    for tri, sg in tmp.groupby(tcol):
                        out[str(tri).strip().upper()] = set(sg["_name_key"].dropna().astype(str).tolist())
    except Exception:
        pass
    return out


_TEAM_ROSTER_NBA_CACHE: dict[tuple[str, str], list[str]] = {}


_GAME_STORY_CACHE: dict[tuple, dict[str, Any]] = {}
_GAME_STORY_CACHE_TS: dict[tuple, float] = {}


def _team_roster_names_via_nba_api(date_str: str, team_tri: str) -> list[str]:
    """Best-effort roster names for a team on a date.

    Intended as a fallback for game-day simulations when processed league_status is
    missing/stale, to avoid including traded/waived players from lookback priors.
    """
    try:
        tri = str(team_tri or "").strip().upper()
        if not tri:
            return []
        k = (str(date_str), tri)
        if k in _TEAM_ROSTER_NBA_CACHE:
            return list(_TEAM_ROSTER_NBA_CACHE.get(k) or [])

        out: list[str] = []

        # 1) Prefer live NBA API team roster for the season containing date_str.
        try:
            from nba_api.stats.endpoints import commonteamroster  # type: ignore

            tid = _get_team_id(tri)
            if tid:
                season_year = _season_year_for_date(str(date_str))
                season_str = _season_str_from_year(int(season_year))
                resp = commonteamroster.CommonTeamRoster(team_id=int(tid), season=str(season_str), timeout=15)
                nd = resp.get_normalized_dict()
                df = pd.DataFrame(nd.get("CommonTeamRoster", []))
                if isinstance(df, pd.DataFrame) and (not df.empty):
                    cols = {c.upper(): c for c in df.columns}
                    ncol = cols.get("PLAYER") or cols.get("PLAYER_NAME") or cols.get("FULL_NAME")
                    if ncol:
                        names = [str(x).strip() for x in df[ncol].dropna().astype(str).tolist()]
                        out = [n for n in names if n]
        except Exception:
            out = []

        # 2) Fallback: latest processed rosters_*.csv (can still be stale, but better than priors-only).
        if not out:
            try:
                rost = _load_latest_rosters()
                if isinstance(rost, pd.DataFrame) and (not rost.empty):
                    cols = {c.upper(): c for c in rost.columns}
                    ncol = cols.get("PLAYER")
                    tcol = cols.get("TEAM_ABBREVIATION")
                    if ncol and tcol:
                        tmp = rost[[tcol, ncol]].copy()
                        tmp[tcol] = tmp[tcol].astype(str).str.strip().str.upper()
                        tmp = tmp[tmp[tcol] == tri]
                        names = [str(x).strip() for x in tmp[ncol].dropna().astype(str).tolist()]
                        out = [n for n in names if n]
            except Exception:
                pass

        # Cache (even empty) to avoid repeated network calls per request burst.
        _TEAM_ROSTER_NBA_CACHE[k] = list(out)
        return list(out)
    except Exception:
        return []

# Helper to reliably resolve the Python interpreter for subprocess tasks
def _resolve_python() -> str:
    """Return best Python executable path for running our CLI.

    Priority:
      1) Explicit PYTHON env var if it exists and is a valid file
      2) Current process interpreter (sys.executable) if it exists
      3) VIRTUAL_ENV/Scripts/python.exe (Windows) or VIRTUAL_ENV/bin/python (POSIX)
      4) Workspace .venv/Scripts/python.exe or .venv/bin/python
      5) Fallback to plain 'python'
    """
    try:
        cand = os.environ.get("PYTHON")
        if cand and Path(cand).exists():
            return cand
        if sys.executable and Path(sys.executable).exists():
            return sys.executable
        venv = os.environ.get("VIRTUAL_ENV")
        if venv:
            py_win = Path(venv) / "Scripts" / "python.exe"
            py_posix = Path(venv) / "bin" / "python"
            if py_win.exists():
                return str(py_win)
            if py_posix.exists():
                return str(py_posix)
        # Try workspace-local .venv
        py_win = BASE_DIR / ".venv" / "Scripts" / "python.exe"
        py_posix = BASE_DIR / ".venv" / "bin" / "python"
        if py_win.exists():
            return str(py_win)
        if py_posix.exists():
            return str(py_posix)
    except Exception:
        pass
    return "python"
# ---- Processed files listing APIs ----
def _add_cache_headers(resp, seconds: int = 60):
    try:
        resp.headers["Cache-Control"] = f"public, max-age={seconds}"
    except Exception:
        pass
    return resp

@app.route("/api/list/processed")
def api_list_processed():
    """List files in data/processed matching a glob pattern.

    Query params:
      - pattern: glob pattern (default '*.csv')
    """
    try:
        from datetime import datetime as _dt
        pat = (request.args.get("pattern") or "*.csv").strip() or "*.csv"
        base = DATA_PROCESSED_DIR
        items = []
        if base.exists():
            for p in sorted(base.glob(pat)):
                try:
                    st = p.stat()
                    items.append({
                        "name": p.name,
                        "size": int(st.st_size),
                        "mtime": _dt.fromtimestamp(st.st_mtime).isoformat(),
                        "path": f"/data/processed/{p.name}",
                    })
                except Exception:
                    continue
        resp = jsonify({"pattern": pat, "count": len(items), "items": items})
        return _add_cache_headers(resp, seconds=30)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/sim/smart-sim")
def api_sim_smart_sim():
    """SmartSim: full-game event-level sims -> distributions for ML/ATS/total + player props.

    Query params:
      - date: YYYY-MM-DD (required)
      - home: team tricode (required)
      - away: team tricode (required)
    - n_sims: number of event-level sims (optional, default 2000)
      - seed: optional int seed for reproducibility
      - market_total: optional total line (defaults from predictions if present)
      - home_spread: optional home spread line (defaults from predictions if present)
    """
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400

    home_tri = (request.args.get("home") or "").strip()
    away_tri = (request.args.get("away") or "").strip()
    try:
        home_tri = (_get_tricode(home_tri) or home_tri).strip().upper()
    except Exception:
        home_tri = home_tri.strip().upper()
    try:
        away_tri = (_get_tricode(away_tri) or away_tri).strip().upper()
    except Exception:
        away_tri = away_tri.strip().upper()
    if not home_tri or not away_tri:
        return jsonify({"error": "missing home/away"}), 400

    try:
        n_sims = int(pd.to_numeric(request.args.get("n_sims", "2000"), errors="coerce"))
    except Exception:
        n_sims = 2000
    n_sims = int(max(50, min(3000, n_sims)))

    seed = request.args.get("seed")
    try:
        seed_i = int(seed) if seed not in (None, "") else None
    except Exception:
        seed_i = None

    def _num(x):
        try:
            v = pd.to_numeric(x, errors="coerce")
            return float(v) if np.isfinite(v) else None
        except Exception:
            return None

    try:
        pred_p = _find_predictions_for_date(d)
        if pred_p is None or (hasattr(pred_p, "exists") and not pred_p.exists()):
            return jsonify({"date": d, "error": "predictions not found"}), 404
        pdf = pd.read_csv(pred_p)
        if pdf is None or pdf.empty:
            return jsonify({"date": d, "error": "predictions empty"}), 404

        def _tri(v):
            try:
                t = _get_tricode(str(v))
                return (t.upper() if isinstance(t, str) and t else str(v).strip().upper())
            except Exception:
                return str(v).strip().upper()

        pdf = pdf.copy()
        if "home_team" in pdf.columns:
            pdf["home_tri"] = pdf["home_team"].apply(_tri)
        if "visitor_team" in pdf.columns:
            pdf["away_tri"] = pdf["visitor_team"].apply(_tri)

        m = None
        try:
            m = (pdf.get("home_tri") == home_tri) & (pdf.get("away_tri") == away_tri)
        except Exception:
            m = None
        if m is None or not bool(m.any()):
            return jsonify({"date": d, "error": "game not found in predictions", "home": home_tri, "away": away_tri}), 404
        row = pdf[m].iloc[0].to_dict()

        # Market lines: query param overrides, else predictions row.
        market_total = _num(request.args.get("market_total"))
        if market_total is None:
            market_total = _num(row.get("total"))
        home_spread = _num(request.args.get("home_spread"))
        if home_spread is None:
            home_spread = _num(row.get("home_spread"))

        input_market_total = market_total
        input_home_spread = home_spread

        # Quarter baseline from totals/spread_margin.
        pred_total = _num(row.get("totals"))
        pred_margin = _num(row.get("spread_margin"))
        home_mu_implied = None
        away_mu_implied = None
        if pred_total is not None and pred_margin is not None:
            home_mu_implied = 0.5 * (pred_total + pred_margin)
            away_mu_implied = 0.5 * (pred_total - pred_margin)

        home_pace = _num(row.get("home_pace")) or 98.0
        away_pace = _num(row.get("away_pace")) or 98.0

        def _rating_from_mu(mu, pace):
            try:
                if mu is None:
                    return 112.0
                return float((float(mu) / max(1e-6, float(pace))) * 100.0)
            except Exception:
                return 112.0

        home_off = _num(row.get("home_off_rating")) or _rating_from_mu(home_mu_implied, home_pace)
        away_off = _num(row.get("away_off_rating")) or _rating_from_mu(away_mu_implied, away_pace)
        home_def = _num(row.get("home_def_rating")) or 112.0
        away_def = _num(row.get("away_def_rating")) or 112.0

        from nba_betting.sim.quarters import TeamContext, GameInputs, simulate_quarters  # type: ignore
        from nba_betting.sim.smart_sim import SmartSimConfig, simulate_smart_game  # type: ignore

        # Best-effort schedule/injury context (pregame-known features)
        prev = None; prev2 = None; prev3 = None
        try:
            prev = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=1)).date().isoformat()
            prev2 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=2)).date().isoformat()
            prev3 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=3)).date().isoformat()
        except Exception:
            prev = None; prev2 = None; prev3 = None
        try:
            prev_teams = _get_slate_team_tricodes(prev) if prev else set()
        except Exception:
            prev_teams = set()
        try:
            prev2_teams = _get_slate_team_tricodes(prev2) if prev2 else set()
        except Exception:
            prev2_teams = set()
        try:
            prev3_teams = _get_slate_team_tricodes(prev3) if prev3 else set()
        except Exception:
            prev3_teams = set()

        def _rest_days(tri: str | None) -> int | None:
            try:
                t = str(tri or "").strip().upper()
                if not t:
                    return None
                if t in prev_teams:
                    return 0
                if t in prev2_teams:
                    return 1
                if t in prev3_teams:
                    return 2
                return 3
            except Exception:
                return None

        hb2b = bool(str(home_tri).upper() in prev_teams)
        ab2b = bool(str(away_tri).upper() in prev_teams)
        h_rest = _rest_days(home_tri)
        a_rest = _rest_days(away_tri)

        try:
            name_keys, short_keys = _injury_name_sets_for_teams(d, {str(home_tri).upper(), str(away_tri).upper()})
        except Exception:
            name_keys, short_keys = (set(), set())
        try:
            roster_map = _roster_players_for_date(d)
        except Exception:
            roster_map = {}

        def _count_outs(tri: str | None) -> int:
            try:
                t = str(tri or "").strip().upper()
                if not t:
                    return 0
                names = roster_map.get(t) or set()
                if not names:
                    return 0
                cnt = sum(1 for n in names if (_norm_player_name(n) in name_keys or _short_player_key(n) in short_keys))
                return int(max(0, min(5, cnt)))
            except Exception:
                return 0

        h_outs = _count_outs(home_tri)
        a_outs = _count_outs(away_tri)

        home_ctx = TeamContext(
            team=home_tri,
            pace=float(home_pace),
            off_rating=float(home_off),
            def_rating=float(home_def),
            injuries_out=int(h_outs),
            back_to_back=bool(hb2b),
            rest_days=h_rest,
        )
        away_ctx = TeamContext(
            team=away_tri,
            pace=float(away_pace),
            off_rating=float(away_off),
            def_rating=float(away_def),
            injuries_out=int(a_outs),
            back_to_back=bool(ab2b),
            rest_days=a_rest,
        )
        qsum = simulate_quarters(
            GameInputs(date=d, home=home_ctx, away=away_ctx, market_total=market_total, market_home_spread=home_spread),
            n_samples=3000,
        )

        props_p = DATA_PROCESSED_DIR / f"props_predictions_{d}.csv"
        if not props_p.exists():
            _maybe_fetch_remote_processed(props_p.name)
        props_df = _read_csv_if_exists(props_p)
        if props_df is None or not isinstance(props_df, pd.DataFrame):
            return jsonify({"date": d, "error": "props predictions not found"}), 404

        cfg = SmartSimConfig(n_sims=int(n_sims), seed=seed_i)
        pre_ctx = {
            "home_injuries_out": int(h_outs),
            "away_injuries_out": int(a_outs),
            "home_pace": float(home_pace) if (home_pace is not None) else None,
            "away_pace": float(away_pace) if (away_pace is not None) else None,
            "home_b2b": bool(hb2b),
            "away_b2b": bool(ab2b),
        }
        out = simulate_smart_game(
            date_str=d,
            home_tri=home_tri,
            away_tri=away_tri,
            props_df=props_df,
            quarters=qsum.quarters,
            market_total=market_total,
            market_home_spread=home_spread,
            cfg=cfg,
            pregame_context=pre_ctx,
        )
        try:
            out = dict(out) if isinstance(out, dict) else {"result": out}
        except Exception:
            out = {"result": out}

        # Add warnings/diagnostics for market lines used (ATS/total probs depend on these).
        warnings: list[str] = []
        used_market = out.get("market") if isinstance(out, dict) else None
        used_total = None
        used_spread = None
        if isinstance(used_market, dict):
            used_total = used_market.get("market_total")
            used_spread = used_market.get("market_home_spread")

        odds_fp = DATA_PROCESSED_DIR / f"game_odds_{d}.csv"
        odds_exists = bool(getattr(odds_fp, "exists")())

        if used_total is None:
            if not odds_exists and input_market_total is None:
                warnings.append(
                    f"Missing market_total: no predictions total line and {odds_fp.name} not found; p_total_over will be null."
                )
            else:
                warnings.append("Missing market_total: p_total_over will be null.")
        if used_spread is None:
            if not odds_exists and input_home_spread is None:
                warnings.append(
                    f"Missing home_spread: no predictions spread line and {odds_fp.name} not found; p_home_cover will be null."
                )
            else:
                warnings.append("Missing home_spread: p_home_cover will be null.")

        if warnings:
            out["warnings"] = warnings

        # Best-effort source attribution.
        if isinstance(used_market, dict):
            used_market = dict(used_market)
            if input_market_total is not None:
                used_market["market_total_source"] = "request_or_predictions"
            elif odds_exists and used_total is not None:
                used_market["market_total_source"] = "game_odds"
            if input_home_spread is not None:
                used_market["market_home_spread_source"] = "request_or_predictions"
            elif odds_exists and used_spread is not None:
                used_market["market_home_spread_source"] = "game_odds"
            out["market"] = used_market

        out["market_inputs"] = {"market_total": input_market_total, "home_spread": input_home_spread}

        return jsonify(out)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/processed/recon_games")
def api_processed_recon_games():
    """Serve recon_games_<date>.csv if present; otherwise return empty CSV.

    Query params:
      - date: YYYY-MM-DD (required)
    """
    try:
        d = (request.args.get("date") or "").strip()
        if not d:
            return jsonify({"error": "missing date"}), 400
        base = DATA_PROCESSED_DIR
        fp = base / f"recon_games_{d}.csv"
        if fp.exists():
            try:
                # Serve the file directly to avoid 404 logs on the static handler
                return send_from_directory(str(base), f"recon_games_{d}.csv")
            except Exception:
                # Fallback: read text and return as CSV
                txt = fp.read_text(encoding="utf-8")
                from flask import Response as _Resp
                return _Resp(txt, mimetype="text/csv")
        # Not present: return empty CSV response (avoids 404 noise)
        from flask import Response as _Resp
        return _Resp("", mimetype="text/csv")
    except Exception as e:  # noqa: BLE001
        return jsonify({"error": str(e)}), 500


