# ---------------- Shared helpers ---------------- #

# In-memory caches
_player_id_cache: dict[tuple[str, str | None], int] = {}
_rosters_df_cache: Optional[pd.DataFrame] = None
_rosters_df_cache_key: Optional[tuple[tuple[str, float, int], ...]] = None
_team_name_to_abbr: Optional[dict[str, str]] = None
_team_abbr_to_id: Optional[dict[str, int]] = None

def _load_team_maps() -> dict[str, str]:
    global _team_name_to_abbr, _team_abbr_to_id
    if _team_name_to_abbr is not None:
        return _team_name_to_abbr
    mapping: dict[str, str] = {}
    abbr_to_id: dict[str, int] = {}
    try:
        from nba_api.stats.static import teams as _static_teams  # type: ignore
        team_list = _static_teams.get_teams()  # list of dicts
        for t in team_list:
            full = str(t.get("full_name") or "").strip()
            abbr = str(t.get("abbreviation") or "").strip().upper()
            tid = t.get("id")
            if full:
                mapping[full.lower()] = abbr
            if abbr:
                mapping[abbr.lower()] = abbr
                try:
                    if tid is not None:
                        abbr_to_id[abbr] = int(tid)
                except Exception:
                    pass
    except Exception:
        # Fallback: built-in NBA full_name -> abbreviation map (no nba_api dependency).
        built_in = [
            ("Atlanta Hawks", "ATL"),
            ("Boston Celtics", "BOS"),
            ("Brooklyn Nets", "BKN"),
            ("Charlotte Hornets", "CHA"),
            ("Chicago Bulls", "CHI"),
            ("Cleveland Cavaliers", "CLE"),
            ("Dallas Mavericks", "DAL"),
            ("Denver Nuggets", "DEN"),
            ("Detroit Pistons", "DET"),
            ("Golden State Warriors", "GSW"),
            ("Houston Rockets", "HOU"),
            ("Indiana Pacers", "IND"),
            ("Los Angeles Clippers", "LAC"),
            ("LA Clippers", "LAC"),
            ("Los Angeles Lakers", "LAL"),
            ("Memphis Grizzlies", "MEM"),
            ("Miami Heat", "MIA"),
            ("Milwaukee Bucks", "MIL"),
            ("Minnesota Timberwolves", "MIN"),
            ("New Orleans Pelicans", "NOP"),
            ("New York Knicks", "NYK"),
            ("Oklahoma City Thunder", "OKC"),
            ("Orlando Magic", "ORL"),
            ("Philadelphia 76ers", "PHI"),
            ("Phoenix Suns", "PHX"),
            ("Portland Trail Blazers", "POR"),
            ("Sacramento Kings", "SAC"),
            ("San Antonio Spurs", "SAS"),
            ("Toronto Raptors", "TOR"),
            ("Utah Jazz", "UTA"),
            ("Washington Wizards", "WAS"),
        ]
        mapping = {}
        for full, abbr in built_in:
            mapping[str(full).strip().lower()] = str(abbr).strip().upper()
            mapping[str(abbr).strip().lower()] = str(abbr).strip().upper()
        abbr_to_id = {}
    _team_name_to_abbr = mapping
    _team_abbr_to_id = abbr_to_id
    return mapping

def _get_tricode(team: str | None) -> str | None:
    if not team:
        return None
    m = _load_team_maps()
    abbr = m.get(str(team).strip().lower())
    return (abbr or str(team).strip().upper() or None)

def _get_team_id(team: str | None) -> Optional[int]:
    if not team:
        return None
    try:
        _ = _load_team_maps()  # ensures _team_abbr_to_id populated
    except Exception:
        pass
    try:
        tri = _get_tricode(team)
        if tri and _team_abbr_to_id and tri.upper() in _team_abbr_to_id:
            return int(_team_abbr_to_id[tri.upper()])
    except Exception:
        return None
    return None

def _get_slate_team_tricodes(date_str: str) -> set[str]:
    """Return tricodes for teams playing on date_str.

    Tries, in order:
      1) processed game odds CSV (game_odds_<date>.csv)
      2) processed predictions_<date>.csv (home/visitor teams)
      3) nba_api ScoreboardV2 -> map TEAM_ID to tricode
    Returns an empty set if none can be determined.
    """
    teams: set[str] = set()
    # 1) Prefer standardized game odds
    try:
        p = _find_game_odds_for_date(date_str)
    except Exception:
        p = None
    if p and p.exists():
        try:
            go = pd.read_csv(p)
            for col in ("home_team","visitor_team","away_team"):
                if col in go.columns:
                    vals = go[col].dropna().astype(str).tolist()
                    for v in vals:
                        tri = _get_tricode(v)
                        if tri:
                            teams.add(tri.upper())
            if teams:
                return teams
        except Exception:
            pass
    # 2) Fall back to predictions_<date>.csv
    try:
        pred_p = _find_predictions_for_date(date_str)
    except Exception:
        pred_p = None
    if pred_p and pred_p.exists():
        try:
            df = pd.read_csv(pred_p)
            for col in ("home_team","visitor_team","away_team"):
                if col in df.columns:
                    vals = df[col].dropna().astype(str).tolist()
                    for v in vals:
                        tri = _get_tricode(v)
                        if tri:
                            teams.add(tri.upper())
            if teams:
                return teams
        except Exception:
            pass
    # 3) ScoreboardV2 (if nba_api available)
    try:
        if _scoreboardv2 is not None:
            sb = _scoreboardv2.ScoreboardV2(game_date=date_str, day_offset=0, timeout=30)
            nd = sb.get_normalized_dict()
            gh = pd.DataFrame(nd.get("GameHeader", []))
            if not gh.empty:
                # Build id->abbr map from static teams
                try:
                    _ = _load_team_maps()  # ensures _team_abbr_to_id is set
                except Exception:
                    pass
                inv: dict[int,str] = {}
                try:
                    if _team_abbr_to_id:
                        inv = {int(v): k for k, v in _team_abbr_to_id.items() if v is not None}
                except Exception:
                    inv = {}
                for _, r in gh.iterrows():
                    hid = r.get("HOME_TEAM_ID"); vid = r.get("VISITOR_TEAM_ID")
                    try:
                        if pd.notna(hid):
                            tri = inv.get(int(hid))
                            if tri:
                                teams.add(tri.upper())
                    except Exception:
                        pass
                    try:
                        if pd.notna(vid):
                            tri = inv.get(int(vid))
                            if tri:
                                teams.add(tri.upper())
                    except Exception:
                        pass
                if teams:
                    return teams
    except Exception:
        pass
    return teams

def _load_latest_rosters(date_str: str | None = None) -> pd.DataFrame:
    """Load the most appropriate rosters_*.csv from processed.

    Preference order:
    1) If date_str provided and a season file exists (rosters_YYYY-YY.csv), use it.
    2) Otherwise, prefer season-format files (stem contains '-') by mtime.
    3) Otherwise, newest rosters_*.csv by mtime.
    """
    try:
        proc = DATA_PROCESSED_DIR
        files = list(proc.glob("rosters_*.csv"))
        if not files:
            return pd.DataFrame(columns=["PLAYER","PLAYER_ID","TEAM_ABBREVIATION"])

        # Prefer the current season roster file when we have a date.
        if date_str:
            try:
                d = pd.to_datetime(date_str, errors="coerce")
                if d is not None and not pd.isna(d):
                    start_year = int(d.year) if int(d.month) >= 7 else int(d.year) - 1
                    season = f"{start_year}-{str(start_year+1)[-2:]}"
                    exact = proc / f"rosters_{season}.csv"
                    if exact.exists():
                        files = [exact]
            except Exception:
                pass

        season_files = [f for f in files if '-' in f.stem]
        if season_files:
            season_files.sort(key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
            p = season_files[0]
        else:
            files.sort(key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
            p = files[0]

        df = pd.read_csv(p)
        if not isinstance(df, pd.DataFrame) or df.empty:
            return pd.DataFrame(columns=["PLAYER","PLAYER_ID","TEAM_ABBREVIATION"])
        # Normalize expected columns
        cols = {c.upper(): c for c in df.columns}
        if "PLAYER" not in cols or "PLAYER_ID" not in cols:
            return pd.DataFrame(columns=["PLAYER","PLAYER_ID","TEAM_ABBREVIATION"])
        if "TEAM_ABBREVIATION" not in cols:
            df["TEAM_ABBREVIATION"] = None
        return df
    except Exception:
        return pd.DataFrame(columns=["PLAYER","PLAYER_ID","TEAM_ABBREVIATION"])

def _build_roster_team_maps(date_str: str | None = None) -> tuple[dict[int, str], dict[str, str]]:
    """Return maps for player_id->team_tri and name_key->team_tri from processed rosters.

    Falls back to empty maps when unavailable. Name map uses _norm_player_name keys.
    """
    pid_to_tri: dict[int, str] = {}
    name_to_tri: dict[str, str] = {}
    try:
        # Prefer the per-date league_status snapshot when available.
        # This is typically the most up-to-date source for "who is on which team".
        ls_pids: set[int] = set()
        ls_names: set[str] = set()
        if date_str:
            try:
                proc = DATA_PROCESSED_DIR
                ls = proc / f"league_status_{str(date_str)}.csv"
                if ls.exists():
                    ldf = pd.read_csv(ls)
                    if isinstance(ldf, pd.DataFrame) and (not ldf.empty):
                        cols = {c.lower(): c for c in ldf.columns}
                        pid_col = cols.get("player_id")
                        name_col = cols.get("player_name")
                        team_col = cols.get("team")
                        if pid_col and team_col:
                            use_cols = [pid_col, team_col] + ([name_col] if name_col else [])
                            tmp_ls = ldf[use_cols].copy()
                            tmp_ls[team_col] = tmp_ls[team_col].astype(str).map(lambda x: (_get_tricode(x) or str(x).strip().upper()))
                            tmp_ls[pid_col] = pd.to_numeric(tmp_ls[pid_col], errors="coerce")
                            if name_col:
                                tmp_ls["_name_key"] = tmp_ls[name_col].astype(str).map(_norm_player_name)

                            for _, r in tmp_ls.iterrows():
                                try:
                                    tri = str(r.get(team_col) or "").strip().upper()
                                    if not tri:
                                        continue
                                    pidv = r.get(pid_col)
                                    if pd.notna(pidv):
                                        try:
                                            pid = int(pidv)
                                            pid_to_tri[pid] = tri
                                            ls_pids.add(pid)
                                        except Exception:
                                            pass
                                    if name_col:
                                        nk = str(r.get("_name_key") or "").strip()
                                        if nk:
                                            name_to_tri[nk] = tri
                                            ls_names.add(nk)
                                except Exception:
                                    continue
            except Exception:
                pass

        # Use only the latest season roster file to avoid cross-season contamination
        rost = _load_latest_rosters(date_str)
        if isinstance(rost, pd.DataFrame) and not rost.empty:
            cols = {c.upper(): c for c in rost.columns}
            pid_col = cols.get("PLAYER_ID"); name_col = cols.get("PLAYER"); tri_col = cols.get("TEAM_ABBREVIATION")
            if pid_col and name_col and tri_col:
                tmp = rost[[pid_col, name_col, tri_col]].dropna(subset=[tri_col]).copy()
                # Normalize tri to 3-letter
                tmp[tri_col] = tmp[tri_col].astype(str).map(lambda x: (_get_tricode(x) or str(x).strip().upper()))
                for _, r in tmp.iterrows():
                    try:
                        tri = str(r[tri_col]).strip().upper()
                        if not tri:
                            continue
                        try:
                            pid = int(pd.to_numeric(r[pid_col], errors="coerce"))
                            if pid not in pid_to_tri:
                                pid_to_tri[pid] = tri
                        except Exception:
                            pass
                        try:
                            nkey = _norm_player_name(str(r[name_col]))
                            if nkey:
                                if nkey not in name_to_tri:
                                    name_to_tri[nkey] = tri
                        except Exception:
                            pass
                    except Exception:
                        continue
        # Apply roster overrides (if any)
        try:
            ov = DATA_OVERRIDES_DIR / "roster_overrides.csv"
            if ov.exists():
                odf = pd.read_csv(ov)
                if isinstance(odf, pd.DataFrame) and not odf.empty:
                    ocols = {c.upper(): c for c in odf.columns}
                    opid = ocols.get("PLAYER_ID"); oname = ocols.get("PLAYER"); otri = ocols.get("TEAM_ABBREVIATION")
                    if otri and (opid or oname):
                        tmpo = odf[[c for c in [opid, oname, otri] if c]].dropna(subset=[otri]).copy()
                        tmpo[otri] = tmpo[otri].astype(str).map(lambda x: (_get_tricode(x) or str(x).strip().upper()))
                        for _, r in tmpo.iterrows():
                            try:
                                tri = str(r[otri]).strip().upper()
                                if not tri:
                                    continue
                                if opid and pd.notna(r.get(opid)):
                                    try:
                                        pid = int(pd.to_numeric(r[opid], errors="coerce"))
                                        if pid not in ls_pids:
                                            pid_to_tri[pid] = tri
                                    except Exception:
                                        pass
                                if oname and pd.notna(r.get(oname)):
                                    try:
                                        nkey = _norm_player_name(str(r[oname]))
                                        if nkey:
                                            if nkey not in ls_names:
                                                name_to_tri[nkey] = tri
                                    except Exception:
                                        pass
                            except Exception:
                                continue
        except Exception:
            pass
    except Exception:
        pass
    return pid_to_tri, name_to_tri

def _games_lookup_for_date(date_str: str) -> dict[str, tuple[str, bool]]:
    """Return mapping team_tri -> (opponent_tri, home_flag) for a date.

    Uses processed game_odds_<date>.csv primarily, else predictions_<date>.csv.
    """
    out: dict[str, tuple[str, bool]] = {}
    # 1) game_odds
    try:
        p = _find_game_odds_for_date(date_str)
        if p is not None:
            go = pd.read_csv(p)
            for _, r in go.iterrows():
                try:
                    h = _get_tricode(r.get("home_team")); a = _get_tricode(r.get("visitor_team") or r.get("away_team"))
                    if h and a:
                        out[h] = (a, True)
                        out[a] = (h, False)
                except Exception:
                    continue
    except Exception:
        pass
    # 2) predictions fallback
    if not out:
        try:
            pp = _find_predictions_for_date(date_str)
        except Exception:
            pp = None
        if pp is not None and pp.exists():
            try:
                df = pd.read_csv(pp)
                for _, r in df.iterrows():
                    try:
                        h = _get_tricode(r.get("home_team")); a = _get_tricode(r.get("visitor_team") or r.get("away_team"))
                        if h and a:
                            out[h] = (a, True)
                            out[a] = (h, False)
                    except Exception:
                        continue
            except Exception:
                pass
    return out

def _correct_props_long_with_roster_and_games(long: pd.DataFrame, date_str: str) -> pd.DataFrame:
    """Best-effort correction for team/opponent/home in props predictions long table.

    - Prefer roster maps by player_id, then by normalized name, to set team tricode.
    - Then use games lookup to set opponent and home flag consistently for the date.
    """
    if not isinstance(long, pd.DataFrame) or long is None or long.empty:
        return long
    try:
        pid_to_tri, name_to_tri = _build_roster_team_maps(date_str)
        games_lu = _games_lookup_for_date(date_str)
        tmp = long.copy()
        # Ensure minimal columns exist
        for c in ("player_id","player_name","team","opponent","home"):
            if c not in tmp.columns:
                tmp[c] = None
        # Normalize player_id
        try:
            tmp["player_id"] = pd.to_numeric(tmp["player_id"], errors="coerce")
        except Exception:
            pass
        # Resolve team via roster maps
        try:
            # By id first
            if pid_to_tri:
                tmp["_pid_tri"] = tmp["player_id"].map(lambda x: pid_to_tri.get(int(x)) if pd.notna(x) else None)
            else:
                tmp["_pid_tri"] = None
            # By name next
            if name_to_tri:
                tmp["_name_tri"] = tmp["player_name"].astype(str).map(lambda s: name_to_tri.get(_norm_player_name(s)))
            else:
                tmp["_name_tri"] = None
            def _pick_team(row):
                for k in ("_pid_tri","_name_tri"):
                    v = row.get(k)
                    if isinstance(v, str) and v:
                        return v
                # fallback to existing but normalized
                return (_get_tricode(row.get("team")) or (str(row.get("team") or "").strip().upper() or None))
            tmp["team"] = tmp.apply(_pick_team, axis=1)
        except Exception:
            pass
        # Apply games lookup to set opponent + home
        try:
            tmp["_team_tri"] = tmp["team"].astype(str).map(lambda x: (_get_tricode(x) or str(x).strip().upper()))
            def _opp_for_team(t: str) -> tuple[str|None, bool|None]:
                v = games_lu.get(str(t).upper()) if isinstance(t, str) else None
                if isinstance(v, tuple) and len(v) == 2:
                    return v[0], v[1]
                return None, None
            opps = tmp["_team_tri"].map(lambda t: _opp_for_team(t))
            try:
                tmp["opponent"] = [a[0] if isinstance(a, tuple) else None for a in opps]
                tmp["home"] = [a[1] if isinstance(a, tuple) else None for a in opps]
            except Exception:
                pass
            tmp.drop(columns=["_team_tri","_pid_tri","_name_tri"], inplace=True, errors="ignore")
        except Exception:
            pass
        return tmp
    except Exception:
        return long

# Lightweight team validation via NBA API for specific player_ids (cached)
_pid_team_cache: dict[int, str] = {}
def _team_for_player_via_nba_api(pid: int) -> Optional[str]:
    try:
        if pid in _pid_team_cache:
            return _pid_team_cache[pid]
        try:
            from nba_api.stats.endpoints import commonplayerinfo as _cpi
            r = _cpi.CommonPlayerInfo(player_id=int(pid), timeout=10)
            nd = r.get_normalized_dict()
            rows = nd.get("CommonPlayerInfo", [])
            if rows:
                tri = str(rows[0].get("TEAM_ABBREVIATION") or "").strip().upper()
                if tri:
                    _pid_team_cache[int(pid)] = tri
                    return tri
        except Exception:
            return None
    except Exception:
        return None

# ---- Finals export helpers (module-level) ----
def _finals_from_cdn_all(date_str_local: str) -> pd.DataFrame:
    """Fetch all games' finals from NBA CDN scoreboard for a date (no filtering)."""
    try:
        import requests as _rq  # type: ignore
    except Exception:
        return pd.DataFrame()
    try:
        ymd = date_str_local.replace('-', '')
        url = f"https://data.nba.com/data/10s/prod/v1/{ymd}/scoreboard.json"
        r = _rq.get(url, timeout=6)
        rows: list[dict[str, object]] = []
        if r.status_code == 200:
            jd = r.json()
            games = jd.get('games', []) if isinstance(jd, dict) else []
            for g in games:
                try:
                    htri = str((g.get('hTeam') or {}).get('triCode') or '').upper()
                    vtri = str((g.get('vTeam') or {}).get('triCode') or '').upper()
                    hs = (g.get('hTeam') or {}).get('score'); vs = (g.get('vTeam') or {}).get('score')
                    hpts = int(hs) if (hs not in (None, '')) else None
                    vpts = int(vs) if (vs not in (None, '')) else None
                    rows.append({"home_tri": htri, "away_tri": vtri, "home_pts": hpts, "visitor_pts": vpts})
                except Exception:
                    continue
        return pd.DataFrame(rows)
    except Exception:
        return pd.DataFrame()

def _finals_from_espn_all(date_str_local: str) -> pd.DataFrame:
    """Fetch all games' finals from ESPN scoreboard for a date (no filtering)."""
    try:
        import requests as _rq  # type: ignore
    except Exception:
        return pd.DataFrame()
    try:
        ymd = date_str_local.replace('-', '')
        url = f"https://site.web.api.espn.com/apis/site/v2/sports/basketball/nba/scoreboard?dates={ymd}"
        r = _rq.get(url, timeout=6)
        if r.status_code != 200:
            return pd.DataFrame()
        jd = r.json()
        evs = jd.get('events', []) if isinstance(jd, dict) else []
        def espn_to_tri(abbr: str) -> str:
            s = str(abbr or '').upper()
            fix = { 'GS': 'GSW', 'NO': 'NOP', 'NY': 'NYK', 'UTAH': 'UTA' }
            return fix.get(s, s)
        rows: list[dict[str, object]] = []
        for e in evs:
            try:
                comps = e.get('competitions', [])
                if not comps: continue
                c = comps[0]
                teams = c.get('competitors', [])
                if len(teams) < 2: continue
                home = next((t for t in teams if str(t.get('homeAway'))=='home'), None)
                away = next((t for t in teams if str(t.get('homeAway'))=='away'), None)
                if not home or not away: continue
                htri = espn_to_tri(((home.get('team') or {}).get('abbreviation')))
                vtri = espn_to_tri(((away.get('team') or {}).get('abbreviation')))
                try:
                    hpts = int(home.get('score')) if str(home.get('score') or '') != '' else None
                except Exception:
                    hpts = None
                try:
                    vpts = int(away.get('score')) if str(away.get('score') or '') != '' else None
                except Exception:
                    vpts = None
                rows.append({'home_tri': htri, 'away_tri': vtri, 'home_pts': hpts, 'visitor_pts': vpts})
            except Exception:
                continue
        return pd.DataFrame(rows)
    except Exception:
        return pd.DataFrame()

def _finals_from_stats_all(date_str_local: str) -> pd.DataFrame:
    """Fetch all games' finals from nba_api ScoreboardV2 (if available)."""
    try:
        if _scoreboardv2 is None:
            return pd.DataFrame()
        try:
            if _nba_http is not None:
                _nba_http.STATS_HEADERS.update({
                    'Accept': 'application/json, text/plain, */*',
                    'Accept-Language': 'en-US,en;q=0.9',
                    'Origin': 'https://www.nba.com',
                    'Referer': 'https://www.nba.com/stats/',
                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36',
                    'Connection': 'keep-alive',
                })
        except Exception:
            pass
        sb = _scoreboardv2.ScoreboardV2(game_date=date_str_local, day_offset=0, timeout=10)
        nd = sb.get_normalized_dict()
        gh = pd.DataFrame(nd.get("GameHeader", []))
        ls = pd.DataFrame(nd.get("LineScore", []))
        if gh.empty or ls.empty:
            return pd.DataFrame()
        cgh = {c.upper(): c for c in gh.columns}
        cls = {c.upper(): c for c in ls.columns}
        team_rows: dict[int, dict[str, object]] = {}
        for _, r in ls.iterrows():
            try:
                tid = int(r[cls["TEAM_ID"]])
                tri = str(r[cls["TEAM_ABBREVIATION"]]).upper()
                pts = None
                if "PTS" in cls:
                    try:
                        pts = int(r[cls["PTS"]])
                    except Exception:
                        pts = None
                team_rows[tid] = {"tri": tri, "pts": pts}
            except Exception:
                continue
        out_rows: list[dict[str, object]] = []
        for _, g in gh.iterrows():
            try:
                hid = int(g[cgh["HOME_TEAM_ID"]]); vid = int(g[cgh["VISITOR_TEAM_ID"]])
                h = team_rows.get(hid, {}); v = team_rows.get(vid, {})
                htri = str(h.get("tri") or "").upper(); vtri = str(v.get("tri") or "").upper()
                hpts = h.get("pts"); vpts = v.get("pts")
                out_rows.append({"home_tri": htri, "away_tri": vtri, "home_pts": hpts, "visitor_pts": vpts})
            except Exception:
                continue
        return pd.DataFrame(out_rows)
    except Exception:
        return pd.DataFrame()

def _write_finals_csv_for_date(date_str: str) -> tuple[str, int]:
    """Fetch finals for date and write data/processed/finals_YYYY-MM-DD.csv; return (path, rows)."""
    # Preference: stats -> CDN -> ESPN
    df = _finals_from_stats_all(date_str)
    if df is None or df.empty:
        df = _finals_from_cdn_all(date_str)
    if df is None or df.empty:
        df = _finals_from_espn_all(date_str)

    # If still empty, try +/- 1 day as a timezone-friendly fallback and merge unique rows
    if df is None or df.empty:
        try:
            from datetime import datetime as _dt, timedelta as _td
            base = _dt.strptime(date_str, "%Y-%m-%d").date()
            candidates: list[pd.DataFrame] = []
            for off in (-1, 1):
                d2 = (base + _td(days=off)).isoformat()
                # Stats first
                d2_df = _finals_from_stats_all(d2)
                if d2_df is None or d2_df.empty:
                    d2_df = _finals_from_cdn_all(d2)
                if d2_df is None or d2_df.empty:
                    d2_df = _finals_from_espn_all(d2)
                if isinstance(d2_df, pd.DataFrame) and not d2_df.empty:
                    candidates.append(d2_df)
            if candidates:
                try:
                    df = pd.concat(candidates, ignore_index=True)
                    # De-duplicate on matchup keys if possible
                    keep_cols = [c for c in ("home_tri","away_tri","home_pts","visitor_pts") if c in df.columns]
                    if keep_cols:
                        df = df[keep_cols].drop_duplicates()
                except Exception:
                    pass
        except Exception:
            pass
    if not isinstance(df, pd.DataFrame):
        df = pd.DataFrame()
    for col in ("home_tri","away_tri","home_pts","visitor_pts"):
        if col not in df.columns:
            df[col] = pd.NA
    out = DATA_PROCESSED_DIR / f"finals_{date_str}.csv"
    out.parent.mkdir(parents=True, exist_ok=True)
    keep = ["home_tri","away_tri","home_pts","visitor_pts"]
    df2 = df[keep].copy()
    df2.insert(0, "date", date_str)
    df2.to_csv(out, index=False)
    return str(out), int(len(df2))

def _ensure_rosters_loaded() -> pd.DataFrame:
    global _rosters_df_cache, _rosters_df_cache_key
    proc = DATA_PROCESSED_DIR

    # Cache invalidation: if the underlying roster CSV(s) changed on disk (mtime/size),
    # reload so the app reflects trade-deadline churn without requiring a restart.
    try:
        files = sorted(proc.glob("rosters_*.csv"))
        key: tuple[tuple[str, float, int], ...] = tuple(
            (p.name, float(p.stat().st_mtime), int(p.stat().st_size)) for p in files if p.exists()
        )
    except Exception:
        files = []
        key = tuple()

    if _rosters_df_cache is not None and _rosters_df_cache_key == key:
        return _rosters_df_cache

    # If we got here, either no cache exists or roster files changed.
    if _rosters_df_cache_key != key:
        try:
            _player_id_cache.clear()
        except Exception:
            pass
    _rosters_df_cache_key = key

    frames: list[pd.DataFrame] = []
    try:
        for p in files:
            try:
                df = pd.read_csv(p)
                # Normalize expected columns
                cols = {c.upper(): c for c in df.columns}
                if ("PLAYER" in cols) and ("PLAYER_ID" in cols):
                    # Ensure TEAM_ABBREVIATION if possible
                    if "TEAM_ABBREVIATION" not in cols:
                        df["TEAM_ABBREVIATION"] = None
                    frames.append(df)
            except Exception:
                continue
    except Exception:
        frames = []
    if frames:
        _rosters_df_cache = pd.concat(frames, ignore_index=True)
    else:
        _rosters_df_cache = pd.DataFrame(columns=["PLAYER","PLAYER_ID","TEAM_ABBREVIATION"])  # empty
    return _rosters_df_cache

def _persist_player_id_cache_entry(name: str, team: str | None, pid: int) -> None:
    try:
        PLAYER_ID_CACHE_PATH.parent.mkdir(parents=True, exist_ok=True)
        # Append if unique
        rec = {"player_name": name, "team": (team or ""), "player_id": int(pid)}
        if PLAYER_ID_CACHE_PATH.exists():
            try:
                df = pd.read_csv(PLAYER_ID_CACHE_PATH)
            except Exception:
                df = pd.DataFrame()
            # If already present, skip append
            try:
                exists = False
                if not df.empty:
                    m = df[(df.get("player_name").astype(str) == str(name)) & (df.get("team").astype(str) == str(team or ""))]
                    exists = (len(m) > 0)
                if not exists:
                    df = pd.concat([df, pd.DataFrame([rec])], ignore_index=True)
                    df.to_csv(PLAYER_ID_CACHE_PATH, index=False)
            except Exception:
                # Fallback: append naive
                with PLAYER_ID_CACHE_PATH.open("a", encoding="utf-8") as f:
                    if PLAYER_ID_CACHE_PATH.stat().st_size == 0:
                        f.write("player_name,team,player_id\n")
                    f.write(f"{name},{team or ''},{pid}\n")
        else:
            pd.DataFrame([rec]).to_csv(PLAYER_ID_CACHE_PATH, index=False)
    except Exception:
        pass

def _resolve_player_id(name: str | None, team: str | None = None) -> Optional[int]:
    if not name:
        return None
    key = (str(name).strip(), (str(team).strip() if team else None))
    if key in _player_id_cache:
        return _player_id_cache[key]
    # Check on-disk cache first
    try:
        if PLAYER_ID_CACHE_PATH.exists():
            df = pd.read_csv(PLAYER_ID_CACHE_PATH)
            if not df.empty:
                m = df[(df.get("player_name").astype(str) == key[0]) & (df.get("team").astype(str) == (key[1] or ""))]
                if len(m) > 0:
                    pid = int(pd.to_numeric(m.iloc[0].get("player_id"), errors="coerce"))
                    _player_id_cache[key] = pid
                    return pid
    except Exception:
        pass
    # Search rosters
    roster = _ensure_rosters_loaded()
    pid: Optional[int] = None
    if not roster.empty and ("PLAYER" in roster.columns):
        try:
            cand = roster[roster["PLAYER"].astype(str).str.strip().str.lower() == key[0].lower()]
            if not cand.empty:
                if team and ("TEAM_ABBREVIATION" in cand.columns):
                    tri = _get_tricode(team) or (team.strip().upper())
                    cc = cand[cand["TEAM_ABBREVIATION"].astype(str).str.upper() == str(tri).upper()]
                    if not cc.empty:
                        pid = int(pd.to_numeric(cc.iloc[0].get("PLAYER_ID"), errors="coerce"))
                if pid is None:
                    pid = int(pd.to_numeric(cand.iloc[0].get("PLAYER_ID"), errors="coerce"))
        except Exception:
            pid = None
    # Fallback to nba_api static players lookup by name
    if pid is None:
        try:
            from nba_api.stats.static import players as _static_players  # type: ignore
            hits = _static_players.find_players_by_full_name(key[0]) or []
            if hits:
                # Prefer exact case-insensitive full name match
                exact = [h for h in hits if str(h.get("full_name","")).strip().lower() == key[0].lower()]
                pick = exact[0] if exact else hits[0]
                pid = int(pick.get("id")) if pick and pick.get("id") is not None else None
        except Exception:
            pid = None
    if isinstance(pid, int):
        _player_id_cache[key] = pid
        _persist_player_id_cache_entry(key[0], key[1], pid)
        return pid
    return None

def _default_us_slate_date_str() -> str:
    try:
        import os
        from datetime import datetime as _dt, timedelta as _td

        cutoff_hour = 6  # Treat 12:00am–5:59am local as the prior NBA slate day.
        tz_name = (os.environ.get("APP_TZ") or "America/New_York").strip()
        try:
            from zoneinfo import ZoneInfo  # Python 3.9+

            now_local = _dt.now(ZoneInfo(tz_name))
            if now_local.hour < cutoff_hour:
                now_local = now_local - _td(days=1)
            return now_local.date().isoformat()
        except Exception:
            tz_map = {
                "America/New_York": -5,
                "US/Eastern": -5,
                "America/Chicago": -6,
                "US/Central": -6,
                "America/Denver": -7,
                "US/Mountain": -7,
                "America/Los_Angeles": -8,
                "US/Pacific": -8,
            }
            off = tz_map.get(tz_name, None)
            if off is None:
                try:
                    off = int((os.environ.get("APP_TZ_OFFSET_HOURS") or "-5").strip())
                except Exception:
                    off = -5
            now_local = (_dt.utcnow() + _td(hours=off))
            if now_local.hour < cutoff_hour:
                now_local = now_local - _td(days=1)
            return now_local.date().isoformat()
    except Exception:
        try:
            return pd.Timestamp.now().date().isoformat()
        except Exception:
            return ""


def _parse_date_param(req, default_to_today: bool = True) -> str:
    val = (req.args.get("date") or req.args.get("d") or "").strip()
    if not val and default_to_today:
        dval = _default_us_slate_date_str()
        try:
            print(f"[_parse_date_param] via helper -> {dval}")
        except Exception:
            pass
        return dval
    if not val and not default_to_today:
        return ""
    try:
        # normalize YYYY-MM-DD
        return pd.to_datetime(val).date().isoformat()
    except Exception:
        return val


def _read_csv_if_exists(path: Path) -> Optional[pd.DataFrame]:
    try:
        if path.exists():
            return pd.read_csv(path)
    except Exception:
        return None
    return None


def _maybe_fetch_remote_processed(fname: str) -> Optional[Path]:
    """Optionally fetch a processed artifact from GitHub raw if missing locally.

    Controlled by env var ALLOW_REMOTE_ARTIFACTS in {"1","true","yes"}.
    Saves to data/processed/<fname> on success and returns that Path.
    """
    try:
        allow = str(os.environ.get("ALLOW_REMOTE_ARTIFACTS", "0")).strip().lower() in {"1", "true", "yes"}
        if not allow:
            return None
        # Only allow safe filenames under processed/
        if not fname or "/" in fname or ".." in fname:
            return None
        out = DATA_PROCESSED_DIR / fname
        if out.exists():
            return out
        repo = os.environ.get("GITHUB_REPOSITORY") or "mostgood1/NBA-Betting"
        branch = os.environ.get("GIT_BRANCH") or os.environ.get("RENDER_GIT_BRANCH") or "main"
        url = f"https://raw.githubusercontent.com/{repo}/{branch}/data/processed/{fname}"
        try:
            import requests as _rq  # type: ignore
        except Exception:
            return None
        try:
            r = _rq.get(url, timeout=8, headers={
                "User-Agent": "NBA-Betting/props-backend",
                "Accept": "text/csv,application/octet-stream,*/*",
            })
            if r.status_code != 200 or not r.content:
                return None
            out.parent.mkdir(parents=True, exist_ok=True)
            with out.open("wb") as f:
                f.write(r.content)
            return out
        except Exception:
            return None
    except Exception:
        return None


def _number(x):
    try:
        if pd.isna(x):
            return None
        v = float(x)
        if not np.isfinite(v):
            return None
        return v
    except Exception:
        return None


def _json_primitive(x):
    """Convert numpy/pandas scalars and datetimes to native JSON-serializable types.

    Strict mode: coerce NaN/Inf to None so JSON is valid (browsers reject NaN/Infinity).
    """
    try:
        # Normalize pandas/NumPy NA first (including plain float('nan'))
        try:
            if x is None:
                return None
            # pandas/NumPy NA detection
            try:
                if pd.isna(x):
                    return None
            except Exception:
                pass
            # Explicitly guard floats for NaN/Inf
            if isinstance(x, float):
                if not np.isfinite(x):
                    return None
                return float(x)
            # NumPy numeric scalars
            if isinstance(x, np.floating):
                xv = float(x)
                if not np.isfinite(xv):
                    return None
                return xv
            if isinstance(x, np.integer):
                return int(x)
        except Exception:
            pass

        # Primitive JSON-safe types
        if isinstance(x, (str, bool, int)):
            return x
        # numpy scalar -> python scalar
        if isinstance(x, np.generic):
            try:
                return x.item()
            except Exception:
                pass
        # datetime-like -> ISO string
        if isinstance(x, (datetime,)):
            try:
                return x.isoformat()
            except Exception:
                return str(x)
        # pandas timestamp
        try:
            import pandas as _pd  # local alias
            if isinstance(x, _pd.Timestamp):
                return x.to_pydatetime().isoformat()
        except Exception:
            pass
        # numpy datetime64
        try:
            if isinstance(x, (np.datetime64,)):
                return str(x)
        except Exception:
            pass
        return x
    except Exception:
        return x


def _to_jsonable(obj):
    """Recursively convert container of dict/list/tuple/numpy/pandas scalars to JSONable primitives."""
    try:
        if isinstance(obj, dict):
            return {str(k): _to_jsonable(v) for k, v in obj.items()}
        if isinstance(obj, (list, tuple, set)):
            return [ _to_jsonable(v) for v in obj ]
        # numpy arrays -> lists
        try:
            if isinstance(obj, np.ndarray):
                return [ _to_jsonable(v) for v in obj.tolist() ]
        except Exception:
            pass
        return _json_primitive(obj)
    except Exception:
        return obj


def _normalize_team_str(x: str) -> str:
    # Best effort normalization: uppercase tricode if given, else strip
    try:
        return str(x).strip()
    except Exception:
        return str(x)


def _implied_prob_american(o: Any) -> Optional[float]:
    try:
        if o is None or (isinstance(o, float) and not np.isfinite(o)):
            return None
        o = float(o)
        if o == 0:
            return None
        if o > 0:
            return 100.0 / (o + 100.0)
        return (-o) / ((-o) + 100.0)
    except Exception:
        return None


def _american_to_b(o: Any) -> Optional[float]:
    try:
        o = float(o)
        return (o / 100.0) if o > 0 else (100.0 / abs(o))
    except Exception:
        return None


def _ev_from_prob_and_american(p: Optional[float], odds: Any) -> Optional[float]:
    if p is None:
        return None
    b = _american_to_b(odds)
    if b is None:
        return None
    try:
        return p * b - (1 - p)
    except Exception:
        return None


def _has_games_for_date(date_str: str, verbose: bool = False) -> bool:
    """Return True if there are NBA games on the given date.

    Preference order:
    1) nba_api ScoreboardV2 (if available)
    2) Bovada odds feed (if available)
    """
    # First try nba_api ScoreboardV2
    try:
        if _scoreboardv2 is not None:
            sb = _scoreboardv2.ScoreboardV2(game_date=date_str, day_offset=0, timeout=30)
            nd = sb.get_normalized_dict()
            gh = pd.DataFrame(nd.get("GameHeader", []))
            if not gh.empty and len(gh) > 0:
                return True
    except Exception as e:
        if verbose:
            print(f"[_has_games_for_date] scoreboard error: {e}")
    # Fallback to Bovada odds (pass date string for consistency)
    try:
        if _fetch_bovada_odds_current is not None:
            # Prefer passing the canonical YYYY-MM-DD string to avoid timezone/type pitfalls
            o = _fetch_bovada_odds_current(str(date_str), verbose=False)
            if isinstance(o, pd.DataFrame) and not o.empty:
                return True
    except Exception as e:
        if verbose:
            print(f"[_has_games_for_date] bovada error: {e}")
    # Last-resort: check processed schedule JSON (if present)
    try:
        sched = DATA_PROCESSED_DIR / "schedule_2025_26.json"
        if sched.exists():
            sdf = pd.read_json(sched)
            if not sdf.empty:
                if "date_utc" in sdf.columns:
                    sdf["date_utc"] = pd.to_datetime(sdf["date_utc"], errors="coerce").dt.date.astype(str)
                have = bool((sdf.get("date_utc") == str(date_str)).sum())
                if have:
                    return True
    except Exception:
        pass
    return False


# ---------------- Admin: daily update (mirrors NFL-Betting shape) ---------------- #
_job_state = {
    "running": False,
    "started_at": None,
    "ended_at": None,
    "ok": None,
    "logs": [],
    "log_file": None,
}

# Separate lightweight job state for OddsAPI props refresh (snapshot/edges/export).
_oddsapi_props_job_state = {
    "running": False,
    "started_at": None,
    "ended_at": None,
    "phase": None,
    "phase_started_at": None,
    "heartbeat_at": None,
    "ok": None,
    "log_file": None,
    "last": {},
    "rc_snapshot": None,
    "rc_edges": None,
    "rc_export": None,
    "snapshot_rows": None,
    "edges_rows": None,
    "recs_rows": None,
    "snapshot_path": None,
    "edges_path": None,
    "recs_path": None,
    "duration_s": None,
    "error": None,
}


def _prime_oddsapi_props_job_state(
    *,
    date_str: str,
    regions: str,
    bookmakers: str,
    markets: str,
    do_edges: bool,
    do_export: bool,
    do_push: bool,
    log_file: Path | str,
    running: bool = True,
    started_at: str | None = None,
) -> None:
    """Initialize the shared async payload for the current props refresh run."""
    started_iso = started_at or datetime.utcnow().isoformat()
    _oddsapi_props_job_state["running"] = bool(running)
    _oddsapi_props_job_state["started_at"] = started_iso
    _oddsapi_props_job_state["ended_at"] = None
    _oddsapi_props_job_state["phase"] = "snapshot"
    _oddsapi_props_job_state["phase_started_at"] = started_iso
    _oddsapi_props_job_state["heartbeat_at"] = datetime.utcnow().isoformat()
    _oddsapi_props_job_state["ok"] = None
    _oddsapi_props_job_state["log_file"] = str(log_file)
    _oddsapi_props_job_state["last"] = {
        "date": date_str,
        "regions": regions,
        "bookmakers": (bookmakers or None),
        "markets": markets,
        "edges": bool(do_edges),
        "export": bool(do_export),
        "push": bool(do_push),
    }
    _oddsapi_props_job_state["rc_snapshot"] = -1
    _oddsapi_props_job_state["rc_edges"] = (-2 if do_edges else None)
    _oddsapi_props_job_state["rc_export"] = (-2 if do_export else None)
    _oddsapi_props_job_state["snapshot_rows"] = 0
    _oddsapi_props_job_state["edges_rows"] = 0
    _oddsapi_props_job_state["recs_rows"] = 0
    _oddsapi_props_job_state["snapshot_path"] = None
    _oddsapi_props_job_state["edges_path"] = None
    _oddsapi_props_job_state["recs_path"] = None
    _oddsapi_props_job_state["duration_s"] = None
    _oddsapi_props_job_state["error"] = None


def _reset_oddsapi_props_job_state() -> None:
    _oddsapi_props_job_state.update({
        "running": False,
        "started_at": None,
        "ended_at": None,
        "phase": None,
        "phase_started_at": None,
        "heartbeat_at": None,
        "ok": None,
        "log_file": None,
        "last": {},
        "rc_snapshot": None,
        "rc_edges": None,
        "rc_export": None,
        "snapshot_rows": None,
        "edges_rows": None,
        "recs_rows": None,
        "snapshot_path": None,
        "edges_path": None,
        "recs_path": None,
        "duration_s": None,
        "error": None,
    })


