@app.route("/api/schedule")
def api_schedule():
    """Serve the NBA schedule as JSON. If the processed JSON is missing, attempt to generate it.

    Query params:
      - season (optional): currently defaults to '2025-26'
      - date (optional): if provided, filter to that YYYY-MM-DD
    """
    season = (request.args.get("season") or "2025-26").strip()
    date_str = _parse_date_param(request, default_to_today=False)
    out_dir = DATA_PROCESSED_DIR
    out_dir.mkdir(parents=True, exist_ok=True)
    json_path = out_dir / "schedule_2025_26.json"  # schema tied to function name for now
    try:
        data: Optional[list[dict[str, Any]]] = None

        # Prefer serving the processed JSON directly (fast + avoids pandas/JSON serialization edge cases)
        if json_path.exists():
            try:
                raw = json_path.read_text(encoding="utf-8")
                parsed = json.loads(raw)
                if isinstance(parsed, list):
                    # Ensure dict elements
                    data = [x for x in parsed if isinstance(x, dict)]
            except Exception:
                data = None

        # Fallback: load via pandas (handles some legacy formats)
        if not data:
            try:
                df = pd.read_json(json_path) if json_path.exists() else None
            except Exception:
                df = None
            if df is not None and not df.empty:
                try:
                    df = df.replace({np.nan: None})
                except Exception:
                    pass
                data = df.to_dict(orient="records")

        # Last resort: attempt to rebuild
        if not data:
            try:
                from nba_betting.schedule import fetch_schedule_2025_26  # type: ignore

                df = fetch_schedule_2025_26()
                if df is None or df.empty:
                    return jsonify([])
                try:
                    df.to_json(json_path, orient="records", date_format="iso")
                except Exception:
                    pass
                try:
                    df = df.replace({np.nan: None})
                except Exception:
                    pass
                data = df.to_dict(orient="records")
            except Exception as e:
                return jsonify({"error": f"Failed to load or build schedule: {e}"}), 500

        # Optional filter by date (YYYY-MM-DD) using an ET calendar day
        if date_str:
            try:
                from zoneinfo import ZoneInfo
                tz = ZoneInfo("America/New_York")
            except Exception:
                tz = None

            def _et_key_from_game(g: dict[str, Any]) -> Optional[str]:
                try:
                    if not isinstance(g, dict):
                        return None
                    for k in ("datetime_utc", "datetime_est", "date_est", "date_utc"):
                        v = g.get(k)
                        if v is None:
                            continue
                        s = str(v)
                        if not s:
                            continue
                        if k == "datetime_utc":
                            dt = pd.to_datetime(s, errors="coerce", utc=True)
                            if pd.isna(dt):
                                return None
                            if tz is not None:
                                dt = dt.tz_convert(tz)
                            return dt.date().isoformat()
                        # For *_est and date-only, slice YYYY-MM-DD
                        return s[:10]
                    return None
                except Exception:
                    return None

            data = [g for g in data if _et_key_from_game(g) == date_str]

        return jsonify(data)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/sim/quarters")
def api_sim_quarters():
    """Simulate quarter scoring for each scheduled game on a date.

    Inputs:
      - date: YYYY-MM-DD (required)
      - team filters (optional): home_team, away_team to narrow to a specific game

    Output per game:
      { home_team, away_team, market_total, market_home_spread,
        summary: { final_total_mu, final_total_sigma, final_margin_mu, final_margin_sigma, probs, evs },
        quarters: [{ q, home_pts_mu, home_pts_sigma, away_pts_mu, away_pts_sigma }]
      }
    """
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400
    try:
        # Load predictions and merge odds if available
        pred_p = _find_predictions_for_date(d)
        if pred_p is None or (hasattr(pred_p, "exists") and not pred_p.exists()):
            return jsonify({"date": d, "rows": []})
        pdf = pd.read_csv(pred_p)
        # Merge odds if present
        odds_p = _find_game_odds_for_date(d)
        if odds_p is not None and odds_p.exists():
            try:
                o = pd.read_csv(odds_p)
                for col in ("date",):
                    if col in o.columns:
                        o[col] = pd.to_datetime(o[col], errors="coerce").dt.date
                if "date" in pdf.columns:
                    pdf["date"] = pd.to_datetime(pdf["date"], errors="coerce").dt.date
                on = ["date", "home_team", "visitor_team"]
                if all(c in pdf.columns for c in on) and all(c in o.columns for c in on):
                    pdf = pdf.merge(o, on=on, how="left", suffixes=("", "_odds"))
            except Exception:
                pass

        # Optional filters
        home_q = (request.args.get("home_team") or "").strip()
        away_q = (request.args.get("away_team") or "").strip()
        if home_q or away_q:
            try:
                m = pd.Series([True] * len(pdf))
                if home_q:
                    m &= (pdf.get("home_team").astype(str).str.strip() == home_q)
                if away_q:
                    m &= (pdf.get("visitor_team").astype(str).str.strip() == away_q)
                pdf = pdf[m]
            except Exception:
                pass

        # Import simulator lazily to avoid hard failures if module missing
        try:
            from nba_betting.sim.quarters import TeamContext, GameInputs, simulate_quarters  # type: ignore
        except Exception as e:
            return jsonify({"error": f"quarters simulator unavailable: {e}"}), 500

        def _num(x):
            try:
                v = pd.to_numeric(x, errors="coerce")
                return float(v) if np.isfinite(v) else None
            except Exception:
                try:
                    v = float(x)
                    return v if np.isfinite(v) else None
                except Exception:
                    return None

        # Load quarter odds if available
        qodds_df = None
        try:
            from nba_betting.odds.quarter_odds import load_quarter_odds  # type: ignore
            qodds_df = load_quarter_odds(d, DATA_PROCESSED_DIR)
        except Exception:
            qodds_df = None

        # Schedule density (B2B / 3-in-4) helpers and injury context
        prev = None; prev2 = None; prev3 = None
        try:
            prev = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=1)).date().isoformat()
            prev2 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=2)).date().isoformat()
            prev3 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=3)).date().isoformat()
        except Exception:
            prev = None; prev2 = None; prev3 = None
        try:
            prev_teams = _get_slate_team_tricodes(prev) if prev else set()
        except Exception:
            prev_teams = set()
        try:
            prev2_teams = _get_slate_team_tricodes(prev2) if prev2 else set()
        except Exception:
            prev2_teams = set()
        try:
            prev3_teams = _get_slate_team_tricodes(prev3) if prev3 else set()
        except Exception:
            prev3_teams = set()
        # Injury name sets and roster map for counting outs
        try:
            name_keys, short_keys = _injury_name_sets_for_date(d)
        except Exception:
            name_keys, short_keys = (set(), set())
        try:
            roster_map = _roster_players_for_date(d)
        except Exception:
            roster_map = {}

        rows: list[dict] = []
        for _, r in pdf.iterrows():
            home = r.get("home_team"); away = r.get("visitor_team")
            if not home or not away:
                continue
            # Try to derive model baselines from predictions if available
            pred_total = _num(r.get("pred_total"))
            if pred_total is None:
                pred_total = _num(r.get("totals"))
            if pred_total is None:
                pred_total = _num(r.get("total_pred"))
            pred_margin = _num(r.get("pred_margin"))
            if pred_margin is None:
                pred_margin = _num(r.get("spread_margin"))
            if pred_margin is None:
                pred_margin = _num(r.get("margin_pred"))
            # Pace and ratings; use defaults if not provided
            home_pace = _num(r.get("home_pace")) or 98.0
            away_pace = _num(r.get("away_pace")) or 98.0
            # Convert predicted total/margin to implied team means when available
            home_mu_implied = None; away_mu_implied = None
            if pred_total is not None and pred_margin is not None:
                home_mu_implied = 0.5 * (pred_total + pred_margin)
                away_mu_implied = 0.5 * (pred_total - pred_margin)
            # Ratings per 100, derived from implied means and pace when possible
            def _rating_from_mu(mu: float | None, pace: float) -> float:
                try:
                    if mu is None:
                        return 112.0
                    return float((mu / max(1e-6, pace)) * 100.0)
                except Exception:
                    return 112.0
            home_off = _num(r.get("home_off_rating")) or _rating_from_mu(home_mu_implied, home_pace)
            away_off = _num(r.get("away_off_rating")) or _rating_from_mu(away_mu_implied, away_pace)
            # Defensive ratings: fallback to league-average if not present
            home_def = _num(r.get("home_def_rating")) or 112.0
            away_def = _num(r.get("away_def_rating")) or 112.0

            # Schedule flags and injuries
            htri = _get_tricode(str(home)) or str(home).strip().upper()
            atri = _get_tricode(str(away)) or str(away).strip().upper()
            hb2b = bool(htri and (htri in prev_teams)); ab2b = bool(atri and (atri in prev_teams))

            def _rest_days(tri: str | None) -> int | None:
                try:
                    t = str(tri or "").strip().upper()
                    if not t:
                        return None
                    if t in prev_teams:
                        return 0
                    if t in prev2_teams:
                        return 1
                    if t in prev3_teams:
                        return 2
                    return 3
                except Exception:
                    return None

            h_rest = _rest_days(htri)
            a_rest = _rest_days(atri)
            # Count outs by roster name intersection with injury sets (normalized via _norm_player_name)
            def _count_outs(tri: str | None) -> int:
                try:
                    if not tri:
                        return 0
                    names = roster_map.get(str(tri).strip().upper()) or set()
                    if not names:
                        return 0
                    cnt = sum(1 for n in names if (_norm_player_name(n) in name_keys or _short_player_key(n) in short_keys))
                    return int(max(0, min(5, cnt)))
                except Exception:
                    return 0
            h_outs = _count_outs(htri)
            a_outs = _count_outs(atri)

            home_ctx = TeamContext(team=str(home), pace=float(home_pace), off_rating=float(home_off), def_rating=float(home_def),
                                   injuries_out=int(h_outs), back_to_back=bool(hb2b), rest_days=h_rest)
            away_ctx = TeamContext(team=str(away), pace=float(away_pace), off_rating=float(away_off), def_rating=float(away_def),
                                   injuries_out=int(a_outs), back_to_back=bool(ab2b), rest_days=a_rest)

            market_total = _num(r.get("total"))
            market_home_spread = _num(r.get("home_spread"))

            inp = GameInputs(date=str(d), home=home_ctx, away=away_ctx, market_total=market_total, market_home_spread=market_home_spread)
            try:
                summary = simulate_quarters(inp, n_samples=3000)
            except Exception as e:
                rows.append({"home_team": home, "away_team": away, "error": str(e)})
                continue

            # Quarter markets integration when quarter odds present
            quarter_markets: list[dict] = []
            if qodds_df is not None and not qodds_df.empty:
                try:
                    qf = qodds_df.copy()
                    qf = qf[(qf.get("home_team").astype(str) == str(home)) & (qf.get("visitor_team").astype(str) == str(away))]
                    # Helper: EV from prob and American odds
                    def _ev_pa(prob: float | None, amer: float | None) -> float | None:
                        try:
                            if prob is None:
                                return None
                            if amer is None:
                                dec = 1.909090909
                            else:
                                a = float(amer)
                                dec = (1.0 + a / 100.0) if a > 0 else (1.0 + 100.0 / abs(a))
                            return (float(prob) * (dec - 1.0)) - ((1.0 - float(prob)) * 1.0)
                        except Exception:
                            return None
                    import math
                    for _, oq in qf.iterrows():
                        try:
                            qn = int(pd.to_numeric(oq.get("q"), errors="coerce"))
                        except Exception:
                            qn = None
                        if qn is None:
                            continue
                        # Find the simulator quarter result
                        qq = None
                        for qres in summary.quarters:
                            if int(getattr(qres, "q", -1)) == int(qn):
                                qq = qres
                                break
                        if qq is None:
                            continue
                        # Quarter margin and total distributions
                        mu_margin_q = float(qq.home_pts_mu - qq.away_pts_mu)
                        var_h = float(qq.home_pts_sigma ** 2)
                        var_a = float(qq.away_pts_sigma ** 2)
                        cov = float((qq.corr or 0.0) * qq.home_pts_sigma * qq.away_pts_sigma)
                        sigma_margin_q = math.sqrt(max(1e-6, var_h + var_a - 2.0 * cov))
                        mu_total_q = float(qq.home_pts_mu + qq.away_pts_mu)
                        sigma_total_q = math.sqrt(max(1e-6, var_h + var_a + 2.0 * cov))
                        # Prices and lines
                        home_ml_q = _num(oq.get("home_ml"))
                        away_ml_q = _num(oq.get("away_ml"))
                        home_spread_q = _num(oq.get("home_spread"))
                        total_q = _num(oq.get("total"))
                        # Normal survival function: P(X > x)
                        def _norm_sf(x: float, mu: float, sigma: float) -> float:
                            try:
                                return 0.5 * math.erfc((x - mu) / (sigma * math.sqrt(2.0)))
                            except Exception:
                                return 0.5
                        # Probabilities
                        p_home_ml_q = _norm_sf(0.0, mu_margin_q, sigma_margin_q)
                        p_home_cover_q = None
                        p_away_cover_q = None
                        if home_spread_q is not None:
                            # Home spread positive means home is underdog; cover if margin + spread > 0
                            p_home_cover_q = _norm_sf(0.0, mu_margin_q + float(home_spread_q), sigma_margin_q)
                            # Optional probability calibration learned from recent smart_sim_quarter_eval.
                            # Applies only when a calibration artifact exists for (date-1).
                            try:
                                from nba_betting.prob_calibration import calibrate_prob  # type: ignore

                                p_home_cover_q = float(calibrate_prob(str(d), f"q{int(qn)}_cover", float(p_home_cover_q)))
                            except Exception:
                                pass
                            # With continuous distributions, push probability is ~0; enforce complement for consistency.
                            p_away_cover_q = None if p_home_cover_q is None else (1.0 - float(p_home_cover_q))
                        p_total_over_q = None
                        p_total_under_q = None
                        if total_q is not None:
                            p_total_over_q = _norm_sf(float(total_q), mu_total_q, sigma_total_q)
                            # Optional probability calibration learned from recent smart_sim_quarter_eval.
                            # Applies only when a calibration artifact exists for (date-1).
                            try:
                                from nba_betting.prob_calibration import calibrate_prob  # type: ignore

                                p_total_over_q = float(calibrate_prob(str(d), f"q{int(qn)}_over", float(p_total_over_q)))
                            except Exception:
                                pass
                            p_total_under_q = 1.0 - float(p_total_over_q)
                        # EVs
                        ev_home_ml_q = _ev_pa(p_home_ml_q, home_ml_q)
                        ev_away_ml_q = _ev_pa(None if p_home_ml_q is None else (1.0 - p_home_ml_q), away_ml_q)
                        ev_home_cover_q = _ev_pa(p_home_cover_q, None) if p_home_cover_q is not None else None
                        ev_away_cover_q = _ev_pa(p_away_cover_q, None) if p_away_cover_q is not None else None
                        ev_total_over_q = _ev_pa(p_total_over_q, None) if p_total_over_q is not None else None
                        ev_total_under_q = _ev_pa(p_total_under_q, None) if p_total_under_q is not None else None
                        quarter_markets.append({
                            "q": qn,
                            "lines": {
                                "home_ml": home_ml_q,
                                "away_ml": away_ml_q,
                                "home_spread": home_spread_q,
                                "total": total_q,
                            },
                            "probs": {
                                "p_home_ml": p_home_ml_q,
                                "p_home_cover": p_home_cover_q,
                                "p_away_cover": p_away_cover_q,
                                "p_total_over": p_total_over_q,
                                "p_total_under": p_total_under_q,
                            },
                            "evs": {
                                "ev_home_ml": ev_home_ml_q,
                                "ev_away_ml": ev_away_ml_q,
                                "ev_home_cover": ev_home_cover_q,
                                "ev_away_cover": ev_away_cover_q,
                                "ev_total_over": ev_total_over_q,
                                "ev_total_under": ev_total_under_q,
                            },
                        })
                except Exception:
                    quarter_markets = []

            rows.append({
                "home_team": home,
                "away_team": away,
                "market_total": market_total,
                "market_home_spread": market_home_spread,
                "summary": {
                    "final_total_mu": summary.final_total_mu,
                    "final_total_sigma": summary.final_total_sigma,
                    "final_margin_mu": summary.final_margin_mu,
                    "final_margin_sigma": summary.final_margin_sigma,
                    "probs": summary.probs,
                    "evs": summary.evs,
                },
                "quarters": [
                    {
                        "q": q.q,
                        "home_pts_mu": q.home_pts_mu,
                        "home_pts_sigma": q.home_pts_sigma,
                        "away_pts_mu": q.away_pts_mu,
                        "away_pts_sigma": q.away_pts_sigma,
                    } for q in summary.quarters
                ],
                "quarter_markets": quarter_markets,
            })

        return jsonify({"date": d, "rows": rows})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/sim/game-story")
def api_sim_game_story():
    """Connected sim: quarter scores + player box score + sportswriter recap.

    Query params:
      - date: YYYY-MM-DD (required)
      - home: team tricode (required)
      - away: team tricode (required)
      - n: number of samples (optional, default 1200)
      - seed: optional int seed for reproducibility
      - rotation_shock_alpha: optional float in [0,1] (default 0; opt-in)
      - correlated_scoring_alpha: optional float in [0,1] (default 0 unless set via CONNECTED_CORRELATED_SCORING_ALPHA)
      - foul_trouble_alpha: optional float in [0,1] (default 0; opt-in)
            - event_level: optional int/bool (0/1) to use event-level (possession) stat-mix for the representative box score (keeps points allocation; default 0)
    """
    d = _parse_date_param(request)
    if not d:
        return jsonify({"error": "missing date"}), 400
    # Accept either tricodes (e.g., "BOS") or human names (e.g., "Boston Celtics").
    home_tri = (request.args.get("home") or "").strip()
    away_tri = (request.args.get("away") or "").strip()
    try:
        home_tri = (_get_tricode(home_tri) or home_tri).strip().upper()
    except Exception:
        home_tri = home_tri.strip().upper()
    try:
        away_tri = (_get_tricode(away_tri) or away_tri).strip().upper()
    except Exception:
        away_tri = away_tri.strip().upper()
    if not home_tri or not away_tri:
        return jsonify({"error": "missing home/away"}), 400
    try:
        n = int(pd.to_numeric(request.args.get("n", "1200"), errors="coerce"))
    except Exception:
        n = 1200
    n = int(max(300, min(6000, n)))
    seed = request.args.get("seed")
    try:
        seed_i = int(seed) if seed not in (None, "") else None
    except Exception:
        seed_i = None

    # If the caller didn't provide a seed, derive a stable seed so the connected
    # scenario is predictable across refreshes.
    if seed_i is None:
        try:
            import hashlib

            stable_key = "|".join(
                [
                    str(d),
                    str(home_tri),
                    str(away_tri),
                    str(n),
                    str(request.args.get("alpha") or ""),
                    str(request.args.get("rotation_shock_alpha") or os.environ.get("CONNECTED_ROTATION_SHOCK_ALPHA") or ""),
                    str(request.args.get("correlated_scoring_alpha") or os.environ.get("CONNECTED_CORRELATED_SCORING_ALPHA") or ""),
                    str(request.args.get("foul_trouble_alpha") or os.environ.get("CONNECTED_FOUL_TROUBLE_ALPHA") or ""),
                    str(request.args.get("use_lineup") or ""),
                    str(request.args.get("event_level") or ""),
                ]
            ).encode("utf-8", errors="ignore")
            h = hashlib.sha256(stable_key).digest()
            seed_i = int.from_bytes(h[:4], "little", signed=False) & 0x7FFFFFFF
        except Exception:
            seed_i = 1337

    alpha = request.args.get("alpha")
    try:
        alpha_f = float(pd.to_numeric(alpha, errors="coerce")) if alpha not in (None, "") else 0.50
    except Exception:
        alpha_f = 0.50
    if not np.isfinite(alpha_f):
        alpha_f = 0.50
    alpha_f = float(max(0.0, min(1.0, alpha_f)))

    # Optional: rotation-shock flattening in connected minutes allocation.
    # Keep default disabled (0.0) unless explicitly provided.
    rotshock = request.args.get("rotation_shock_alpha")
    if rotshock in (None, ""):
        rotshock = os.environ.get("CONNECTED_ROTATION_SHOCK_ALPHA")
    try:
        rotshock_f = float(pd.to_numeric(rotshock, errors="coerce")) if rotshock not in (None, "") else 0.0
    except Exception:
        rotshock_f = 0.0
    if not np.isfinite(rotshock_f):
        rotshock_f = 0.0
    rotshock_f = float(max(0.0, min(1.0, rotshock_f)))

    # Optional: correlated scoring variance (latent factor scaling of quarter points).
    corr_sc = request.args.get("correlated_scoring_alpha")
    if corr_sc in (None, ""):
        corr_sc = os.environ.get("CONNECTED_CORRELATED_SCORING_ALPHA")
    try:
        corr_sc_f = float(pd.to_numeric(corr_sc, errors="coerce")) if corr_sc not in (None, "") else 0.0
    except Exception:
        corr_sc_f = 0.0
    if not np.isfinite(corr_sc_f):
        corr_sc_f = 0.0
    corr_sc_f = float(max(0.0, min(1.0, corr_sc_f)))

    # Optional: foul-trouble minutes disruption.
    foul_tr = request.args.get("foul_trouble_alpha")
    if foul_tr in (None, ""):
        foul_tr = os.environ.get("CONNECTED_FOUL_TROUBLE_ALPHA")
    try:
        foul_tr_f = float(pd.to_numeric(foul_tr, errors="coerce")) if foul_tr not in (None, "") else 0.0
    except Exception:
        foul_tr_f = 0.0
    if not np.isfinite(foul_tr_f):
        foul_tr_f = 0.0
    foul_tr_f = float(max(0.0, min(1.0, foul_tr_f)))

    use_lineup = request.args.get("use_lineup")
    try:
        use_lineup_i = int(pd.to_numeric(use_lineup, errors="coerce")) if use_lineup not in (None, "") else 1
    except Exception:
        use_lineup_i = 1
    use_lineup_effects = bool(int(use_lineup_i) != 0)

    event_level = request.args.get("event_level")
    try:
        event_level_i = int(pd.to_numeric(event_level, errors="coerce")) if event_level not in (None, "") else 0
    except Exception:
        event_level_i = 0
    use_event_level = bool(int(event_level_i) != 0)

    # Fast path: memoize identical requests to keep Render responsive.
    # Cache key excludes seed when the seed is derived/stable.
    try:
        cache_key = (
            "game_story",
            "v8_mean_box",
            str(d),
            str(home_tri),
            str(away_tri),
            int(n),
            float(alpha_f),
            float(rotshock_f),
            float(corr_sc_f),
            float(foul_tr_f),
            bool(use_lineup_effects),
            bool(use_event_level),
            int(seed_i or 0),
            int(pd.to_numeric(request.args.get("minutes_lookback_days", 21), errors="coerce") or 21),
            int(pd.to_numeric(request.args.get("player_priors_lookback_days", 45), errors="coerce") or 45),
        )
        now_ts = float(time.time())
        ttl = 6 * 60 * 60
        ts0 = float(_GAME_STORY_CACHE_TS.get(cache_key) or 0.0)
        if cache_key in _GAME_STORY_CACHE and (now_ts - ts0) < ttl:
            return jsonify(_GAME_STORY_CACHE[cache_key])
    except Exception:
        cache_key = None

    try:
        pred_p = _find_predictions_for_date(d)
        if pred_p is None or (hasattr(pred_p, "exists") and not pred_p.exists()):
            return jsonify({"date": d, "error": "predictions not found"}), 404
        pdf = pd.read_csv(pred_p)
        if pdf is None or pdf.empty:
            return jsonify({"date": d, "error": "predictions empty"}), 404

        # Derive tricodes for robust matching
        def _tri(v):
            try:
                t = _get_tricode(str(v))
                return (t.upper() if isinstance(t, str) and t else str(v).strip().upper())
            except Exception:
                return str(v).strip().upper()

        pdf = pdf.copy()
        if "home_team" in pdf.columns:
            pdf["home_tri"] = pdf["home_team"].apply(_tri)
        if "visitor_team" in pdf.columns:
            pdf["away_tri"] = pdf["visitor_team"].apply(_tri)
        m = None
        try:
            m = (pdf.get("home_tri") == home_tri) & (pdf.get("away_tri") == away_tri)
        except Exception:
            m = None
        if m is None or not bool(m.any()):
            # Try reverse order just in case
            try:
                m = (pdf.get("home_tri") == away_tri) & (pdf.get("away_tri") == home_tri)
            except Exception:
                m = None
        if m is None or not bool(m.any()):
            return jsonify({"date": d, "error": "game not found in predictions", "home": home_tri, "away": away_tri}), 404
        row = pdf[m].iloc[0].to_dict()

        # Load props predictions for player baselines
        props_p = DATA_PROCESSED_DIR / f"props_predictions_{d}.csv"
        if not props_p.exists():
            _maybe_fetch_remote_processed(props_p.name)
        props_df = _read_csv_if_exists(props_p)
        if props_df is None or not isinstance(props_df, pd.DataFrame):
            props_df = pd.DataFrame()

        # Import simulator lazily
        from nba_betting.sim.quarters import TeamContext, GameInputs, simulate_quarters  # type: ignore
        from nba_betting.sim.connected_game import simulate_connected_game, write_sportswriter_recap  # type: ignore

        def _num(x):
            try:
                v = pd.to_numeric(x, errors="coerce")
                return float(v) if np.isfinite(v) else None
            except Exception:
                return None

        # Build TeamContexts; if ratings missing, derive from implied means when possible
        pred_total = _num(row.get("pred_total"))
        if pred_total is None:
            pred_total = _num(row.get("totals"))
        if pred_total is None:
            pred_total = _num(row.get("total_pred"))
        pred_margin = _num(row.get("pred_margin"))
        if pred_margin is None:
            pred_margin = _num(row.get("spread_margin"))
        if pred_margin is None:
            pred_margin = _num(row.get("margin_pred"))
        home_mu_implied = None
        away_mu_implied = None
        if pred_total is not None and pred_margin is not None:
            home_mu_implied = 0.5 * (pred_total + pred_margin)
            away_mu_implied = 0.5 * (pred_total - pred_margin)
        home_pace = _num(row.get("home_pace")) or 98.0
        away_pace = _num(row.get("away_pace")) or 98.0
        def _rating_from_mu(mu, pace):
            try:
                if mu is None:
                    return 112.0
                return float((float(mu) / max(1e-6, float(pace))) * 100.0)
            except Exception:
                return 112.0
        home_off = _num(row.get("home_off_rating")) or _rating_from_mu(home_mu_implied, home_pace)
        away_off = _num(row.get("away_off_rating")) or _rating_from_mu(away_mu_implied, away_pace)
        home_def = _num(row.get("home_def_rating")) or 112.0
        away_def = _num(row.get("away_def_rating")) or 112.0

        # Team names for context (the quarter sim uses these strings, but story uses tricodes)
        home_name = row.get("home_team") or home_tri
        away_name = row.get("visitor_team") or away_tri

        # Best-effort schedule/injury context (match api_sim_quarters)
        # Use team-aware injury exclusions to avoid mis-assigned team rows.
        try:
            name_keys, short_keys = _injury_name_sets_for_teams(d, {str(home_tri).upper(), str(away_tri).upper()})
        except Exception:
            name_keys, short_keys = (set(), set())
        try:
            roster_map = _roster_players_for_date(d)
        except Exception:
            roster_map = {}
        def _count_outs(tri: str | None) -> int:
            try:
                if not tri:
                    return 0
                names = roster_map.get(str(tri).strip().upper()) or set()
                if not names:
                    return 0
                cnt = sum(1 for n in names if (_norm_player_name(n) in name_keys or _short_player_key(n) in short_keys))
                return int(max(0, min(5, cnt)))
            except Exception:
                return 0
        h_outs = _count_outs(home_tri)
        a_outs = _count_outs(away_tri)

        # Schedule density (B2B / approximate rest days) based on previous slates.
        prev = None; prev2 = None; prev3 = None
        try:
            prev = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=1)).date().isoformat()
            prev2 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=2)).date().isoformat()
            prev3 = (pd.to_datetime(d, errors="coerce") - pd.Timedelta(days=3)).date().isoformat()
        except Exception:
            prev = None; prev2 = None; prev3 = None
        try:
            prev_teams = _get_slate_team_tricodes(prev) if prev else set()
        except Exception:
            prev_teams = set()
        try:
            prev2_teams = _get_slate_team_tricodes(prev2) if prev2 else set()
        except Exception:
            prev2_teams = set()
        try:
            prev3_teams = _get_slate_team_tricodes(prev3) if prev3 else set()
        except Exception:
            prev3_teams = set()

        def _rest_days(tri: str | None) -> int | None:
            try:
                t = str(tri or "").strip().upper()
                if not t:
                    return None
                if t in prev_teams:
                    return 0
                if t in prev2_teams:
                    return 1
                if t in prev3_teams:
                    return 2
                return 3
            except Exception:
                return None

        hb2b = bool(str(home_tri).upper() in prev_teams)
        ab2b = bool(str(away_tri).upper() in prev_teams)
        h_rest = _rest_days(home_tri)
        a_rest = _rest_days(away_tri)

        home_ctx = TeamContext(team=str(home_name), pace=float(home_pace), off_rating=float(home_off), def_rating=float(home_def),
                               injuries_out=int(h_outs), back_to_back=bool(hb2b), rest_days=h_rest)
        away_ctx = TeamContext(team=str(away_name), pace=float(away_pace), off_rating=float(away_off), def_rating=float(away_def),
                               injuries_out=int(a_outs), back_to_back=bool(ab2b), rest_days=a_rest)

        market_total = _num(row.get("total"))
        market_home_spread = _num(row.get("home_spread"))

        # If the prediction row doesn't carry market prices/lines, fall back to game_odds_<date>.csv
        try:
            need_any = any(
                _num(row.get(k)) is None
                for k in ("home_ml", "away_ml", "total", "home_spread")
            )
            if need_any:
                odds_path = _find_game_odds_for_date(d)
                if odds_path is not None and hasattr(odds_path, "exists") and odds_path.exists():
                    odf = pd.read_csv(odds_path)
                    if isinstance(odf, pd.DataFrame) and not odf.empty:
                        # Match by tricodes (robust to odds file using full names)
                        if ("home_team" in odf.columns) and ("visitor_team" in odf.columns):
                            odf = odf.copy()
                            try:
                                from nba_betting.teams import to_tricode as _to_tri  # type: ignore
                            except Exception:
                                _to_tri = None
                            if _to_tri is not None:
                                odf["home_tri"] = odf["home_team"].astype(str).map(lambda x: _to_tri(str(x)))
                                odf["visitor_tri"] = odf["visitor_team"].astype(str).map(lambda x: _to_tri(str(x)))
                            else:
                                odf["home_tri"] = odf["home_team"].astype(str).str.strip().str.upper()
                                odf["visitor_tri"] = odf["visitor_team"].astype(str).str.strip().str.upper()
                            mm = (odf["home_tri"] == home_tri) & (odf["visitor_tri"] == away_tri)
                            if not bool(mm.any()):
                                mm = (odf["home_tri"] == away_tri) & (odf["visitor_tri"] == home_tri)
                            if bool(mm.any()):
                                o = odf[mm].iloc[0].to_dict()
                                # Fill missing fields only
                                for k in (
                                    "home_ml",
                                    "away_ml",
                                    "total",
                                    "home_spread",
                                    "away_spread",
                                    "home_spread_price",
                                    "away_spread_price",
                                    "total_over_price",
                                    "total_under_price",
                                    "bookmaker",
                                ):
                                    if _num(row.get(k)) is None and _num(o.get(k)) is not None:
                                        row[k] = o.get(k)

                                # Recompute market fields if they were missing
                                market_total = _num(row.get("total"))
                                market_home_spread = _num(row.get("home_spread"))
        except Exception:
            pass

        inp = GameInputs(date=str(d), home=home_ctx, away=away_ctx, market_total=market_total, market_home_spread=market_home_spread)
        summary = simulate_quarters(inp, n_samples=min(3000, max(1200, n)))

        # Build real-player rotation hints from roster + recent boxscores minutes.
        try:
            roster_map = _roster_players_for_date(str(d))
        except Exception:
            roster_map = {}
        home_roster = sorted(list(roster_map.get(str(home_tri).upper(), set()) or []))
        away_roster = sorted(list(roster_map.get(str(away_tri).upper(), set()) or []))

        # If we're simulating a game-day slate and the processed roster is missing/stale,
        # prefer a live roster to avoid including players who are no longer on the team.
        try:
            req_dt = datetime.strptime(str(d), "%Y-%m-%d").date()
            today_utc = datetime.utcnow().date()
            is_game_day = req_dt >= (today_utc - timedelta(days=1))
        except Exception:
            is_game_day = True
        if is_game_day:
            try:
                h_live = _team_roster_names_via_nba_api(str(d), str(home_tri))
                if isinstance(h_live, list) and int(len(h_live)) >= 10:
                    home_roster = h_live
            except Exception:
                pass
            try:
                a_live = _team_roster_names_via_nba_api(str(d), str(away_tri))
                if isinstance(a_live, list) and int(len(a_live)) >= 10:
                    away_roster = a_live
            except Exception:
                pass

        # Build injury designation lists for UI transparency (before removing out players).
        try:
            inj_home_roster = None
            inj_away_roster = None
            try:
                h_live2 = _team_roster_names_via_nba_api(str(d), str(home_tri))
                if isinstance(h_live2, list) and len(h_live2) >= 10:
                    inj_home_roster = h_live2
            except Exception:
                inj_home_roster = None
            try:
                a_live2 = _team_roster_names_via_nba_api(str(d), str(away_tri))
                if isinstance(a_live2, list) and len(a_live2) >= 10:
                    inj_away_roster = a_live2
            except Exception:
                inj_away_roster = None
            injuries_payload = _injury_designations_for_matchup(
                str(d),
                home_tri=str(home_tri),
                away_tri=str(away_tri),
                home_roster=list(inj_home_roster or home_roster),
                away_roster=list(inj_away_roster or away_roster),
            )
        except Exception:
            injuries_payload = {"home": [], "away": []}

        # Remove injured/out players from the connected-sim rotation.
        # We already computed (name_keys, short_keys) for this date.
        try:
            def _is_out_player(nm: str) -> bool:
                try:
                    return (_norm_player_name(nm) in name_keys) or (_short_player_key(nm) in short_keys)
                except Exception:
                    return False

            home_roster = [n for n in home_roster if not _is_out_player(str(n))]
            away_roster = [n for n in away_roster if not _is_out_player(str(n))]
        except Exception:
            pass
        # Priors lookbacks (tunable). Longer windows stabilize per-minute rates.
        try:
            minutes_lookback_days = int(pd.to_numeric(request.args.get("minutes_lookback_days", 21), errors="coerce"))
        except Exception:
            minutes_lookback_days = 21
        try:
            player_priors_lookback_days = int(pd.to_numeric(request.args.get("player_priors_lookback_days", 45), errors="coerce"))
        except Exception:
            player_priors_lookback_days = 45
        minutes_lookback_days = int(max(7, min(120, minutes_lookback_days)))
        player_priors_lookback_days = int(max(14, min(180, player_priors_lookback_days)))

        minutes_priors = _compute_player_minutes_priors(str(d), days_back=minutes_lookback_days)
        player_priors = _compute_player_stat_priors(str(d), days_back=player_priors_lookback_days)

        # Compute a UI-consistent blend line (matches web/app.js):
        # alpha*prediction_model_quarters + (1-alpha)*quarter_sim_means
        def _q_model(i: int) -> Optional[Dict[str, Any]]:
            try:
                tot = _num(row.get(f"quarters_q{i}_total"))
                if tot is None:
                    tot = _num(row.get(f"q{i}_total"))
                mar = _num(row.get(f"quarters_q{i}_margin"))
                if mar is None:
                    mar = _num(row.get(f"q{i}_margin"))
                if tot is None or mar is None:
                    return None
                return {"q": i, "home": 0.5 * (float(tot) + float(mar)), "away": 0.5 * (float(tot) - float(mar))}
            except Exception:
                return None

        model_quarters = [q for q in (_q_model(1), _q_model(2), _q_model(3), _q_model(4)) if isinstance(q, dict)]
        model_by_q = {int(r.get("q") or 0): r for r in model_quarters if isinstance(r, dict)}

        sim_quarters = []
        try:
            for qq in (summary.quarters or []):
                sim_quarters.append({
                    "q": int(getattr(qq, "q", 0) or 0),
                    "home": float(getattr(qq, "home_pts_mu", 0.0) or 0.0),
                    "away": float(getattr(qq, "away_pts_mu", 0.0) or 0.0),
                })
        except Exception:
            sim_quarters = []
        sim_by_q = {int(r.get("q") or 0): r for r in sim_quarters if isinstance(r, dict)}

        blend_quarters = []
        for qi in (1, 2, 3, 4):
            mrow = model_by_q.get(qi) or {}
            srow = sim_by_q.get(qi) or {}
            hm = _num(mrow.get("home"))
            am = _num(mrow.get("away"))
            hs = _num(srow.get("home"))
            as_ = _num(srow.get("away"))
            hb = (alpha_f * hm + (1.0 - alpha_f) * hs) if (hm is not None and hs is not None) else (hm if hm is not None else hs)
            ab = (alpha_f * am + (1.0 - alpha_f) * as_) if (am is not None and as_ is not None) else (am if am is not None else as_)
            blend_quarters.append({"q": qi, "home": float(hb or 0.0), "away": float(ab or 0.0)})

        def _sum_side(rows, k):
            try:
                xs = [float((r or {}).get(k) or 0.0) for r in (rows or [])]
                return float(np.sum(xs))
            except Exception:
                return 0.0

        model_home_score = _sum_side(model_quarters, "home")
        model_away_score = _sum_side(model_quarters, "away")
        blend_home_score = _sum_side(blend_quarters, "home")
        blend_away_score = _sum_side(blend_quarters, "away")

        blend_payload = {
            "alpha": alpha_f,
            "quarters": blend_quarters,
            "home_score": blend_home_score,
            "away_score": blend_away_score,
            "total": blend_home_score + blend_away_score,
            "margin": blend_home_score - blend_away_score,
        }
        model_payload = {
            "quarters": model_quarters,
            "home_score": model_home_score,
            "away_score": model_away_score,
            "total": model_home_score + model_away_score,
            "margin": model_home_score - model_away_score,
        }

        # Optional model guardrails for connected sim (default OFF).
        # These do NOT replace the blend target line; they only softly anchor
        # the sampled quarter scoring environment to model priors.
        gr_alpha = 0.0
        try:
            s = request.args.get("guardrail_alpha")
            if s is None or s == "":
                s = os.environ.get("CONNECTED_GUARDRAIL_ALPHA")
            gr_alpha = float(s) if s not in (None, "") else 0.0
        except Exception:
            gr_alpha = 0.0
        gr_max_scale = 0.10
        try:
            s = request.args.get("guardrail_max_scale")
            if s is None or s == "":
                s = os.environ.get("CONNECTED_GUARDRAIL_MAX_SCALE")
            gr_max_scale = float(s) if s not in (None, "") else 0.10
        except Exception:
            gr_max_scale = 0.10

        priors: dict[str, Any] = {}
        try:
            if pred_total is not None:
                priors["pred_total"] = float(pred_total)
            if pred_margin is not None:
                priors["pred_margin"] = float(pred_margin)
            p_home = _num(row.get("home_win_prob"))
            if p_home is not None:
                priors["home_win_prob"] = float(p_home)
            # Period priors (quarters) when present in predictions.
            for qi in (1, 2, 3, 4):
                qt = _num(row.get(f"quarters_q{qi}_total"))
                qm = _num(row.get(f"quarters_q{qi}_margin"))
                qw = _num(row.get(f"quarters_q{qi}_win"))
                if qt is not None:
                    priors[f"quarters_q{qi}_total"] = float(qt)
                if qm is not None:
                    priors[f"quarters_q{qi}_margin"] = float(qm)
                if qw is not None:
                    priors[f"quarters_q{qi}_win"] = float(qw)
        except Exception:
            priors = {}

        # Connected sim for player box scores (representative sample aligned to the blend line).
        sim = simulate_connected_game(
            summary.quarters,
            home_tri=home_tri,
            away_tri=away_tri,
            props_df=props_df,
            home_roster=home_roster,
            away_roster=away_roster,
            minutes_priors=minutes_priors,
            player_priors=player_priors,
            n_samples=n,
            seed=seed_i,
            target_quarters=blend_quarters,
            target_home_score=blend_home_score,
            target_away_score=blend_away_score,
            date_str=d,
            use_lineup_teammate_effects=use_lineup_effects,
            use_event_level_sim=use_event_level,
            rotation_shock_alpha=float(rotshock_f),
            correlated_scoring_alpha=float(corr_sc_f),
            foul_trouble_alpha=float(foul_tr_f),
            guardrail_priors=priors,
            guardrail_alpha=float(gr_alpha or 0.0),
            guardrail_max_scale=float(gr_max_scale if gr_max_scale is not None else 0.10),
        )

        recap = write_sportswriter_recap(
            sim,
            market_total=market_total,
            market_home_spread=market_home_spread,
            # Narrate aggregate outcomes (means) so the recap aligns with the
            # aggregate (mean) connected box score displayed in the UI.
            use_means=True,
            probs=getattr(summary, "probs", None),
        )

        # --- Connect to recommendations + props edges engines ---
        game_recs: list[dict[str, Any]] = []
        try:
            # ML
            p_home = _num(row.get("home_win_prob"))
            if p_home is not None:
                try:
                    # Apply same calibration as /api/recommendations when available
                    # (Inlined minimal version: use games_prob_calibration.json if present)
                    fp = DATA_PROCESSED_DIR / "games_prob_calibration.json"
                    if fp.exists():
                        with open(fp, "r", encoding="utf-8") as fh:
                            cmap = json.load(fh)
                        xs = cmap.get("x") or []
                        ys = cmap.get("y") or []
                        pv = max(0.0, min(1.0, float(p_home)))
                        if isinstance(xs, list) and isinstance(ys, list) and len(xs) >= 2 and len(xs) == len(ys):
                            if pv <= float(xs[0]):
                                p_home = float(ys[0])
                            elif pv >= float(xs[-1]):
                                p_home = float(ys[-1])
                            else:
                                for i in range(len(xs) - 1):
                                    x0 = float(xs[i]); x1 = float(xs[i+1])
                                    if x0 <= pv <= x1:
                                        y0 = float(ys[i]); y1 = float(ys[i+1])
                                        t = 0.0 if x1 == x0 else (pv - x0) / (x1 - x0)
                                        p_home = (1.0 - t) * y0 + t * y1
                                        break
                except Exception:
                    pass
            ev_h = _ev_from_prob_and_american(p_home, row.get("home_ml")) if p_home is not None else None
            ev_a = _ev_from_prob_and_american(None if p_home is None else (1 - p_home), row.get("away_ml"))
            if ev_h is not None or ev_a is not None:
                side = home_tri if (ev_h or -1) >= (ev_a or -1) else away_tri
                ev = ev_h if side == home_tri else ev_a
                if ev is not None and float(ev) > 0:
                    price = _num(row.get("home_ml")) if side == home_tri else _num(row.get("away_ml"))
                    implied = _implied_prob_american(price) if price is not None else None
                    game_recs.append({
                        "market": "ML",
                        "side": side,
                        "ev": float(ev),
                        "price": price,
                        "implied_prob": (float(implied) if implied is not None else None),
                    })

            # ATS
            pred_m = _num(row.get("pred_margin"))
            if pred_m is None:
                pred_m = _num(row.get("spread_margin"))
            home_spread = _num(row.get("home_spread"))
            if pred_m is not None and home_spread is not None:
                market_home_margin = -home_spread
                edge = float(pred_m - market_home_margin)
                if abs(edge) >= 1.0:
                    side = home_tri if edge > 0 else away_tri
                    line = float(home_spread if side == home_tri else -home_spread)
                    game_recs.append({
                        "market": "ATS",
                        "side": side,
                        "edge": edge,
                        "line": line,
                        "pred_margin": float(pred_m),
                        "market_home_margin": float(market_home_margin),
                    })

            # TOTAL
            pred_t = _num(row.get("pred_total"))
            if pred_t is None:
                pred_t = _num(row.get("totals"))
            total_line = _num(row.get("total"))
            if pred_t is not None and total_line is not None:
                edge_t = float(pred_t - total_line)
                if abs(edge_t) >= 1.5:
                    side = "Over" if edge_t > 0 else "Under"
                    game_recs.append({
                        "market": "TOTAL",
                        "side": side,
                        "edge": edge_t,
                        "line": float(total_line),
                        "pred_total": float(pred_t),
                    })
        except Exception:
            game_recs = []

        # Props edges (OddsAPI) filtered to this matchup and (optionally) to players in the connected box
        props_payload: dict[str, Any] = {"edges": [], "recommendations": []}
        try:
            rep_players = []
            try:
                rep = (sim or {}).get("rep") or {}
                for p in ((rep.get("home_box") or {}).get("players") or []):
                    rep_players.append(str(p.get("player_name") or ""))
                for p in ((rep.get("away_box") or {}).get("players") or []):
                    rep_players.append(str(p.get("player_name") or ""))
            except Exception:
                rep_players = []
            rep_keys = set(_norm_player_name(x) for x in rep_players if x and "Replacement" not in str(x))

            edges_p = DATA_PROCESSED_DIR / f"props_edges_{d}.csv"
            if edges_p.exists():
                edf = pd.read_csv(edges_p)
                if isinstance(edf, pd.DataFrame) and not edf.empty:
                    def _tri_name(x: Any) -> str:
                        try:
                            t = _get_tricode(str(x))
                            return (t or str(x)).strip().upper()
                        except Exception:
                            return str(x).strip().upper()
                    if "home_team" in edf.columns and "away_team" in edf.columns:
                        edf = edf.copy()
                        edf["home_tri"] = edf["home_team"].apply(_tri_name)
                        edf["away_tri"] = edf["away_team"].apply(_tri_name)
                        edf = edf[(edf["home_tri"] == home_tri) & (edf["away_tri"] == away_tri) | ((edf["home_tri"] == away_tri) & (edf["away_tri"] == home_tri))]
                    else:
                        # fallback: use team only
                        if "team" in edf.columns:
                            edf = edf[edf["team"].astype(str).str.upper().isin([home_tri, away_tri])]
                    if rep_keys and "player_name" in edf.columns:
                        edf = edf[edf["player_name"].astype(str).map(_norm_player_name).isin(rep_keys)]
                    # Sort by EV then edge
                    if "ev" in edf.columns:
                        edf = edf.sort_values(["ev", "edge"], ascending=[False, False])
                    props_payload["edges"] = edf.head(25).fillna("").to_dict(orient="records")
        except Exception:
            pass

        # Props recommendations (derived from edges) filtered to teams in this matchup
        try:
            import ast as _ast
            pr_p = DATA_PROCESSED_DIR / f"props_recommendations_{d}.csv"
            if pr_p.exists():
                pr = pd.read_csv(pr_p)
                if isinstance(pr, pd.DataFrame) and not pr.empty:
                    pr = pr.copy()
                    if "team" in pr.columns:
                        pr["team"] = pr["team"].astype(str).str.upper().str.strip()
                        pr = pr[pr["team"].isin([home_tri, away_tri])]
                    def _canonical_standard_plays(plays: Any) -> list[dict]:
                        try:
                            if not isinstance(plays, list) or not plays:
                                return []
                            out: list[dict] = []
                            buckets: dict[tuple[str, str], list[dict]] = {}
                            for p in plays:
                                if not isinstance(p, dict):
                                    continue
                                mk = str(p.get("market") or "").strip().lower()
                                sd = str(p.get("side") or "").strip().upper()
                                if not mk or not sd:
                                    continue
                                try:
                                    ln = float(p.get("line"))
                                except Exception:
                                    continue
                                buckets.setdefault((mk, sd), []).append(p)
                            def _ev_key(pp: dict) -> float:
                                try:
                                    if pp.get("ev_pct") is not None and not pd.isna(pp.get("ev_pct")):
                                        return float(pp.get("ev_pct"))
                                except Exception:
                                    pass
                                try:
                                    if pp.get("ev") is not None and not pd.isna(pp.get("ev")):
                                        return float(pp.get("ev")) * 100.0
                                except Exception:
                                    pass
                                return -1e18

                            for (mk, sd), ps in buckets.items():
                                counts: dict[float, int] = {}
                                for pp in ps:
                                    try:
                                        ln = float(pp.get("line"))
                                    except Exception:
                                        continue
                                    counts[ln] = counts.get(ln, 0) + 1
                                if not counts:
                                    continue
                                max_n = max(counts.values())
                                mode_lines = sorted([ln for ln, n in counts.items() if n == max_n])
                                std_line = mode_lines[len(mode_lines) // 2]
                                cand = [pp for pp in ps if (pp.get("line") is not None and float(pp.get("line")) == float(std_line))]
                                if not cand:
                                    cand = ps
                                cand.sort(key=_ev_key, reverse=True)
                                out.append(cand[0])
                            out.sort(key=_ev_key, reverse=True)
                            return out
                        except Exception:
                            return []
                    out_rows = []
                    for _, rr in pr.iterrows():
                        player = str(rr.get("player") or rr.get("player_name") or "").strip()
                        if not player:
                            continue
                        if rep_keys and (_norm_player_name(player) not in rep_keys):
                            continue
                        plays_raw = rr.get("plays")
                        ladders_raw = rr.get("ladders")
                        try:
                            plays = _ast.literal_eval(plays_raw) if isinstance(plays_raw, str) and plays_raw.strip().startswith("[") else []
                        except Exception:
                            plays = []
                        try:
                            ladders = _ast.literal_eval(ladders_raw) if isinstance(ladders_raw, str) and ladders_raw.strip().startswith("[") else []
                        except Exception:
                            ladders = []
                        plays = _canonical_standard_plays(plays)
                        # Keep top plays by EV%
                        def _evpct(x: Any) -> float:
                            try:
                                return float(x.get("ev_pct"))
                            except Exception:
                                return -1e9
                        if isinstance(plays, list):
                            plays = sorted([p for p in plays if isinstance(p, dict)], key=_evpct, reverse=True)[:12]
                        if isinstance(ladders, list):
                            ladders = sorted([p for p in ladders if isinstance(p, dict)], key=_evpct, reverse=True)[:12]
                        out_rows.append({
                            "player": player,
                            "team": str(rr.get("team") or "").strip().upper(),
                            "plays": plays,
                            "ladders": ladders,
                        })
                    props_payload["recommendations"] = out_rows
        except Exception:
            pass

        # Period (halves/quarters) predictions from the main predictions row, if present.
        # These come from trained period models and are helpful for quarter-by-quarter
        # winner probabilities (separate from mean points).
        periods_pred: dict[str, Any] | None = None
        try:
            pred_home_tri = str(row.get("home_tri") or "").strip().upper()
            pred_away_tri = str(row.get("away_tri") or "").strip().upper()
            quarters_pred: list[dict[str, Any]] = []
            for i in range(1, 5):
                quarters_pred.append(
                    {
                        "q": i,
                        "p_home_win": _num(row.get(f"quarters_q{i}_win")),
                        "home_margin": _num(row.get(f"quarters_q{i}_margin")),
                        "total": _num(row.get(f"quarters_q{i}_total")),
                    }
                )
            halves_pred: list[dict[str, Any]] = []
            for i in range(1, 3):
                halves_pred.append(
                    {
                        "h": i,
                        "p_home_win": _num(row.get(f"halves_h{i}_win")),
                        "home_margin": _num(row.get(f"halves_h{i}_margin")),
                        "total": _num(row.get(f"halves_h{i}_total")),
                    }
                )
            periods_pred = {
                "home": pred_home_tri,
                "away": pred_away_tri,
                "quarters": quarters_pred,
                "halves": halves_pred,
            }
        except Exception:
            periods_pred = None

        # Quarter win probabilities implied by the quarter simulator distributions.
        sim_quarters: list[dict[str, Any]] = []
        try:
            import math

            def _norm_sf(x: float, mu: float, sigma: float) -> float:
                try:
                    return 0.5 * math.erfc((x - mu) / (sigma * math.sqrt(2.0)))
                except Exception:
                    return 0.5

            for qq in getattr(summary, "quarters", []) or []:
                try:
                    mu_margin_q = float(qq.home_pts_mu - qq.away_pts_mu)
                    var_h = float(qq.home_pts_sigma ** 2)
                    var_a = float(qq.away_pts_sigma ** 2)
                    cov = float((qq.corr or 0.0) * qq.home_pts_sigma * qq.away_pts_sigma)
                    sigma_margin_q = float(math.sqrt(max(1e-6, var_h + var_a - 2.0 * cov)))
                    p_home_win_q = float(_norm_sf(0.0, mu_margin_q, sigma_margin_q))
                    sim_quarters.append(
                        {
                            "q": int(getattr(qq, "q", 0) or 0),
                            "p_home_win": p_home_win_q,
                            "mu_margin": mu_margin_q,
                            "sigma_margin": sigma_margin_q,
                        }
                    )
                except Exception:
                    continue
        except Exception:
            sim_quarters = []

        payload_out = {
            "date": d,
            "home": home_tri,
            "away": away_tri,
            "market": {"total": market_total, "home_spread": market_home_spread},
            "model": model_payload,
            "blend": blend_payload,
            "periods": {
                "pred": periods_pred,
                "sim": {"quarters": sim_quarters},
            },
            "summary": {
                "probs": getattr(summary, "probs", None),
                "evs": getattr(summary, "evs", None),
                "final_total_mu": getattr(summary, "final_total_mu", None),
                "final_margin_mu": getattr(summary, "final_margin_mu", None),
            },
            "injuries": injuries_payload,
            "game_recommendations": game_recs,
            "props": props_payload,
            "sim": sim,
            "recap": recap,
        }

        try:
            if cache_key is not None:
                _GAME_STORY_CACHE[cache_key] = payload_out
                _GAME_STORY_CACHE_TS[cache_key] = float(time.time())
                # Bound cache size (best-effort)
                try:
                    if int(len(_GAME_STORY_CACHE_TS)) > 128:
                        oldest = sorted(_GAME_STORY_CACHE_TS.items(), key=lambda kv: float(kv[1]))[:32]
                        for k, _ in oldest:
                            _GAME_STORY_CACHE_TS.pop(k, None)
                            _GAME_STORY_CACHE.pop(k, None)
                except Exception:
                    pass
        except Exception:
            pass

        return jsonify(payload_out)
    except Exception as e:
        return jsonify({"date": d, "home": home_tri, "away": away_tri, "error": str(e)}), 500


@app.route("/api/cron/refresh-bovada", methods=["POST", "GET"])
def api_cron_refresh_bovada():
    """Fetch current Bovada odds for a specific date and save a standardized CSV under data/processed.

    Query params:
      - date (required): YYYY-MM-DD
    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback if CRON_TOKEN unset).
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=False)
    if not d:
        # Default to yesterday (UTC) for closing lines capture
        d = (datetime.utcnow().date() - timedelta(days=1)).isoformat()
    if _fetch_bovada_odds_current is None:
        try:
            _cron_meta_update("refresh_bovada", {"date": d, "ok": False, "error": "bovada fetcher not available"})
        except Exception:
            pass
        # Render cron: avoid non-2xx for operational conditions
        return jsonify({"date": d, "ok": False, "error": "bovada fetcher not available"}), 200
    # Pass date string directly; function treats as ET calendar date
    try:
        _ = pd.to_datetime(d)
    except Exception:
        return jsonify({"error": "invalid date"}), 400
    try:
        df = _fetch_bovada_odds_current(d)
        rows = 0 if df is None else len(df)
        out = DATA_PROCESSED_DIR / f"game_odds_{d}.csv"
        out_periods = DATA_PROCESSED_DIR / f"period_lines_{d}.csv"
        used_fallback = False
        fallback_path = None
        # For props: we'll attempt to fetch Bovada player props and compute edges if present
        props_raw_rows = 0
        props_raw_path = None
        props_edges_rows = 0
        props_edges_path = None
        if df is not None and not df.empty:
            out.parent.mkdir(parents=True, exist_ok=True)
            df.to_csv(out, index=False)
            # Best-effort: also save quarter/half lines if Bovada exposes them
            try:
                from nba_betting.odds_bovada import fetch_bovada_period_lines_current as _fbplc  # type: ignore
                pl = _fbplc(d)
                if pl is not None and not pl.empty:
                    out_periods.parent.mkdir(parents=True, exist_ok=True)
                    pl.to_csv(out_periods, index=False)
            except Exception:
                pass
        else:
            # Try fallback to consensus/closing lines if Bovada has nothing
            fb = _find_fallback_odds_for_date(d)
            if fb is not None:
                try:
                    o = pd.read_csv(fb)
                    if not o.empty:
                        out.parent.mkdir(parents=True, exist_ok=True)
                        o.to_csv(out, index=False)
                        rows = int(len(o))
                        used_fallback = True
                        fallback_path = str(fb)
                except Exception:
                    pass
        # Attempt Bovada player props for this date and run props-edges if any lines found
        try:
            if _fetch_bovada_player_props_current is not None:  # type: ignore[name-defined]
                props_df = _fetch_bovada_player_props_current(d)
            else:
                try:
                    from nba_betting.odds_bovada import fetch_bovada_player_props_current as _fbppc  # type: ignore
                    props_df = _fbppc(d)
                except Exception:
                    props_df = None
            if props_df is not None and not props_df.empty:
                raw_dir = DATA_RAW_DIR
                raw_dir.mkdir(parents=True, exist_ok=True)
                props_raw = raw_dir / f"odds_bovada_player_props_{d}.csv"
                try:
                    props_df.to_csv(props_raw, index=False)
                    props_raw_rows = int(len(props_df))
                    props_raw_path = str(props_raw)
                except Exception:
                    pass
                # Compute props edges from Bovada source for this date
                try:
                    # Choose python executable
                    py = os.environ.get("PYTHON", (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python")
                    if not py or not Path(str(py)).exists():
                        py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
                        py = str(py_win) if py_win.exists() else "python"
                    env = dict(os.environ)
                    env["PYTHONPATH"] = str(SRC_DIR)
                    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
                    log_file = logs_dir / f"cron_props_edges_from_bovada_{d}_{stamp}.log"
                    # Compute props edges without running models server-side
                    _ = _run_to_file([str(py), "-m", "nba_betting.cli", "props-edges", "--date", d, "--source", "bovada", "--no-use-saved", "--file-only"], log_file, cwd=BASE_DIR, env=env)
                    pe = DATA_PROCESSED_DIR / f"props_edges_{d}.csv"
                    if pe.exists():
                        try:
                            props_edges_rows = int(len(pd.read_csv(pe)))
                            props_edges_path = str(pe)
                        except Exception:
                            props_edges_rows = 0
                except Exception:
                    pass
        except Exception:
            pass
        # Record cron meta best-effort
        try:
            meta = {
                "date": d,
                "rows": int(rows),
                "output": str(out),
            }
            if used_fallback:
                meta.update({"used_fallback": True, "fallback_path": fallback_path})
            if props_raw_path:
                meta.update({"props_raw_rows": int(props_raw_rows), "props_raw_path": props_raw_path})
            if props_edges_path:
                meta.update({"props_edges_rows": int(props_edges_rows), "props_edges_path": props_edges_path})
            _cron_meta_update("refresh_bovada", meta)
        except Exception:
            pass
        # Optional push
        pushed = None; push_detail = None
        if str(request.args.get("push", "0")).lower() in {"1","true","yes"}:
            ok, detail = _git_commit_and_push(msg=f"refresh-bovada {d}")
            pushed = bool(ok); push_detail = detail
        return jsonify({
            "date": d, "rows": int(rows), "output": str(out),
            "used_fallback": used_fallback, "fallback_path": fallback_path,
            "props_raw_rows": int(props_raw_rows), "props_raw_path": props_raw_path,
            "props_edges_rows": int(props_edges_rows), "props_edges_path": props_edges_path,
            "pushed": pushed, "push_detail": push_detail,
        })
    except Exception as e:
        # Render cron: avoid non-2xx for operational conditions
        try:
            _cron_meta_update("refresh_bovada", {"date": d, "ok": False, "error": f"bovada fetch failed: {e}"})
        except Exception:
            pass
        return jsonify({"date": d, "ok": False, "error": f"bovada fetch failed: {e}"}), 200


@app.route("/api/cron/refresh-oddsapi-props", methods=["POST", "GET"])
def api_cron_refresh_oddsapi_props():
    """Fetch current OddsAPI player props for a given date and persist under data/raw.

    Query params:
    - date (optional): YYYY-MM-DD (defaults to the current US local slate date)
      - regions (optional): OddsAPI regions (default 'us')
            - bookmakers (optional): comma-separated bookmaker ids; default FanDuel,DraftKings,BetMGM,bet365
      - markets (optional): comma-separated market keys; default uses our full player_* list
      - edges (optional): '1' to run props-edges from OddsAPI after snapshot
      - export (optional): '1' to run export-props-recommendations after edges
      - push (optional): '1' to git commit/push artifacts

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    Writes:
      - data/raw/odds_nba_player_props_<date>.csv (via CLI odds-snapshots-props)
      - data/processed/props_edges_<date>.csv (optional, via CLI)
      - data/processed/props_recommendations_<date>.csv (optional, via CLI)
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=True)
    regions = (request.args.get("regions") or "us").strip() or "us"
    bookmakers = ",".join(_player_prop_bookmakers_tuple(request.args.get("bookmakers"), env_name="PLAYER_PROP_BOOKMAKERS"))
    markets = (request.args.get("markets") or "").strip()
    do_edges = (str(request.args.get("edges", "0")).lower() in {"1", "true", "yes"})
    do_export = (str(request.args.get("export", "0")).lower() in {"1", "true", "yes"})
    do_push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})

    # Render/gunicorn proxies may time out long requests, presenting as HTTP 502.
    # Default to async execution when heavy work is requested.
    force_sync = (str(request.args.get("sync", "0")).lower() in {"1", "true", "yes"})
    use_async = (not force_sync) and (do_edges or do_export)

    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    try:
        log_file = logs_dir / f"cron_refresh_oddsapi_props_{d}_{stamp}.log"
    except Exception:
        # Extremely defensive fallback: ensure we can still run without logging.
        log_file = Path("/tmp") / f"cron_refresh_oddsapi_props_{d}_{stamp}.log"
    try:
        # Fast preflight: if OddsAPI key is missing, treat as a clean no-op.
        api_key = (os.environ.get("ODDS_API_KEY") or os.environ.get("THE_ODDS_API_KEY") or "").strip()
        if not api_key:
            return jsonify({
                "date": d,
                "regions": regions,
                "bookmakers": (bookmakers or None),
                "markets": markets,
                "skipped": True,
                "reason": "missing ODDS_API_KEY",
                "log_file": str(log_file),
            }), 200

        if use_async:
            active_refresh_meta = _load_refresh_oddsapi_props_meta(persist_stale=True)
            if _oddsapi_props_job_state.get("running") or bool(active_refresh_meta.get("running")):
                active_started_at = active_refresh_meta.get("started_at") if active_refresh_meta.get("running") else _oddsapi_props_job_state.get("started_at")
                active_log_file = active_refresh_meta.get("log_file") if active_refresh_meta.get("running") else _oddsapi_props_job_state.get("log_file")
                active_last = {
                    "date": active_refresh_meta.get("date"),
                    "regions": active_refresh_meta.get("regions"),
                    "bookmakers": active_refresh_meta.get("bookmakers"),
                    "markets": active_refresh_meta.get("markets"),
                    "edges": active_refresh_meta.get("run_edges"),
                    "export": active_refresh_meta.get("run_export"),
                    "push": active_refresh_meta.get("run_push"),
                } if active_refresh_meta.get("running") else _oddsapi_props_job_state.get("last")
                return jsonify({
                    "status": "already-running",
                    "async": True,
                    "started_at": active_started_at,
                    "log_file": active_log_file,
                    "last": active_last,
                    "note": "A refresh job is already running; skipping new start.",
                }), 202

            queued_started_at = datetime.utcnow().isoformat()
            _prime_oddsapi_props_job_state(
                date_str=d,
                regions=regions,
                bookmakers=bookmakers,
                markets=markets,
                do_edges=bool(do_edges),
                do_export=bool(do_export),
                do_push=bool(do_push),
                log_file=log_file,
                running=True,
                started_at=queued_started_at,
            )

            try:
                _cron_meta_update(
                    "refresh_oddsapi_props",
                    {
                        "date": d,
                        "regions": regions,
                        "bookmakers": (bookmakers or None),
                        "markets": markets,
                        "run_edges": bool(do_edges),
                        "run_export": bool(do_export),
                        "run_push": bool(do_push),
                        "running": True,
                        "ok": None,
                        "log_file": str(log_file),
                        "started_at": queued_started_at,
                        "ended_at": None,
                        "phase": _oddsapi_props_job_state.get("phase"),
                        "phase_started_at": _oddsapi_props_job_state.get("phase_started_at"),
                        "heartbeat_at": _oddsapi_props_job_state.get("heartbeat_at"),
                        "rc_snapshot": _oddsapi_props_job_state.get("rc_snapshot"),
                        "rc_edges": _oddsapi_props_job_state.get("rc_edges"),
                        "rc_export": _oddsapi_props_job_state.get("rc_export"),
                        "snapshot_rows": _oddsapi_props_job_state.get("snapshot_rows"),
                        "edges_rows": _oddsapi_props_job_state.get("edges_rows"),
                        "recs_rows": _oddsapi_props_job_state.get("recs_rows"),
                        "snapshot": _oddsapi_props_job_state.get("snapshot_path"),
                        "edges": _oddsapi_props_job_state.get("edges_path"),
                        "recs": _oddsapi_props_job_state.get("recs_path"),
                        "duration_s": None,
                    },
                )
            except Exception:
                pass

            launched, launch_error, launch_mode = _launch_refresh_oddsapi_props_background(
                date_str=d,
                regions=regions,
                bookmakers=bookmakers,
                markets=markets,
                do_edges=bool(do_edges),
                do_export=bool(do_export),
                do_push=bool(do_push),
                log_file=Path(log_file),
                started_at=queued_started_at,
            )
            if not launched:
                ended_at = datetime.utcnow().isoformat()
                _reset_oddsapi_props_job_state()
                try:
                    _cron_meta_update(
                        "refresh_oddsapi_props",
                        {
                            "date": d,
                            "regions": regions,
                            "bookmakers": (bookmakers or None),
                            "markets": markets,
                            "run_edges": bool(do_edges),
                            "run_export": bool(do_export),
                            "run_push": bool(do_push),
                            "running": False,
                            "ok": False,
                            "error": f"DetachedStartError: {launch_error}",
                            "log_file": str(log_file),
                            "started_at": queued_started_at,
                            "ended_at": ended_at,
                        },
                    )
                except Exception:
                    pass
                return jsonify({
                    "error": f"failed to start async refresh job: {launch_error}",
                    "date": d,
                    "log_file": str(log_file),
                }), 500

            _reset_oddsapi_props_job_state()

            # Accept quickly so schedulers don't fail due to timeouts.
            return jsonify({
                "status": "started",
                "async": True,
                "date": d,
                "regions": regions,
                "bookmakers": (bookmakers or None),
                "markets": markets,
                "edges": bool(do_edges),
                "export": bool(do_export),
                "push": bool(do_push),
                "launch_mode": launch_mode,
                "started_at": queued_started_at,
                "log_file": str(log_file),
                "note": "Running in background to avoid request timeouts; check artifacts/logs later.",
            }), 202

        py = _resolve_python()
        env = dict(os.environ)
        env["PYTHONPATH"] = str(SRC_DIR)

        # Report file locations via nba_betting.config.paths (supports NBA_BETTING_DATA_ROOT)
        try:
            from nba_betting.config import paths as _paths  # type: ignore
            raw_fp = _paths.data_raw / f"odds_nba_player_props_{d}.csv"
            pred_fp = _paths.data_processed / f"props_predictions_{d}.csv"
            edges_fp = _paths.data_processed / f"props_edges_{d}.csv"
            rec_fp = _paths.data_processed / f"props_recommendations_{d}.csv"
        except Exception:
            raw_fp = DATA_RAW_DIR / f"odds_nba_player_props_{d}.csv"
            pred_fp = DATA_PROCESSED_DIR / f"props_predictions_{d}.csv"
            edges_fp = DATA_PROCESSED_DIR / f"props_edges_{d}.csv"
            rec_fp = DATA_PROCESSED_DIR / f"props_recommendations_{d}.csv"

        # 1) Snapshot player props to data/raw
        snap_cmd = [str(py), "-m", "nba_betting.cli", "odds-snapshots-props", "--date", d, "--regions", regions]
        if bookmakers:
            snap_cmd += ["--bookmakers", bookmakers]
        if markets:
            snap_cmd += ["--markets", markets]
        rc_snap = _run_to_file(snap_cmd, log_file, cwd=BASE_DIR, env=env)

        pipeline_error = None

        # 2) Optionally compute props edges via the same same-day snapshot fast path as the worker.
        rc_edges = None
        rc_export = None
        if do_edges or do_export:
            try:
                from nba_betting.refresh_oddsapi_props_job import (
                    _compute_props_edges_direct as _worker_compute_props_edges_direct,
                    _ensure_props_predictions_for_refresh as _worker_ensure_props_predictions_for_refresh,
                    _export_props_recommendations_direct as _worker_export_props_recommendations_direct,
                )
            except Exception as exc:
                pipeline_error = f"failed to import props refresh helpers: {exc}"
                if do_edges:
                    rc_edges = 1
                if do_export and not do_edges:
                    rc_export = 1
            else:
                pred_path, pred_error = _worker_ensure_props_predictions_for_refresh(
                    date_str=d,
                    log_file=log_file,
                    heartbeat_cb=lambda: None,
                    snapshot_path=raw_fp,
                )
                if pred_path is None:
                    pipeline_error = pred_error or f"props predictions unavailable for {d}"
                    if do_edges:
                        rc_edges = 1
                    if do_export and not do_edges:
                        rc_export = 1
                else:
                    if do_edges:
                        rc_edges, _, edges_error = _worker_compute_props_edges_direct(
                            date_str=d,
                            snapshot_path=raw_fp,
                            predictions_path=pred_path,
                            bookmakers=bookmakers,
                            log_file=log_file,
                            heartbeat_cb=lambda: None,
                        )
                        if int(rc_edges) != 0:
                            pipeline_error = edges_error or f"props-edges failed with exit code {int(rc_edges)}"
                        elif int(_count_csv_rows_quick(raw_fp) or 0) > 0 and int(_count_csv_rows_quick(edges_fp) or 0) <= 0:
                            pipeline_error = "props-edges produced zero rows after a non-empty snapshot"

                    if do_export and (not do_edges or (int(rc_edges or 0) == 0 and int(_count_csv_rows_quick(edges_fp) or 0) > 0)):
                        rc_export, _, export_error = _worker_export_props_recommendations_direct(
                            date_str=d,
                            log_file=log_file,
                            heartbeat_cb=lambda: None,
                        )
                        if int(rc_export) != 0 and not pipeline_error:
                            pipeline_error = export_error or f"export-props-recommendations failed with exit code {int(rc_export)}"

        snap_rows = 0
        try:
            if raw_fp.exists():
                snap_rows = int(len(pd.read_csv(raw_fp)))
        except Exception:
            snap_rows = 0

        edges_rows = 0
        try:
            if edges_fp.exists():
                edges_rows = int(len(pd.read_csv(edges_fp)))
        except Exception:
            edges_rows = 0

        rec_rows = 0
        try:
            if rec_fp.exists():
                rec_rows = int(len(pd.read_csv(rec_fp)))
        except Exception:
            rec_rows = 0

        # Cron meta best-effort
        try:
            _cron_meta_update(
                "refresh_oddsapi_props",
                {
                    "date": d,
                    "bookmakers": (bookmakers or None),
                    "snapshot_rows": int(snap_rows),
                    "snapshot": str(raw_fp),
                    "edges_rows": int(edges_rows),
                    "edges": str(edges_fp),
                    "recs_rows": int(rec_rows),
                    "recs": str(rec_fp),
                },
            )
        except Exception:
            pass

        pushed = None; push_detail = None
        if do_push:
            ok, detail = _git_commit_and_push(msg=f"refresh-oddsapi-props {d}")
            pushed = bool(ok); push_detail = detail

        # Note: even if CLI rc != 0, return 200 so Render Cron Jobs don't show "failed"
        # for expected operational conditions (rate limits, no markets yet, etc.).
        return jsonify({
            "date": d,
            "regions": regions,
            "bookmakers": (bookmakers or None),
            "markets": markets,
            "rc_snapshot": int(rc_snap),
            "snapshot_rows": int(snap_rows),
            "snapshot_path": str(raw_fp),
            "rc_edges": (int(rc_edges) if rc_edges is not None else None),
            "edges_rows": int(edges_rows),
            "edges_path": str(edges_fp),
            "rc_export": (int(rc_export) if rc_export is not None else None),
            "recs_rows": int(rec_rows),
            "recs_path": str(rec_fp),
            "log_file": str(log_file),
            "error": pipeline_error,
            "pushed": pushed,
            "push_detail": push_detail,
        }), 200
    except Exception as e:
        # Still avoid non-2xx for cron: return diagnostics for inspection.
        return jsonify({
            "date": d,
            "regions": regions,
            "markets": markets,
            "error": f"oddsapi props refresh failed: {e}",
            "log_file": str(log_file),
        }), 200


@app.route("/api/cron/probe-bovada")
def api_cron_probe_bovada():
    """Debug endpoint: probe Bovada endpoints and report event counts for a date.

    Auth: CRON_TOKEN or ADMIN_KEY. Query: date=YYYY-MM-DD
    """
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=True)
    if _probe_bovada is None:
        return jsonify({"error": "probe not available"}), 500
    try:
        dt = pd.to_datetime(d)
        out = _probe_bovada(dt, verbose=True)
        return jsonify(out)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/cron/capture-closing", methods=["POST", "GET"])
def api_cron_capture_closing():
    """Export consensus closing lines CSV for a given date under data/processed.

    Query params:
      - date (required): YYYY-MM-DD
    """
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=False)
    if not d:
        return jsonify({"error": "missing date"}), 400
    # Choose python executable
    py = _resolve_python()
    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_capture_closing_{d}_{stamp}.log"
    try:
        env = {"PYTHONPATH": str(SRC_DIR)}
        rc = _run_to_file([str(py), "-m", "nba_betting.cli", "export-closing-lines-csv", "--date", d], log_file, cwd=BASE_DIR, env=env)
        out = DATA_PROCESSED_DIR / f"closing_lines_{d}.csv"
        rows = 0
        if out.exists():
            try:
                rows = int(sum(1 for _ in out.open("r", encoding="utf-8", errors="ignore")) - 1)
            except Exception:
                try:
                    rows = len(pd.read_csv(out))
                except Exception:
                    rows = 0
        # Optional push
        pushed = None; push_detail = None
        if str(request.args.get("push", "0")).lower() in {"1","true","yes"}:
            ok, detail = _git_commit_and_push(msg=f"capture closing lines {d}")
            pushed = bool(ok); push_detail = detail
        return jsonify({"date": d, "rc": int(rc), "output": str(out), "rows": int(rows), "log_file": str(log_file), "pushed": pushed, "push_detail": push_detail})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/cron/predict-date", methods=["POST", "GET"])
def api_cron_predict_date():
    """Run predict-date for the given date to refresh predictions_YYYY-MM-DD.csv and odds CSV.

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    """
    cron_ok = _cron_auth_ok(request)
    admin_ok = _admin_auth_ok(request)
    if not (cron_ok or admin_ok):
        return jsonify({"error": "unauthorized"}), 401
    # Allow CRON_TOKEN access in production; keep ADMIN_KEY access debug-only.
    if (not _debug_routes_enabled()) and (not cron_ok):
        return jsonify({"error": "disabled"}), 404
    d = _parse_date_param(request, default_to_today=True)
    do_push = (str(request.args.get("push", "0")).lower() in {"1","true","yes"})
    do_async = (str(request.args.get("async", "0")).lower() in {"1","true","yes"})
    skip_if_no_games = (str(request.args.get("skip_if_no_games", "1")).lower() in {"1","true","yes"})
    # If there are no games today and skipping is allowed, fast-exit.
    if skip_if_no_games and d:
        try:
            if not _has_games_for_date(d):
                return jsonify({
                    "status": "skipped",
                    "reason": "no games for date",
                    "date": d,
                    "push": do_push,
                })
        except Exception:
            # On check failure, proceed to run to be safe
            pass
    # Choose python executable
    py = _resolve_python()
    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_predict_date_{d}_{stamp}.log"
    try:
        env = {"PYTHONPATH": str(SRC_DIR)}
        if do_async:
            # Background job to avoid Render timeouts. If models are missing, ensure them inside the job.
            missing_models = (not _quick_have_game_models())
            def _job():
                try:
                    if missing_models:
                        _ensure_game_models(log_file)
                    _run_to_file([str(py), "-m", "nba_betting.cli", "predict-date", "--date", d], log_file, cwd=BASE_DIR, env=env)
                    if do_push:
                        _git_commit_and_push(msg=f"predict-date {d}")
                except Exception:
                    pass
            t = threading.Thread(target=_job, daemon=True)
            t.start()
            return jsonify({
                "status": "started",
                "date": d,
                "log_file": str(log_file),
                "push": do_push,
                "models": ({"skipped": True} if not missing_models else {"ensured_in_background": True}),
            }), 202
        # Synchronous path: ensure models now, then run
        ok_models, info = _ensure_game_models(log_file)
        if not ok_models:
            # Proceed anyway; CLI will fail clearly if models missing
            pass
        # Synchronous mode (original behavior)
        rc = _run_to_file([str(py), "-m", "nba_betting.cli", "predict-date", "--date", d], log_file, cwd=BASE_DIR, env=env)
        # Locate predictions from either processed/ or legacy root
        pred_path = _find_predictions_for_date(d)
        pred = pred_path if pred_path is not None else (BASE_DIR / f"predictions_{d}.csv")
        odds = DATA_PROCESSED_DIR / f"game_odds_{d}.csv"
        n_pred = int(len(pd.read_csv(pred))) if (hasattr(pred, 'exists') and pred.exists()) else (int(len(pd.read_csv(pred))) if pred_path is not None else 0)
        n_odds = int(len(pd.read_csv(odds))) if odds.exists() else 0
        pushed = None; push_detail = None
        if do_push:
            ok, detail = _git_commit_and_push(msg=f"predict-date {d}")
            pushed = bool(ok); push_detail = detail
        return jsonify({
            "date": d,
            "rc": int(rc),
            "predictions": (str(pred) if (hasattr(pred, 'exists') and pred.exists()) else (str(pred) if pred_path is not None else None)),
            "pred_rows": n_pred,
            "odds": str(odds) if odds.exists() else None,
            "odds_rows": n_odds,
            "log_file": str(log_file),
            "pushed": pushed,
            "push_detail": push_detail,
            "models": info,
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/cron/reconcile-games", methods=["POST", "GET"])
def api_cron_reconcile_games():
    """Build reconciliation CSV for a date by joining predictions with final scores.

    - Input date defaults to yesterday (UTC) if omitted.
    - Output: data/processed/recon_games_YYYY-MM-DD.csv
    - Columns: date, home_team, visitor_team, home_pts, visitor_pts, pred_margin, pred_total, actual_margin, total_actual, margin_error, total_error
    """
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    # Date defaults to yesterday
    d = _parse_date_param(request, default_to_today=False)
    if not d:
        d = (datetime.utcnow().date() - timedelta(days=1)).isoformat()
    # Load predictions for that date (prefer processed/ fallback root)
    pred_path = _find_predictions_for_date(d)
    if pred_path is None:
        # Gracefully return rows=0 so cron runs don't fail on off days or missed predictions
        try:
            _cron_meta_update("reconcile_games", {"date": d, "rows": 0, "output": None, "reason": "predictions missing"})
        except Exception:
            pass
        return jsonify({"date": d, "rows": 0, "output": None, "reason": "predictions missing"})
    try:
        preds = pd.read_csv(pred_path)
    except Exception as e:
        # Cron should not hard-fail due to a transient/partial artifact; return diagnostics.
        try:
            _cron_meta_update("reconcile_games", {"date": d, "ok": False, "error": f"failed to read predictions: {e}", "predictions": str(pred_path)})
        except Exception:
            pass
        return jsonify({"date": d, "ok": False, "error": f"failed to read predictions: {e}", "predictions": str(pred_path)}), 200

    # Normalize prediction team names to tricodes
    try:
        from nba_api.stats.static import teams as _static_teams  # type: ignore
        team_list = _static_teams.get_teams()
        full_to_abbr = {str(t.get('full_name')).upper(): str(t.get('abbreviation')).upper() for t in team_list}
        alt = {
            "LOS ANGELES CLIPPERS": "LAC",
            "LA CLIPPERS": "LAC",
            "PHOENIX SUNS": "PHX",
            "GOLDEN STATE WARRIORS": "GSW",
            "SAN ANTONIO SPURS": "SAS",
            "NEW YORK KNICKS": "NYK",
            "BROOKLYN NETS": "BKN",
            "UTAH JAZZ": "UTA",
        }
        def to_tri(name: str) -> str:
            if name is None:
                return ""
            s = str(name).strip().upper()
            if s in full_to_abbr:
                return full_to_abbr[s]
            if s in alt:
                return alt[s]
            return s if len(s) <= 4 else s
        preds = preds.copy()
        preds["home_tri"] = preds.get("home_team").apply(to_tri)
        preds["away_tri"] = preds.get("visitor_team").apply(to_tri)
    except Exception:
        preds = preds.copy()
        preds["home_tri"] = preds.get("home_team").astype(str).str.upper()
        preds["away_tri"] = preds.get("visitor_team").astype(str).str.upper()

    # Helper: finals from NBA CDN (with optional ±1 day) limited to prediction pairs
    def _finals_from_cdn(date_str_local: str, pred_pairs: set[tuple[str, str]], include_adjacent: bool = False) -> pd.DataFrame:
        try:
            import requests as _rq  # type: ignore
        except Exception:
            return pd.DataFrame()

        def _rows_for(ds: str) -> list[dict[str, object]]:
            try:
                ymd = ds.replace('-', '')
                url = f"https://data.nba.com/data/10s/prod/v1/{ymd}/scoreboard.json"
                r = _rq.get(url, timeout=4)
                out: list[dict[str, object]] = []
                if r.status_code == 200:
                    jd = r.json()
                    games = jd.get('games', []) if isinstance(jd, dict) else []
                    for g in games:
                        try:
                            htri = str((g.get('hTeam') or {}).get('triCode') or '').upper()
                            vtri = str((g.get('vTeam') or {}).get('triCode') or '').upper()
                            if (htri, vtri) not in pred_pairs:
                                continue
                            hs = (g.get('hTeam') or {}).get('score'); vs = (g.get('vTeam') or {}).get('score')
                            hpts = int(hs) if (hs not in (None, '')) else None
                            vpts = int(vs) if (vs not in (None, '')) else None
                            out.append({"home_tri": htri, "away_tri": vtri, "home_pts": hpts, "visitor_pts": vpts})
                        except Exception:
                            continue
                return out
            except Exception:
                return []

        rows = _rows_for(date_str_local)
        if include_adjacent and not rows:
            try:
                from datetime import datetime as _dt, timedelta as _td
                base = _dt.strptime(date_str_local, "%Y-%m-%d").date()
                for off in (-1, 1):
                    rows += _rows_for((base + _td(days=off)).isoformat())
            except Exception:
                pass
        return pd.DataFrame(rows)

    def _finals_from_espn(date_str_local: str, pred_pairs: set[tuple[str, str]]) -> pd.DataFrame:
        """Fallback finals via ESPN scoreboard public API."""
        try:
            import requests as _rq  # type: ignore
        except Exception:
            return pd.DataFrame()
        try:
            ymd = date_str_local.replace('-', '')
            url = f"https://site.web.api.espn.com/apis/site/v2/sports/basketball/nba/scoreboard?dates={ymd}"
            r = _rq.get(url, timeout=6)
            if r.status_code != 200:
                return pd.DataFrame()
            jd = r.json()
            evs = jd.get('events', []) if isinstance(jd, dict) else []
            def espn_to_tri(abbr: str) -> str:
                s = str(abbr or '').upper()
                fix = {
                    'GS': 'GSW',  # ESPN sometimes uses GS
                    'NO': 'NOP',
                    'NY': 'NYK',
                }
                return fix.get(s, s)
            rows: list[dict[str, object]] = []
            for e in evs:
                try:
                    comps = e.get('competitions', [])
                    if not comps: continue
                    c = comps[0]
                    at = c.get('competitors', [])
                    if len(at) < 2: continue
                    home = next((t for t in at if str(t.get('homeAway'))=='home'), None)
                    away = next((t for t in at if str(t.get('homeAway'))=='away'), None)
                    if not home or not away: continue
                    htri = espn_to_tri(((home.get('team') or {}).get('abbreviation')))
                    vtri = espn_to_tri(((away.get('team') or {}).get('abbreviation')))
                    if (htri, vtri) not in pred_pairs:
                        continue
                    try:
                        hpts = int(home.get('score')) if str(home.get('score') or '') != '' else None
                    except Exception:
                        hpts = None
                    try:
                        vpts = int(away.get('score')) if str(away.get('score') or '') != '' else None
                    except Exception:
                        vpts = None
                    rows.append({'home_tri': htri, 'away_tri': vtri, 'home_pts': hpts, 'visitor_pts': vpts})
                except Exception:
                    continue
            return pd.DataFrame(rows)
        except Exception:
            return pd.DataFrame()

    # Fetch finals from ScoreboardV2 if available, else use CDN fallback
    pred_pairs: set[tuple[str, str]] = set(zip(
        preds.get("home_tri").astype(str).str.upper(),
        preds.get("away_tri").astype(str).str.upper()
    ))
    try:
        # Prefer a pre-generated finals CSV if available
        finals_csv = DATA_PROCESSED_DIR / f"finals_{d}.csv"
        finals: pd.DataFrame
        if finals_csv.exists():
            try:
                _f = pd.read_csv(finals_csv)
                finals = _f[["home_tri","away_tri","home_pts","visitor_pts"]].copy()
            except Exception:
                finals = pd.DataFrame()
        else:
            finals = pd.DataFrame()
        if finals.empty and _scoreboardv2 is None:
            # Use CDN with ±1 day tolerance to handle timezone/reporting offsets; then ESPN fallback
            finals = _finals_from_cdn(d, pred_pairs, include_adjacent=True)
            if finals.empty:
                finals = _finals_from_espn(d, pred_pairs)
        elif finals.empty:
            # Try stats API once
            try:
                if _nba_http is not None:
                    _nba_http.STATS_HEADERS.update({
                        'Accept': 'application/json, text/plain, */*',
                        'Accept-Language': 'en-US,en;q=0.9',
                        'Origin': 'https://www.nba.com',
                        'Referer': 'https://www.nba.com/stats/',
                        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36',
                        'Connection': 'keep-alive',
                    })
            except Exception:
                pass
            last_err: Optional[Exception] = None
            gh = pd.DataFrame(); ls = pd.DataFrame()
            try:
                sb = _scoreboardv2.ScoreboardV2(game_date=d, day_offset=0, timeout=10)
                nd = sb.get_normalized_dict()
                gh = pd.DataFrame(nd.get("GameHeader", []))
                ls = pd.DataFrame(nd.get("LineScore", []))
            except Exception as e:
                last_err = e
            out_rows: list[dict[str, object]] = []
            finals = pd.DataFrame()
            if not (gh.empty or ls.empty):
                cgh = {c.upper(): c for c in gh.columns}
                cls = {c.upper(): c for c in ls.columns}
                team_rows: dict[int, dict[str, object]] = {}
                for _, r in ls.iterrows():
                    try:
                        tid = int(r[cls["TEAM_ID"]])
                        tri = str(r[cls["TEAM_ABBREVIATION"]]).upper()
                        pts = None
                        if "PTS" in cls:
                            try:
                                pts = int(r[cls["PTS"]])
                            except Exception:
                                pts = None
                        team_rows[tid] = {"tri": tri, "pts": pts}
                    except Exception:
                        continue
                for _, g in gh.iterrows():
                    try:
                        hid = int(g[cgh["HOME_TEAM_ID"]]); vid = int(g[cgh["VISITOR_TEAM_ID"]])
                        h = team_rows.get(hid, {}); v = team_rows.get(vid, {})
                        htri = str(h.get("tri") or "").upper(); vtri = str(v.get("tri") or "").upper()
                        hpts = h.get("pts"); vpts = v.get("pts")
                        if (htri, vtri) not in pred_pairs:
                            continue
                        out_rows.append({"home_tri": htri, "away_tri": vtri, "home_pts": hpts, "visitor_pts": vpts})
                    except Exception:
                        continue
                finals = pd.DataFrame(out_rows)
            if finals.empty and last_err is not None:
                finals = _finals_from_cdn(d, pred_pairs, include_adjacent=True)
                if finals.empty:
                    finals = _finals_from_espn(d, pred_pairs)

        # Join and compute errors
        merged = preds.merge(finals, on=["home_tri","away_tri"], how="left")
        for col in ("pred_margin", "pred_total", "home_pts", "visitor_pts"):
            if col not in merged.columns:
                merged[col] = pd.NA
            try:
                merged[col] = pd.to_numeric(merged[col], errors="coerce")
            except Exception:
                merged[col] = pd.NA
        merged["actual_margin"] = merged["home_pts"] - merged["visitor_pts"]
        merged["total_actual"] = merged[["home_pts","visitor_pts"]].sum(axis=1)
        merged["margin_error"] = merged["pred_margin"] - merged["actual_margin"]
        merged["total_error"] = merged["pred_total"] - merged["total_actual"]
    except Exception:
        # Fallback to minimal recon if any step fails
        merged = preds.copy()
        for col in ("home_pts","visitor_pts","actual_margin","total_actual","margin_error","total_error"):
            merged[col] = pd.NA

    keep = [
        "date","home_team","visitor_team","home_tri","away_tri",
        "home_pts","visitor_pts","pred_margin","pred_total",
        "actual_margin","total_actual","margin_error","total_error"
    ]
    if "date" not in merged.columns:
        merged["date"] = d
    out_df = merged[[c for c in keep if c in merged.columns]]

    out = DATA_PROCESSED_DIR / f"recon_games_{d}.csv"
    out.parent.mkdir(parents=True, exist_ok=True)
    out_df.to_csv(out, index=False)

    pushed = None; push_detail = None
    if str(request.args.get("push", "0")).lower() in {"1","true","yes"}:
        ok, detail = _git_commit_and_push(msg=f"reconcile games {d}")
        pushed = bool(ok); push_detail = detail
    try:
        _cron_meta_update("reconcile_games", {"date": d, "rows": int(len(out_df)), "output": str(out), "pushed": pushed})
    except Exception:
        pass
    return jsonify({"date": d, "rows": int(len(out_df)), "output": str(out), "pushed": pushed, "push_detail": push_detail})


@app.route("/api/finals/export", methods=["POST", "GET"])
def api_finals_export():
    """Export finals CSVs for a single date or a date range.

    Query:
      - date=YYYY-MM-DD (single) OR since=YYYY-MM-DD&until=YYYY-MM-DD (range)
    Writes:
      - data/processed/finals_YYYY-MM-DD.csv per date
    """
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    one = (request.args.get("date") or "").strip()
    since = (request.args.get("since") or "").strip()
    until = (request.args.get("until") or "").strip()
    dates: list[str] = []
    if one:
        dates = [one]
    else:
        try:
            from datetime import datetime as _dt
            if not since:
                return jsonify({"error": "missing date or since/until"}), 400
            if not until:
                until = _default_us_slate_date_str()
            ds = _dt.strptime(since, "%Y-%m-%d").date()
            de = _dt.strptime(until, "%Y-%m-%d").date()
            if de < ds:
                ds, de = de, ds
            cur = ds
            while cur <= de:
                dates.append(cur.isoformat())
                cur = cur + timedelta(days=1)
        except Exception as e:
            return jsonify({"error": f"invalid dates: {e}"}), 400
    written: list[dict[str, object]] = []
    for d in dates:
        try:
            path, n = _write_finals_csv_for_date(d)
            written.append({"date": d, "path": path, "rows": int(n)})
        except Exception as e:
            written.append({"date": d, "error": str(e)})
    # Optional: commit and push generated CSVs
    pushed = None; push_detail = None
    if str(request.args.get("push", "0")).lower() in {"1","true","yes"}:
        try:
            ok, detail = _git_commit_and_push(msg=f"finals export {dates[0]}..{dates[-1]}" if len(dates) > 1 else f"finals export {dates[0]}")
            pushed = bool(ok); push_detail = detail
        except Exception as e:
            pushed = False; push_detail = str(e)
    return jsonify({"count": len(written), "items": written, "pushed": pushed, "push_detail": push_detail})

@app.route("/api/cron/daily-update", methods=["POST", "GET"])
def api_cron_daily_update():
    """Trigger the daily update job via cron token. Git push is disabled by default for cron."""
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    if _job_state["running"]:
        return jsonify({"status": "already-running", "started_at": _job_state["started_at"]}), 409
    do_push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})
    date_str = (request.args.get("date") or "").strip() or None
    mode = (request.args.get("mode") or "full").strip().lower()
    t = threading.Thread(target=_daily_update_job, args=(do_push, date_str, mode), daemon=True)
    t.start()
    return jsonify({"status": "started", "push": do_push, "mode": mode, "date": date_str, "started_at": datetime.utcnow().isoformat()}), 202


@app.route("/api/cron/run-all", methods=["POST", "GET"])
def api_cron_run_all():
    """Minimal Render-safe daily cron: refresh odds (today) and reconcile games (yesterday).

    Intent: Keep server-side work light. Models and props actuals/edges run locally only.
    Steps (best-effort, continue on failures):
      1) Refresh Bovada odds for today
      2) Reconcile yesterday's games
    """
    if not _cron_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401

    mode = (request.args.get("mode") or "minimal").strip().lower()
    if mode in {"full", "pipeline", "props"}:
        # Keep Render-safe by requiring debug routes for full pipeline mode.
        if not _debug_routes_enabled():
            return jsonify({"error": "full mode disabled"}), 404
        if _job_state["running"]:
            return jsonify({"status": "already-running", "started_at": _job_state["started_at"]}), 409
        d = (request.args.get("date") or "").strip() or _default_us_slate_date_str()
        push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})
        t = threading.Thread(target=_daily_update_job, args=(push, d, mode), daemon=True)
        t.start()
        return jsonify({"status": "started", "mode": mode, "date": d, "push": push, "started_at": datetime.utcnow().isoformat()}), 202

    today = datetime.strptime(_default_us_slate_date_str(), "%Y-%m-%d").date()
    yesterday = today - timedelta(days=1)
    d_today = request.args.get("date") or today.isoformat()
    d_yest = request.args.get("yesterday") or yesterday.isoformat()
    push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})

    # Logging setup
    logdir = _ensure_logs_dir()
    stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logdir / f"web_daily_update_{stamp}.log"
    results: Dict[str, Any] = {"date": d_today, "yesterday": d_yest, "log_file": str(log_file)}

    try:
        # Resolve base URL for internal HTTP calls (Render-safe)
        base_url = os.environ.get("RENDER_EXTERNAL_URL") or os.environ.get("BASE_URL")
        if not base_url:
            port_env = os.environ.get("PORT", "5000")
            base_url = f"http://127.0.0.1:{port_env}"

        # Server-side: do not run models or props jobs.
        results["note"] = "server-only: odds refresh + game reconciliation"

        # 1) refresh-bovada for today
        try:
            import requests as _rq
            token = os.environ.get("CRON_TOKEN")
            headers = {"Authorization": f"Bearer {token}"} if token else {}
            r = _rq.get(f"{base_url}/api/cron/refresh-bovada?date={d_today}", headers=headers, timeout=60)
            results["refresh_bovada"] = (r.status_code, r.text[:200])
        except Exception as e:
            results["refresh_bovada_error"] = str(e)

        # 2) reconcile-games for yesterday
        try:
            import requests as _rq
            token = os.environ.get("CRON_TOKEN")
            headers = {"Authorization": f"Bearer {token}"} if token else {}
            r = _rq.get(f"{base_url}/api/cron/reconcile-games?date={d_yest}", headers=headers, timeout=60)
            results["reconcile_games"] = (r.status_code, r.text[:200])
        except Exception as e:
            results["reconcile_games_error"] = str(e)

        if push:
            ok, detail = _git_commit_and_push(msg=f"daily-run-all {d_today}")
            results["pushed"] = bool(ok)
            results["push_detail"] = detail

        _cron_meta_update("run_all", {"date": d_today, "yesterday": d_yest, "log_file": str(log_file)})
        return jsonify(results)

    except Exception as e:
        return jsonify({"error": str(e), **results}), 500


@app.route("/api/cron/live-lens-reports", methods=["POST", "GET"])
def api_cron_live_lens_reports():
    """Build daily Live Lens audit/ROI reports and a rolling driver-tag rollup.

    Runs on the web service so outputs land on the Render persistent disk.
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401

    ds = _parse_date_param(request, default_to_today=False)
    if not ds:
        ds = (datetime.utcnow().date() - timedelta(days=1)).isoformat()
    try:
        end_dt = datetime.strptime(ds, "%Y-%m-%d").date()
    except Exception:
        return jsonify({"error": "invalid date"}), 400

    try:
        rollup_days = int(float(str(request.args.get("rollup_days") or request.args.get("lookback_days") or "30").strip()))
    except Exception:
        rollup_days = 30
    rollup_days = int(max(1, min(365, rollup_days)))
    start_dt = end_dt - timedelta(days=int(rollup_days) - 1)

    try:
        min_denom = int(float(str(request.args.get("min_denom") or "20").strip()))
    except Exception:
        min_denom = 20
    min_denom = int(max(1, min(5000, min_denom)))

    include_watch = str(request.args.get("include_watch", "0")).lower() in {"1", "true", "yes"}
    include_model_lines = str(request.args.get("include_model_lines", "0")).lower() in {"1", "true", "yes"}
    by_klass = str(request.args.get("by_klass", "1")).lower() in {"1", "true", "yes"}
    include_base_tags = str(request.args.get("include_base_tags", "0")).lower() in {"1", "true", "yes"}
    do_push = str(request.args.get("push", "0")).lower() in {"1", "true", "yes"}
    markets = (request.args.get("markets") or "player_prop,total,half_total,quarter_total,ats").strip()
    decision_policy = (request.args.get("decision_policy") or "first_bet_else_first").strip().lower() or "first_bet_else_first"
    if decision_policy not in {"first_bet_else_first", "first_actionable_else_first", "first_signal"}:
        decision_policy = "first_bet_else_first"

    logs_dir = _ensure_logs_dir()
    stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_live_lens_reports_{ds}_{stamp}.log"

    try:
        from nba_betting.config import paths as _paths  # type: ignore

        reports_dir = _paths.data_processed / "reports"
    except Exception:
        reports_dir = DATA_PROCESSED_DIR / "reports"
    reports_dir.mkdir(parents=True, exist_ok=True)

    audit_md = reports_dir / f"live_lens_audit_{ds}.md"
    audit_csv = reports_dir / f"live_lens_scored_{ds}.csv"
    roi_md = reports_dir / f"live_lens_roi_{ds}.md"
    roi_csv = reports_dir / f"live_lens_roi_scored_{ds}.csv"
    rollup_md = reports_dir / "live_lens_driver_tag_rollup.md"

    py = _resolve_python()
    env = dict(os.environ)
    env["PYTHONPATH"] = str(SRC_DIR)

    try:
        audit_cmd = [
            str(py),
            str(BASE_DIR / "tools" / "daily_live_lens_audit.py"),
            "--date",
            ds,
            "--out-dir",
            str(reports_dir),
        ]
        if include_model_lines:
            audit_cmd.append("--include-model-lines")
        rc_audit = _run_to_file(audit_cmd, log_file, cwd=BASE_DIR, env=env)

        roi_cmd = [str(py), str(BASE_DIR / "tools" / "daily_live_lens_roi.py"), "--date", ds]
        if include_watch:
            roi_cmd.append("--include-watch")
        if include_model_lines:
            roi_cmd.append("--include-model-lines")
        rc_roi = _run_to_file(roi_cmd, log_file, cwd=BASE_DIR, env=env)

        rc_rollup = None
        if list(reports_dir.glob("live_lens_scored_*.csv")):
            rollup_cmd = [
                str(py),
                str(BASE_DIR / "tools" / "rollup_live_lens_driver_tags.py"),
                "--in-dir",
                str(reports_dir),
                "--glob",
                "live_lens_scored_*.csv",
                "--out",
                str(rollup_md),
                "--min-denom",
                str(min_denom),
                "--markets",
                markets,
                "--decision-policy",
                decision_policy,
                "--start-date",
                start_dt.isoformat(),
                "--end-date",
                end_dt.isoformat(),
            ]
            if include_base_tags:
                rollup_cmd.append("--include-base-tags")
            if by_klass:
                rollup_cmd.append("--by-klass")
            rc_rollup = _run_to_file(rollup_cmd, log_file, cwd=BASE_DIR, env=env)

        pushed = None
        push_detail = None
        if do_push:
            ok, detail = _git_commit_and_push(msg=f"live lens reports {start_dt.isoformat()}..{end_dt.isoformat()}")
            pushed = bool(ok)
            push_detail = detail

        try:
            _cron_meta_update(
                "live_lens_reports",
                {
                    "date": ds,
                    "start_date": start_dt.isoformat(),
                    "rollup_days": int(rollup_days),
                    "audit_md": str(audit_md),
                    "audit_csv": str(audit_csv),
                    "roi_md": str(roi_md),
                    "roi_csv": str(roi_csv),
                    "rollup_md": str(rollup_md),
                    "rc_audit": int(rc_audit),
                    "rc_roi": int(rc_roi),
                    "rc_rollup": (int(rc_rollup) if rc_rollup is not None else None),
                },
            )
        except Exception:
            pass

        return jsonify(
            {
                "date": ds,
                "start_date": start_dt.isoformat(),
                "rollup_days": int(rollup_days),
                "min_denom": int(min_denom),
                "markets": markets,
                "decision_policy": decision_policy,
                "include_watch": bool(include_watch),
                "include_model_lines": bool(include_model_lines),
                "rc_audit": int(rc_audit),
                "audit_md": str(audit_md),
                "audit_csv": str(audit_csv),
                "rc_roi": int(rc_roi),
                "roi_md": str(roi_md),
                "roi_csv": str(roi_csv),
                "rc_rollup": (int(rc_rollup) if rc_rollup is not None else None),
                "rollup_md": (str(rollup_md) if rc_rollup is not None else None),
                "log_file": str(log_file),
                "pushed": pushed,
                "push_detail": push_detail,
            }
        ), 200
    except Exception as e:
        return jsonify(
            {
                "date": ds,
                "start_date": start_dt.isoformat(),
                "rollup_days": int(rollup_days),
                "error": f"live lens reports failed: {e}",
                "log_file": str(log_file),
            }
        ), 200


