@app.route("/api/cron/assess-oddsapi", methods=["POST", "GET"])
def api_cron_assess_oddsapi():
    """Assess OddsAPI key capabilities (markets/books + quota headers).

    Query params:
    - date (optional): YYYY-MM-DD (defaults to the current US local slate date)
      - regions (optional): OddsAPI regions (default 'us')
      - event_id (optional): assess a specific event id (otherwise first event on date)
      - sample_markets (optional): comma-separated markets to sample via /odds

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    Persists JSON under data/processed/oddsapi_capabilities_<date>.json (respects NBA_BETTING_DATA_ROOT).
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401

    api_key = (os.environ.get("ODDS_API_KEY") or "").strip()
    if not api_key:
        return jsonify({"error": "missing ODDS_API_KEY"}), 500

    d = _parse_date_param(request, default_to_today=True)
    regions = (request.args.get("regions") or "us").strip() or "us"
    event_id_q = (request.args.get("event_id") or request.args.get("event-id") or "").strip()
    sample_markets_q = (request.args.get("sample_markets") or request.args.get("sample-markets") or "").strip()
    if not sample_markets_q:
        sample_markets_q = "h2h,spreads,totals,player_points,player_rebounds,player_assists,player_threes,player_steals,player_blocks,player_turnovers"
    sample_markets = [m.strip() for m in str(sample_markets_q).split(",") if m.strip()]

    try:
        target = pd.to_datetime(d).date()
    except Exception:
        return jsonify({"error": "invalid date"}), 400

    # Local imports (avoid import cost on unrelated requests)
    try:
        from nba_betting.odds_api import (
            NBA_SPORT_KEY,
            ODDS_HOST,
            OddsApiConfig,
            discover_event_market_keys,
            fetch_event_odds_current,
            list_events_current,
        )
        from nba_betting.config import paths as _paths
    except Exception as e:
        return jsonify({"error": f"oddsapi modules unavailable: {e}"}), 500

    def _usage_headers(resp) -> dict:
        try:
            h = {str(k).lower(): v for k, v in (resp.headers or {}).items()}
        except Exception:
            h = {}
        out = {}
        for k in [
            "x-requests-remaining",
            "x-requests-used",
            "x-requests-last",
            "x-requests-per-minute-remaining",
            "x-requests-per-minute-used",
        ]:
            if k in h:
                out[k] = h.get(k)
        return out

    usage = {}
    try:
        r = requests.get(
            f"{ODDS_HOST}/v4/sports/{NBA_SPORT_KEY}/events",
            params={"apiKey": api_key},
            headers={"Accept": "application/json", "User-Agent": "nba-betting/1.0"},
            timeout=45,
        )
        r.raise_for_status()
        usage = _usage_headers(r)
    except Exception:
        usage = {}

    cfg = OddsApiConfig(api_key=api_key, regions=regions)
    events = list_events_current(cfg, pd.to_datetime(str(target)))

    chosen_event = None
    if event_id_q:
        for ev in events:
            if str(ev.get("id")) == str(event_id_q):
                chosen_event = ev
                break
    if chosen_event is None and events:
        chosen_event = events[0]

    eid = str(chosen_event.get("id")) if chosen_event else ""
    discovered = sorted(discover_event_market_keys(cfg, eid)) if eid else []

    sampled_df = pd.DataFrame()
    if eid and sample_markets:
        try:
            sampled_df = fetch_event_odds_current(cfg, eid, sample_markets, verbose=False)
        except Exception:
            sampled_df = pd.DataFrame()

    books = []
    try:
        if sampled_df is not None and not sampled_df.empty:
            cols = [c for c in ["bookmaker", "bookmaker_title"] if c in sampled_df.columns]
            if cols:
                books = (
                    sampled_df[cols]
                    .dropna()
                    .drop_duplicates()
                    .sort_values(cols)
                    .to_dict(orient="records")
                )
    except Exception:
        books = []

    out = {
        "ok": True,
        "asof_utc": datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
        "target_date": str(target),
        "regions": regions,
        "usage_headers": usage,
        "events_count": int(len(events)),
        "chosen_event": {
            "event_id": eid,
            "commence_time": (chosen_event.get("commence_time") if chosen_event else None),
            "home_team": (chosen_event.get("home_team") if chosen_event else None),
            "away_team": (chosen_event.get("away_team") if chosen_event else None),
        },
        "discovered_markets_count": int(len(discovered)),
        "discovered_markets": discovered,
        "sample_markets": sample_markets,
        "sample_rows": int(0 if sampled_df is None else len(sampled_df)),
        "sample_markets_returned": (
            sorted([str(x) for x in sampled_df["market"].dropna().astype(str).unique()])
            if (sampled_df is not None and ("market" in sampled_df.columns) and (not sampled_df.empty))
            else []
        ),
        "sample_bookmakers": books,
    }

    # Persist best-effort
    try:
        _paths.data_processed.mkdir(parents=True, exist_ok=True)
        p = _paths.data_processed / f"oddsapi_capabilities_{target}.json"
        p.write_text(json.dumps(out, indent=2, sort_keys=True), encoding="utf-8")
        out["output"] = str(p)
    except Exception:
        pass

    try:
        _cron_meta_update("assess_oddsapi", {"date": str(target), "regions": regions, "events": int(len(events))})
    except Exception:
        pass

    return jsonify(out)


@app.route("/api/cron/ping")
def api_cron_ping():
    """Lightweight cron auth check. Returns 200 quickly if token is valid.

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/local).
    """
    try:
        if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
            return jsonify({"ok": False, "error": "unauthorized"}), 401
        return jsonify({
            "ok": True,
            "utc": datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
        })
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/api/cron/live-lens-tick", methods=["POST", "GET"])
def api_cron_live_lens_tick():
    """Server-side Live Lens logger tick.

    Goal: write Live Lens JSONL logs even when the UI is not open.

    Writes (under NBA_LIVE_LENS_DIR / LIVE_LENS_DIR):
      - live_lens_signals_<date>.jsonl
            - live_lens_projections_<date>.jsonl

    Query params:
      - date: YYYY-MM-DD (optional; defaults via _parse_date_param w/ US cutoff)
      - min_interval_sec: throttle window per (game_id, signal_key) (default 60)
      - max_props_per_game: cap logged player props per game (default 8)
      - recent_window_sec: passed to /api/live_player_lens (default 180)
    - include_total: 1/0 (default 1; covers game + 1H + current quarter totals)
    - include_ats: 1/0 (default 1)
    - include_ml: 1/0 (default 1)
      - include_player_props: 1/0 (default 1)
            - first_bet_only: 1/0 (default 1; when enabled, logs at most the first BET per unique idea)
      - ttl: forwarded to live endpoints (default 15)

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401

    ds = _parse_date_param(request, default_to_today=True)
    try:
        min_interval_sec = int(float((request.args.get("min_interval_sec") or "60").strip()))
    except Exception:
        min_interval_sec = 60
    min_interval_sec = int(max(5, min(3600, min_interval_sec)))

    try:
        max_props = int(float((request.args.get("max_props_per_game") or "8").strip()))
    except Exception:
        max_props = 8
    max_props = int(max(0, min(50, max_props)))

    try:
        recent_window_sec = int(float((request.args.get("recent_window_sec") or "180").strip()))
    except Exception:
        recent_window_sec = 180
    recent_window_sec = int(max(10, min(600, recent_window_sec)))

    first_bet_only = str(request.args.get("first_bet_only") or "1").strip().lower() in {"1", "true", "yes"}

    include_total = str(request.args.get("include_total") or "1").strip().lower() in {"1", "true", "yes"}
    include_ats = str(request.args.get("include_ats") or "1").strip().lower() in {"1", "true", "yes"}
    include_ml = str(request.args.get("include_ml") or "1").strip().lower() in {"1", "true", "yes"}
    include_player_props = str(request.args.get("include_player_props") or "1").strip().lower() in {"1", "true", "yes"}
    ttl = _parse_ttl_param(request, default=15, lo=1, hi=300)

    # Keep the in-memory first-BET cache bounded across long-lived processes.
    try:
        with _live_lens_tick_lock:
            if len(_live_lens_tick_first_bet_logged) > 20000:
                prefix = f"{ds}:"
                for k in list(_live_lens_tick_first_bet_logged.keys()):
                    if not str(k).startswith(prefix):
                        _live_lens_tick_first_bet_logged.pop(k, None)
    except Exception:
        pass

    # Pull tuning (including optional override file) so server-side classifications match UI.
    tune: dict[str, Any] = {}
    try:
        with app.test_client() as c:
            r = c.get(f"/api/live_lens_tuning?ttl={int(max(30, ttl))}")
            if r.status_code == 200:
                j = r.get_json(silent=True)
                if isinstance(j, dict):
                    tune = j
    except Exception:
        tune = {}

    def _klass(abs_edge: float | None, watch: float, bet: float) -> str:
        try:
            if abs_edge is None:
                return "NONE"
            v = float(abs_edge)
            if not math.isfinite(v):
                return "NONE"
            if v >= float(bet):
                return "BET"
            if v >= float(watch):
                return "WATCH"
            return "NONE"
        except Exception:
            return "NONE"

    mk = (tune.get("markets") if isinstance(tune.get("markets"), dict) else {})
    tot_thr = mk.get("total") if isinstance(mk.get("total"), dict) else {"watch": 3.0, "bet": 6.0}
    pp_thr = mk.get("player_prop") if isinstance(mk.get("player_prop"), dict) else {"watch": 2.0, "bet": 4.0}
    try:
        tot_watch = float(tot_thr.get("watch", 3.0))
        tot_bet = float(tot_thr.get("bet", 6.0))
    except Exception:
        tot_watch, tot_bet = 3.0, 6.0
    half_thr = mk.get("half_total") if isinstance(mk.get("half_total"), dict) else {"watch": 3.0, "bet": 6.0}
    qtr_thr = mk.get("quarter_total") if isinstance(mk.get("quarter_total"), dict) else {"watch": 2.0, "bet": 4.0}
    ats_thr = mk.get("ats") if isinstance(mk.get("ats"), dict) else {"watch": 2.0, "bet": 4.0}
    ml_thr = mk.get("ml") if isinstance(mk.get("ml"), dict) else {"watch": 0.03, "bet": 0.06}
    try:
        half_watch = float(half_thr.get("watch", 3.0))
        half_bet = float(half_thr.get("bet", 6.0))
    except Exception:
        half_watch, half_bet = 3.0, 6.0
    try:
        qtr_watch = float(qtr_thr.get("watch", 2.0))
        qtr_bet = float(qtr_thr.get("bet", 4.0))
    except Exception:
        qtr_watch, qtr_bet = 2.0, 4.0
    try:
        ats_watch = float(ats_thr.get("watch", 2.0))
        ats_bet = float(ats_thr.get("bet", 4.0))
    except Exception:
        ats_watch, ats_bet = 2.0, 4.0
    try:
        ml_watch = float(ml_thr.get("watch", 0.03))
        ml_bet = float(ml_thr.get("bet", 0.06))
    except Exception:
        ml_watch, ml_bet = 0.03, 0.06
    try:
        pp_watch = float(pp_thr.get("watch", 2.0))
        pp_bet = float(pp_thr.get("bet", 4.0))
    except Exception:
        pp_watch, pp_bet = 2.0, 4.0

    log_cfg = (tune.get("logging") if isinstance(tune.get("logging"), dict) else {})
    log_mode = str(log_cfg.get("mode") or "bet").strip().lower() or "bet"
    # Cron logger default: BET-only to keep logs decision-focused and small.
    log_mode_props = str(log_cfg.get("player_props_mode") or "bet").strip().lower() or "bet"

    def _allow(mode: str, klass: str) -> bool:
        k = str(klass or "NONE").strip().upper()
        m = str(mode or "bet").strip().lower()
        if m == "bet":
            return k == "BET"
        if m == "watch":
            return k in {"WATCH", "BET"}
        if m == "all":
            return k in {"NONE", "WATCH", "BET"}
        return k == "BET"

    def _poss_avg(home_tri: Any, away_tri: Any, poss_obj: Any) -> float | None:
        try:
            if not isinstance(poss_obj, dict):
                return None
            htri = str(home_tri or "").upper().strip()
            atri = str(away_tri or "").upper().strip()
            hp = poss_obj.get(htri) if htri else None
            ap = poss_obj.get(atri) if atri else None
            if not isinstance(hp, dict):
                hp = poss_obj.get("home") if isinstance(poss_obj.get("home"), dict) else None
            if not isinstance(ap, dict):
                ap = poss_obj.get("away") if isinstance(poss_obj.get("away"), dict) else None
            hpv = _safe_float((hp or {}).get("poss_est")) if isinstance(hp, dict) else None
            apv = _safe_float((ap or {}).get("poss_est")) if isinstance(ap, dict) else None
            if hpv is None or apv is None:
                return None
            return float((float(hpv) + float(apv)) / 2.0)
        except Exception:
            return None

    def _edge_shrink(raw_diff: float | None, poss_live: float | None, elapsed_min: float | None, total_minutes: float) -> dict[str, float | None]:
        try:
            if raw_diff is None:
                return {"diff_shrunk": None, "lambda": None, "lambda_poss": None, "lambda_time": None}
            tm = float(total_minutes)
            scale = max(0.15, tm / 48.0) if tm > 0 else 1.0
            poss_min = 10.0 * scale
            poss_range = 25.0 * scale
            time_min = 6.0 * scale
            time_range = 18.0 * scale
            if poss_live is None:
                w_poss = 1.0
            else:
                w_poss = max(0.0, min(1.0, (float(poss_live) - poss_min) / max(1e-6, poss_range)))
            if elapsed_min is None:
                w_time = 1.0
            else:
                w_time = max(0.0, min(1.0, (float(elapsed_min) - time_min) / max(1e-6, time_range)))
            lam = max(0.0, min(1.0, min(w_poss, w_time)))
            return {
                "diff_shrunk": float(raw_diff) * lam,
                "lambda": lam,
                "lambda_poss": w_poss,
                "lambda_time": w_time,
            }
        except Exception:
            return {"diff_shrunk": raw_diff, "lambda": None, "lambda_poss": None, "lambda_time": None}

    def _scope_projection(intervals_obj: Any, *, scope_start_min: float, scope_end_min: float, elapsed_scope_min: float, actual_total: float | None) -> tuple[float | None, float | None, float | None]:
        try:
            if actual_total is None or intervals_obj is None:
                return (None, None, None)
            start_min = float(scope_start_min)
            end_min = float(scope_end_min)
            elapsed_scope = max(0.0, min(float(end_min - start_min), float(elapsed_scope_min)))
            elapsed_abs = start_min + elapsed_scope
            sim_start = _live_interp_cum_p50(intervals_obj, elapsed_min=float(start_min), total_minutes=int(round(end_min))) or 0.0
            sim_at_cum = _live_interp_cum_p50(intervals_obj, elapsed_min=float(elapsed_abs), total_minutes=int(round(end_min)))
            sim_end_cum = _live_interp_cum_p50(intervals_obj, elapsed_min=float(end_min), total_minutes=int(round(end_min)))
            if sim_at_cum is None or sim_end_cum is None:
                return (None, None, None)
            sim_at = float(sim_at_cum) - float(sim_start)
            sim_final = float(sim_end_cum) - float(sim_start)
            proj = max(float(actual_total), float(actual_total) + (float(sim_final) - float(sim_at)))
            return (float(sim_at), float(sim_final), float(proj))
        except Exception:
            return (None, None, None)

    def _scope_pace_context(*, actual_total: float | None, scope_minutes: float, elapsed_scope: float | None, sim_final_scope: float | None, poss_live: float | None, exp_pace: float | None) -> dict[str, Any]:
        ctx: dict[str, Any] = {
            "poss_live": poss_live,
            "poss_expected_so_far": None,
            "poss_expected_full": None,
            "exp_ppp": None,
            "act_ppp": None,
            "pace_ratio": None,
        }
        try:
            if exp_pace is None or scope_minutes <= 0:
                return ctx
            poss_expected_full = float(exp_pace) * (float(scope_minutes) / 48.0)
            poss_expected_so_far = None
            if elapsed_scope is not None:
                poss_expected_so_far = float(exp_pace) * (float(max(0.0, min(float(scope_minutes), float(elapsed_scope)))) / 48.0)
            exp_ppp = None
            if sim_final_scope is not None and poss_expected_full > 1e-9:
                exp_ppp = float(sim_final_scope) / poss_expected_full
            act_ppp = None
            if actual_total is not None and poss_live is not None and float(poss_live) > 1e-9:
                act_ppp = float(actual_total) / float(poss_live)
            pace_ratio = None
            if poss_live is not None and poss_expected_so_far is not None and poss_expected_so_far > 1e-9:
                pace_ratio = float(poss_live) / float(poss_expected_so_far)
            ctx.update({
                "poss_expected_so_far": poss_expected_so_far,
                "poss_expected_full": poss_expected_full,
                "exp_ppp": exp_ppp,
                "act_ppp": act_ppp,
                "pace_ratio": pace_ratio,
            })
            return ctx
        except Exception:
            return ctx

    # Find in-progress games.
    try:
        _src, sb_games = _live_build_scoreboard_games(ds)
    except Exception:
        sb_games = []

    inprog: list[dict[str, Any]] = []
    for g in sb_games or []:
        try:
            if bool(g.get("in_progress")) and not bool(g.get("final")):
                inprog.append(g)
        except Exception:
            continue

    event_ids = [str(g.get("espn_event_id") or "").strip() for g in inprog]
    event_ids = [x for x in event_ids if x]

    now = datetime.utcnow().isoformat(timespec="seconds") + "Z"
    bucket_key = str(int(time.time() // float(min_interval_sec)))

    wrote_signals = 0
    wrote_projections = 0
    skipped_throttle = 0
    skipped_first_bet = 0
    errors: list[str] = []

    # ---- Game totals (SmartSim ladder + live score) ----
    if include_total:
        try:
            with app.test_client() as c:
                # Fetch current lines + period totals for all in-progress games.
                lines_by_eid: dict[str, Any] = {}
                pbp_by_eid: dict[str, Any] = {}
                if event_ids:
                    r = c.get(
                        f"/api/live_lines?ttl={int(ttl)}&date={ds}&event_ids={','.join(event_ids)}&include_period_totals=1"
                    )
                    if r.status_code == 200:
                        j = r.get_json(silent=True)
                        if isinstance(j, dict) and isinstance(j.get("games"), list):
                            for rec in j.get("games") or []:
                                if isinstance(rec, dict) and rec.get("event_id") is not None:
                                    lines_by_eid[str(rec.get("event_id"))] = rec
                    r2 = c.get(
                        f"/api/live_pbp_stats?ttl={int(ttl)}&date={ds}&event_ids={','.join(event_ids)}&recent_window_sec={int(recent_window_sec)}"
                    )
                    if r2.status_code == 200:
                        j2 = r2.get_json(silent=True)
                        if isinstance(j2, dict) and isinstance(j2.get("games"), list):
                            for rec in j2.get("games") or []:
                                if isinstance(rec, dict) and rec.get("event_id") is not None:
                                    pbp_by_eid[str(rec.get("event_id"))] = rec

                for g in inprog:
                    try:
                        eid = str(g.get("espn_event_id") or "").strip()
                        gid = g.get("game_id")
                        home = g.get("home")
                        away = g.get("away")
                        period = _safe_int(g.get("period"))
                        clock = g.get("clock")
                        sec_left_period = _live_parse_clock_to_sec_left(clock)
                        elapsed_min = _live_game_elapsed_minutes(period, clock, is_final=False)
                        try:
                            total_pts = float((_safe_int(g.get("home_pts")) or 0) + (_safe_int(g.get("away_pts")) or 0))
                        except Exception:
                            total_pts = None

                        rec = lines_by_eid.get(eid) if lines_by_eid else None
                        lines = rec.get("lines") if isinstance(rec, dict) and isinstance(rec.get("lines"), dict) else {}
                        game_total_line = _safe_float(lines.get("total"))
                        home_spread = _safe_float(lines.get("home_spread"))
                        home_ml = _safe_float(lines.get("home_ml"))
                        away_ml = _safe_float(lines.get("away_ml"))
                        period_totals = lines.get("period_totals") if isinstance(lines.get("period_totals"), dict) else {}

                        pbp_rec = pbp_by_eid.get(eid) if pbp_by_eid else None
                        pbp_possessions = pbp_rec.get("pbp_possessions") if isinstance(pbp_rec, dict) and isinstance(pbp_rec.get("pbp_possessions"), dict) else {}
                        pbp_possessions_periods = pbp_rec.get("pbp_possessions_periods") if isinstance(pbp_rec, dict) and isinstance(pbp_rec.get("pbp_possessions_periods"), dict) else {}
                        pbp_quarters = pbp_rec.get("pbp_quarters") if isinstance(pbp_rec, dict) and isinstance(pbp_rec.get("pbp_quarters"), dict) else {}
                        pbp_recent = pbp_rec.get("pbp_recent") if isinstance(pbp_rec, dict) and isinstance(pbp_rec.get("pbp_recent"), dict) else {}

                        home_margin = None
                        try:
                            if g.get("home_pts") is not None and g.get("away_pts") is not None:
                                home_margin = float((_safe_int(g.get("home_pts")) or 0) - (_safe_int(g.get("away_pts")) or 0))
                        except Exception:
                            home_margin = None

                        game_min_left = (48.0 - float(elapsed_min)) if elapsed_min is not None else None
                        half_min_left = None
                        if period is not None and sec_left_period is not None:
                            try:
                                if int(period) <= 2:
                                    half_min_left = (((2 - int(period)) * 12 * 60) + int(sec_left_period)) / 60.0
                                elif int(period) > 2:
                                    half_min_left = 0.0
                            except Exception:
                                half_min_left = None

                        ss = _live_load_smart_sim_by_game_id(str(ds), str(gid or "")) if gid else None
                        score = ss.get("score") if isinstance(ss, dict) and isinstance(ss.get("score"), dict) else {}
                        ctx_obj = ss.get("context") if isinstance(ss, dict) and isinstance(ss.get("context"), dict) else {}
                        total_mean = _safe_float(score.get("total_mean"))
                        margin_mean = _safe_float(score.get("margin_mean"))
                        p_home_win = _safe_float(score.get("p_home_win"))
                        home_pace = _safe_float(ctx_obj.get("home_pace"))
                        away_pace = _safe_float(ctx_obj.get("away_pace"))
                        exp_pace = ((float(home_pace) + float(away_pace)) / 2.0) if (home_pace is not None and away_pace is not None) else None

                        intervals = None
                        if isinstance(ss, dict):
                            itv1 = ss.get("intervals_1m") if isinstance(ss.get("intervals_1m"), dict) else None
                            itv3 = ss.get("intervals") if isinstance(ss.get("intervals"), dict) else None
                            intervals = itv1 or itv3

                        game_poss_live = _poss_avg(home, away, pbp_possessions)
                        recent_poss_live = _poss_avg(home, away, pbp_recent.get("possessions") if isinstance(pbp_recent, dict) else None)
                        recent_pts = _safe_float(pbp_recent.get("points_total")) if isinstance(pbp_recent, dict) else None
                        recent_window_used = _safe_float(pbp_recent.get("window_sec")) if isinstance(pbp_recent, dict) else None

                        # Game total
                        if game_total_line is not None and total_pts is not None and elapsed_min is not None:
                            sim_at_g, sim_final_g, proj_g = _scope_projection(
                                intervals,
                                scope_start_min=0.0,
                                scope_end_min=48.0,
                                elapsed_scope_min=float(elapsed_min),
                                actual_total=float(total_pts),
                            )
                            if proj_g is None and total_mean is not None:
                                sim_at_g = float(total_mean) * float(max(0.0, min(48.0, float(elapsed_min)))) / 48.0
                                sim_final_g = float(total_mean)
                                proj_g = max(float(total_pts), float(total_pts) + (float(sim_final_g) - float(sim_at_g)))
                            if proj_g is not None:
                                edge_raw_g = float(proj_g) - float(game_total_line)
                                shrink_g = _edge_shrink(edge_raw_g, game_poss_live, elapsed_min, 48.0)
                                edge_g = _safe_float(shrink_g.get("diff_shrunk"))
                                edge_g = edge_raw_g if edge_g is None else float(edge_g)
                                klass = _klass(abs(edge_g), tot_watch, tot_bet)
                                if _allow(log_mode, klass):
                                    if not (first_bet_only and klass != "BET"):
                                        side = "OVER" if edge_g > 0 else ("UNDER" if edge_g < 0 else None)
                                        if not (first_bet_only and side is None):
                                            first_bet_k = None
                                            if first_bet_only:
                                                first_bet_k = f"{ds}:{str(gid)}:total:game:{str(side)}"
                                                with _live_lens_tick_lock:
                                                    if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                                        skipped_first_bet += 1
                                                        first_bet_k = None
                                                    else:
                                                        _live_lens_tick_first_bet_logged[first_bet_k] = "pending"
                                            if (not first_bet_only) or (first_bet_k is not None):
                                                signal_key = "game_total"
                                                throttle_k = f"{str(gid)}:{signal_key}"
                                                with _live_lens_tick_lock:
                                                    last = _live_lens_tick_last_logged.get(throttle_k)
                                                    if last == bucket_key:
                                                        skipped_throttle += 1
                                                        throttle_ok = False
                                                    else:
                                                        _live_lens_tick_last_logged[throttle_k] = bucket_key
                                                        throttle_ok = True
                                                if throttle_ok:
                                                    game_ctx = _scope_pace_context(
                                                        actual_total=float(total_pts),
                                                        scope_minutes=48.0,
                                                        elapsed_scope=float(elapsed_min),
                                                        sim_final_scope=sim_final_g,
                                                        poss_live=game_poss_live,
                                                        exp_pace=exp_pace,
                                                    )
                                                    body = {
                                                        "date": ds,
                                                        "game_id": gid,
                                                        "event_id": eid,
                                                        "home": home,
                                                        "away": away,
                                                        "period": period,
                                                        "sec_left_period": sec_left_period,
                                                        "margin_home": home_margin,
                                                        "tuning_source": "cron",
                                                        "schema_version": 2,
                                                        "klass": klass,
                                                        "horizon": "game",
                                                        "market": "total",
                                                        "signal_key": signal_key,
                                                        "elapsed": float(elapsed_min),
                                                        "remaining": float(game_min_left) if game_min_left is not None else None,
                                                        "total_points": float(total_pts),
                                                        "live_line": float(game_total_line),
                                                        "side": side,
                                                        "edge": float(edge_g),
                                                        "edge_raw": float(edge_raw_g),
                                                        "edge_adj": float(edge_g),
                                                        "pred": float(proj_g),
                                                        "strength": float(abs(edge_g)),
                                                        "context": {
                                                            "thr_watch": float(tot_watch),
                                                            "thr_bet": float(tot_bet),
                                                            "edge_shrink_lambda": _safe_float(shrink_g.get("lambda")),
                                                            "edge_shrink_lambda_poss": _safe_float(shrink_g.get("lambda_poss")),
                                                            "edge_shrink_lambda_time": _safe_float(shrink_g.get("lambda_time")),
                                                            "exp_home_pace": home_pace,
                                                            "exp_away_pace": away_pace,
                                                            "exp_total_mean": total_mean,
                                                            "sim_at": sim_at_g,
                                                            "sim_final": sim_final_g,
                                                            "recent_window_sec": recent_window_used,
                                                            "recent_window_poss": recent_poss_live,
                                                            "recent_window_pts": recent_pts,
                                                            **game_ctx,
                                                        },
                                                        "received_at": now,
                                                        "tick_bucket": bucket_key,
                                                    }
                                                    ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                                                    if ok:
                                                        wrote_signals += 1
                                                        if first_bet_only and first_bet_k is not None:
                                                            with _live_lens_tick_lock:
                                                                _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                                                    else:
                                                        errors.append(f"total:{eid}:{info}")
                                                        if first_bet_only and first_bet_k is not None:
                                                            with _live_lens_tick_lock:
                                                                _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                                                    throttle_p = f"{str(gid)}:{signal_key}:proj"
                                                    with _live_lens_tick_lock:
                                                        lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                                        if lastp != bucket_key:
                                                            _live_lens_tick_last_proj_logged[throttle_p] = bucket_key
                                                            proj_ok = True
                                                        else:
                                                            proj_ok = False
                                                    if proj_ok:
                                                        proj_body = {
                                                            "date": ds,
                                                            "game_id": gid,
                                                            "event_id": eid,
                                                            "home": home,
                                                            "away": away,
                                                            "period": period,
                                                            "sec_left_period": sec_left_period,
                                                            "klass": klass,
                                                            "horizon": "game",
                                                            "market": "total",
                                                            "proj_key": signal_key,
                                                            "elapsed": float(elapsed_min),
                                                            "remaining": float(game_min_left) if game_min_left is not None else None,
                                                            "total_points": float(total_pts),
                                                            "line": float(game_total_line),
                                                            "live_line": float(game_total_line),
                                                            "side": side,
                                                            "proj": float(proj_g),
                                                            "sim_mu": sim_final_g,
                                                            "strength": float(abs(edge_g)),
                                                            "context": {
                                                                "scope_context": {
                                                                    "pace_final": float(proj_g),
                                                                    "sim_at": sim_at_g,
                                                                    "sim_final": sim_final_g,
                                                                    **game_ctx,
                                                                }
                                                            },
                                                            "received_at": now,
                                                            "tick_bucket": bucket_key,
                                                        }
                                                        okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                                                        if okp:
                                                            wrote_projections += 1
                                                        else:
                                                            errors.append(f"proj_total:{eid}:{infop}")

                        # 1H total
                        if total_pts is not None and period is not None and int(period) <= 2 and half_min_left is not None:
                            h1_line = _safe_float(period_totals.get("h1")) if isinstance(period_totals, dict) else None
                            if h1_line is not None:
                                elapsed_h = float(max(0.0, min(24.0, 24.0 - float(half_min_left))))
                                sim_at_h, sim_final_h, proj_h = _scope_projection(
                                    intervals,
                                    scope_start_min=0.0,
                                    scope_end_min=24.0,
                                    elapsed_scope_min=elapsed_h,
                                    actual_total=float(total_pts),
                                )
                                if proj_h is not None:
                                    poss_h = _poss_avg(home, away, pbp_possessions_periods.get("h1") if isinstance(pbp_possessions_periods, dict) else None)
                                    edge_raw_h = float(proj_h) - float(h1_line)
                                    shrink_h = _edge_shrink(edge_raw_h, poss_h, elapsed_h, 24.0)
                                    edge_h = _safe_float(shrink_h.get("diff_shrunk"))
                                    edge_h = edge_raw_h if edge_h is None else float(edge_h)
                                    klass_h = _klass(abs(edge_h), half_watch, half_bet)
                                    if _allow(log_mode, klass_h):
                                        if not (first_bet_only and klass_h != "BET"):
                                            side_h = "OVER" if edge_h > 0 else ("UNDER" if edge_h < 0 else None)
                                            if not (first_bet_only and side_h is None):
                                                first_bet_k = None
                                                if first_bet_only:
                                                    first_bet_k = f"{ds}:{str(gid)}:half_total:h1:{str(side_h)}"
                                                    with _live_lens_tick_lock:
                                                        if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                                            skipped_first_bet += 1
                                                            first_bet_k = None
                                                        else:
                                                            _live_lens_tick_first_bet_logged[first_bet_k] = "pending"
                                                if (not first_bet_only) or (first_bet_k is not None):
                                                    signal_key = "h1_total"
                                                    throttle_k = f"{str(gid)}:{signal_key}"
                                                    with _live_lens_tick_lock:
                                                        last = _live_lens_tick_last_logged.get(throttle_k)
                                                        if last == bucket_key:
                                                            skipped_throttle += 1
                                                            throttle_ok = False
                                                        else:
                                                            _live_lens_tick_last_logged[throttle_k] = bucket_key
                                                            throttle_ok = True
                                                    if throttle_ok:
                                                        half_ctx = _scope_pace_context(
                                                            actual_total=float(total_pts),
                                                            scope_minutes=24.0,
                                                            elapsed_scope=elapsed_h,
                                                            sim_final_scope=sim_final_h,
                                                            poss_live=poss_h,
                                                            exp_pace=exp_pace,
                                                        )
                                                        body = {
                                                            "date": ds,
                                                            "game_id": gid,
                                                            "event_id": eid,
                                                            "home": home,
                                                            "away": away,
                                                            "period": period,
                                                            "sec_left_period": sec_left_period,
                                                            "margin_home": home_margin,
                                                            "tuning_source": "cron",
                                                            "schema_version": 2,
                                                            "klass": klass_h,
                                                            "horizon": "h1",
                                                            "market": "half_total",
                                                            "signal_key": signal_key,
                                                            "elapsed": float(elapsed_h),
                                                            "remaining": float(half_min_left),
                                                            "total_points": float(total_pts),
                                                            "live_line": float(h1_line),
                                                            "side": side_h,
                                                            "edge": float(edge_h),
                                                            "edge_raw": float(edge_raw_h),
                                                            "edge_adj": float(edge_h),
                                                            "pred": float(proj_h),
                                                            "strength": float(abs(edge_h)),
                                                            "context": {
                                                                "thr_watch": float(half_watch),
                                                                "thr_bet": float(half_bet),
                                                                "edge_shrink_lambda": _safe_float(shrink_h.get("lambda")),
                                                                "edge_shrink_lambda_poss": _safe_float(shrink_h.get("lambda_poss")),
                                                                "edge_shrink_lambda_time": _safe_float(shrink_h.get("lambda_time")),
                                                                **half_ctx,
                                                            },
                                                            "received_at": now,
                                                            "tick_bucket": bucket_key,
                                                        }
                                                        ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                                                        if ok:
                                                            wrote_signals += 1
                                                            if first_bet_only and first_bet_k is not None:
                                                                with _live_lens_tick_lock:
                                                                    _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                                                        else:
                                                            errors.append(f"half_total:{eid}:{info}")
                                                            if first_bet_only and first_bet_k is not None:
                                                                with _live_lens_tick_lock:
                                                                    _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                                                        throttle_p = f"{str(gid)}:{signal_key}:proj"
                                                        with _live_lens_tick_lock:
                                                            lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                                            if lastp != bucket_key:
                                                                _live_lens_tick_last_proj_logged[throttle_p] = bucket_key
                                                                proj_ok = True
                                                            else:
                                                                proj_ok = False
                                                        if proj_ok:
                                                            proj_body = {
                                                                "date": ds,
                                                                "game_id": gid,
                                                                "event_id": eid,
                                                                "home": home,
                                                                "away": away,
                                                                "period": period,
                                                                "sec_left_period": sec_left_period,
                                                                "klass": klass_h,
                                                                "horizon": "h1",
                                                                "market": "half_total",
                                                                "proj_key": signal_key,
                                                                "elapsed": float(elapsed_h),
                                                                "remaining": float(half_min_left),
                                                                "total_points": float(total_pts),
                                                                "line": float(h1_line),
                                                                "live_line": float(h1_line),
                                                                "side": side_h,
                                                                "proj": float(proj_h),
                                                                "sim_mu": sim_final_h,
                                                                "strength": float(abs(edge_h)),
                                                                "context": {"scope_context": {"pace_final": float(proj_h), "sim_at": sim_at_h, "sim_final": sim_final_h, **half_ctx}},
                                                                "received_at": now,
                                                                "tick_bucket": bucket_key,
                                                            }
                                                            okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                                                            if okp:
                                                                wrote_projections += 1
                                                            else:
                                                                errors.append(f"proj_half_total:{eid}:{infop}")

                        # Current quarter total
                        q_current = pbp_quarters.get("current") if isinstance(pbp_quarters, dict) and isinstance(pbp_quarters.get("current"), dict) else {}
                        q_num = _safe_int(q_current.get("period")) if isinstance(q_current, dict) else None
                        if q_num is None:
                            q_num = period if (period is not None and 1 <= int(period) <= 4) else None
                        if q_num is not None and sec_left_period is not None and 1 <= int(q_num) <= 4:
                            q_key = f"q{int(q_num)}"
                            q_line = _safe_float(period_totals.get(q_key)) if isinstance(period_totals, dict) else None
                            q_total_now = _safe_float(q_current.get("q_total")) if isinstance(q_current, dict) else None
                            if q_total_now is None:
                                q_totals = pbp_quarters.get("q_totals") if isinstance(pbp_quarters, dict) and isinstance(pbp_quarters.get("q_totals"), dict) else {}
                                q_total_now = _safe_float(q_totals.get(q_key)) if isinstance(q_totals, dict) else None
                            if q_line is not None and q_total_now is not None:
                                elapsed_q = float(max(0.0, min(12.0, 12.0 - (float(sec_left_period) / 60.0))))
                                q_start = float((int(q_num) - 1) * 12)
                                q_end = float(int(q_num) * 12)
                                sim_at_q, sim_final_q, proj_q = _scope_projection(
                                    intervals,
                                    scope_start_min=q_start,
                                    scope_end_min=q_end,
                                    elapsed_scope_min=elapsed_q,
                                    actual_total=float(q_total_now),
                                )
                                if proj_q is not None:
                                    poss_q = _poss_avg(home, away, pbp_possessions_periods.get(q_key) if isinstance(pbp_possessions_periods, dict) else None)
                                    edge_raw_q = float(proj_q) - float(q_line)
                                    shrink_q = _edge_shrink(edge_raw_q, poss_q, elapsed_q, 12.0)
                                    edge_q = _safe_float(shrink_q.get("diff_shrunk"))
                                    edge_q = edge_raw_q if edge_q is None else float(edge_q)
                                    klass_q = _klass(abs(edge_q), qtr_watch, qtr_bet)
                                    if _allow(log_mode, klass_q):
                                        if not (first_bet_only and klass_q != "BET"):
                                            side_q = "OVER" if edge_q > 0 else ("UNDER" if edge_q < 0 else None)
                                            if not (first_bet_only and side_q is None):
                                                first_bet_k = None
                                                if first_bet_only:
                                                    first_bet_k = f"{ds}:{str(gid)}:quarter_total:{q_key}:{str(side_q)}"
                                                    with _live_lens_tick_lock:
                                                        if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                                            skipped_first_bet += 1
                                                            first_bet_k = None
                                                        else:
                                                            _live_lens_tick_first_bet_logged[first_bet_k] = "pending"
                                                if (not first_bet_only) or (first_bet_k is not None):
                                                    signal_key = "q_total"
                                                    throttle_k = f"{str(gid)}:{signal_key}:{q_key}"
                                                    with _live_lens_tick_lock:
                                                        last = _live_lens_tick_last_logged.get(throttle_k)
                                                        if last == bucket_key:
                                                            skipped_throttle += 1
                                                            throttle_ok = False
                                                        else:
                                                            _live_lens_tick_last_logged[throttle_k] = bucket_key
                                                            throttle_ok = True
                                                    if throttle_ok:
                                                        quarter_ctx = _scope_pace_context(
                                                            actual_total=float(q_total_now),
                                                            scope_minutes=12.0,
                                                            elapsed_scope=elapsed_q,
                                                            sim_final_scope=sim_final_q,
                                                            poss_live=poss_q,
                                                            exp_pace=exp_pace,
                                                        )
                                                        body = {
                                                            "date": ds,
                                                            "game_id": gid,
                                                            "event_id": eid,
                                                            "home": home,
                                                            "away": away,
                                                            "period": period,
                                                            "sec_left_period": sec_left_period,
                                                            "margin_home": home_margin,
                                                            "tuning_source": "cron",
                                                            "schema_version": 2,
                                                            "klass": klass_q,
                                                            "horizon": q_key,
                                                            "market": "quarter_total",
                                                            "signal_key": signal_key,
                                                            "elapsed": float(elapsed_q),
                                                            "remaining": float(sec_left_period) / 60.0,
                                                            "total_points": float(q_total_now),
                                                            "live_line": float(q_line),
                                                            "side": side_q,
                                                            "edge": float(edge_q),
                                                            "edge_raw": float(edge_raw_q),
                                                            "edge_adj": float(edge_q),
                                                            "pred": float(proj_q),
                                                            "strength": float(abs(edge_q)),
                                                            "context": {
                                                                "scope_present": 1,
                                                                "q_num": int(q_num),
                                                                "thr_watch": float(qtr_watch),
                                                                "thr_bet": float(qtr_bet),
                                                                "edge_shrink_lambda": _safe_float(shrink_q.get("lambda")),
                                                                "edge_shrink_lambda_poss": _safe_float(shrink_q.get("lambda_poss")),
                                                                "edge_shrink_lambda_time": _safe_float(shrink_q.get("lambda_time")),
                                                                **quarter_ctx,
                                                            },
                                                            "received_at": now,
                                                            "tick_bucket": bucket_key,
                                                        }
                                                        ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                                                        if ok:
                                                            wrote_signals += 1
                                                            if first_bet_only and first_bet_k is not None:
                                                                with _live_lens_tick_lock:
                                                                    _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                                                        else:
                                                            errors.append(f"quarter_total:{eid}:{info}")
                                                            if first_bet_only and first_bet_k is not None:
                                                                with _live_lens_tick_lock:
                                                                    _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                                                        throttle_p = f"{str(gid)}:{signal_key}:proj:{q_key}"
                                                        with _live_lens_tick_lock:
                                                            lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                                            if lastp != bucket_key:
                                                                _live_lens_tick_last_proj_logged[throttle_p] = bucket_key
                                                                proj_ok = True
                                                            else:
                                                                proj_ok = False
                                                        if proj_ok:
                                                            proj_body = {
                                                                "date": ds,
                                                                "game_id": gid,
                                                                "event_id": eid,
                                                                "home": home,
                                                                "away": away,
                                                                "period": period,
                                                                "sec_left_period": sec_left_period,
                                                                "klass": klass_q,
                                                                "horizon": q_key,
                                                                "market": "quarter_total",
                                                                "proj_key": f"{signal_key}:{q_key}",
                                                                "elapsed": float(elapsed_q),
                                                                "remaining": float(sec_left_period) / 60.0,
                                                                "total_points": float(q_total_now),
                                                                "line": float(q_line),
                                                                "live_line": float(q_line),
                                                                "side": side_q,
                                                                "proj": float(proj_q),
                                                                "sim_mu": sim_final_q,
                                                                "strength": float(abs(edge_q)),
                                                                "context": {"q_num": int(q_num), "scope_context": {"pace_final": float(proj_q), "sim_at": sim_at_q, "sim_final": sim_final_q, **quarter_ctx}},
                                                                "received_at": now,
                                                                "tick_bucket": bucket_key,
                                                            }
                                                            okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                                                            if okp:
                                                                wrote_projections += 1
                                                            else:
                                                                errors.append(f"proj_quarter_total:{eid}:{infop}")

                        # ATS
                        if include_ats and home_spread is not None and margin_mean is not None and home_margin is not None and elapsed_min is not None:
                            blend_w = float(max(0.0, min(1.0, float(elapsed_min) / 48.0)))
                            adj_margin_home = (1.0 - blend_w) * float(margin_mean) + blend_w * float(home_margin)
                            edge_home = adj_margin_home + float(home_spread)
                            edge_away = -adj_margin_home - float(home_spread)
                            pick_home = abs(edge_home) >= abs(edge_away)
                            ats_edge = float(edge_home if pick_home else edge_away)
                            ats_side = str(home if pick_home else away)
                            ats_klass = _klass(abs(ats_edge), ats_watch, ats_bet)
                            if _allow(log_mode, ats_klass):
                                if not (first_bet_only and ats_klass != "BET"):
                                    first_bet_k = None
                                    if first_bet_only:
                                        first_bet_k = f"{ds}:{str(gid)}:ats:game:{ats_side}"
                                        with _live_lens_tick_lock:
                                            if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                                skipped_first_bet += 1
                                                first_bet_k = None
                                            else:
                                                _live_lens_tick_first_bet_logged[first_bet_k] = "pending"
                                    if (not first_bet_only) or (first_bet_k is not None):
                                        signal_key = "game_ats"
                                        throttle_k = f"{str(gid)}:{signal_key}"
                                        with _live_lens_tick_lock:
                                            last = _live_lens_tick_last_logged.get(throttle_k)
                                            if last == bucket_key:
                                                skipped_throttle += 1
                                                throttle_ok = False
                                            else:
                                                _live_lens_tick_last_logged[throttle_k] = bucket_key
                                                throttle_ok = True
                                        if throttle_ok:
                                            body = {
                                                "date": ds,
                                                "game_id": gid,
                                                "event_id": eid,
                                                "home": home,
                                                "away": away,
                                                "period": period,
                                                "sec_left_period": sec_left_period,
                                                "margin_home": home_margin,
                                                "tuning_source": "cron",
                                                "schema_version": 2,
                                                "klass": ats_klass,
                                                "horizon": "game",
                                                "market": "ats",
                                                "signal_key": signal_key,
                                                "elapsed": float(elapsed_min),
                                                "remaining": float(game_min_left) if game_min_left is not None else None,
                                                "total_points": float(total_pts) if total_pts is not None else None,
                                                "live_line": float(home_spread),
                                                "side": ats_side,
                                                "edge": float(ats_edge),
                                                "edge_raw": float(ats_edge),
                                                "edge_adj": float(ats_edge),
                                                "strength": float(abs(ats_edge)),
                                                "context": {
                                                    "thr_watch": float(ats_watch),
                                                    "thr_bet": float(ats_bet),
                                                    "spr_home": float(home_spread),
                                                    "pregame_margin_mean": float(margin_mean),
                                                    "cur_margin_home": float(home_margin),
                                                    "elapsed_min": float(elapsed_min),
                                                    "blend_w": float(blend_w),
                                                    "adj_margin_home": float(adj_margin_home),
                                                    "edge_home": float(edge_home),
                                                    "edge_away": float(edge_away),
                                                    "pick_home": 1 if pick_home else 0,
                                                },
                                                "received_at": now,
                                                "tick_bucket": bucket_key,
                                            }
                                            ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                                            if ok:
                                                wrote_signals += 1
                                                if first_bet_only and first_bet_k is not None:
                                                    with _live_lens_tick_lock:
                                                        _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                                            else:
                                                errors.append(f"ats:{eid}:{info}")
                                                if first_bet_only and first_bet_k is not None:
                                                    with _live_lens_tick_lock:
                                                        _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                                            throttle_p = f"{str(gid)}:{signal_key}:proj"
                                            with _live_lens_tick_lock:
                                                lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                                if lastp != bucket_key:
                                                    _live_lens_tick_last_proj_logged[throttle_p] = bucket_key
                                                    proj_ok = True
                                                else:
                                                    proj_ok = False
                                            if proj_ok:
                                                proj_body = {
                                                    "date": ds,
                                                    "game_id": gid,
                                                    "event_id": eid,
                                                    "home": home,
                                                    "away": away,
                                                    "period": period,
                                                    "sec_left_period": sec_left_period,
                                                    "klass": ats_klass,
                                                    "horizon": "game",
                                                    "market": "ats",
                                                    "proj_key": signal_key,
                                                    "elapsed": float(elapsed_min),
                                                    "remaining": float(game_min_left) if game_min_left is not None else None,
                                                    "line": float(home_spread),
                                                    "live_line": float(home_spread),
                                                    "side": ats_side,
                                                    "proj": float(adj_margin_home),
                                                    "sim_mu": float(margin_mean),
                                                    "strength": float(abs(ats_edge)),
                                                    "context": {
                                                        "pick_home": 1 if pick_home else 0,
                                                        "edge_home": float(edge_home),
                                                        "edge_away": float(edge_away),
                                                    },
                                                    "received_at": now,
                                                    "tick_bucket": bucket_key,
                                                }
                                                okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                                                if okp:
                                                    wrote_projections += 1
                                                else:
                                                    errors.append(f"proj_ats:{eid}:{infop}")

                        # ML
                        if include_ml and p_home_win is not None and home_ml is not None and away_ml is not None and home_margin is not None and elapsed_min is not None:
                            p_home_implied = _american_to_implied_prob(home_ml)
                            p_away_implied = _american_to_implied_prob(away_ml)
                            if p_home_implied is not None and p_away_implied is not None:
                                min_left = float(max(0.0, 48.0 - float(elapsed_min)))
                                scale = 6.0 + (0.35 * min_left)
                                try:
                                    poss_exp_so_far = (float(exp_pace) * float(elapsed_min) / 48.0) if (exp_pace is not None and elapsed_min is not None) else None
                                    if game_poss_live is not None and poss_exp_so_far is not None and poss_exp_so_far > 5.0:
                                        ratio = float(game_poss_live) / float(poss_exp_so_far)
                                        ratio_clamped = max(0.6, min(1.6, ratio))
                                        scale = scale / math.sqrt(ratio_clamped)
                                except Exception:
                                    pass
                                p_home_score = 1.0 / (1.0 + math.exp(-(float(home_margin) / float(scale))))
                                blend_w = float(max(0.0, min(1.0, float(elapsed_min) / 48.0)))
                                p_home_model = (1.0 - blend_w) * float(p_home_win) + blend_w * float(p_home_score)
                                edge_home = float(p_home_model) - float(p_home_implied)
                                edge_away = float(1.0 - p_home_model) - float(p_away_implied)
                                pick_home = abs(edge_home) >= abs(edge_away)
                                ml_edge = float(edge_home if pick_home else edge_away)
                                ml_side = str(home if pick_home else away)
                                ml_klass = _klass(abs(ml_edge), ml_watch, ml_bet)
                                if _allow(log_mode, ml_klass):
                                    if not (first_bet_only and ml_klass != "BET"):
                                        first_bet_k = None
                                        if first_bet_only:
                                            first_bet_k = f"{ds}:{str(gid)}:ml:game:{ml_side}"
                                            with _live_lens_tick_lock:
                                                if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                                    skipped_first_bet += 1
                                                    first_bet_k = None
                                                else:
                                                    _live_lens_tick_first_bet_logged[first_bet_k] = "pending"
                                        if (not first_bet_only) or (first_bet_k is not None):
                                            signal_key = "game_ml"
                                            throttle_k = f"{str(gid)}:{signal_key}"
                                            with _live_lens_tick_lock:
                                                last = _live_lens_tick_last_logged.get(throttle_k)
                                                if last == bucket_key:
                                                    skipped_throttle += 1
                                                    throttle_ok = False
                                                else:
                                                    _live_lens_tick_last_logged[throttle_k] = bucket_key
                                                    throttle_ok = True
                                            if throttle_ok:
                                                body = {
                                                    "date": ds,
                                                    "game_id": gid,
                                                    "event_id": eid,
                                                    "home": home,
                                                    "away": away,
                                                    "period": period,
                                                    "sec_left_period": sec_left_period,
                                                    "margin_home": home_margin,
                                                    "tuning_source": "cron",
                                                    "schema_version": 2,
                                                    "klass": ml_klass,
                                                    "horizon": "game",
                                                    "market": "ml",
                                                    "signal_key": signal_key,
                                                    "elapsed": float(elapsed_min),
                                                    "remaining": float(game_min_left) if game_min_left is not None else None,
                                                    "total_points": float(total_pts) if total_pts is not None else None,
                                                    "live_line": float(home_ml if pick_home else away_ml),
                                                    "side": ml_side,
                                                    "edge": float(ml_edge),
                                                    "edge_raw": float(ml_edge),
                                                    "edge_adj": float(ml_edge),
                                                    "strength": float(abs(ml_edge)),
                                                    "context": {
                                                        "thr_watch": float(ml_watch),
                                                        "thr_bet": float(ml_bet),
                                                        "p_home_pregame": float(p_home_win),
                                                        "p_home_implied": float(p_home_implied),
                                                        "p_away_implied": float(p_away_implied),
                                                        "cur_margin_home": float(home_margin),
                                                        "elapsed_min": float(elapsed_min),
                                                        "game_min_left": float(min_left),
                                                        "blend_w": float(blend_w),
                                                        "p_home_score": float(p_home_score),
                                                        "p_home_model": float(p_home_model),
                                                        "scale": float(scale),
                                                    },
                                                    "received_at": now,
                                                    "tick_bucket": bucket_key,
                                                }
                                                ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                                                if ok:
                                                    wrote_signals += 1
                                                    if first_bet_only and first_bet_k is not None:
                                                        with _live_lens_tick_lock:
                                                            _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                                                else:
                                                    errors.append(f"ml:{eid}:{info}")
                                                    if first_bet_only and first_bet_k is not None:
                                                        with _live_lens_tick_lock:
                                                            _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                                                throttle_p = f"{str(gid)}:{signal_key}:proj"
                                                with _live_lens_tick_lock:
                                                    lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                                    if lastp != bucket_key:
                                                        _live_lens_tick_last_proj_logged[throttle_p] = bucket_key
                                                        proj_ok = True
                                                    else:
                                                        proj_ok = False
                                                if proj_ok:
                                                    proj_body = {
                                                        "date": ds,
                                                        "game_id": gid,
                                                        "event_id": eid,
                                                        "home": home,
                                                        "away": away,
                                                        "period": period,
                                                        "sec_left_period": sec_left_period,
                                                        "klass": ml_klass,
                                                        "horizon": "game",
                                                        "market": "ml",
                                                        "proj_key": signal_key,
                                                        "elapsed": float(elapsed_min),
                                                        "remaining": float(game_min_left) if game_min_left is not None else None,
                                                        "line": float(home_ml if pick_home else away_ml),
                                                        "live_line": float(home_ml if pick_home else away_ml),
                                                        "side": ml_side,
                                                        "proj": float(p_home_model),
                                                        "sim_mu": float(p_home_win),
                                                        "strength": float(abs(ml_edge)),
                                                        "context": {
                                                            "pick_home": 1 if pick_home else 0,
                                                            "p_home_score": float(p_home_score),
                                                            "p_home_implied": float(p_home_implied),
                                                            "p_away_implied": float(p_away_implied),
                                                        },
                                                        "received_at": now,
                                                        "tick_bucket": bucket_key,
                                                    }
                                                    okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                                                    if okp:
                                                        wrote_projections += 1
                                                    else:
                                                        errors.append(f"proj_ml:{eid}:{infop}")
                    except Exception as e:
                        errors.append(f"total:{str(e)}")
        except Exception as e:
            errors.append(f"total_block:{str(e)}")

    # ---- Player props (use /api/live_player_lens rows; already has pace_vs_line + klass) ----
    if include_player_props and event_ids and max_props > 0:
        try:
            with app.test_client() as c:
                r = c.get(
                    f"/api/live_player_lens?ttl={int(ttl)}&recent_window_sec={int(recent_window_sec)}&date={ds}&event_ids={','.join(event_ids)}"
                )
                if r.status_code == 200:
                    j = r.get_json(silent=True)
                else:
                    j = None

            games_obj = (j.get("games") if isinstance(j, dict) else None)
            games_obj = games_obj if isinstance(games_obj, list) else []

            for gg in games_obj:
                if not isinstance(gg, dict):
                    continue
                try:
                    st = gg.get("status") if isinstance(gg.get("status"), dict) else {}
                    if not bool(st.get("in_progress")) or bool(st.get("final")):
                        continue

                    eid = str(gg.get("event_id") or "").strip()
                    gid = gg.get("game_id")
                    home = gg.get("home")
                    away = gg.get("away")
                    period = _safe_int(st.get("period"))
                    clock = st.get("clock")
                    sec_left_period = _live_parse_clock_to_sec_left(clock)
                    elapsed_min = _safe_float(st.get("elapsed_min"))

                    # Use server-side row klass/strength, but re-check thresholds from tuning
                    rows = gg.get("rows") if isinstance(gg.get("rows"), list) else []
                    # Keep only meaningful candidates
                    cands: list[dict[str, Any]] = []
                    for r0 in rows:
                        if not isinstance(r0, dict):
                            continue
                        if r0.get("player") is None or r0.get("stat") is None:
                            continue
                        if _safe_float(r0.get("line")) is None:
                            continue
                        ev = _safe_float(r0.get("pace_vs_line"))
                        if ev is None:
                            continue
                        strength = abs(float(ev))
                        klass = _klass(strength, pp_watch, pp_bet)
                        if not _allow(log_mode_props, klass):
                            continue

                        if first_bet_only and klass != "BET":
                            continue
                        r1 = dict(r0)
                        r1["_edge"] = float(ev)
                        r1["_strength"] = float(strength)
                        r1["_klass"] = klass
                        cands.append(r1)
                    cands.sort(key=lambda r: float(r.get("_strength") or 0.0), reverse=True)
                    cands = cands[: int(max_props)]

                    for r0 in cands:
                        try:
                            player = str(r0.get("player") or "").strip() or None
                            team_tri = str(r0.get("team_tri") or "").strip().upper() or None
                            stat_key = str(r0.get("stat") or "").strip().lower() or None
                            name_key = str(r0.get("name_key") or player or "").strip() or None
                            name_norm = _norm_player_name(name_key or "")
                            if not (player and stat_key and name_norm):
                                continue

                            throttle_key = f"player_prop:{name_norm}:{stat_key}"
                            edge = _safe_float(r0.get("_edge"))
                            strength = _safe_float(r0.get("_strength"))
                            klass = str(r0.get("_klass") or "NONE")
                            side = None
                            try:
                                if edge is not None:
                                    side = "OVER" if float(edge) > 0 else ("UNDER" if float(edge) < 0 else None)
                            except Exception:
                                side = None

                            # Best-effort throttling per (gid, throttle_key)
                            throttle_k = f"{str(gid)}:{throttle_key}"
                            with _live_lens_tick_lock:
                                last = _live_lens_tick_last_logged.get(throttle_k)
                                if last == bucket_key:
                                    skipped_throttle += 1
                                    continue
                                _live_lens_tick_last_logged[throttle_k] = bucket_key

                            first_bet_k = None
                            if first_bet_only and side is not None:
                                first_bet_k = f"{ds}:{str(gid)}:player_prop:{name_norm}:{stat_key}:{str(side)}"
                                with _live_lens_tick_lock:
                                    if _live_lens_tick_first_bet_logged.get(first_bet_k):
                                        skipped_first_bet += 1
                                        continue
                                    _live_lens_tick_first_bet_logged[first_bet_k] = "pending"

                            base = {
                                "date": ds,
                                "game_id": gid,
                                "event_id": eid,
                                "home": home,
                                "away": away,
                                "period": period,
                                "sec_left_period": sec_left_period,
                                "tuning_source": "cron",
                                "schema_version": 2,
                                "tick_bucket": bucket_key,
                            }

                            body = {
                                **base,
                                "klass": klass,
                                "horizon": "live",
                                "market": "player_prop",
                                "signal_key": throttle_key,
                                "player": player,
                                "team_tri": team_tri,
                                "name_key": name_norm,
                                "stat": stat_key,
                                "side": side,
                                "mp": _safe_float(r0.get("mp")),
                                "pf": _safe_float(r0.get("pf")),
                                "starter": (bool(r0.get("starter")) if ("starter" in r0 and r0.get("starter") is not None) else None),
                                "actual": _safe_float(r0.get("actual")),
                                "line": _safe_float(r0.get("line")),
                                "line_source": (str(r0.get("line_source")) if r0.get("line_source") is not None else None),
                                "line_live_age_sec": _safe_float(r0.get("line_live_age_sec")),
                                "line_live_span": _safe_float(r0.get("line_live_span")),
                                "line_live_n": _safe_int(r0.get("line_live_n")),
                                "pace_proj": _safe_float(r0.get("pace_proj")),
                                "sim_mu": _safe_float(r0.get("sim_mu")),
                                "edge": _safe_float(edge),
                                "edge_raw": _safe_float(edge),
                                "edge_adj": _safe_float(edge),
                                "strength": _safe_float(strength),
                                "klass_raw": (str(r0.get("klass_raw")) if r0.get("klass_raw") is not None else None),
                                "bettable": (bool(r0.get("bettable")) if ("bettable" in r0 and r0.get("bettable") is not None) else None),
                                "bettable_score": _safe_float(r0.get("bettable_score")),
                                "bettable_reasons": ([str(x).strip() for x in r0.get("bettable_reasons") if str(x).strip()] if isinstance(r0.get("bettable_reasons"), list) else None),
                                "price_hold": _safe_float(r0.get("price_hold")),
                                "edge_sigma": _safe_float(r0.get("edge_sigma")),
                                "context": {
                                    "sim_vs_line": _safe_float(r0.get("sim_vs_line")),
                                    "sim_sd": _safe_float(r0.get("sim_sd")),
                                    "exp_min": _safe_float(r0.get("exp_min")),
                                    "exp_min_eff": _safe_float(r0.get("exp_min_eff")),
                                    "exp_min_rot": _safe_float(r0.get("exp_min_rot")),
                                    "proj_min_final": _safe_float(r0.get("proj_min_final")),
                                    "rot_w": _safe_float(r0.get("rot_w")),
                                    "rot_on_court": (bool(r0.get("rot_on_court")) if ("rot_on_court" in r0 and r0.get("rot_on_court") is not None) else None),
                                    "rot_cur_on_sec": _safe_int(r0.get("rot_cur_on_sec")),
                                    "rot_cur_off_sec": _safe_int(r0.get("rot_cur_off_sec")),
                                    "rot_avg_stint_sec": _safe_float(r0.get("rot_avg_stint_sec")),
                                    "rot_avg_rest_sec": _safe_float(r0.get("rot_avg_rest_sec")),
                                    "injury_flag": (bool(r0.get("injury_flag")) if ("injury_flag" in r0 and r0.get("injury_flag") is not None) else None),
                                    "injury_gap": _safe_float(r0.get("injury_gap")),
                                    "usage_window_sec": int(recent_window_sec),
                                    "pace_mult": _safe_float(r0.get("pace_mult")),
                                    "role_mult": _safe_float(r0.get("role_mult")),
                                    "foul_mult": _safe_float(r0.get("foul_mult")),
                                    "hot_cold_mult": _safe_float(r0.get("hot_cold_mult")),
                                    "hot_ppp_recent": _safe_float(r0.get("hot_ppp_recent")),
                                    "hot_ppp_game": _safe_float(r0.get("hot_ppp_game")),
                                    "hot_p3_recent": _safe_float(r0.get("hot_p3_recent")),
                                    "hot_p3_game": _safe_float(r0.get("hot_p3_game")),
                                    "usg_recent": _safe_float(r0.get("usg_recent")),
                                    "usg_game": _safe_float(r0.get("usg_game")),
                                    "team_usg_recent": _safe_float(r0.get("team_usg_recent")),
                                    "team_usg_game": _safe_float(r0.get("team_usg_game")),
                                    "fg3a_recent": _safe_float(r0.get("fg3a_recent")),
                                    "fg3a_game": _safe_float(r0.get("fg3a_game")),
                                    "team_3a_recent": _safe_float(r0.get("team_3a_recent")),
                                    "team_3a_game": _safe_float(r0.get("team_3a_game")),
                                    "price_over": _safe_float(r0.get("price_over")),
                                    "price_under": _safe_float(r0.get("price_under")),
                                    "win_prob_over": _safe_float(r0.get("win_prob_over")),
                                    "win_prob_under": _safe_float(r0.get("win_prob_under")),
                                    "implied_prob_over": _safe_float(r0.get("implied_prob_over")),
                                    "implied_prob_under": _safe_float(r0.get("implied_prob_under")),
                                    "ev_side": (str(r0.get("ev_side")) if r0.get("ev_side") is not None else None),
                                    "win_prob": _safe_float(r0.get("win_prob")),
                                    "implied_prob": _safe_float(r0.get("implied_prob")),
                                    "ev": _safe_float(r0.get("ev")),
                                },
                                "elapsed": float(elapsed_min) if elapsed_min is not None else None,
                                "received_at": now,
                            }

                            ok, info = _append_live_lens_signal_jsonl(_to_jsonable(body), ds)
                            if ok:
                                wrote_signals += 1
                                if first_bet_only and first_bet_k is not None:
                                    with _live_lens_tick_lock:
                                        _live_lens_tick_first_bet_logged[first_bet_k] = bucket_key
                            else:
                                errors.append(f"prop:{eid}:{throttle_key}:{info}")
                                if first_bet_only and first_bet_k is not None:
                                    with _live_lens_tick_lock:
                                        _live_lens_tick_first_bet_logged.pop(first_bet_k, None)

                            # Projection stream (mirrors client): throttle separately
                            throttle_p = f"{str(gid)}:{throttle_key}:proj"
                            with _live_lens_tick_lock:
                                lastp = _live_lens_tick_last_proj_logged.get(throttle_p)
                                if lastp == bucket_key:
                                    continue
                                _live_lens_tick_last_proj_logged[throttle_p] = bucket_key

                            proj_body = {
                                **base,
                                "klass": klass,
                                "horizon": "live",
                                "market": "player_prop",
                                "proj_key": throttle_key,
                                "player": player,
                                "team_tri": team_tri,
                                "name_key": name_norm,
                                "stat": stat_key,
                                "side": side,
                                "line": _safe_float(r0.get("line")),
                                "proj": _safe_float(r0.get("pace_proj")),
                                "sim_mu": _safe_float(r0.get("sim_mu")),
                                "win_prob_over": _safe_float(r0.get("win_prob_over")),
                                "win_prob_under": _safe_float(r0.get("win_prob_under")),
                                "implied_prob_over": _safe_float(r0.get("implied_prob_over")),
                                "implied_prob_under": _safe_float(r0.get("implied_prob_under")),
                                "price_over": _safe_float(r0.get("price_over")),
                                "price_under": _safe_float(r0.get("price_under")),
                                "strength": _safe_float(strength),
                                "elapsed": float(elapsed_min) if elapsed_min is not None else None,
                                "received_at": now,
                            }
                            okp, infop = _append_live_lens_projection_jsonl(_to_jsonable(proj_body), ds)
                            if okp:
                                wrote_projections += 1
                            else:
                                errors.append(f"proj:{eid}:{throttle_key}:{infop}")
                        except Exception as e:
                            errors.append(f"prop_row:{str(e)}")
                except Exception as e:
                    errors.append(f"prop_game:{str(e)}")
        except Exception as e:
            errors.append(f"props_block:{str(e)}")

    return jsonify({
        "ok": True,
        "date": ds,
        "in_progress_games": int(len(inprog)),
        "event_ids": event_ids,
        "wrote_signals": int(wrote_signals),
        "wrote_projections": int(wrote_projections),
        "skipped_throttle": int(skipped_throttle),
        "skipped_first_bet": int(skipped_first_bet),
        "first_bet_only": bool(first_bet_only),
        "min_interval_sec": int(min_interval_sec),
        "max_props_per_game": int(max_props),
        "recent_window_sec": int(recent_window_sec),
        "artifacts_dir": str(_live_lens_artifacts_dir()),
        "errors": errors[:25],
        "utc": datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
    })


@app.route("/api/admin/daily-update", methods=["POST", "GET"])
def api_admin_daily_update():
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not _admin_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    if _job_state["running"]:
        return jsonify({"status": "already-running", "started_at": _job_state["started_at"]}), 409
    do_push = (str(request.args.get("push", "1")).lower() in {"1", "true", "yes"})
    t = threading.Thread(target=_daily_update_job, args=(do_push,), daemon=True)
    t.start()
    return jsonify({"status": "started", "push": do_push, "started_at": datetime.utcnow().isoformat()}), 202


@app.route("/api/admin/daily-update/status")
def api_admin_daily_update_status():
    if not _debug_routes_enabled():
        return jsonify({"error": "disabled"}), 404
    if not _admin_auth_ok(request):
        return jsonify({"error": "unauthorized"}), 401
    try:
        tail = int(request.args.get("tail", "200"))
    except Exception:
        tail = 200
    logs = _job_state.get("logs", [])
    if tail > 0:
        logs = logs[-tail:]
    return jsonify({
        "running": _job_state["running"],
        "started_at": _job_state["started_at"],
        "ended_at": _job_state["ended_at"],
        "ok": _job_state["ok"],
        "log_file": _job_state.get("log_file"),
        "logs": logs,
    })


@app.route("/api/cron/props-edges", methods=["POST", "GET"])
def api_cron_props_edges():
    """Compute player props edges CSV for the given date via CLI.

    Query params:
      - date (required): YYYY-MM-DD
      - source (optional): odds source; default 'auto'
      - push (optional): '1' to git commit/push artifacts

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    Writes data/processed/props_edges_YYYY-MM-DD.csv
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=True)
    source = (request.args.get("source") or "auto").strip()
    mode = (request.args.get("mode") or "auto").strip()
    use_saved_q = (request.args.get("use_saved") or request.args.get("use-saved") or "1").strip().lower()
    use_saved = (use_saved_q in {"1","true","yes"})
    do_push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})
    do_async = (str(request.args.get("async", "0")).lower() in {"1","true","yes"})
    # Choose python executable
    py = _resolve_python()
    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_props_edges_{d}_{stamp}.log"
    try:
        # Do not block request path on long training when async=1. We'll ensure in background job.
        def _quick_have_props_models() -> bool:
            try:
                mdir = BASE_DIR / "models"
                return (mdir / "props_models.joblib").exists() and (mdir / "props_feature_columns.joblib").exists()
            except Exception:
                return False
        env = dict(os.environ)
        env["PYTHONPATH"] = str(SRC_DIR)
        cmd = [str(py), "-m", "nba_betting.cli", "props-edges", "--date", d, "--source", source]
        if mode:
            cmd += ["--mode", mode]
        if not use_saved:
            cmd += ["--no-use-saved"]
        if do_async:
            def _job():
                try:
                    # Ensure props models exist before computing edges (can be slow on first run)
                    if not _quick_have_props_models():
                        _ensure_props_models(log_file)
                    _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
                    if do_push:
                        _git_commit_and_push(msg=f"props-edges {d}")
                except Exception:
                    pass
            t = threading.Thread(target=_job, daemon=True)
            t.start()
            return jsonify({
                "status": "started",
                "date": d,
                "log_file": str(log_file),
            }), 202
        # Synchronous path: ensure models now, then run
        _okp, _info = _ensure_props_models(log_file)
        rc = _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
        out = DATA_PROCESSED_DIR / f"props_edges_{d}.csv"
        rows = 0
        if out.exists():
            try:
                rows = int(len(pd.read_csv(out)))
            except Exception:
                rows = 0
        pushed = None; push_detail = None
        if do_push:
            ok, detail = _git_commit_and_push(msg=f"props-edges {d}")
            pushed = bool(ok); push_detail = detail
        try:
            _cron_meta_update("props_edges", {"date": d, "rows": int(rows), "output": str(out)})
        except Exception:
            pass
        return jsonify({
            "date": d,
            "rc": int(rc),
            "output": str(out),
            "rows": int(rows),
            "log_file": str(log_file),
            "pushed": pushed,
            "push_detail": push_detail,
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/cron/fetch-rosters", methods=["POST", "GET"])
def api_cron_fetch_rosters():
    """Fetch team rosters for a season and persist under data/processed.

    Query params:
      - season: NBA season string (e.g., 2025-26)
      - push: 1 to commit/push artifacts
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    season = (request.args.get("season") or "2025-26").strip()
    # Choose python executable
    py = os.environ.get("PYTHON", (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python")
    if not py or not Path(str(py)).exists():
        py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
        py = str(py_win) if py_win.exists() else "python"
    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_fetch_rosters_{season}_{stamp}.log"
    try:
        env = dict(os.environ); env["PYTHONPATH"] = str(SRC_DIR)
        cmd = [str(py), "-m", "nba_betting.cli", "fetch-rosters-cmd", "--season", season]
        rc = _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
        out_csv = DATA_PROCESSED_DIR / f"rosters_{season.replace('/', '-')}.csv"
        rows = 0
        if out_csv.exists():
            try:
                rows = int(len(pd.read_csv(out_csv)))
            except Exception:
                rows = 0
        pushed = None; push_detail = None
        if str(request.args.get("push", "0")).lower() in {"1","true","yes"}:
            ok, detail = _git_commit_and_push(msg=f"fetch-rosters {season}")
            pushed = bool(ok); push_detail = detail
        return jsonify({"season": season, "rc": int(rc), "rows": int(rows), "output": str(out_csv), "log_file": str(log_file), "pushed": pushed, "push_detail": push_detail})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/cron/props-predictions", methods=["POST", "GET"])
def api_cron_props_predictions():
    """Precompute player props predictions CSV for a given date via CLI.

    Query params:
    - date (optional): YYYY-MM-DD, defaults to the current US local slate date
      - slate_only (optional): '1' to limit to today's slate (default 1)
      - push (optional): '1' to git commit/push artifacts

    Auth: CRON_TOKEN (preferred) or ADMIN_KEY (fallback/manual).
    Writes data/processed/props_predictions_YYYY-MM-DD.csv
    """
    if not (_cron_auth_ok(request) or _admin_auth_ok(request)):
        return jsonify({"error": "unauthorized"}), 401
    d = _parse_date_param(request, default_to_today=True)
    slate_only_q = (request.args.get("slate_only") or request.args.get("slate-only") or "1").strip().lower()
    slate_only = (slate_only_q in {"1", "true", "yes"})
    calib_q = (request.args.get("calibrate") or "1").strip().lower()
    do_calib = (calib_q in {"1","true","yes"})
    calib_window = request.args.get("calib_window") or request.args.get("calib-window") or "7"
    do_push = (str(request.args.get("push", "0")).lower() in {"1", "true", "yes"})
    do_async = (str(request.args.get("async", "0")).lower() in {"1","true","yes"})

    # Choose python executable
    py = os.environ.get("PYTHON", (os.environ.get("VIRTUAL_ENV") or "") + "/bin/python")
    if not py or not Path(str(py)).exists():
        py_win = (Path(os.environ.get("VIRTUAL_ENV") or "") / "Scripts" / "python.exe")
        py = str(py_win) if py_win.exists() else "python"

    logs_dir = _ensure_logs_dir(); stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    log_file = logs_dir / f"cron_props_predictions_{d}_{stamp}.log"
    try:
        # Avoid blocking request thread on model build when async=1; do a quick existence check instead.
        def _quick_have_props_models() -> bool:
            try:
                mdir = BASE_DIR / "models"
                return (mdir / "props_models.joblib").exists() and (mdir / "props_feature_columns.joblib").exists()
            except Exception:
                return False
        env = dict(os.environ)
        env["PYTHONPATH"] = str(SRC_DIR)
        cmd = [str(py), "-m", "nba_betting.cli", "predict-props", "--date", d, "--use-pure-onnx"]
        if slate_only:
            cmd += ["--slate-only"]
        else:
            cmd += ["--no-slate-only"]
        if do_calib:
            cmd += ["--calibrate", "--calib-window", str(calib_window)]
        else:
            cmd += ["--no-calibrate"]
        if do_async:
            def _job():
                try:
                    if not _quick_have_props_models():
                        _ensure_props_models(log_file)
                    _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
                    if do_push:
                        _git_commit_and_push(msg=f"props-predictions {d}")
                except Exception:
                    pass
            t = threading.Thread(target=_job, daemon=True)
            t.start()
            return jsonify({
                "status": "started",
                "date": d,
                "log_file": str(log_file),
            }), 202
        # Synchronous: ensure models then run
        _okp, _info = _ensure_props_models(log_file)
        rc = _run_to_file(cmd, log_file, cwd=BASE_DIR, env=env)
        out = DATA_PROCESSED_DIR / f"props_predictions_{d}.csv"
        rows = 0
        if out.exists():
            try:
                rows = int(len(pd.read_csv(out)))
            except Exception:
                rows = 0
        pushed = None; push_detail = None
        if do_push:
            ok, detail = _git_commit_and_push(msg=f"props-predictions {d}")
            pushed = bool(ok); push_detail = detail
        try:
            _cron_meta_update("props_predictions", {"date": d, "rows": int(rows), "output": str(out)})
        except Exception:
            pass
        return jsonify({
            "date": d,
            "rc": int(rc),
            "output": str(out),
            "rows": int(rows),
            "log_file": str(log_file),
            "pushed": pushed,
            "push_detail": push_detail,
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


